INSERT INTO "app_table_rows" ("pk","table_name","row_json","created_at","updated_at") VALUES(873,'authors','{"id":"1772140265202","name":"তোয়া নিধী দোয়েল","bio":"কল্পনার ডানায় ভর করে, কল্পিত স্বপ্ন ছোঁয়ার অভিলাষে!","avatar":"/uploads/authors/avatars/2026/02/45e4608d-5856-4c62-ae3a-41914d664132.jpg","username":"TuaNidhiDoyel","links":[{"name":"Facebook","url":"https://www.facebook.com/profile.php?id=61558867560710"}]}','2026-03-07T23:14:15.343Z','2026-03-07T23:14:15.343Z');
INSERT INTO "app_table_rows" ("pk","table_name","row_json","created_at","updated_at") VALUES(874,'authors','{"id":"1772353078374","name":"মোঃ সাইফুল ইসলাম","bio":"তবু তোমাকে ভালোবেসে\nমুহূর্তের মধ্যে ফিরে এসে\nবুঝেছি অকূলে জেগে রয়\nঘড়ির সময়ে আর মহাকালে যেখানেই রাখি এ হৃদয়।\n\nজীবনানন্দ দাশ...","avatar":"/uploads/authors/avatars/2026/03/8d3bd759-d69c-416c-b147-b6a87cf20a39.jpg","username":"Md_Saiful_Islam","links":[{"name":"Facebook","url":"https://www.facebook.com/sojibargolpojuri"}]}','2026-03-07T23:14:15.343Z','2026-03-07T23:14:15.343Z');
INSERT INTO "app_table_rows" ("pk","table_name","row_json","created_at","updated_at") VALUES(875,'authors','{"id":"1772389296824","name":"সাদিয়া তিন্তি","bio":"জীবনে যা কিছু বাকি রয়ে গেল, সেসব কল্পনা হয়ে বাঁচুক। কলমের আঁচড়ে তাদের নতুন জীবন হোক। পূর্ণতা পাক প্রতিটা স্বপ্ন।\n~সাদিয়া তিন্তি 🥀","avatar":"/uploads/authors/avatars/2026/03/3b828a03-b628-467c-ac3b-2cf331e8a5b9.jpg","username":"SadiaTinti","links":[{"name":"Facebook","url":"https://www.facebook.com/profile.php?id=61573501343530"}]}','2026-03-07T23:14:15.343Z','2026-03-07T23:14:15.343Z');
INSERT INTO "app_table_rows" ("pk","table_name","row_json","created_at","updated_at") VALUES(876,'authors','{"id":"1772353381257","name":"সায়মা ইসলাম","bio":"যা লিখি, তা হয়তো এলোমেলো...\nতবু প্রতিটি শব্দে লুকিয়ে থাকে\nএক টুকরো ব্যথা, এক বিন্দু ভালোবাসা।✨❤️\n~সায়মা ইসলাম 🌸","avatar":"/uploads/authors/avatars/2026/03/281ba299-6aa6-4bf8-bdaf-e26e4c8f0ca6.jpg","username":"SaymaIslam","links":[{"name":"Facebook","url":"https://www.facebook.com/profile.php?id=61577742482132"}]}','2026-03-07T23:14:15.343Z','2026-03-07T23:14:15.343Z');
