INSERT INTO "app_table_rows" ("pk","table_name","row_json","created_at","updated_at") VALUES(905,'stories','{"id":"1772140462893","title":"একপাক্ষিক অনুরাগ","excerpt":"__MAHEAN_META__:{\"status\":\"published\",\"submittedBy\":\"primary-admin\",\"author\":\"তোয়া নিধী দোয়েল\",\"category\":\"অণুগল্প\",\"coverImage\":\"/uploads/stories/covers/2026/03/f0d1f377-c295-4916-b823-fd97d92ce861.png\",\"slug\":\"একপাক্ষিক-অনুরাগ\",\"parts\":[{\"id\":\"1\",\"title\":\"পর্ব 01\",\"content\":\"\"}],\"comments\":0}:__MAHEAN_META_END__সে কখনো বলেওনি ভালোবাসি। তবুও আমি ভেবেছিলাম সে আমাকে ভালোবাসে। তাঁর নীরবতাকেই প্রতিদিন ছুঁয়ে ভেবেছিলাম— ভালোবাসা বোধহয় এমনি, যেখানে শব্দ লাগে না। শুধু একাকী নিভৃতে অনুভব কর‍তে হয়!","content":"সে কখনো বলেওনি ভালোবাসি। তবুও আমি ভেবেছিলাম সে আমাকে ভালোবাসে। তাঁর নীরবতাকেই প্রতিদিন ছুঁয়ে ভেবেছিলাম— ভালোবাসা বোধহয় এমনি, যেখানে শব্দ লাগে না। শুধু একাকী নিভৃতে অনুভব কর‍তে হয়!\nআমি প্রতিদিন চোখের নিচে ক্লান্তি এঁকে তাঁর নামটা মুখে নিতাম। দিন শেষে নেত্রপল্লব বুজিলে ভেসে ওঠতো তাঁর মায়াবী মুখশ্রী। যা আমাকে সপ্নে তাড়া করে বেড়াতো। চেষ্টা করতাম তাকে মনে না করার, তবুও প্রতিবার সূর্যাস্তে মনে হতো— সে যেনো আমার শরীরের থেকে ছেঁকে নেওয়া শেষ আলোটুকু!\nভালোবাসা আসলে একটা নিঃশব্দ আগুন!\nযেটা বাইরের কেউ দেখে না,\nকিন্তু ভেতরটা ছাই করে দেয়। \nসে একদিন চলে গেলো। সরাসরি কিছু বললো না। হয়তো সে অনেক আগেই চলে গিয়েছিলো, আমিই শুধু নিজের মাঝে ধরে রেখেছিলাম। একটা মৃত সম্পর্কের শবদেহ। তাঁর চলে যাওয়া দেখেছিলাম ভেজা দৃষ্টিতে। বুকের ভেতর খুব ঠান্ডা লেগেছিলো। যেন ভিতরে ভেতরে বরফ জমে আছে।\nআমি তাকে দোষ দেই না। আসলে সে থাকতি চায়নি। আমার হাত ধরতে চায়নি। হয়তো কখনো ইচ্ছেই ছিলো না। শুধু আমি ধরতে চেয়েছি। ভেবেছিলাম— ভালোবাসা মানে ধরে রাখা।\nচেষ্টা করেছিলাম একটা গল্প বুনতে। যেখানে সে আর আমি থাকবো। থাকবে কিছু ছোট ছোট সপ্ন। আর থাকবে কিছু সহজ কথা।\nকিন্তু হায়! কথা শেষ হলো না। কেউ শুনলো না। সে গুলো দীর্ঘদিন আমার বুকের ভেতর থেকে পচে গেলো।\nআমার প্রেমটা ছিলো এমনই। সে আমার হয়নি। আর আমি অন্য কাউকে তাঁর মতো হতে দিইনি। প্রতিটা মুখের আড়ালে আমি শুধু তাঁর চোখ খুঁজে গেছি। আর প্রতিবার ব্যর্থ হয়ে ফিরে এসেছি আয়নার কাছে। নিজের মুখ টা দেখে অবাক হয়েছি। এই কী সেই আমি!\nপ্রেম খুব সুন্দর ধ্বংস।\nযেখানে ফুল ফোটে ঠিকই। শুধু মালির বুকে রক্ত জমে থাকে কেবল। যেখানে নিজেকে খুব ধীরে ধীরে, শান্তভাবে শেষ করে ফেলতে হয়।\nসে চলে যাওয়ার পর ভেবেছিলাম— হয়তো সব কিছু থেমে যাবে। কিন্তু না; কিছুই থামে নি। থেমে গেছি শুধু আমি। থেমে গেছে আমার সময়। এখনো সে মাঝে মঝে আমায় সপ্নে তাড়া করে। আমি জেগে ওঠে লম্বা শ্বাস ফেলি। নিজেকে বোঝায়াই সপ্ন তো শুধু সপ্ন। সপ্নে যা পাই বাস্তবে তা কখনোই আসে না।\nযদি এখনো তাঁর ছবি দেখি, মুগ্ধ নয়নে তাকিয়ে থাকি। কেউ বুঝতে পারে না। এই নাম বলা মুখটাই আমার জীবনে কত বড় কবিতা। কত শত ছন্দ তাকে ঘিরে। একতরফা, অসম্পূর্ণ আর কত ভয়ংকর সুন্দর।\nএকতরফা প্রেম ফুলের মত নয়!\nএটা জ্বলন্ত দাবানল।\nযা মানুষ নিজেই জ্বালায়, আবার নিজেই পুড়ে।\nকেউ আসে না নিভাতে। কেউ আসে না দেখতে।\nআসলে একতরফা ভালবাসাই ভুল। \nযে করে, সে নিজেই নিজের সর্বনাশের মূল!\n_____________________সমাপ্ত__________________\n®দোয়েল\n১৫জুন, ২০২৫\nরবিবার","author_id":"1772140265202","author":"তোয়া নিধী দোয়েল","category_id":"অণুগল্প","category":"অণুগল্প","views":2,"image":null,"cover_image":"/uploads/stories/covers/2026/03/f0d1f377-c295-4916-b823-fd97d92ce861-cb202603311808-1.png","slug":"একপাক্ষিক-অনুরাগ","tags":[],"parts":[{"id":"1","title":"পর্ব 01","content":"সে কখনো বলেওনি ভালোবাসি। তবুও আমি ভেবেছিলাম সে আমাকে ভালোবাসে। তাঁর নীরবতাকেই প্রতিদিন ছুঁয়ে ভেবেছিলাম— ভালোবাসা বোধহয় এমনি, যেখানে শব্দ লাগে না। শুধু একাকী নিভৃতে অনুভব কর‍তে হয়!\nআমি প্রতিদিন চোখের নিচে ক্লান্তি এঁকে তাঁর নামটা মুখে নিতাম। দিন শেষে নেত্রপল্লব বুজিলে ভেসে ওঠতো তাঁর মায়াবী মুখশ্রী। যা আমাকে সপ্নে তাড়া করে বেড়াতো। চেষ্টা করতাম তাকে মনে না করার, তবুও প্রতিবার সূর্যাস্তে মনে হতো— সে যেনো আমার শরীরের থেকে ছেঁকে নেওয়া শেষ আলোটুকু!\nভালোবাসা আসলে একটা নিঃশব্দ আগুন!\nযেটা বাইরের কেউ দেখে না,\nকিন্তু ভেতরটা ছাই করে দেয়। \nসে একদিন চলে গেলো। সরাসরি কিছু বললো না। হয়তো সে অনেক আগেই চলে গিয়েছিলো, আমিই শুধু নিজের মাঝে ধরে রেখেছিলাম। একটা মৃত সম্পর্কের শবদেহ। তাঁর চলে যাওয়া দেখেছিলাম ভেজা দৃষ্টিতে। বুকের ভেতর খুব ঠান্ডা লেগেছিলো। যেন ভিতরে ভেতরে বরফ জমে আছে।\nআমি তাকে দোষ দেই না। আসলে সে থাকতি চায়নি। আমার হাত ধরতে চায়নি। হয়তো কখনো ইচ্ছেই ছিলো না। শুধু আমি ধরতে চেয়েছি। ভেবেছিলাম— ভালোবাসা মানে ধরে রাখা।\nচেষ্টা করেছিলাম একটা গল্প বুনতে। যেখানে সে আর আমি থাকবো। থাকবে কিছু ছোট ছোট সপ্ন। আর থাকবে কিছু সহজ কথা।\nকিন্তু হায়! কথা শেষ হলো না। কেউ শুনলো না। সে গুলো দীর্ঘদিন আমার বুকের ভেতর থেকে পচে গেলো।\nআমার প্রেমটা ছিলো এমনই। সে আমার হয়নি। আর আমি অন্য কাউকে তাঁর মতো হতে দিইনি। প্রতিটা মুখের আড়ালে আমি শুধু তাঁর চোখ খুঁজে গেছি। আর প্রতিবার ব্যর্থ হয়ে ফিরে এসেছি আয়নার কাছে। নিজের মুখ টা দেখে অবাক হয়েছি। এই কী সেই আমি!\nপ্রেম খুব সুন্দর ধ্বংস।\nযেখানে ফুল ফোটে ঠিকই। শুধু মালির বুকে রক্ত জমে থাকে কেবল। যেখানে নিজেকে খুব ধীরে ধীরে, শান্তভাবে শেষ করে ফেলতে হয়।\nসে চলে যাওয়ার পর ভেবেছিলাম— হয়তো সব কিছু থেমে যাবে। কিন্তু না; কিছুই থামে নি। থেমে গেছি শুধু আমি। থেমে গেছে আমার সময়। এখনো সে মাঝে মঝে আমায় সপ্নে তাড়া করে। আমি জেগে ওঠে লম্বা শ্বাস ফেলি। নিজেকে বোঝায়াই সপ্ন তো শুধু সপ্ন। সপ্নে যা পাই বাস্তবে তা কখনোই আসে না।\nযদি এখনো তাঁর ছবি দেখি, মুগ্ধ নয়নে তাকিয়ে থাকি। কেউ বুঝতে পারে না। এই নাম বলা মুখটাই আমার জীবনে কত বড় কবিতা। কত শত ছন্দ তাকে ঘিরে। একতরফা, অসম্পূর্ণ আর কত ভয়ংকর সুন্দর।\nএকতরফা প্রেম ফুলের মত নয়!\nএটা জ্বলন্ত দাবানল।\nযা মানুষ নিজেই জ্বালায়, আবার নিজেই পুড়ে।\nকেউ আসে না নিভাতে। কেউ আসে না দেখতে।\nআসলে একতরফা ভালবাসাই ভুল। \nযে করে, সে নিজেই নিজের সর্বনাশের মূল!\n_____________________সমাপ্ত__________________\n®দোয়েল\n১৫জুন, ২০২৫\nরবিবার"}],"comments":0,"is_featured":false,"read_time":null,"status":"published","submitted_by":"primary-admin","date":"2026-02-26T21:14:22.893Z","updated_at":"2026-03-31T18:08:55.968Z"}','2026-03-07T23:14:15.343Z','2026-03-31T11:35:43.777Z');
INSERT INTO "app_table_rows" ("pk","table_name","row_json","created_at","updated_at") VALUES(906,'stories','{"id":"1772140577928","title":"মনপবন ","excerpt":"__MAHEAN_META__:{\"status\":\"published\",\"submittedBy\":\"primary-admin\",\"author\":\"তোয়া নিধী দোয়েল\",\"category\":\"অণুগল্প\",\"coverImage\":\"/uploads/stories/covers/2026/03/0d8f0e35-85e8-45da-b380-fb047f0ecb64.png\",\"slug\":\"মনপবন\",\"parts\":[{\"id\":\"1\",\"title\":\"পর্ব 01\",\"content\":\"\"}],\"comments\":0}:__MAHEAN_META_END__সওদাগর বাড়ির, গেটের সামনে এসে থামে একটি রিকশা। সময়টা সন্ধ্যা নামার কিছু আগ মূহুর্ত। পশ্চিম আকাশে সোনার রবি অস্ত গিয়েছে। পরিবেশে ধীরে ধীরে আগমন ঘটছে অন্ধকারের!","content":"সওদাগর বাড়ির, গেটের সামনে এসে থামে একটি রিকশা। সময়টা সন্ধ্যা নামার কিছু আগ মূহুর্ত। পশ্চিম আকাশে সোনার রবি অস্ত গিয়েছে। পরিবেশে ধীরে ধীরে আগমন ঘটছে অন্ধকারের!\nরিকশা থেকে নামে, আকাশী রঙের থ্রি-পিছ পরা এক নারী। সাদা ওড়নার আঁচল মাথায় টানা। তবে, নামার সময় কিঞ্চিৎ বিপত্তি ঘটে! তাড়াহুড়ো করে নামতে গিয়ে, অসাবধানতাবশতঃ রিকশার হুডের সাথে মাথায় আঘাত পায়। এমনিতে-ই মনে রাগ, ক্ষোভ আর বিরক্ততে ছেয়ে আছে! তার ওপর হুট করে মাথায় চোট পাওয়াতে, বিরক্তির মাত্রা আকাশ ছোঁয়! মুখ দিয়ে বিরক্তি সূচক শব্দ করে।\nরিকশাওয়ালা দ্রত মেয়েটির কাছে এসে জিজ্ঞাসা করে,\n-আফামনি, দুক্কু পাইলেন?\nমেয়েটা মাথায় এক পাশে হাত দিয়ে; চোখ মুখ খিঁচে দাঁড়ায়। রিকশাওয়ালার কথা শুনে ডানে-বামে মাথা নাড়ায়। যার অর্থ সে আঘাত পায়নি! \nতারপর মাথা থেকে হাত নামিয়ে, পার্স থেকে টাকা বের করে ভাড়া পরিশোধ করে। রিকশাওয়ালা চলে যায় অজানা গন্তব্যে।\nমেয়েটা হাতের পার্স এক হাতে নিয়ে; অন্য হাতে মাথার ওড়না টেনে নেয়। ঘুরে দাঁড়ায় সওদাগর বাড়ির উদ্দেশ্যে। \nকয়েক পা হেঁটে গেটে টোকা দেয়। গেটের সামনে বসে থাকা দারোয়ান রফিক; গেটে থাকা ছিদ্র দিয়ে দেখে কে এসেছে। বাড়ির বড় বউয়ের মুখশ্রী দৃষ্টিগোচর হতেই; দ্রততরে গেট খুলে দেয়।\nমেয়েটি ভেতরে ঢুকলে, রফিক মোল্লা চমৎকার করে হেসে সালাম দেয়। মেয়েটা ও মৃদু হেসে সালামের উত্তর নিয়ে, মূল বাড়ির দিকে পা বাড়ায়।\nডুপ্লেক্স বাড়িটির মূল দরজায় প্রবেশ করার আগে, রাস্তার বাম পাশে একটা ওয়াটার ফাইউন্টেন। যেথায় থেকে পানি নির্গত হচ্ছে। আর ডান পাশে কুচকুচে কালো রঙের একটা গাড়ি। \nগাড়িটি দেখে মেয়েটার রাগের মাত্রা যেনো কিঞ্চিৎ পরিমাণ বেড়ে গেলো। পরপরই নিজেকে ধাতস্থ করে নিয়ে বাড়ির ভেতরে প্রবেশ করে।\n★\nশীত-তাপ নিয়ন্ত্রিত ঘরটির মধ্যে; আয়নার সামনে বসে আছে এক প্রাপ্ত বয়স্ক পুরুষ ও তাঁর দুই পুত্র। তাদের পরনে শুধু সাদা রঙের টাওয়েল। উপরি ভাগ খালি। বলা-বাহুল্য লোকটার ছানা-পোনা দুজনের বয়স তিন কি সাড়ে তিন বছর। যারা যমজ।\nলোকটা তাঁর এক পুত্র কে কোলে বসিয়ে, হেয়ার ড্রায়ারের মাধ্যমে চুল শুকিয়ে দিচ্ছে। উপর ছানা পাশে বসে বাবার কর্ম-কাণ্ড দেখছে। তাদের দেখে ধারণা করা যায়, তাঁরা মাত্র গোসল সেরেছে। \nতাদের থেকে কিঞ্চিৎ দূরে একটা মাইক্রোল্যাব স্পিকারে গান বাজছে। সেই গানের তালে-তালে মাথা দোলাচ্ছে লোকটা। বাচ্চা দু''জন গানের আগা-গোড়া না বুঝলে ও বাপের দেখা-দেখি দুলছে!\n★\nগটগট পায়ে বাড়ির ভেতরে প্রবেশ করে ঊষসী। সে এই বাড়ির বড়-বউ। চার-পাঁচ দিন আগে বাপের বাড়ি গিয়েছিলো। আবার একাই ফিরে এসেছে। কোনো একটা কারণে রাগে তার শরীর জ্বলছে! \nবাড়ির বৈঠক-খানায় বসে চা পান করছিলেন কালাম সওদাগর। ছেলের বউকে হন্ত-দন্ত হয়ে বাড়িতে প্রবেশ করতে দেখে ভ্রু কুঁচকায়। তবে তা দৃষ্টি-গোচর হয় না ঊষসীর। সে এক মনে হেঁটে দোতালায় উঠায় মগ্ন।\nঊষসীকে ঐ-ভাবে যেতে দেখে মনে দ্বিধা নিয়ে ডাকে,\n- মামনি!\nশ্বশুরের ডাক কানে যেতে পা -যুগল থেমে যায় ঊষসীর। নিজেকে নিয়ন্ত্রণ করে ঘুরে সালাম দেয়। কালাম সওদাগর সালামের উত্তর নিয়ে জিজ্ঞাসা করে\n-একা এসেছো? ঋত্বিক কই?\nস্বামীর কথা উঠতেই রাগের মাত্রা তর-তর করে বাড়ে। তবে তা প্রকাশ করতে দেয় না। সে মিথ্যে হাসি ফুটিয়ে বলে,\n-জি আব্বু, একাই এসেছি। জানিনা আপনার ছেলে কই।\nএইটুকু বলে সে প্রস্থান করে। কালাম সাহেব আর কিছু বলে না। বৌমা-র যাওয়ার দিকে ভাবুক দৃষ্টিতে তাকিয়ে থাকে। হয়তো দু''জনের জানে মধ্যে কিছু হয়েছে!\n★\nঋত্বিক তাঁর এক ছেলে ঋণয়ের চুল শুকিয়ে দিয়ে; অপর ছেলে ঋশানকে ও কোলে তুলে নেয়। গানের লিরিক্স এর সাথে সাথে তিন বাপ-ব্যাটা দুলে দুলে নাচ্ছে। তাদের দেখে বোঝা যাচ্ছে তাঁরা ভীষণ ফুর্তিতে আছে। ঋত্বিক ঋশান ও ঋণয়ের এক সাথে কোলে নিয়ে লিরিক্স এর তালে তালে তাল মিলিয়ে গাইতে লাগলো‚\n‘Peechhe Kuaa, Aage Mere Khaai\nTu Hi Bata Jaaun Main Kahaan\nMujhko Duaa Kiski Lagi Bhai\nAake Padhara Hoon Jo Yahaan\nIlle Fikar, Aaja Idhar\nBeat Pe Laga Le Tu Thumka’\nছানা-পোনা দুইজন সঠিক লিরিক্স বলতে না পারলেও; বাপের তালে তাল মেলানোর জন্য নিজেদের মত করে কি যেনো বলতে লাগলো! ঋত্বিক দুই ছেলে কে নামিয়ে দিয়ে ছেলেদের সমান সমান হয়ে হাঁটু ভেঙে বসলো। তারপর গানের তালে তালে হাত উপরে দিয়ে, শরীরের উপরিভাগ দুলিয়ে নাচতে লাগলো। আর ছেলেরা ঘুরে-ঘুরে, লাফিয়ে-লাফিয়ে নাচতে আরম্ভ করে। ঋত্বিক গেয়ে উঠে‚\n‘One Two Three Four Get On The Dance Floor\nOne Two Three Four Get On The Dance Floor\nBooty Shake, Booty Shake\nDappan Koothu Hard Core\nShoulder Hichak Michak\nBody Hichak Michak\nGimme, Gimme, Gimme\nGimme, Gimme, Gimme Some More’\nঋণয় ঋশান লাফাতে-লাফাতে তোতলিয়ে শুধু বলে,\n‘ওয়ান, তু, তিরি, ফ্লোর\nওয়ান, তু, তিরি, ফ্লোর’\nতিন বাপ-ব্যাটা ভীষণ ফুর্তি করে নেচে যাচ্ছে।\nরুমের সামনে এসে থমকে দাঁড়ায় ঊষসী। দরজা ভিড়ানো। ভেতর থেকে গানের বাজার আওয়াজ আসছে। সাথে হৈ-হুল্লোড়ের আওয়াজ ও আসছে। ও কপালে ভাজ ফেলে ভিড়ানো দরজা খুলে। \nভেতরের দৃশ্য দেখে মুখ হাঁ হয়ে যায়। ড্রেসিং টেবিলের সামনে বাদরের মত নাচ্ছে; সাদা টাওয়েল পড়া এক বড় বাদর ও তাঁর দুই ছানা। রুমের অবস্থা নাজেহাল! ফ্লোরে ছড়ানো বিভিন্ন চিপসের প্যাকেট, কোল্ড ড্রিংস, চকলেটের প্যাকেট,বার্গারের বক্স! \nসাথে ছড়িয়ে-ছিটিয়ে রয়েছে লেগো সেট, সুপারহিরো ফিগারস, একশন ফিগারস, রিমোট কন্ট্রোল গাড়ি, হেলিকপ্টার, বাবল গান, ক্যারাম বোর্ড, পাজাল, টুল বক্স ইত্যাদি। \nবিছানার এক পাশে উল্টো হয়ে পড়ে আছে মোটর-সাইকেল (বাচ্চাদের)। শার্ট-প্যান্ট, গেঞ্জি সব এলো মেলো হয়ে আছে বিছানায়। ঊষসী রুমের অবস্থা থেকে রাগে ফোসে উঠে। রুমটাকে বস্তি বানিয়ে ফেলেছে! সে যে এত দিন ধরে বাসায় নেই, তাতে এই বাপ-বেটার কিছুই যায় আসে না! ও রাগান্বিত কণ্ঠে বলে উঠে,\n-এই এই... এই সব কী করছেন?\nসহধর্মিণীর কণ্ঠ কর্ণগোচর হতে-ই নাচ থামিয়ে দেয় ঋত্বিক। ঘাড় ঘুরিয়ে তাকায় দরজার দিকে। নীল রঙের থ্রি-পিছ পরে চোখ দিয়ে আগুন ঝড়ছে যাঁর। সে দুই ছেলে কে ধরে তাদের নাচ ও বন্ধ করায়। তার পর উঠে দাঁড়ায়। কোমরে হাত দিয়ে পরনের টাওয়েল একটু উপরে তোলে। তার পর বুকে হাত গুঁজে দাঁড়ায়। দুই ছেলে ও ঘাড় বাঁকিয়ে একবার বাপ কে দেখে, বাপের মত বুকে হাত গুঁজে দাঁড়ানোর চেষ্টা করে। তবে ঋণের টাওয়েলের প্যাঁচ খুলে যেতে নেয়। ও কোনো মতে টাওয়েল ধরে ছোট করে ডাকে,\n-আব্বু, থুলে গ্যালো...!\nঋত্বিক ছেলের দিকে তাকিয়ে দ্রুত বসে ছেলের টাওয়েল আবার প্যাঁচিয়ে বেঁধে দেয়। \n-আরে আমার রাজপুত্র! ডোন্ট ওরি।\nএই বলে আবার উঠে দাঁড়ায়। তিন বাপ-বেটার কর্ম- কাণ্ড দেখে ঝাঁঝালো কণ্ঠে ঊষসী আবার বলে,\n-এই সব কী হচ্ছে এখানে? রুম টার এই অবস্থা কেন? বস্তি বানিয়ে ফেলেছেন।\nঋত্বিক আয়নাতে চুল ঠিক করে বলে,\n-আরে, ম্যাডাম। আপনি এখানে? কী মনে করে হঠাৎ, বাপের বাড়ি থেকে এত দ্রুত চলে এলেন? দেখতে এসেছেন আপনাকে ছাড়া আমরা তিন বাপ-বেটা কেমন আছি?\nঋত্বিকের কথায় আরও কয়েক দফা চেতে যায় ঊষসী। চোখ গরম করে তাকিয়ে থাকে। ঋত্বিক ছেলেদের উদ্দেশ্যে বলে,\n-বয়ে''স, এটা তোমাদের খালামণি। আমাদের সাথে দেখা করতে এসেছে। খালামণি কে হাই বলো।\nদুই ছেলে বাপের কথায়, ঊষসীর দিকে তাকিয়ে হাত নাড়িয়ে বলে,\n-হাই, খাম্নি!\n-হাই, খাম্নি!\nনিজের ছেলেদের মুখে খালামণি ডাক শুনে ঠোঁট হাঁ হয়ে যায় ঊষসীর। এই সব কি শিখেছে ওরা! চার-পাঁচ দিন বাড়ি থেকে চলে গেছে বলে এই সব শিখবে! ও ঋত্বিকের দিকে তাকিয়ে কটমট করতে করতে বলে,\n-এই সব ওদের কী শিখিয়েছেন আপনি? এই সব কোন ধরনের ভাষা?\nঋত্বিক দুই ছেলের দিকে তাকিয়ে বলে,\n-পিতৃভাষা! এই সব পিতৃভাষা! সবাই তো মাতৃভাষা শেখে৷ আমার ছেলেরা পিতৃভাষা শিখবে। তোমাদের মায়েদের জন্য; আমাদের বাপ দের স্থান অনেক পিছিয়ে গেছে। তোমাদের কথার জন্য, আমরা বাপরা কথা বলার ওয়ে পাইনা।  তাই আমার ছেলেদের পিতৃভাষা শিখিয়ে; পিতৃভাষা আইন চালু করবো। এতে সব বাবারা নিজেদের হারানো অধিকার ফিরে পাবে।\nএরপর ছেলেদের দিকে তাকিয়ে বলে,\n-কী বয়েস, আব্বুর নাম উজ্জ্বল করতে পারবে তো?\nঊষসী তেরে এসে বলে,\n-এক দম আলতু-ফালতু কথা বলবেন না। আমি বাসায় নেই আর (আশে-পাশে তাকিয়ে) এই সব কি করেছন? রুমটাকে বস্তি বানিয়ে ফেলেছেন। আর ছেলেদের এই সব কী বলছেন?\nঋত্বিক ঘাড় বাঁকিয়ে বলে,\n-তো, আপনাকে এত তাড়াতাড়ি বাপের বাড়ি থেকে আসতে বলেছে কে? আমি আর আমার ছানারা তো ভেবেছি এক-দুই বছর থাকবেন! আর আমরা একটু আমোদ-ফুর্তি করবো। আর আপনি আমাদের বিশ্বাস ভেঙে এত দ্রুত চলে এলেন? এইটা মোটেও আশা করি নি। আপনি এত বড় বিশ্বাসঘাতক!\nতারপর ছেলেদের উদ্দেশ্যে বলে,\n-বয়েস, কাম। আমাদের বেরোতে হবে।\nঋত্বিকের কথায় চোখ ছোট ছোট করে তাকিয়ে থাকে ঊষসী। মনে মনে একটু অবাক ও হয়। ও চলে যাওয়াতে বাপ-বেটার তাহলে ভীষণ ভালোই লেগেছে। ঋত্বিক ছেলেদের আদেশ করে আলমারির দিকে চলে যায়। বাচ্চারা ও বাধ্য ছেলের মত বাবার পিছু-পিছু হাঁটতে থাকে। এত দিন পর ছেলেদের দেখতে পেয়ে বুকের ভেতর ছট-ফট কতে থাকে ঊষসীর। কোলে নিয়ে আদর করতে মন ব্যাকুল হয়ে যায়। ও ছেলেদের উদ্দেশ্যে অস্থির কণ্ঠে ডেকে উঠে,\n-বাবা। আমার সোনারা। এই দিকে আসো।\nমায়ের ডাক শুনে ঘাড় ঘুরিয়ে তাকায় ঋণয় ঋশান। ঊষসীর চোখ ছলছল করে উঠে। হাত বাড়াতেই ছেলেরা বাবার উদ্দেশ্যে বলে,\n-আব্বু, আম্মা তি তোলে যাবো?\nঋত্বিক কাবাড থেকে নিজের ও ছেলেদের পোশাক বের কর‍তে করতে বলে,\n-এক দম না, আব্বু। এই দিকে চলে আসো।\nছেলেদুইটা বাবার আদেশ পেয়ে ঘুড়ে ঋত্বিকের দিকে চলে যায়। ঊষসী অগ্নি দৃষ্টি নিয়ে তাকিয়ে থাকে। যাওয়ার পথে আবার ঋশানের টাওয়েলের প্যাঁচ খুলে যায়। ও ঋত্বিক কে ডেকে উঠে,\n-আব্বু...!\nঋত্বিক পোশাক বের করে ছেলের দিকে এগিয়ে আসে। টাওয়েলে প্যাঁচ দিতে দিতে বলে,\n-ইস্! বার বার খুলে যায় কেনো?\nঊষসী চ্যাঁচিয়ে উঠে,\n-আমার ছেলেদের আমাকে দিয়ে দিন। আমি ওদের নিয়ে চলে যাবো।\nঋত্বিক ভ্রু কুঁচকে বলে,\n-মামার বাড়ির ওয়ারিশ পাওনি। চাইবার মাত্র হাতে তুলে দিবো। ইটস মাই প্রোপার্টি!\n-ছেলে দুইটা কিন্তু, আপনার একা-র না।\n-আমার একা-র না মানে? কোনো সন্দেহ আছে?\nঊষসী এক পা এগিয়ে এসে বলে,\n-আমি না থাকলে ছেলে দুইটা পেতেন কই?\nঋত্বিক অবজ্ঞার স্বরে বলে,\n-পৃথিবীতে কি মেয়ের আকাল পড়ছে? তুমি না থাকলে যেনো হতোই না!\nঊষসী ভ্রু কুঁচকে বলে,\n-ওরা হওয়ার আগে তো কত ঢং করতেন। সব সময় আমার পিছু পিছু ঘুর ঘুর করতেন। আর আজ পাঁচ দিন ধরে আমি বাড়ি নেই; তাতে আপনার কোনো ভ্রুক্ষেপ নেই!\nঋত্বিক ডানে বামে মাথা নাড়িয়ে বলে,\n-নির্বাচন শেষ। প্রচার ও শেষ! বুঝতে পেরেছো?\nঊষসীর কিছু বলতে গেলে, ওকে থামিয়ে দিয়ে; বাইরে থেকে একিটা ঝাড়ু এনে ঊষসীর হাতে তুলে দেয়। ওর দিকে ঝুঁকে বলে,\n-আমাকে ও আমার ছেলেদের রেখে, এত দিন বাপের বাড়ি থাকার অপরাধে ; মিঃ সওদাগর মিসেস সওদাগরকে, তাঁর এবং তাঁর ছানাপোনাদের জন্য আ্যসিস্ট্যান্ট হিসেবে নিযুক্ত করলো। \nআশা করি আপনি খুব ভালো-ভাবে অগোছালো রুমটাকে পরিষ্কার করবেন। আমাদের বাপ-বেটাদের বের হতে হবে। বায়!\nঊষসীর হাতে ঝাড়ু গুঁজে দিয়ে; বের করা পোশাক নিয়ে দুই ছেলের কাছে আসে। দুইটা ফর্মাল ব্ল্যাক শার্ট দুই ছেলেকে পড়িয়ে দেয়। সাথে ব্ল্যাক প্যান্ট। ছেলেদের সাথে ম্যাচ করে নিজেও ফর্মাল ব্ল্যাক শার্ট পড়ে। তার পর তিন জন আয়নার সামনে দাঁড়ায়। ঋত্বিক আয়নায় দেখতে দেখতে শার্টের কফ ভাজ করতে থাকে। আর আড়চোখে সহধর্মিণীর রাগ দেখতে থাকে। \nওর দেখা-দেখি ছেলেরাও তাদের ছোট ছোট হাত উঠিয়ে কফ ভাজ করার চেষ্টা করে। ঋত্বিক বাঁকা হেসে ছেলেদের কফ ভাজ করে দেয়। তার পর জেল দিয়ে চুল ঠিক করে, ড্রয়ার থেকে তিনিটা পোলারাইজড ব্ল্যাক সানক্লাস বের করে। বাকি দুইটা তুলোনামূলক ছোট। দুইটা দুই ছেলের হাতে দিয়ে, নিজে একটা হাতে তুলে নেয়। তার পর আয়নার দিকে তাকিয়ে বলে,\n-বয়ে''স, রেডি।\nছেলেরা উপরে নিচে মাথা নাড়ায়। ঋত্বিক ওয়ান, টু, থ্রি বলে তিনজনে এক সাথে আয়নার দিকে তাকিয়ে সানক্লাস চোখে পড়ে। তারপর ঋত্বিক ইশরা করে পকেটে হাত দিতে। ছেলেরা নিজেদের প্যান্টের পকেট খুঁজে তাতে হাঁত গুঁজে।\nদূরে ঝাড়ু হাতে অগ্নি দৃষ্টি নিয়ে তিন বাপ-বেটার ভাব দেখছে ঊষসী। বাপ-বেটাদের রেডি হওয়া শেষ হলে তিন জনে বাইরে যাওয়ার জন্য উদ্যত হয়। দুই ছেলে আগে বের হয়। ঊষসীর পাশ দিয়ে যাওয়ার সময়, ঋত্বিক সানগ্লাস তর্জনী আঙুলের দ্বারা একটু নিচু করে  ঊষসীকে চোখ মারে। ঊষসী দৃষ্টি সরিয়ে নেয়। ঋত্বিক রুম থেকে বেরিয়ে ঊষসীকে চেতানোর জন্য ছেলেদের উদ্দেশ্যে বলে,\n-বয়েস, কোনো আম্মু পছন্দ হলে আমাকে বলো। তোমাদের এনে দিবো।\nঋত্বিকের কথা কানে পৌঁছাতে ঊষসী ঝাড়ু ফেলে ছুটে বাইরে আসে। ততক্ষণে ঋত্বিক ঋশান ঋণয় নিচে নেমে গেছে। ঊষসী দাঁতে-দাঁত চেপে শুধু দাঁড়িয়ে থাকে।\n★\nরাত প্রায় অনেক টা। বেল্কনিতে বসে আছে ঊষসী। মৃদু-মন্দ বাতাস বইছে। আকাশে অর্ধ-চন্দ্র মেঘের আড়ালে লুকিয়ে পড়ছে। \nতিন বাপ-বেটা এখনো ফিরিনি। কই গেছে কে জানে। তা জানার আগ্রহ নেই ঊষসীর। স্বামীর সাথে বিবাদ সৃষ্টি হওয়াতে বাপের বাড়ি গিয়েছিলো। ভেবে ছিলো স্বামী মান ভাঙিয়ে নিয়ে আসবে। কিন্তু না! সে তো কোনো ভ্রুক্ষেপ-ই করলো না।\nগাড়ির হর্নের শব্দে ধ্যান ভাঙে ঊষসীর। গেট দিয়ে কালো গাড়িটা বাড়ির ভেতরে প্রবেশ করেছে। বোধহয় রাজ সাহেবরা ফিরলো। ঊষসী সেই দিকে এক পলক তাকিয়ে অন্য দিকে দৃষ্টি নেয়। \nকিছুক্ষণ সময় অতিবাহিত হওয়ার পর; ঊষসীর সামনে গোলাপের একটা তোড়া ধরে কেউ! যেখানে অনেক গুলো লাল টকটকে গোলাপ। ঊষসী ঘাড় ঘুরায় আগন্তুককে দেখার জন্য। ঋত্বিক এর মুখশ্রী দৃষ্টিগোচরে হতে সরে যেতে নেয়। তবে তার আগেই শক্ত বাহুডরে আবদ্ধ হয়ে যায়। ঋত্বিক ওকে পেছন থেকে শক্ত করে জড়িয়ে ধরে। গোলাপের তোড়া সামনে রেখে ওর ঘাড়ে থুতনি ঠেকায়। ঊষসী ছোটার চেষ্টা করে ঝাঁঝালো কণ্ঠে বলে উঠে,\n-এক দম নাটক করতে আসবেন না, এখন। ছাড়ুন। \nঋত্বিক মোহময় কণ্ঠে বলে,\n-ঝগড়া সব দিনে হবে। রাতের বেলা হাসবেন্ড-ওয়াইফ ঝগড়া কর‍ল এ ঘোর পাপ হয়।\nএই বলে হাতের বাঁধন আরও শক্ত করে। ঊষসী দাঁতে-দাঁত চেপে বলে,\n-নাটক করতে খুব ভালো ভাবেই শিখেছেন? তাইনা? রাগ করে চলে গেলাম, কই একটা বার তো আনতে গেলেন না। কল দিলেন না। এখন আবার ঢং করতে এসেছেন?\n-আজ তো যেতাম-ই। তোমাকে বেঁধে নিয়ে আসতাম। কিন্তু, তুমি তো নিজে থেকে চলে এলে। এতে কি দোষ আমার।\n-সরুন।\n-সরি, বউ। আর হবে না।\n-আমি আপনার কোনো কথা শুনতে চাই না।\n-এমন করো না বউ। বোঝার চেষ্টা করো, পাঁচ- পাঁচটা দিন তুমি আমার থেকে দূরে ছিলে। জানো কতটা বিরহে ছিলাম আমি? এখন আর দূরত্ব ভালো লাগছে না। তোমার যা বক্তব্য আছে, যত রাগ আছে সকালে দেখিও। আমি তো বলেছিই ঝগড়া সব দিনে হবে। রাতে ঝগড়া করতে নেই।\n-সরুন।\nঋত্বিক ফুলের তোড়া এক পাশে রেখে ঊষসীকে নিজের দিকে ঘোরায়। ঋত্বিক ঊষসীর দুই গালে হাত দিয়ে কপালে গভীর চুম্বন এঁকে দেয়। ও চোখের পাতা বন্ধ করে ফেলে। ঋত্বিক গাল ছেড়ে বুকের সাথে মিশিয়ে নেয় ওকে। মাথায় হাত বুলাতে বুলাতে বলে,\n-তোমাকে রাগাতে আমার ভীষণ ভালো লাগে, ম্যাডাম। আমি শুধু চাই, সেটা আমার কাছ থেকে, আমাকে একটু জড়িয়ে ধরে দেখাও।\n-হ্যাঁ, তাই তো এত দিন থেকে আসলাম; তাতে আপনার কিছু যায় আসি-নি।\nঋত্বিক ঊষসী কে ছেড়ে, নিজের দুই কান ধরে বলে,\n-ভালোবাসি, ভালোবাসি আর ভালোবাসি! আর রাগ করে থেকে ও না। সব দোষ আমার। আমার ভুল সব। আর কখনো এই রকম হবে না। এই বারের মত মাফ করে দিন ম্যাডাম।\nএকটু থেমে আবার বলে,\n-রাগ করো ঠিক আছে, তবে এই ভাবে দূরে ঠেলে দিও না। তোমার রাগের মধ্যে ও যে ভালোবাসা লুকানো আছে, সেটা আমি দেখে ফেলেছি। তাই তো আমাকে ছেড়ে থাকতে না পেরে নিজে থেকে চলে এসেছো।  তো, এবার একটু মুচকি হাসো।\n-মোটেও না। যান, নিজের ছেলেদের নিয়ে ঘুরে আসুন। আমোদ-ফুর্তি করুন। আমি না থাকলে তো আপনার ভালো।\nঋত্বিক কান ছেড়ে অর্ধাঙ্গিনীকে আবার আলিঙ্গন করে বলে,\n-তোমার রাগ, অভিমানে দু''টোই আমার কাছে অমূল্য। কারণ, সেটা প্রমাণ করে তুমি আমাকে কত ভালোবাসো। রাগ অভিমান আছে বলেই পৃথিবীতে ভালবাসার তীব্রতা এত!\n-খুব কথা শিখেছেন দেখছি। ছেলেরা কই?\n-আজ ওরা ওরদের দাদুর কাছে ঘুমামে। ওইখানে দিয়ে এসেছি। কারণ, আমার আমার একটা রাজকন্যা চাই!\nঊষসী ঋত্বিকের বুক থেকে মাথা তুলে বলে,\n-এক দম না। দুইটা হয়েছে এতেই আপনি আমাকে পাত্তা দিতে চান না। আরেকটা হলে আমার খোঁজ-ই রাখবেন না।\nঋত্বিক মুচকি হেসে গোলাপের তোড়া থেকে একটা গোলাপ ছিঁড়ে ঊষসীর কানে খুঁজে দেয়। দ্বিতীয় বারের মত কপালে  চুম্বন করে বলে,\n-তোমার অভিমানে ফেটে পড়ে সন্ধ্যা।\nতোমার একটুখানি ছোঁয়ায়, ভরে যায় অন্তর্লোকের কন্দ সত্তা।\nতুমি চোখ তুলে তাকালে থমকে যায় জীবন,\nতুমি যে আমার নিঃশব্দ প্রেম- মনপবন!\nকথা শেষ হতে দুজন-দুজন কে গভীর আলিঙ্গনে আবদ্ধ করে নেয়। যত ঝগড়া-বিবাদই হোক, ভালবাসা শেষ হবার নয়। রাগ অভিমান তো ভালোবাসার গভীতাকে আরও তীব্র করে মাত্র!\n__________________সমাপ্ত_____________\n®দোয়েল\n১০মে, ২০২৫\nশনিবার।\n#মনপবন \n#অণুগল্প \n#তোয়া_নিধী_দোয়েল \n[হুট করে মাথায় এলো! টপ করে লিখে ফেললাম!\nপ্রিয় পাঠক, ভালো লাগলে গঠনমূলক মন্তব্য করবেন। তাহলে চলমান গল্প শেষ হলে, এইটা শুরু করার চেষ্টা করবো। ধন্যবাদ🤍]","author_id":"1772140265202","author":"তোয়া নিধী দোয়েল","category_id":"অণুগল্প","category":"অণুগল্প","views":6,"image":null,"cover_image":"/uploads/stories/covers/2026/03/0d8f0e35-85e8-45da-b380-fb047f0ecb64-cb202603311808-2.png","slug":"মনপবন","tags":[],"parts":[{"id":"1","title":"পর্ব 01","content":"সওদাগর বাড়ির, গেটের সামনে এসে থামে একটি রিকশা। সময়টা সন্ধ্যা নামার কিছু আগ মূহুর্ত। পশ্চিম আকাশে সোনার রবি অস্ত গিয়েছে। পরিবেশে ধীরে ধীরে আগমন ঘটছে অন্ধকারের!\nরিকশা থেকে নামে, আকাশী রঙের থ্রি-পিছ পরা এক নারী। সাদা ওড়নার আঁচল মাথায় টানা। তবে, নামার সময় কিঞ্চিৎ বিপত্তি ঘটে! তাড়াহুড়ো করে নামতে গিয়ে, অসাবধানতাবশতঃ রিকশার হুডের সাথে মাথায় আঘাত পায়। এমনিতে-ই মনে রাগ, ক্ষোভ আর বিরক্ততে ছেয়ে আছে! তার ওপর হুট করে মাথায় চোট পাওয়াতে, বিরক্তির মাত্রা আকাশ ছোঁয়! মুখ দিয়ে বিরক্তি সূচক শব্দ করে।\nরিকশাওয়ালা দ্রত মেয়েটির কাছে এসে জিজ্ঞাসা করে,\n-আফামনি, দুক্কু পাইলেন?\nমেয়েটা মাথায় এক পাশে হাত দিয়ে; চোখ মুখ খিঁচে দাঁড়ায়। রিকশাওয়ালার কথা শুনে ডানে-বামে মাথা নাড়ায়। যার অর্থ সে আঘাত পায়নি! \nতারপর মাথা থেকে হাত নামিয়ে, পার্স থেকে টাকা বের করে ভাড়া পরিশোধ করে। রিকশাওয়ালা চলে যায় অজানা গন্তব্যে।\nমেয়েটা হাতের পার্স এক হাতে নিয়ে; অন্য হাতে মাথার ওড়না টেনে নেয়। ঘুরে দাঁড়ায় সওদাগর বাড়ির উদ্দেশ্যে। \nকয়েক পা হেঁটে গেটে টোকা দেয়। গেটের সামনে বসে থাকা দারোয়ান রফিক; গেটে থাকা ছিদ্র দিয়ে দেখে কে এসেছে। বাড়ির বড় বউয়ের মুখশ্রী দৃষ্টিগোচর হতেই; দ্রততরে গেট খুলে দেয়।\nমেয়েটি ভেতরে ঢুকলে, রফিক মোল্লা চমৎকার করে হেসে সালাম দেয়। মেয়েটা ও মৃদু হেসে সালামের উত্তর নিয়ে, মূল বাড়ির দিকে পা বাড়ায়।\nডুপ্লেক্স বাড়িটির মূল দরজায় প্রবেশ করার আগে, রাস্তার বাম পাশে একটা ওয়াটার ফাইউন্টেন। যেথায় থেকে পানি নির্গত হচ্ছে। আর ডান পাশে কুচকুচে কালো রঙের একটা গাড়ি। \nগাড়িটি দেখে মেয়েটার রাগের মাত্রা যেনো কিঞ্চিৎ পরিমাণ বেড়ে গেলো। পরপরই নিজেকে ধাতস্থ করে নিয়ে বাড়ির ভেতরে প্রবেশ করে।\n★\nশীত-তাপ নিয়ন্ত্রিত ঘরটির মধ্যে; আয়নার সামনে বসে আছে এক প্রাপ্ত বয়স্ক পুরুষ ও তাঁর দুই পুত্র। তাদের পরনে শুধু সাদা রঙের টাওয়েল। উপরি ভাগ খালি। বলা-বাহুল্য লোকটার ছানা-পোনা দুজনের বয়স তিন কি সাড়ে তিন বছর। যারা যমজ।\nলোকটা তাঁর এক পুত্র কে কোলে বসিয়ে, হেয়ার ড্রায়ারের মাধ্যমে চুল শুকিয়ে দিচ্ছে। উপর ছানা পাশে বসে বাবার কর্ম-কাণ্ড দেখছে। তাদের দেখে ধারণা করা যায়, তাঁরা মাত্র গোসল সেরেছে। \nতাদের থেকে কিঞ্চিৎ দূরে একটা মাইক্রোল্যাব স্পিকারে গান বাজছে। সেই গানের তালে-তালে মাথা দোলাচ্ছে লোকটা। বাচ্চা দু''জন গানের আগা-গোড়া না বুঝলে ও বাপের দেখা-দেখি দুলছে!\n★\nগটগট পায়ে বাড়ির ভেতরে প্রবেশ করে ঊষসী। সে এই বাড়ির বড়-বউ। চার-পাঁচ দিন আগে বাপের বাড়ি গিয়েছিলো। আবার একাই ফিরে এসেছে। কোনো একটা কারণে রাগে তার শরীর জ্বলছে! \nবাড়ির বৈঠক-খানায় বসে চা পান করছিলেন কালাম সওদাগর। ছেলের বউকে হন্ত-দন্ত হয়ে বাড়িতে প্রবেশ করতে দেখে ভ্রু কুঁচকায়। তবে তা দৃষ্টি-গোচর হয় না ঊষসীর। সে এক মনে হেঁটে দোতালায় উঠায় মগ্ন।\nঊষসীকে ঐ-ভাবে যেতে দেখে মনে দ্বিধা নিয়ে ডাকে,\n- মামনি!\nশ্বশুরের ডাক কানে যেতে পা -যুগল থেমে যায় ঊষসীর। নিজেকে নিয়ন্ত্রণ করে ঘুরে সালাম দেয়। কালাম সওদাগর সালামের উত্তর নিয়ে জিজ্ঞাসা করে\n-একা এসেছো? ঋত্বিক কই?\nস্বামীর কথা উঠতেই রাগের মাত্রা তর-তর করে বাড়ে। তবে তা প্রকাশ করতে দেয় না। সে মিথ্যে হাসি ফুটিয়ে বলে,\n-জি আব্বু, একাই এসেছি। জানিনা আপনার ছেলে কই।\nএইটুকু বলে সে প্রস্থান করে। কালাম সাহেব আর কিছু বলে না। বৌমা-র যাওয়ার দিকে ভাবুক দৃষ্টিতে তাকিয়ে থাকে। হয়তো দু''জনের জানে মধ্যে কিছু হয়েছে!\n★\nঋত্বিক তাঁর এক ছেলে ঋণয়ের চুল শুকিয়ে দিয়ে; অপর ছেলে ঋশানকে ও কোলে তুলে নেয়। গানের লিরিক্স এর সাথে সাথে তিন বাপ-ব্যাটা দুলে দুলে নাচ্ছে। তাদের দেখে বোঝা যাচ্ছে তাঁরা ভীষণ ফুর্তিতে আছে। ঋত্বিক ঋশান ও ঋণয়ের এক সাথে কোলে নিয়ে লিরিক্স এর তালে তালে তাল মিলিয়ে গাইতে লাগলো‚\n‘Peechhe Kuaa, Aage Mere Khaai\nTu Hi Bata Jaaun Main Kahaan\nMujhko Duaa Kiski Lagi Bhai\nAake Padhara Hoon Jo Yahaan\nIlle Fikar, Aaja Idhar\nBeat Pe Laga Le Tu Thumka’\nছানা-পোনা দুইজন সঠিক লিরিক্স বলতে না পারলেও; বাপের তালে তাল মেলানোর জন্য নিজেদের মত করে কি যেনো বলতে লাগলো! ঋত্বিক দুই ছেলে কে নামিয়ে দিয়ে ছেলেদের সমান সমান হয়ে হাঁটু ভেঙে বসলো। তারপর গানের তালে তালে হাত উপরে দিয়ে, শরীরের উপরিভাগ দুলিয়ে নাচতে লাগলো। আর ছেলেরা ঘুরে-ঘুরে, লাফিয়ে-লাফিয়ে নাচতে আরম্ভ করে। ঋত্বিক গেয়ে উঠে‚\n‘One Two Three Four Get On The Dance Floor\nOne Two Three Four Get On The Dance Floor\nBooty Shake, Booty Shake\nDappan Koothu Hard Core\nShoulder Hichak Michak\nBody Hichak Michak\nGimme, Gimme, Gimme\nGimme, Gimme, Gimme Some More’\nঋণয় ঋশান লাফাতে-লাফাতে তোতলিয়ে শুধু বলে,\n‘ওয়ান, তু, তিরি, ফ্লোর\nওয়ান, তু, তিরি, ফ্লোর’\nতিন বাপ-ব্যাটা ভীষণ ফুর্তি করে নেচে যাচ্ছে।\nরুমের সামনে এসে থমকে দাঁড়ায় ঊষসী। দরজা ভিড়ানো। ভেতর থেকে গানের বাজার আওয়াজ আসছে। সাথে হৈ-হুল্লোড়ের আওয়াজ ও আসছে। ও কপালে ভাজ ফেলে ভিড়ানো দরজা খুলে। \nভেতরের দৃশ্য দেখে মুখ হাঁ হয়ে যায়। ড্রেসিং টেবিলের সামনে বাদরের মত নাচ্ছে; সাদা টাওয়েল পড়া এক বড় বাদর ও তাঁর দুই ছানা। রুমের অবস্থা নাজেহাল! ফ্লোরে ছড়ানো বিভিন্ন চিপসের প্যাকেট, কোল্ড ড্রিংস, চকলেটের প্যাকেট,বার্গারের বক্স! \nসাথে ছড়িয়ে-ছিটিয়ে রয়েছে লেগো সেট, সুপারহিরো ফিগারস, একশন ফিগারস, রিমোট কন্ট্রোল গাড়ি, হেলিকপ্টার, বাবল গান, ক্যারাম বোর্ড, পাজাল, টুল বক্স ইত্যাদি। \nবিছানার এক পাশে উল্টো হয়ে পড়ে আছে মোটর-সাইকেল (বাচ্চাদের)। শার্ট-প্যান্ট, গেঞ্জি সব এলো মেলো হয়ে আছে বিছানায়। ঊষসী রুমের অবস্থা থেকে রাগে ফোসে উঠে। রুমটাকে বস্তি বানিয়ে ফেলেছে! সে যে এত দিন ধরে বাসায় নেই, তাতে এই বাপ-বেটার কিছুই যায় আসে না! ও রাগান্বিত কণ্ঠে বলে উঠে,\n-এই এই... এই সব কী করছেন?\nসহধর্মিণীর কণ্ঠ কর্ণগোচর হতে-ই নাচ থামিয়ে দেয় ঋত্বিক। ঘাড় ঘুরিয়ে তাকায় দরজার দিকে। নীল রঙের থ্রি-পিছ পরে চোখ দিয়ে আগুন ঝড়ছে যাঁর। সে দুই ছেলে কে ধরে তাদের নাচ ও বন্ধ করায়। তার পর উঠে দাঁড়ায়। কোমরে হাত দিয়ে পরনের টাওয়েল একটু উপরে তোলে। তার পর বুকে হাত গুঁজে দাঁড়ায়। দুই ছেলে ও ঘাড় বাঁকিয়ে একবার বাপ কে দেখে, বাপের মত বুকে হাত গুঁজে দাঁড়ানোর চেষ্টা করে। তবে ঋণের টাওয়েলের প্যাঁচ খুলে যেতে নেয়। ও কোনো মতে টাওয়েল ধরে ছোট করে ডাকে,\n-আব্বু, থুলে গ্যালো...!\nঋত্বিক ছেলের দিকে তাকিয়ে দ্রুত বসে ছেলের টাওয়েল আবার প্যাঁচিয়ে বেঁধে দেয়। \n-আরে আমার রাজপুত্র! ডোন্ট ওরি।\nএই বলে আবার উঠে দাঁড়ায়। তিন বাপ-বেটার কর্ম- কাণ্ড দেখে ঝাঁঝালো কণ্ঠে ঊষসী আবার বলে,\n-এই সব কী হচ্ছে এখানে? রুম টার এই অবস্থা কেন? বস্তি বানিয়ে ফেলেছেন।\nঋত্বিক আয়নাতে চুল ঠিক করে বলে,\n-আরে, ম্যাডাম। আপনি এখানে? কী মনে করে হঠাৎ, বাপের বাড়ি থেকে এত দ্রুত চলে এলেন? দেখতে এসেছেন আপনাকে ছাড়া আমরা তিন বাপ-বেটা কেমন আছি?\nঋত্বিকের কথায় আরও কয়েক দফা চেতে যায় ঊষসী। চোখ গরম করে তাকিয়ে থাকে। ঋত্বিক ছেলেদের উদ্দেশ্যে বলে,\n-বয়ে''স, এটা তোমাদের খালামণি। আমাদের সাথে দেখা করতে এসেছে। খালামণি কে হাই বলো।\nদুই ছেলে বাপের কথায়, ঊষসীর দিকে তাকিয়ে হাত নাড়িয়ে বলে,\n-হাই, খাম্নি!\n-হাই, খাম্নি!\nনিজের ছেলেদের মুখে খালামণি ডাক শুনে ঠোঁট হাঁ হয়ে যায় ঊষসীর। এই সব কি শিখেছে ওরা! চার-পাঁচ দিন বাড়ি থেকে চলে গেছে বলে এই সব শিখবে! ও ঋত্বিকের দিকে তাকিয়ে কটমট করতে করতে বলে,\n-এই সব ওদের কী শিখিয়েছেন আপনি? এই সব কোন ধরনের ভাষা?\nঋত্বিক দুই ছেলের দিকে তাকিয়ে বলে,\n-পিতৃভাষা! এই সব পিতৃভাষা! সবাই তো মাতৃভাষা শেখে৷ আমার ছেলেরা পিতৃভাষা শিখবে। তোমাদের মায়েদের জন্য; আমাদের বাপ দের স্থান অনেক পিছিয়ে গেছে। তোমাদের কথার জন্য, আমরা বাপরা কথা বলার ওয়ে পাইনা।  তাই আমার ছেলেদের পিতৃভাষা শিখিয়ে; পিতৃভাষা আইন চালু করবো। এতে সব বাবারা নিজেদের হারানো অধিকার ফিরে পাবে।\nএরপর ছেলেদের দিকে তাকিয়ে বলে,\n-কী বয়েস, আব্বুর নাম উজ্জ্বল করতে পারবে তো?\nঊষসী তেরে এসে বলে,\n-এক দম আলতু-ফালতু কথা বলবেন না। আমি বাসায় নেই আর (আশে-পাশে তাকিয়ে) এই সব কি করেছন? রুমটাকে বস্তি বানিয়ে ফেলেছেন। আর ছেলেদের এই সব কী বলছেন?\nঋত্বিক ঘাড় বাঁকিয়ে বলে,\n-তো, আপনাকে এত তাড়াতাড়ি বাপের বাড়ি থেকে আসতে বলেছে কে? আমি আর আমার ছানারা তো ভেবেছি এক-দুই বছর থাকবেন! আর আমরা একটু আমোদ-ফুর্তি করবো। আর আপনি আমাদের বিশ্বাস ভেঙে এত দ্রুত চলে এলেন? এইটা মোটেও আশা করি নি। আপনি এত বড় বিশ্বাসঘাতক!\nতারপর ছেলেদের উদ্দেশ্যে বলে,\n-বয়েস, কাম। আমাদের বেরোতে হবে।\nঋত্বিকের কথায় চোখ ছোট ছোট করে তাকিয়ে থাকে ঊষসী। মনে মনে একটু অবাক ও হয়। ও চলে যাওয়াতে বাপ-বেটার তাহলে ভীষণ ভালোই লেগেছে। ঋত্বিক ছেলেদের আদেশ করে আলমারির দিকে চলে যায়। বাচ্চারা ও বাধ্য ছেলের মত বাবার পিছু-পিছু হাঁটতে থাকে। এত দিন পর ছেলেদের দেখতে পেয়ে বুকের ভেতর ছট-ফট কতে থাকে ঊষসীর। কোলে নিয়ে আদর করতে মন ব্যাকুল হয়ে যায়। ও ছেলেদের উদ্দেশ্যে অস্থির কণ্ঠে ডেকে উঠে,\n-বাবা। আমার সোনারা। এই দিকে আসো।\nমায়ের ডাক শুনে ঘাড় ঘুরিয়ে তাকায় ঋণয় ঋশান। ঊষসীর চোখ ছলছল করে উঠে। হাত বাড়াতেই ছেলেরা বাবার উদ্দেশ্যে বলে,\n-আব্বু, আম্মা তি তোলে যাবো?\nঋত্বিক কাবাড থেকে নিজের ও ছেলেদের পোশাক বের কর‍তে করতে বলে,\n-এক দম না, আব্বু। এই দিকে চলে আসো।\nছেলেদুইটা বাবার আদেশ পেয়ে ঘুড়ে ঋত্বিকের দিকে চলে যায়। ঊষসী অগ্নি দৃষ্টি নিয়ে তাকিয়ে থাকে। যাওয়ার পথে আবার ঋশানের টাওয়েলের প্যাঁচ খুলে যায়। ও ঋত্বিক কে ডেকে উঠে,\n-আব্বু...!\nঋত্বিক পোশাক বের করে ছেলের দিকে এগিয়ে আসে। টাওয়েলে প্যাঁচ দিতে দিতে বলে,\n-ইস্! বার বার খুলে যায় কেনো?\nঊষসী চ্যাঁচিয়ে উঠে,\n-আমার ছেলেদের আমাকে দিয়ে দিন। আমি ওদের নিয়ে চলে যাবো।\nঋত্বিক ভ্রু কুঁচকে বলে,\n-মামার বাড়ির ওয়ারিশ পাওনি। চাইবার মাত্র হাতে তুলে দিবো। ইটস মাই প্রোপার্টি!\n-ছেলে দুইটা কিন্তু, আপনার একা-র না।\n-আমার একা-র না মানে? কোনো সন্দেহ আছে?\nঊষসী এক পা এগিয়ে এসে বলে,\n-আমি না থাকলে ছেলে দুইটা পেতেন কই?\nঋত্বিক অবজ্ঞার স্বরে বলে,\n-পৃথিবীতে কি মেয়ের আকাল পড়ছে? তুমি না থাকলে যেনো হতোই না!\nঊষসী ভ্রু কুঁচকে বলে,\n-ওরা হওয়ার আগে তো কত ঢং করতেন। সব সময় আমার পিছু পিছু ঘুর ঘুর করতেন। আর আজ পাঁচ দিন ধরে আমি বাড়ি নেই; তাতে আপনার কোনো ভ্রুক্ষেপ নেই!\nঋত্বিক ডানে বামে মাথা নাড়িয়ে বলে,\n-নির্বাচন শেষ। প্রচার ও শেষ! বুঝতে পেরেছো?\nঊষসীর কিছু বলতে গেলে, ওকে থামিয়ে দিয়ে; বাইরে থেকে একিটা ঝাড়ু এনে ঊষসীর হাতে তুলে দেয়। ওর দিকে ঝুঁকে বলে,\n-আমাকে ও আমার ছেলেদের রেখে, এত দিন বাপের বাড়ি থাকার অপরাধে ; মিঃ সওদাগর মিসেস সওদাগরকে, তাঁর এবং তাঁর ছানাপোনাদের জন্য আ্যসিস্ট্যান্ট হিসেবে নিযুক্ত করলো। \nআশা করি আপনি খুব ভালো-ভাবে অগোছালো রুমটাকে পরিষ্কার করবেন। আমাদের বাপ-বেটাদের বের হতে হবে। বায়!\nঊষসীর হাতে ঝাড়ু গুঁজে দিয়ে; বের করা পোশাক নিয়ে দুই ছেলের কাছে আসে। দুইটা ফর্মাল ব্ল্যাক শার্ট দুই ছেলেকে পড়িয়ে দেয়। সাথে ব্ল্যাক প্যান্ট। ছেলেদের সাথে ম্যাচ করে নিজেও ফর্মাল ব্ল্যাক শার্ট পড়ে। তার পর তিন জন আয়নার সামনে দাঁড়ায়। ঋত্বিক আয়নায় দেখতে দেখতে শার্টের কফ ভাজ করতে থাকে। আর আড়চোখে সহধর্মিণীর রাগ দেখতে থাকে। \nওর দেখা-দেখি ছেলেরাও তাদের ছোট ছোট হাত উঠিয়ে কফ ভাজ করার চেষ্টা করে। ঋত্বিক বাঁকা হেসে ছেলেদের কফ ভাজ করে দেয়। তার পর জেল দিয়ে চুল ঠিক করে, ড্রয়ার থেকে তিনিটা পোলারাইজড ব্ল্যাক সানক্লাস বের করে। বাকি দুইটা তুলোনামূলক ছোট। দুইটা দুই ছেলের হাতে দিয়ে, নিজে একটা হাতে তুলে নেয়। তার পর আয়নার দিকে তাকিয়ে বলে,\n-বয়ে''স, রেডি।\nছেলেরা উপরে নিচে মাথা নাড়ায়। ঋত্বিক ওয়ান, টু, থ্রি বলে তিনজনে এক সাথে আয়নার দিকে তাকিয়ে সানক্লাস চোখে পড়ে। তারপর ঋত্বিক ইশরা করে পকেটে হাত দিতে। ছেলেরা নিজেদের প্যান্টের পকেট খুঁজে তাতে হাঁত গুঁজে।\nদূরে ঝাড়ু হাতে অগ্নি দৃষ্টি নিয়ে তিন বাপ-বেটার ভাব দেখছে ঊষসী। বাপ-বেটাদের রেডি হওয়া শেষ হলে তিন জনে বাইরে যাওয়ার জন্য উদ্যত হয়। দুই ছেলে আগে বের হয়। ঊষসীর পাশ দিয়ে যাওয়ার সময়, ঋত্বিক সানগ্লাস তর্জনী আঙুলের দ্বারা একটু নিচু করে  ঊষসীকে চোখ মারে। ঊষসী দৃষ্টি সরিয়ে নেয়। ঋত্বিক রুম থেকে বেরিয়ে ঊষসীকে চেতানোর জন্য ছেলেদের উদ্দেশ্যে বলে,\n-বয়েস, কোনো আম্মু পছন্দ হলে আমাকে বলো। তোমাদের এনে দিবো।\nঋত্বিকের কথা কানে পৌঁছাতে ঊষসী ঝাড়ু ফেলে ছুটে বাইরে আসে। ততক্ষণে ঋত্বিক ঋশান ঋণয় নিচে নেমে গেছে। ঊষসী দাঁতে-দাঁত চেপে শুধু দাঁড়িয়ে থাকে।\n★\nরাত প্রায় অনেক টা। বেল্কনিতে বসে আছে ঊষসী। মৃদু-মন্দ বাতাস বইছে। আকাশে অর্ধ-চন্দ্র মেঘের আড়ালে লুকিয়ে পড়ছে। \nতিন বাপ-বেটা এখনো ফিরিনি। কই গেছে কে জানে। তা জানার আগ্রহ নেই ঊষসীর। স্বামীর সাথে বিবাদ সৃষ্টি হওয়াতে বাপের বাড়ি গিয়েছিলো। ভেবে ছিলো স্বামী মান ভাঙিয়ে নিয়ে আসবে। কিন্তু না! সে তো কোনো ভ্রুক্ষেপ-ই করলো না।\nগাড়ির হর্নের শব্দে ধ্যান ভাঙে ঊষসীর। গেট দিয়ে কালো গাড়িটা বাড়ির ভেতরে প্রবেশ করেছে। বোধহয় রাজ সাহেবরা ফিরলো। ঊষসী সেই দিকে এক পলক তাকিয়ে অন্য দিকে দৃষ্টি নেয়। \nকিছুক্ষণ সময় অতিবাহিত হওয়ার পর; ঊষসীর সামনে গোলাপের একটা তোড়া ধরে কেউ! যেখানে অনেক গুলো লাল টকটকে গোলাপ। ঊষসী ঘাড় ঘুরায় আগন্তুককে দেখার জন্য। ঋত্বিক এর মুখশ্রী দৃষ্টিগোচরে হতে সরে যেতে নেয়। তবে তার আগেই শক্ত বাহুডরে আবদ্ধ হয়ে যায়। ঋত্বিক ওকে পেছন থেকে শক্ত করে জড়িয়ে ধরে। গোলাপের তোড়া সামনে রেখে ওর ঘাড়ে থুতনি ঠেকায়। ঊষসী ছোটার চেষ্টা করে ঝাঁঝালো কণ্ঠে বলে উঠে,\n-এক দম নাটক করতে আসবেন না, এখন। ছাড়ুন। \nঋত্বিক মোহময় কণ্ঠে বলে,\n-ঝগড়া সব দিনে হবে। রাতের বেলা হাসবেন্ড-ওয়াইফ ঝগড়া কর‍ল এ ঘোর পাপ হয়।\nএই বলে হাতের বাঁধন আরও শক্ত করে। ঊষসী দাঁতে-দাঁত চেপে বলে,\n-নাটক করতে খুব ভালো ভাবেই শিখেছেন? তাইনা? রাগ করে চলে গেলাম, কই একটা বার তো আনতে গেলেন না। কল দিলেন না। এখন আবার ঢং করতে এসেছেন?\n-আজ তো যেতাম-ই। তোমাকে বেঁধে নিয়ে আসতাম। কিন্তু, তুমি তো নিজে থেকে চলে এলে। এতে কি দোষ আমার।\n-সরুন।\n-সরি, বউ। আর হবে না।\n-আমি আপনার কোনো কথা শুনতে চাই না।\n-এমন করো না বউ। বোঝার চেষ্টা করো, পাঁচ- পাঁচটা দিন তুমি আমার থেকে দূরে ছিলে। জানো কতটা বিরহে ছিলাম আমি? এখন আর দূরত্ব ভালো লাগছে না। তোমার যা বক্তব্য আছে, যত রাগ আছে সকালে দেখিও। আমি তো বলেছিই ঝগড়া সব দিনে হবে। রাতে ঝগড়া করতে নেই।\n-সরুন।\nঋত্বিক ফুলের তোড়া এক পাশে রেখে ঊষসীকে নিজের দিকে ঘোরায়। ঋত্বিক ঊষসীর দুই গালে হাত দিয়ে কপালে গভীর চুম্বন এঁকে দেয়। ও চোখের পাতা বন্ধ করে ফেলে। ঋত্বিক গাল ছেড়ে বুকের সাথে মিশিয়ে নেয় ওকে। মাথায় হাত বুলাতে বুলাতে বলে,\n-তোমাকে রাগাতে আমার ভীষণ ভালো লাগে, ম্যাডাম। আমি শুধু চাই, সেটা আমার কাছ থেকে, আমাকে একটু জড়িয়ে ধরে দেখাও।\n-হ্যাঁ, তাই তো এত দিন থেকে আসলাম; তাতে আপনার কিছু যায় আসি-নি।\nঋত্বিক ঊষসী কে ছেড়ে, নিজের দুই কান ধরে বলে,\n-ভালোবাসি, ভালোবাসি আর ভালোবাসি! আর রাগ করে থেকে ও না। সব দোষ আমার। আমার ভুল সব। আর কখনো এই রকম হবে না। এই বারের মত মাফ করে দিন ম্যাডাম।\nএকটু থেমে আবার বলে,\n-রাগ করো ঠিক আছে, তবে এই ভাবে দূরে ঠেলে দিও না। তোমার রাগের মধ্যে ও যে ভালোবাসা লুকানো আছে, সেটা আমি দেখে ফেলেছি। তাই তো আমাকে ছেড়ে থাকতে না পেরে নিজে থেকে চলে এসেছো।  তো, এবার একটু মুচকি হাসো।\n-মোটেও না। যান, নিজের ছেলেদের নিয়ে ঘুরে আসুন। আমোদ-ফুর্তি করুন। আমি না থাকলে তো আপনার ভালো।\nঋত্বিক কান ছেড়ে অর্ধাঙ্গিনীকে আবার আলিঙ্গন করে বলে,\n-তোমার রাগ, অভিমানে দু''টোই আমার কাছে অমূল্য। কারণ, সেটা প্রমাণ করে তুমি আমাকে কত ভালোবাসো। রাগ অভিমান আছে বলেই পৃথিবীতে ভালবাসার তীব্রতা এত!\n-খুব কথা শিখেছেন দেখছি। ছেলেরা কই?\n-আজ ওরা ওরদের দাদুর কাছে ঘুমামে। ওইখানে দিয়ে এসেছি। কারণ, আমার আমার একটা রাজকন্যা চাই!\nঊষসী ঋত্বিকের বুক থেকে মাথা তুলে বলে,\n-এক দম না। দুইটা হয়েছে এতেই আপনি আমাকে পাত্তা দিতে চান না। আরেকটা হলে আমার খোঁজ-ই রাখবেন না।\nঋত্বিক মুচকি হেসে গোলাপের তোড়া থেকে একটা গোলাপ ছিঁড়ে ঊষসীর কানে খুঁজে দেয়। দ্বিতীয় বারের মত কপালে  চুম্বন করে বলে,\n-তোমার অভিমানে ফেটে পড়ে সন্ধ্যা।\nতোমার একটুখানি ছোঁয়ায়, ভরে যায় অন্তর্লোকের কন্দ সত্তা।\nতুমি চোখ তুলে তাকালে থমকে যায় জীবন,\nতুমি যে আমার নিঃশব্দ প্রেম- মনপবন!\nকথা শেষ হতে দুজন-দুজন কে গভীর আলিঙ্গনে আবদ্ধ করে নেয়। যত ঝগড়া-বিবাদই হোক, ভালবাসা শেষ হবার নয়। রাগ অভিমান তো ভালোবাসার গভীতাকে আরও তীব্র করে মাত্র!\n__________________সমাপ্ত_____________\n®দোয়েল\n১০মে, ২০২৫\nশনিবার।\n#মনপবন \n#অণুগল্প \n#তোয়া_নিধী_দোয়েল \n[হুট করে মাথায় এলো! টপ করে লিখে ফেললাম!\nপ্রিয় পাঠক, ভালো লাগলে গঠনমূলক মন্তব্য করবেন। তাহলে চলমান গল্প শেষ হলে, এইটা শুরু করার চেষ্টা করবো। ধন্যবাদ🤍]"}],"comments":0,"is_featured":false,"read_time":null,"status":"published","submitted_by":"primary-admin","date":"2026-02-26T21:16:17.928Z","updated_at":"2026-03-31T18:08:55.968Z"}','2026-03-07T23:14:15.343Z','2026-03-31T11:35:43.777Z');
INSERT INTO "app_table_rows" ("pk","table_name","row_json","created_at","updated_at") VALUES(907,'stories','{"id":"1772140647802","title":"চলে যাওয়া বসন্ত","excerpt":"__MAHEAN_META__:{\"status\":\"published\",\"submittedBy\":\"primary-admin\",\"author\":\"তোয়া নিধী দোয়েল\",\"category\":\"অণুগল্প\",\"coverImage\":\"/uploads/stories/covers/2026/03/bb8c1792-4e10-4b68-899d-c3e40bb5f71a.png\",\"slug\":\"চলে-যাওয়া-বসন্ত\",\"parts\":[{\"id\":\"1\",\"title\":\"পর্ব 01\",\"content\":\"\"}],\"comments\":0}:__MAHEAN_META_END__গ্রীষ্মের দুপুরে সূর্যের প্রচণ্ড কিরণে; সমগ্র প্রকৃতি যেন রুক্ষমূর্তি ধারণ করে। গ্রীষ্মের এই খররৌদ্রে প্রকৃতির সতেজ রূপ নির্জীব হয়ে যায়। চারদিক পুড়ে খাঁ খাঁ করতে থাকে। ও-দূর ফাটা মাঠের বুক থেকে বেরিয়ে আসছে তপ্ত সুবাস।","content":"গ্রীষ্মের দুপুরে সূর্যের প্রচণ্ড কিরণে; সমগ্র প্রকৃতি যেন রুক্ষমূর্তি ধারণ করে। গ্রীষ্মের এই খররৌদ্রে প্রকৃতির সতেজ রূপ নির্জীব হয়ে যায়। চারদিক পুড়ে খাঁ খাঁ করতে থাকে। ও-দূর ফাটা মাঠের বুক থেকে বেরিয়ে আসছে তপ্ত সুবাস।\nবারান্দায় বেঞ্চ এর উপরে শুয়ে আছে, এক প্রাপ্ত বয়স্ক পুরুষ। ক্ষনে ক্ষনে ডান পা বাম পায়ের উপর দিয়ে নাড়াচ্ছে। কপালে এক হাত রেখে, বাড়িতে থাকা গাছ গুলোকে পর্যবেক্ষণ করছে। যারা নতমুখে স্তব্ধ হয়ে দাঁড়িয়ে আছে। তাদের দেখে মনে হচ্ছে, সূর্যের আদেশ আছে তাদের উপর। তার এই তীব্র দহন তাদের সহ্য করতে হবে।\nবাড়ির পশ্চিম পাশ দিয়ে বয়ে গেছে একটা ছোট নদী। সেথায় ক্লান্ত এক পাখি পানি পান করছে। বাড়ির সামনে একটি প্রশস্ত রাস্তা। যা সোজা গুঞ্জের সঙ্গে যুক্ত হয়েছে। রাস্তায় তেমন জন মানব নেই। এক ফেরিওয়ালার হাঁক-ডাক শোনা যাচ্ছে। সে তার মৌখিক ফিরিস্তির মাধ্যমে ক্রেতার আগ্রহ চেষ্টা সৃষ্টি করছে। মাথার উপর টিনের চালে; থেকে থেকে ভেসে আসছে কবুতরের গুম গুম আওয়াজ।\nতারপর দীর্ঘক্ষণ কোনো শব্দ নেই। উতপ্ত এই দুপরের পরিবেশ ধীরে ধীরে নৈঃশব্দে নিমজ্জিত হয়। প্রকৃতির এই নির্জনতা; পুরুষটির মনের নির্জনতা আরও কয়েক গুন বাড়িয়ে দেয়। বাড়িতে থাকা জলপাই গাছ থেকে মাঝে মাঝে পাতা খসে পড়ছে। পাতা খসার দৃশ্য দেখে, স্মৃতির পাতায় ভেসে উঠে কিছু নিদারুণ বিষাক্ত স্মৃতি! নিদারুণ বিষাক্ত স্মৃতি!? \nহ্যাঁ! স্মৃতি গুলা ভীষণ সুন্দর ছিলো এক সময়। কিন্তু, এখন তারা বিষে পরিণত হয়েছে। আসো, তোমাদের সেই নিদারুণ বিষাক্ত স্মৃতির গল্প শোনাই।\nকিছুদিন আগে মায়ের গলা জড়িয়ে আহ্লাদী কণ্ঠে বলে ছিলাম,\n-মা, আমি একজন কে ভীষণ ভালোবাসি। ও -ও আমাকে ভীষণ ভালোবাসে। যদি এই বার চাকরিটা হয়ে যায় তবে, ওকে বিয়ে করবো।\nমা স্মিত হেসে আমার মাথায় হাত বুলিয়ে বলে ছিলো,\n-ওমা! তাই নাকি। তা মেয়েটা কে শুনি?\nআমি মাকে ছেড়ে, মায়ের কোলে মাথা দিয়ে শুয়ে বর্ণনা করছিলাম; সেই  অপ্সরীর কথা! সে অদ্ভুত রকমের সুন্দর! পানপাতার মতো মুখশ্রীতে, ছোট ছোট তিল। তাই তো তার নাম দিয়েছি তিলবতী! মাথার কেশগুচ্ছ যেনো মেঘের মতো মসৃণ আর মহনীয়। সে যেনো আলো আর শান্তির মিশ্রণ। তার সামীপ্যে আমার অন্ধকারে কেটে যায়। অশান্ত মন শান্ত হয়ে যায়!\nতারপর মায়ের দিকে তাকিয়ে বলেছিলাম,\nআমার তিলবতীর সাথে তার সাক্ষাৎ করিয়ে দেবো। তোমার পরে কেউ যদি আমাকে ভালোবাসে, তাহলে ও। ‘মা আমি কিন্তু ওকেই বিয়ে করবো।’\nমা মৃদু হেসে প্রত্যুত্তরে বলেছিলো,\nঠিক আছে। আল্লাহ চাইলে হবে। তুই এখন ঘুমা তো। অনেক রাত হয়েছে। কাল তো আবার তোর চাকরির ফল দিবে। আল্লাহ নিশ্চয়ই ভালো কিছু করবে।\nঅতঃপর ভোর হলো। সূর্যের কিরণ ক্রমাগত তীব্র ভাবে ছড়িয়ে পড়তে থাকে ধরনীর বুকে৷ দীর্ঘ প্রতিক্ষা নিয়ে চেয়ারে বসে আছি ফোন হাতে নিয়ে। কখন এসএমএস আসবে। কখন অপেক্ষার অবসান হবে। যদি সত্যি এ বার চাকরিটা পেয়ে যাই; তাহলে মাকে রানী বানাতে আর কোনো বাধা থাকবে না। বাধা থাকবে না তিলবতীকে পেতে। প্রাণ ভরে সৃষ্টিকর্তাকে স্মরণ করতে থাকলাম। পাশে মা ও বসে ছিলো। সে ও সৃষ্টিকর্তার কাছে অনবরত বলে চলেছেন; আমাদের দিকে যেনো তাকায়। \nআরও দীর্ঘক্ষণ পর ফোনে একটা ই-মেইল ঢুকলো। আমার বুকের পাঁজর টনটন করে উঠলো। হাত কাঁপতে থাকলো। কাঁপা হাতে ই-মেইল টা খুললাম। মা আমার দিকে ভীষণ উচ্ছ্বাস নিয়ে চাকিয়ে আছে। আমি কি বলবো শোনার জন্য।\nই-মেইলে চোখ বুলিয়ে আমার দৃষ্টি স্থির হয়ে গেলো। হৃদয়ে কাঁপুনি ও থেমে গেলো। সারা শরীর অবশ হওয়ার উপক্রম হলো। মা আমার হাত ধরে অনবরত বলে চলেছে\nকিরে কি হলো? কিছু বলছিস না কেনো? চাকরিটা কি হয়েছে?\nআমি শান্ত ভাবে মায়ের দিকে চোখ তুলে তাকালাম। চোখের তারা চিকচিক করছে মা তা স্পষ্ট টের পেলো। এক বুক হতাশ নিয়ে ডানে-বামে মাথা নাড়ালাম। কাঁপা কণ্ঠে বললাম ‘নাহ্।’\nছুটে চলে গেলাম নিজের ঘরে। বাবা না ফেরার দেশে পাড়ি জমানোর পর, মা কত কষ্ট করেছে আমার জন্য। কত কষ্ট করে আমাকে লেখা-পড়া শিখিয়েছে। গেরস্ত বাড়ির বউ হয়ে ও অন্যের বাড়ি দাসীর মত কাজ করেছে। শুধু মাত্র আমাকে মানুষ করবে বলে। আমার পেটে দু-মুটো ভাত তুলে দিবে বলে। কত কটূ কথা সহ্য করেছে। কত অপমান,লাঞ্ছনা কত কি!\nএত কিছু দেখে মাকে কথা দিছিলাম, আমি বড় হয়ে অনেক বড় চাকরি করে মায়ের দুঃখ ঘুচিয়ে দেবো। কিন্তু, হায়! আজ ভাগ্য সঙ্গ দিলো না। আমি পারলাম না মায়ের পাশে দাঁড়াতে। পারলাম না মাকে রাজরানী করতে। মা কে কথা দিছিলাম, আমি মায়ের দুঃখ ঘুচিয়ে দিবো। মা''কে আবার তার রানীর আসন ফিরিয়ে দেবো। কিন্তু, তা আর হলো না। \nসেই দিন আর বের হলাম না ঘর থেকে। মা অনেকবার ডেকেছে। তবু ও ভালো লাগে নি। কোন মুখ নিয়ে মায়ের সামনে দাঁড়াবো? তাই ভেবে আর বের হলাম না। \nপরের দিন খুব ভোরে আরেকটা এসএমএস আসলো ফোনে। যেখানে লেখা ছিলো আমার সেই তিলবতী নাকি পবিত্র বিবাহ-বন্ধনে আবদ্ধ হতে যাচ্ছে। যে টুকু ঘুরে দাঁড়ানোর আশা ছিলো সে টুকু ও নিভে গেলো। শান্ত পাথরের মত স্থির হয়ে গেলো আমার চলমান জীবন। ভাবনারা সব উড়ে গেলো দূর আকাশে। না পারলাম মা''কে রানীর আসনে বসাতে; আর না পারলাম মনের মানুষ টাকে ধরে রাখতে। এই হচ্ছে, একটা বেকার ছেলের বিষাক্ত কিছু স্মৃতি।  \nমায়ের ডাকে ভাবনার জগৎ থেকে বের হয় ছেলেটি। বাটি ভর্তি কিছু পেঁপে কেটে নিয়ে এসেছে। যে মূহুর্ত থেকে শুনেছে আমি আমার প্রিয় মানুষটিকে হারিয়েছি, সে চলে গেছে আমাকে ছেড়ে, সেই মূহুর্ত থেকে দশটা মিনিটের জন্য আমার পাশ থেকে সরে নি। শান্তনা দিয়ে গেছে। সাহস দিয়ে গেছে। ভরসা দিয়ে গেছে। বলেছে তুই চিন্তা করিস না বাবা, আল্লাহ যা করে ভালোর জন্য করে। আমি আরও দু বাড়ি কাজ নিয়েছি। আরেকবার চেষ্টা কর। চাকিরটা এবার ঠিক হবে। আমাদের দুর্দিন কেটে যাবে। নিরাশ হইস না। সৃষ্টি কর্তা বান্দার পরিক্ষা নেওয়ার জন্য বিপদে ফেলে। এক দম নিরাশ হইস না। মা আছে তো।\nমা''কে কি ভাবে বোঝাবো, সে আছে বলেই আমি মরে গিয়ে ও বেঁচে আছি। সে আছে বলেই বিফল হয়ে ও আবার সফল হওয়ার স্বপ্ন বুনি। \n_______সমাপ্ত_________\n®️নিধী\n১৪ এপ্রিল,২০২৫\nসোমবার।\n[অনেক আগে লিখেছিলাম। ডায়েরিতে লেখা ছিলো। আরেকটু কারেকশন করে পোস্ট করলাম।]","author_id":"1772140265202","author":"তোয়া নিধী দোয়েল","category_id":"অণুগল্প","category":"অণুগল্প","views":2,"image":null,"cover_image":"/uploads/stories/covers/2026/03/bb8c1792-4e10-4b68-899d-c3e40bb5f71a-cb202603311808-3.png","slug":"চলে-যাওয়া-বসন্ত","tags":[],"parts":[{"id":"1","title":"পর্ব 01","content":"গ্রীষ্মের দুপুরে সূর্যের প্রচণ্ড কিরণে; সমগ্র প্রকৃতি যেন রুক্ষমূর্তি ধারণ করে। গ্রীষ্মের এই খররৌদ্রে প্রকৃতির সতেজ রূপ নির্জীব হয়ে যায়। চারদিক পুড়ে খাঁ খাঁ করতে থাকে। ও-দূর ফাটা মাঠের বুক থেকে বেরিয়ে আসছে তপ্ত সুবাস।\nবারান্দায় বেঞ্চ এর উপরে শুয়ে আছে, এক প্রাপ্ত বয়স্ক পুরুষ। ক্ষনে ক্ষনে ডান পা বাম পায়ের উপর দিয়ে নাড়াচ্ছে। কপালে এক হাত রেখে, বাড়িতে থাকা গাছ গুলোকে পর্যবেক্ষণ করছে। যারা নতমুখে স্তব্ধ হয়ে দাঁড়িয়ে আছে। তাদের দেখে মনে হচ্ছে, সূর্যের আদেশ আছে তাদের উপর। তার এই তীব্র দহন তাদের সহ্য করতে হবে।\nবাড়ির পশ্চিম পাশ দিয়ে বয়ে গেছে একটা ছোট নদী। সেথায় ক্লান্ত এক পাখি পানি পান করছে। বাড়ির সামনে একটি প্রশস্ত রাস্তা। যা সোজা গুঞ্জের সঙ্গে যুক্ত হয়েছে। রাস্তায় তেমন জন মানব নেই। এক ফেরিওয়ালার হাঁক-ডাক শোনা যাচ্ছে। সে তার মৌখিক ফিরিস্তির মাধ্যমে ক্রেতার আগ্রহ চেষ্টা সৃষ্টি করছে। মাথার উপর টিনের চালে; থেকে থেকে ভেসে আসছে কবুতরের গুম গুম আওয়াজ।\nতারপর দীর্ঘক্ষণ কোনো শব্দ নেই। উতপ্ত এই দুপরের পরিবেশ ধীরে ধীরে নৈঃশব্দে নিমজ্জিত হয়। প্রকৃতির এই নির্জনতা; পুরুষটির মনের নির্জনতা আরও কয়েক গুন বাড়িয়ে দেয়। বাড়িতে থাকা জলপাই গাছ থেকে মাঝে মাঝে পাতা খসে পড়ছে। পাতা খসার দৃশ্য দেখে, স্মৃতির পাতায় ভেসে উঠে কিছু নিদারুণ বিষাক্ত স্মৃতি! নিদারুণ বিষাক্ত স্মৃতি!? \nহ্যাঁ! স্মৃতি গুলা ভীষণ সুন্দর ছিলো এক সময়। কিন্তু, এখন তারা বিষে পরিণত হয়েছে। আসো, তোমাদের সেই নিদারুণ বিষাক্ত স্মৃতির গল্প শোনাই।\nকিছুদিন আগে মায়ের গলা জড়িয়ে আহ্লাদী কণ্ঠে বলে ছিলাম,\n-মা, আমি একজন কে ভীষণ ভালোবাসি। ও -ও আমাকে ভীষণ ভালোবাসে। যদি এই বার চাকরিটা হয়ে যায় তবে, ওকে বিয়ে করবো।\nমা স্মিত হেসে আমার মাথায় হাত বুলিয়ে বলে ছিলো,\n-ওমা! তাই নাকি। তা মেয়েটা কে শুনি?\nআমি মাকে ছেড়ে, মায়ের কোলে মাথা দিয়ে শুয়ে বর্ণনা করছিলাম; সেই  অপ্সরীর কথা! সে অদ্ভুত রকমের সুন্দর! পানপাতার মতো মুখশ্রীতে, ছোট ছোট তিল। তাই তো তার নাম দিয়েছি তিলবতী! মাথার কেশগুচ্ছ যেনো মেঘের মতো মসৃণ আর মহনীয়। সে যেনো আলো আর শান্তির মিশ্রণ। তার সামীপ্যে আমার অন্ধকারে কেটে যায়। অশান্ত মন শান্ত হয়ে যায়!\nতারপর মায়ের দিকে তাকিয়ে বলেছিলাম,\nআমার তিলবতীর সাথে তার সাক্ষাৎ করিয়ে দেবো। তোমার পরে কেউ যদি আমাকে ভালোবাসে, তাহলে ও। ‘মা আমি কিন্তু ওকেই বিয়ে করবো।’\nমা মৃদু হেসে প্রত্যুত্তরে বলেছিলো,\nঠিক আছে। আল্লাহ চাইলে হবে। তুই এখন ঘুমা তো। অনেক রাত হয়েছে। কাল তো আবার তোর চাকরির ফল দিবে। আল্লাহ নিশ্চয়ই ভালো কিছু করবে।\nঅতঃপর ভোর হলো। সূর্যের কিরণ ক্রমাগত তীব্র ভাবে ছড়িয়ে পড়তে থাকে ধরনীর বুকে৷ দীর্ঘ প্রতিক্ষা নিয়ে চেয়ারে বসে আছি ফোন হাতে নিয়ে। কখন এসএমএস আসবে। কখন অপেক্ষার অবসান হবে। যদি সত্যি এ বার চাকরিটা পেয়ে যাই; তাহলে মাকে রানী বানাতে আর কোনো বাধা থাকবে না। বাধা থাকবে না তিলবতীকে পেতে। প্রাণ ভরে সৃষ্টিকর্তাকে স্মরণ করতে থাকলাম। পাশে মা ও বসে ছিলো। সে ও সৃষ্টিকর্তার কাছে অনবরত বলে চলেছেন; আমাদের দিকে যেনো তাকায়। \nআরও দীর্ঘক্ষণ পর ফোনে একটা ই-মেইল ঢুকলো। আমার বুকের পাঁজর টনটন করে উঠলো। হাত কাঁপতে থাকলো। কাঁপা হাতে ই-মেইল টা খুললাম। মা আমার দিকে ভীষণ উচ্ছ্বাস নিয়ে চাকিয়ে আছে। আমি কি বলবো শোনার জন্য।\nই-মেইলে চোখ বুলিয়ে আমার দৃষ্টি স্থির হয়ে গেলো। হৃদয়ে কাঁপুনি ও থেমে গেলো। সারা শরীর অবশ হওয়ার উপক্রম হলো। মা আমার হাত ধরে অনবরত বলে চলেছে\nকিরে কি হলো? কিছু বলছিস না কেনো? চাকরিটা কি হয়েছে?\nআমি শান্ত ভাবে মায়ের দিকে চোখ তুলে তাকালাম। চোখের তারা চিকচিক করছে মা তা স্পষ্ট টের পেলো। এক বুক হতাশ নিয়ে ডানে-বামে মাথা নাড়ালাম। কাঁপা কণ্ঠে বললাম ‘নাহ্।’\nছুটে চলে গেলাম নিজের ঘরে। বাবা না ফেরার দেশে পাড়ি জমানোর পর, মা কত কষ্ট করেছে আমার জন্য। কত কষ্ট করে আমাকে লেখা-পড়া শিখিয়েছে। গেরস্ত বাড়ির বউ হয়ে ও অন্যের বাড়ি দাসীর মত কাজ করেছে। শুধু মাত্র আমাকে মানুষ করবে বলে। আমার পেটে দু-মুটো ভাত তুলে দিবে বলে। কত কটূ কথা সহ্য করেছে। কত অপমান,লাঞ্ছনা কত কি!\nএত কিছু দেখে মাকে কথা দিছিলাম, আমি বড় হয়ে অনেক বড় চাকরি করে মায়ের দুঃখ ঘুচিয়ে দেবো। কিন্তু, হায়! আজ ভাগ্য সঙ্গ দিলো না। আমি পারলাম না মায়ের পাশে দাঁড়াতে। পারলাম না মাকে রাজরানী করতে। মা কে কথা দিছিলাম, আমি মায়ের দুঃখ ঘুচিয়ে দিবো। মা''কে আবার তার রানীর আসন ফিরিয়ে দেবো। কিন্তু, তা আর হলো না। \nসেই দিন আর বের হলাম না ঘর থেকে। মা অনেকবার ডেকেছে। তবু ও ভালো লাগে নি। কোন মুখ নিয়ে মায়ের সামনে দাঁড়াবো? তাই ভেবে আর বের হলাম না। \nপরের দিন খুব ভোরে আরেকটা এসএমএস আসলো ফোনে। যেখানে লেখা ছিলো আমার সেই তিলবতী নাকি পবিত্র বিবাহ-বন্ধনে আবদ্ধ হতে যাচ্ছে। যে টুকু ঘুরে দাঁড়ানোর আশা ছিলো সে টুকু ও নিভে গেলো। শান্ত পাথরের মত স্থির হয়ে গেলো আমার চলমান জীবন। ভাবনারা সব উড়ে গেলো দূর আকাশে। না পারলাম মা''কে রানীর আসনে বসাতে; আর না পারলাম মনের মানুষ টাকে ধরে রাখতে। এই হচ্ছে, একটা বেকার ছেলের বিষাক্ত কিছু স্মৃতি।  \nমায়ের ডাকে ভাবনার জগৎ থেকে বের হয় ছেলেটি। বাটি ভর্তি কিছু পেঁপে কেটে নিয়ে এসেছে। যে মূহুর্ত থেকে শুনেছে আমি আমার প্রিয় মানুষটিকে হারিয়েছি, সে চলে গেছে আমাকে ছেড়ে, সেই মূহুর্ত থেকে দশটা মিনিটের জন্য আমার পাশ থেকে সরে নি। শান্তনা দিয়ে গেছে। সাহস দিয়ে গেছে। ভরসা দিয়ে গেছে। বলেছে তুই চিন্তা করিস না বাবা, আল্লাহ যা করে ভালোর জন্য করে। আমি আরও দু বাড়ি কাজ নিয়েছি। আরেকবার চেষ্টা কর। চাকিরটা এবার ঠিক হবে। আমাদের দুর্দিন কেটে যাবে। নিরাশ হইস না। সৃষ্টি কর্তা বান্দার পরিক্ষা নেওয়ার জন্য বিপদে ফেলে। এক দম নিরাশ হইস না। মা আছে তো।\nমা''কে কি ভাবে বোঝাবো, সে আছে বলেই আমি মরে গিয়ে ও বেঁচে আছি। সে আছে বলেই বিফল হয়ে ও আবার সফল হওয়ার স্বপ্ন বুনি। \n_______সমাপ্ত_________\n®️নিধী\n১৪ এপ্রিল,২০২৫\nসোমবার।\n[অনেক আগে লিখেছিলাম। ডায়েরিতে লেখা ছিলো। আরেকটু কারেকশন করে পোস্ট করলাম।]"}],"comments":0,"is_featured":false,"read_time":null,"status":"published","submitted_by":"primary-admin","date":"2026-02-26T21:17:27.803Z","updated_at":"2026-03-31T18:08:55.968Z"}','2026-03-07T23:14:15.343Z','2026-03-31T11:35:43.777Z');
INSERT INTO "app_table_rows" ("pk","table_name","row_json","created_at","updated_at") VALUES(908,'stories','{"id":"1772140696756","title":"এক নরকের অগ্নিকুণ্ড","excerpt":"__MAHEAN_META__:{\"status\":\"published\",\"submittedBy\":\"primary-admin\",\"author\":\"তোয়া নিধী দোয়েল\",\"category\":\"অণুগল্প\",\"coverImage\":\"/uploads/stories/covers/2026/03/c243a2ea-adb7-42ba-a642-12d2b05a388d.png\",\"slug\":\"এক-নরকের-অগ্নিকুণ্ড\",\"parts\":[{\"id\":\"1\",\"title\":\"পর্ব 01\",\"content\":\"\"}],\"comments\":0}:__MAHEAN_META_END__স্রষ্টার কাছে, একদিন নরক দেখতে চাইলাম।\nতিনি আমারে নরক দেখাইলো। সেই নরকে আগুন ছিল না,ছিল আমার ঘর। যে ঘরে এক সময়, সর্গের সুবাস বইতো। আজ সে ঘর কেবল, নরকের অগ্নিকুণ্ড!","content":"স্রষ্টার কাছে, একদিন নরক দেখতে চাইলাম।\nতিনি আমারে নরক দেখাইলো। সেই নরকে আগুন ছিল না,ছিল আমার ঘর। যে ঘরে এক সময়, সর্গের সুবাস বইতো। আজ সে ঘর কেবল, নরকের অগ্নিকুণ্ড!\nসারাদিনের ক্লান্তি শেষে, যখন ঘরে এসে আয়নায় নিজেকে দেখি, খুব মায়া হয় নিজের উপর। সাথে খানিকটা আফসোসও হয়। লম্বা একটা দীর্ঘশ্বাস, বোঝার মত কেউ নেই। দু চোখে উপচে পড়া কান্না, দেখার মত কেউ নাই। বুকের ভেতরটা রক্তাক্ত, জড়িয়ে ধরার মত কেউ নাই।\nএক সময়, এই আয়নায় নিজের পাশে দৃশ্যমান হতো, সৌষ্ঠব লাবণ্যময়ী! যার ডাগর ডাগর আঁখিতে লেপটে থাকতো, ঘন কালো মেঘর মত কাজলের ছোঁয়া! যার দুই খিলান ভ্রুর মাঝে থাকতো ছোট টিপ। লম্বা কেশগুচ্ছে, কখনো কখনো গাঁথা থাকতো বেলি, কখনো কনকচাঁপা। যার কলকল হাসির শব্দে, এই ঘরের প্রতিটি কোণে ফিরত নতুন প্রাণ! যার নূপুরের ঝুমঝুম শব্দে, নৃত্য করে উঠতো সারা বাড়ি। আজ সে বাড়ি শুধুই মরুভূমির বালুচর!\nসে পাড়ি জমালো না ফেরার দেশে। সাথে নিয়ে গেলো আমার আত্মা হৃদয় আর ভালো থাকার শেষ ভরসা। শেষবার তার শান্ত নির্জীব হাত দুখানা, জড়িয়ে ধরে বলে ছিলাম,\n ‘চলে যাওয়া কি ভীষণ অবশ্য? থেকে গেলে হয়না? আমি আগের থেকে অনেক ভালোবাসা দেবো। অনেক যত্ন নেবো।  হারিয়ে যেও না আমার থেকে। আমি যে বড্ড নিঃস্ব তুমি বিহীন। তুমি হীনা প্রতিটা মূহুর্ত মূল্যহীন।’\nসে ম্লান হেসে বলেছিলো,\n‘দুঃখ পেয়েও না। ক্ষণিকের ভালোবাসা পাওয়ায় যে সুখ আছে, হয়তো চিরদিন সেই ভালোবাসায় সুখ নাও থাকতে পারে। তোমাকে ছোঁয়ার সাধ্য আর হবে না। তবে মনে রেখো, দূরত্ব যতই হোক আমি তোমাকে ভীষণ ভালোবাসি! \n‘তবে, নিয়ে যাও আমাকে।’\n‘নিয়ে গেলে যদি আর আমাকে ভালো না বাসো। ক্ষনে ক্ষনে মনে না করো। তখন? তখন ঐ ভালবাসা না পাওয়ার আক্ষেপ আমি কোথায় রাখবো? তাই ভালোবাসলে দূরত্ব সৃষ্টি করতে হয়। যাতে ভালোবাসা কখনো না কমে!\n‘তাহলে চলেই যাবে....?’\nসে প্রত্যুত্তরে আর কিছু বললো না। শুধু ফুটে উঠলো শ্রী ভরা মুখের, অতীব সুন্দর হাসি!\nসেই থেকে আজ অব্দি, সেই হাসি আমাকে তাড়া করে বেড়ায়। আমার প্রতি মূহুর্ত বিষিয়ে তোলে! পুড়ে খাক হয়ে যায় হৃদয়। তবু ও সে ফিরে আসে না। এসে বলে না, এইতো আমি। তোমার আমি!\nকোথাও হারিয়ে যায়নি। আসো আমার কোলে মাথা রাখো। এত কিসের দুঃখ তোমার? এত কিসের অপ্রাপ্তি তোমার? সব দুঃখকে দীর্ঘশ্বাসের মধ্যে বের করে দেও। মধুর এক আলিঙ্গনের মাধ্যমে, তৃষ্ণার্ত হৃদয়ের তৃষ্ণা মিটিয়ে দেও!\nউফফ! আবার সেই অকল্পনীয়, অসম্ভাব্য কল্পনা গুলো। এ মন কেনো বোঝে না, মানুষ না ফেরার জন্যই হারায়!  তুমি আমার সেই স্বপ্ন যা জীবনের প্রতিটা পৃষ্ঠায় লেখা থাকবে। তবে কখনো আমার জীবনে পূর্ণতা আনবে না। তুমি আমার সেই স্বপ্ন যাকে হারানোর পর, জীবন কাটছে বিরল নির্জনতায়। তুমি আমার সেই স্বপ্ন যাকে হারানোর পর, কষ্টেরা আমাকে ভীষণ আপন করে নিয়েছে। নিজের করে নিয়েছে। শুধু আফসোস তুমি নিলে না!\nচোখের কার্নিশে জমা নিত্য দিনের সঙ্গিকে, মুছে বারান্দায় বসলাম। স্নিগ্ধ বাতাস আমায় ছুঁয়ে দিলো। চেয়ারে হেলান দিয়ে চোখ বুজলাম। ইসস যদি তুমি ছুঁয়ে দিতে! তোমার জন্য ক্ষয় হয়ে যাওয়া এই নেত্র পল্লব যুগল কে!\nস্রষ্টা আমারে নরক দেখাইলো। সেই নরকে আগুন ছিল না,ছিল আমার ঘর। আর ভগ্ন হৃদয়!\n__________সমাপ্ত_____________\n®️দোয়েল\n২৮ মার্চ, ২০২৫\nঅসুস্থ শরীর নিয়ে😑","author_id":"1772140265202","author":"তোয়া নিধী দোয়েল","category_id":"অণুগল্প","category":"অণুগল্প","views":1,"image":null,"cover_image":"/uploads/stories/covers/2026/03/c243a2ea-adb7-42ba-a642-12d2b05a388d-cb202603311808-4.png","slug":"এক-নরকের-অগ্নিকুণ্ড","tags":[],"parts":[{"id":"1","title":"পর্ব 01","content":"স্রষ্টার কাছে, একদিন নরক দেখতে চাইলাম।\nতিনি আমারে নরক দেখাইলো। সেই নরকে আগুন ছিল না,ছিল আমার ঘর। যে ঘরে এক সময়, সর্গের সুবাস বইতো। আজ সে ঘর কেবল, নরকের অগ্নিকুণ্ড!\nসারাদিনের ক্লান্তি শেষে, যখন ঘরে এসে আয়নায় নিজেকে দেখি, খুব মায়া হয় নিজের উপর। সাথে খানিকটা আফসোসও হয়। লম্বা একটা দীর্ঘশ্বাস, বোঝার মত কেউ নেই। দু চোখে উপচে পড়া কান্না, দেখার মত কেউ নাই। বুকের ভেতরটা রক্তাক্ত, জড়িয়ে ধরার মত কেউ নাই।\nএক সময়, এই আয়নায় নিজের পাশে দৃশ্যমান হতো, সৌষ্ঠব লাবণ্যময়ী! যার ডাগর ডাগর আঁখিতে লেপটে থাকতো, ঘন কালো মেঘর মত কাজলের ছোঁয়া! যার দুই খিলান ভ্রুর মাঝে থাকতো ছোট টিপ। লম্বা কেশগুচ্ছে, কখনো কখনো গাঁথা থাকতো বেলি, কখনো কনকচাঁপা। যার কলকল হাসির শব্দে, এই ঘরের প্রতিটি কোণে ফিরত নতুন প্রাণ! যার নূপুরের ঝুমঝুম শব্দে, নৃত্য করে উঠতো সারা বাড়ি। আজ সে বাড়ি শুধুই মরুভূমির বালুচর!\nসে পাড়ি জমালো না ফেরার দেশে। সাথে নিয়ে গেলো আমার আত্মা হৃদয় আর ভালো থাকার শেষ ভরসা। শেষবার তার শান্ত নির্জীব হাত দুখানা, জড়িয়ে ধরে বলে ছিলাম,\n ‘চলে যাওয়া কি ভীষণ অবশ্য? থেকে গেলে হয়না? আমি আগের থেকে অনেক ভালোবাসা দেবো। অনেক যত্ন নেবো।  হারিয়ে যেও না আমার থেকে। আমি যে বড্ড নিঃস্ব তুমি বিহীন। তুমি হীনা প্রতিটা মূহুর্ত মূল্যহীন।’\nসে ম্লান হেসে বলেছিলো,\n‘দুঃখ পেয়েও না। ক্ষণিকের ভালোবাসা পাওয়ায় যে সুখ আছে, হয়তো চিরদিন সেই ভালোবাসায় সুখ নাও থাকতে পারে। তোমাকে ছোঁয়ার সাধ্য আর হবে না। তবে মনে রেখো, দূরত্ব যতই হোক আমি তোমাকে ভীষণ ভালোবাসি! \n‘তবে, নিয়ে যাও আমাকে।’\n‘নিয়ে গেলে যদি আর আমাকে ভালো না বাসো। ক্ষনে ক্ষনে মনে না করো। তখন? তখন ঐ ভালবাসা না পাওয়ার আক্ষেপ আমি কোথায় রাখবো? তাই ভালোবাসলে দূরত্ব সৃষ্টি করতে হয়। যাতে ভালোবাসা কখনো না কমে!\n‘তাহলে চলেই যাবে....?’\nসে প্রত্যুত্তরে আর কিছু বললো না। শুধু ফুটে উঠলো শ্রী ভরা মুখের, অতীব সুন্দর হাসি!\nসেই থেকে আজ অব্দি, সেই হাসি আমাকে তাড়া করে বেড়ায়। আমার প্রতি মূহুর্ত বিষিয়ে তোলে! পুড়ে খাক হয়ে যায় হৃদয়। তবু ও সে ফিরে আসে না। এসে বলে না, এইতো আমি। তোমার আমি!\nকোথাও হারিয়ে যায়নি। আসো আমার কোলে মাথা রাখো। এত কিসের দুঃখ তোমার? এত কিসের অপ্রাপ্তি তোমার? সব দুঃখকে দীর্ঘশ্বাসের মধ্যে বের করে দেও। মধুর এক আলিঙ্গনের মাধ্যমে, তৃষ্ণার্ত হৃদয়ের তৃষ্ণা মিটিয়ে দেও!\nউফফ! আবার সেই অকল্পনীয়, অসম্ভাব্য কল্পনা গুলো। এ মন কেনো বোঝে না, মানুষ না ফেরার জন্যই হারায়!  তুমি আমার সেই স্বপ্ন যা জীবনের প্রতিটা পৃষ্ঠায় লেখা থাকবে। তবে কখনো আমার জীবনে পূর্ণতা আনবে না। তুমি আমার সেই স্বপ্ন যাকে হারানোর পর, জীবন কাটছে বিরল নির্জনতায়। তুমি আমার সেই স্বপ্ন যাকে হারানোর পর, কষ্টেরা আমাকে ভীষণ আপন করে নিয়েছে। নিজের করে নিয়েছে। শুধু আফসোস তুমি নিলে না!\nচোখের কার্নিশে জমা নিত্য দিনের সঙ্গিকে, মুছে বারান্দায় বসলাম। স্নিগ্ধ বাতাস আমায় ছুঁয়ে দিলো। চেয়ারে হেলান দিয়ে চোখ বুজলাম। ইসস যদি তুমি ছুঁয়ে দিতে! তোমার জন্য ক্ষয় হয়ে যাওয়া এই নেত্র পল্লব যুগল কে!\nস্রষ্টা আমারে নরক দেখাইলো। সেই নরকে আগুন ছিল না,ছিল আমার ঘর। আর ভগ্ন হৃদয়!\n__________সমাপ্ত_____________\n®️দোয়েল\n২৮ মার্চ, ২০২৫\nঅসুস্থ শরীর নিয়ে😑"}],"comments":0,"is_featured":false,"read_time":null,"status":"published","submitted_by":"primary-admin","date":"2026-02-26T21:18:16.756Z","updated_at":"2026-03-31T18:08:55.968Z"}','2026-03-07T23:14:15.343Z','2026-03-31T11:35:43.777Z');
