INSERT INTO "app_table_rows" ("pk","table_name","row_json","created_at","updated_at") VALUES(124391,'stories','{"id":"1773089993198","title":"পুনর্জন্ম (এক প্রেম কাহিনী)","excerpt":"__MAHEAN_META__:{\"status\":\"published\",\"submittedBy\":\"primary-admin\",\"author\":\"রিয়াদ ইসলাম আযান\",\"category\":\"সিজন সিরিজ\",\"categories\":[\"সিজন সিরিজ\"],\"coverImage\":\"/uploads/stories/covers/2026/03/3239a5d1-9858-40fe-b8f3-1c1cd15cd26d.png\",\"slug\":\"পুনর্জন্ম\",\"parts\":[{\"id\":\"1\",\"title\":\"01\",\"slug\":\"part-01\",\"content\":\"\"},{\"id\":\"1773089795551-2\",\"title\":\"02\",\"slug\":\"part-02\",\"content\":\"\"},{\"id\":\"1773089830012-3\",\"title\":\"03\",\"slug\":\"part-03\",\"content\":\"\"},{\"id\":\"1773089848003-4\",\"title\":\"04\",\"slug\":\"part-04\",\"content\":\"\"},{\"id\":\"1773089864364-5\",\"title\":\"05\",\"slug\":\"part-05\",\"content\":\"\"},{\"id\":\"1773089882096-6\",\"title\":\"06\",\"slug\":\"part-06\",\"content\":\"\"},{\"id\":\"1773089911536-7\",\"title\":\"07\",\"slug\":\"part-07\",\"content\":\"\"},{\"id\":\"1773089930158-8\",\"title\":\"08\",\"slug\":\"part-08\",\"content\":\"\"},{\"id\":\"1773089976071-9\",\"title\":\"last part 09\",\"slug\":\"last-part-09\",\"content\":\"\"}],\"comments\":0,\"season\":1}:__MAHEAN_META_END__ প্রায় ১৬ বছর পরে আমি গ্রামে ফিরলাম। চারপাশে সবুজের বাহার, মন ছুঁয়ে যাওয়া ফুটফুটে বাতাস, আর সুন্দর প্রকৃতি আমাকে এক নতুন জীবনের স্বাদ দিচ্ছে। শহরের কোলাহলে বেড়ে উঠার পর গ্রামের শান্ত পরিবেশে এসে বোধ হয় যেনো আমি নতুন করে শ্বাস নিচ্ছি। আমার মা-বাবা আমার জন্মের অনেক আগে শহরে চলে যান, কারণ তারা গ্রামের পরিবেশে স্বাচ্ছন্দ্যবোধ করতেন না।","content":"","author_id":"1773089545405","author":"রিয়াদ ইসলাম আযান","category_id":"সিজন সিরিজ","category":"সিজন সিরিজ","views":1,"image":null,"cover_image":"/uploads/stories/covers/2026/03/3239a5d1-9858-40fe-b8f3-1c1cd15cd26d.png","slug":"পুনর্জন্ম","tags":[],"parts":[{"id":"1","title":"01","slug":"part-01","content":"প্রায় ১৬ বছর পরে আমি গ্রামে ফিরলাম। চারপাশে সবুজের বাহার, মন ছুঁয়ে যাওয়া ফুটফুটে বাতাস, আর সুন্দর প্রকৃতি আমাকে এক নতুন জীবনের স্বাদ দিচ্ছে। শহরের কোলাহলে বেড়ে উঠার পর গ্রামের শান্ত পরিবেশে এসে বোধ হয় যেনো আমি নতুন করে শ্বাস নিচ্ছি। আমার মা-বাবা আমার জন্মের অনেক আগে শহরে চলে যান, কারণ তারা গ্রামের পরিবেশে স্বাচ্ছন্দ্যবোধ করতেন না। গ্রামের বাড়ির কেয়ারটেকার, রফিক দাদু, ছোটবেলা থেকে এই বাড়ির দেখাশোনা করছেন। তাঁর নাতি আব্রাহাম আমাদের সমবয়সী। আমরা তিন বন্ধু, আমি -আরিয়ান, তৌহিদ ও রনি, আব্রাহামের সাথে গ্রামটা ঘুরে দেখার পরিকল্পনা করি।\nদ্বিতীয় দিনে আমরা গ্রামের কোণা-কোনা, নদীর পাড়ের গাছের ছায়া, পুরোনো পুকুরের ঘাট ঘুরে বেড়ালাম। সুর্যের আলোতে পাতা খেলা করছে, ঝিরিঝিরে বাতাস বইছে। গ্রামের শান্ত ও স্নিগ্ধ পরিবেশ আমার মনকে অবধারিত প্রশান্তি দেয়, যেনো আমি শহুরে জীবনের ক্লান্তি থেকে মুক্তি পেয়েছি। তবে, বাড়ি ফিরার সময় আমি হঠাৎ নজর দিলাম এক হুজুরের উপর, সে একজন নিষ্পাপ ছেলেকে নিমপাতার ডাল দিয়ে মা*রছিলেন। হুজুর জোরে জোরে বলছিলেন, \"এই নিষ্পাপ ছেলেটির দেহে কেনো এসেছিস, সয়তান? ছেড়ে দে এই নিষ্পাপ ছেলেটিকে!\" আমি কৌতূহলবশত হুজুরের কাছে গিয়ে বললাম, \"আপনি কি মানুষ? কীভাবে একজন মানুষকে এভাবে অ*ত্যা*চার করেন? আপনি যদি তাঁর মঙ্গল চান, তাহলে তাঁকে একফোঁটা ভালোবাসাও দিতে পারেন না?\"  হুজুর বললেন, \"আপনাকে তো আগে কখনো দেখিনি। নতুন এসেছেন গ্রামে?\" আব্রাহাম তখন জানালো, \"ইয়ে মানে হুজুর, উনি খান সাহেবের নাতি।\" হুজুর আমার দিকে তাকিয়ে বললেন, \"আপনি এদের বিষয়ে কিছুই জানেন না। ওরা ইনসানের দুশমন।\" আমি জানতে চাইলাম, \"কে ইনসানের দুশমান?\" হুজুর বললেন, \"এই নিষ্পাপ ছেলেটির দেহে যে সয়তান আছে, সে-ই হচ্ছে ইনসানের দুশমন।\" হুজুর আবারও ছেলেটিকে নিমপাতার ডাল দিয়ে মা*রতে থাকলে, আমি নিজের নিয়ন্ত্রণ হারিয়ে ইউনার হাত থেকে ডালটি কেড়ে নিয়ে ফেলে দিলাম। \"যদি ভালো চান, ওকে ছেড়ে দিন, নতুবা বিপদ আছে বলে দিলাম।\" আমি বললাম। এরপর চলে আসছিলাম ঠিক তখনই হুজুর আমাকে পিছু ডাক দিলেন, \"বিপদ আমার নয়, বিপদ আপনার হতে চলেছে। যত তাড়াতাড়ি সম্ভব এই পাহাড়িতলা গ্রাম ছেড়ে যান।\" অথচ আমি উনার কথার তোয়াক্কা না করে বাড়ি ফিরে এলাম। সারাদিন আমরা কৌতূহল নিয়ে গ্রামে ঘুরলাম। সন্ধ্যাবেলায় ঘটনার আলোচনা করতে থাকলাম। এমন সময় আম্মু চা দিতে এসে আমাদের কথা শুনলেন এবং জিজ্ঞেস করলেন, \"কি হয়েছে বিকেলে?\" রনি বললো, \"বিকেলে দেখলাম একজন হুজুর একটা ছেলেকে মা*রছিলো এবং বলছিলো, ''এই নিষ্পাপ ছেলেটিকে ছেড়ে দে ইনসানের দুশমন!''\"  আম্মু আশ্চর্যের সুরে বললেন, \"আব্রাহাম! ওরা কোন হুজুরের কথা বলছে?\" আব্রাহাম জানালো, \"আসলে, খালামণি, উনারা আলতাফ সাহেবের কথা বলছেন।\" মা বললেন, \"শুনো বাবারা, আলতাফ সাহেব বহুদিন ধরে এই পাহাড়িতলা গ্রামে আছেন। তাঁর বাবা যখন এখানে এসেছিলেন, তখন আলতাফ সাহেবও ছোট ছিলেন। তিনি এখানকার ইমামতি করেন এবং গ্রামবাসীদের বিনামূল্যে সেবা করে আসছেন। উনার দেয়া সতর্কবানীগুলো সব সত্যি।\" এরপর আমরা আলাপচারিতায় মগ্ন হয়ে পড়লাম।\nপরের দিন, আমরা চারজন আবারো গ্রামে ঘুরতে বের হলাম। হাঁটার সময় হঠাৎ আমি একটা মেয়েকে লক্ষ্য করলাম, যার চোখ ছিলো ডাগর ডাগর নীল নয়না, গায়ের রঙ ছিলো দুধে আলতা, আর হালকা কুঁকড়ানো চুল যেনো এক অপরূপ সুন্দরী। আমি অজ্ঞাতসারে তার পিছু নিতে লাগলাম, এক নির্জন জায়গায় গিয়ে পৌঁছালাম। সেখানে শুধু বিশাল একটি বটগাছ ছাড়া কিছুই ছিলো না। আমি মেয়েটিকে বটগাছের পাশ দিয়ে যেতে দেখলাম, কিন্তু পরে আর তাকে খুঁজে পেলাম না। আমি পাগলের মতো তাকে খুঁজতে লাগলাম, কিন্তু সফল হলাম না। চারপাশের মানুষের কাছ থেকে আলাদা হয়ে যাওয়ার কোনো হুঁশ ছিলো না আমার। হঠাৎ আব্রাহামের চিৎকারে আমার হুঁশ ফিরলো। \"এ-কি সাব! আপনি এই নিষিদ্ধ স্থানে কী করছেন? আপনি জানেন না এই জায়গায় আসা বারণ?\" সে বললো। আমি মাথা নেড়ে নিষ্প্রভভাবে ফিরে এলাম। বাড়িতে এসে আমি আব্রাহামকে ডেকে আলাদা করে জানতে চাইলাম, \"আচ্ছা আব্রাহাম! ওই জায়গাটিকে নিষিদ্ধ স্থান বলা হয় কেনো? আর সেখানে যাওয়া বারণ কেনো?\" আব্রাহাম বললো, \"কথিত আছে, বহু বছর আগে এই গ্রামে একটি ডাইনীর অভিশাপ ছড়িয়ে পড়েছিলো পরে আপনার পরদাদা নিজের জীবন দিয়ে ওই ডাইনীকে নিষিদ্ধ স্থানে বন্দী করে রেখেছিলেন।\" কথা বলার সময় আমি লক্ষ করলাম, দেওয়ালের দিকে একটি ছায়া যেনো সরে গেলো। আমি তাতে পাত্তা না দিয়ে রুমে চলে এলাম। আব্রাহামের কথার প্রভাবে চিন্তিত হয়ে পড়লাম। আমি মনে মনে ভাবলাম, কি আমি ডাইনির কেলেঙ্কারিতে পড়ে গেলাম? তারপর থেকেই আমি কেমন অন্যমনস্ক থাকার চেষ্টা করছি, আমার মনের মধ্যে শুধু ওই মেয়েটির চিন্তা। মাথায় শুধু সেই নীল নয়না মেয়েটি, এবং একটি উদ্বেগ মেয়েটিই কি সেই ডাইনী, নাকি অন্য কেউ?\nআমাকে এমন অবসাদগ্রস্ত দেখে আম্মু আমাকে জিজ্ঞেস করলেন, \"আরিয়ান, কি হয়েছে তোর?\" আমি বললাম, \"কিছু হয়নি তো?\" আম্মু বললেন, \"তোকে আমি দুই দিন ধরে দেখছি, কি হয়েছে সত্যি করে বলতো?\" অবশেষে, পরিস্থিতির চাপের কারণে সাহস সঞ্চয় করে বললাম, \"আচ্ছা আম্মু, গ্রামের ওই নিষিদ্ধ স্থানের কাহিনি কি?\" কথাটি বলার সাথে সাথেই আম্মুর মুখের অভিব্যক্তি বদলে গেলো। তিনি কিছুক্ষণ চুপ থেকে বললেন, \"এই বিষয়ে আমি কিছুই জানি না। আমার অনেক কাজ আছে। এখন এসব নিয়ে কথা বলার সময় না আমি কাজে গেলাম।\" তাঁর অনিচ্ছা এবং রহস্যময় চাহনি আমার মনে আরও প্রশ্ন উত্থাপন করলো "},{"id":"1773089795551-2","title":"02","slug":"part-02","content":"ঘুম থেকে উঠে দোতলার বারান্দায় দাঁড়িয়ে নিচের দিকে নজর দিলাম। দেখতে পেলাম, তৌহিদ এবং আব্রাহাম কিছু একটা নিয়ে কথা বলছে। তাদের মাঝে কি হচ্ছে তা জানার জন্য নেমে গেলাম। আমাকে দেখে তৌহিদ আমতা আমতা করে বললো, \"কিরে! এত তাড়াতাড়ি ঘুম ভেঙ্গে গেলো?\" আমি বললাম, \"হ্যাঁ, ওই আরকি।\" ঠিক তখনই রনি ভেতর থেকে ডাক দেওয়ায় তৌহিদ তড়িঘড়ি করে ভেতরে চলে গেলো। আমি আব্রাহামকে নিয়ে আলতাফ সাহেবের বাসায় যাওয়ার সিদ্ধান্ত নিলাম, এবং আব্রাহামও সঙ্গে আসতে রাজি হয়ে গেলো।\nআমি এবং আব্রাহাম মাওলানা আলতাফ সাহেবের বাড়িতে পৌঁছালাম। সেখানে গিয়ে, আব্রাহাম বললো, \"হুজুর, শহরের সাব এসেছেন আপনার সাথে দেখা করতে।\" মাওলানা আলতাফ সাহেব একটু অভিভূত হয়ে বললেন, \"কি মনে করে আসা হলো এই গরীবের দরবারে?\" আমি আমার ভুল বুঝতে পেরে বললাম, \"হুজুর, সত্যি আমাকে ক্ষমা করে দিবেন প্লিজ, আসলে আমি ভেবেছিলাম যে আপনি ভুল কাজ করছেন। কিন্তু বাসায় গিয়ে আম্মুর কথা শোনার পর আমি বুঝতে পারলাম যে আমি বিভ্রান্ত ছিলাম।\" তিনি হেসে বললেন, \"ও-ও, আমি কিছু মনে করিনি। আপনি আপনার ভুল বুঝতে পেরেছেন, এটাই অনেক।\" এভাবে আমাদের কথোপকথন চলতে থাকলো। \"আচ্ছা! এবার তাহলে যাই। ভালো থাকবেন।\" বললাম আমি। মাওলানা আলতাফ সাহেব বললেন, \"চলে যাবেন? আচ্ছা যান! কিন্তু তাড়াতাড়ি এই গ্রাম থেকে চলে যান। আর একটি কথা, আপনার বন্ধুরা কিন্তু আপনার বিপদ হয়ে দাঁড়াবে।\" আমি অবাক হয়ে বললাম, \"মানে! ওরা আমার বিপদ হবে কেনো?\" তিনি সাঙ্ঘাতিকভাবে বললেন, \"সময় হোক, সব বুঝতে পারবেন।\" তাঁর কথা আমাকে আরও হতভম্ব করে দিলো।\nবাড়ি ফিরে এসে, আমি তৌহিদ এবং রনিকে নিয়ে গ্রাম ঘুরতে বের হলাম। সারাদিন ঘুরাঘুরি করার পর আমরা একটি পাহাড়ি ঝর্ণায় গেলাম। ঝর্ণার কাছে গিয়ে হঠাৎ আমার মাথা ব্যথা শুরু হলো। ঝাপসা চোখে কিছু দেখতে পেলাম, কিন্তু ঠিক কি দেখলাম তা মনে পড়ছিলো না। তবে একটুকু নিশ্চিত ছিলাম যে আমি নিজের প্রতিবিম্ব দেখলাম। যদি আমি নিজের প্রতিবিম্ব দেখে থাকি তাহলে এত ঝাপসা কেন? এর আগে তো আমি এই পাহাড়তলা গ্রামে আসিনি। তাহলে আমি কিভাবে এরকম দৃশ্য দেখতে পেলাম? শরীর খারাপ হয়ে বাড়ি ফিরে এলাম, প্রচুর ক্লান্ত লাগছিলো। সন্ধ্যাবেলা বাসায় ফিরে এসে আমি সন্ধ্যার নাস্তা সারলাম। কিছুক্ষণ টিভি দেখার পর ফোন দিয়ে যথারীতি হালকা ঘাটাঘাটি করতে থাকলাম। কিছুক্ষণ পর আম্মুকে বললাম, \"আব্বুকে বলো, আমাদের যেনো কালকেই এসে নিয়ে যায়।\"  আম্মু অবাক হয়ে জিজ্ঞেস করলেন, \"হঠাৎ, কালকেই চলে যাওয়ার কথা বলছিস কেনো? তুই তো গ্রামের বাড়ি আসার জন্য পাগল হয়ে গিয়েছিলি, এখন তুই''ই চলে যেতে চাইছিস?\" আমি বললাম, \"হ্যাঁ, আমি কালকেই চলে যাবো। তোমাদের যদি থাকার ইচ্ছে থাকে, তাহলে তোমরা আরো কিছুদিন থাকতে পারো।\" আম্মু মাথা নেড়ে বললেন, \"আচ্ছা, কালকে তোর আব্বুকে এসে নিয়ে যেতে বলবো। এখন ঘুমা, অনেক রাত হয়েছে।\"\nআম্মুকে বিদায় জানিয়ে আমি ঘুমাতে গেলাম, কিন্তু ঘুম আসছিলো না। মনে তখনও সেই মেয়েটি আর গ্রামের সেই নিষিদ্ধ স্থানটির কথা ঘুরপাক খাচ্ছিলো। তাই কাউকে জানান না দিয়েই একা একা সেই স্থানে চলে গেলাম। জায়গাটা আজ যেনো অন্যরকম মনে হচ্ছিলো। বটগাছটির ভেতর থেকে যেনো অনেকের কান্নার শব্দ ভেসে আসছিলো। একটু ভালো করে লক্ষ্য করতেই দেখলাম, গাছের এক কোণে একটা মাটির পাত্র বেঁধে রাখা ছিলো। পাত্রটি মনে হচ্ছিলো বহুদিন ধরে ওই গাছে বাঁধা পড়ে আছে। গাছের চারপাশে অনেক লাল সুতা ও তাবিজ বেঁধে রাখা ছিলো, যেনো শেওলা পড়ে এসব প্রায় নষ্ট হয়ে গেছে। এদিকে, আমার মূল কাজ হলো সেই মেয়েটিকে খুঁজে বের করা এবং জানতে চাওয়া, সে কেনো এই নিষিদ্ধ স্থানে আসে। আবার একটু নজর দিতে যাবো, তখনই রিশার ফোন কল আসলো। রিশা আমার কলেজ জীবনের বেস্ট ফ্রেন্ড, এবং আমার বাবার বন্ধু রাশেদ আঙ্কেলের একমাত্র মেয়ে। কল রিসিভ করতেই, \"তুমি এমন বেইমান হলে কিভাবে?\" আমি অবাক হয়ে বললাম, \"কি! আমি আবার কি করলাম?\" রিশা উত্তর দিলো, \"গ্রামের বাড়ি গেছো আজকে প্রায় ৯ দিন, এতদিনে একটা কল বা টেক্সট দেওয়ারও প্রয়োজন মনে করোনি আমায়।\" আমি বললাম, \"ওহ্, এই ব্যাপার! আচ্ছা বাবা সরি, এখন থেকে প্রতিদিন তোমাকে কল দিবো। গ্রামের পরিবেশটা এত সুন্দর যে একবার গ্রাম ঘুরতে বের হলে কিছুই মনে থাকে না।\" রিশা বললো, \"এতকিছু আমি বুঝি নাহ, তুমি এখন থেকে প্রতিদিন আমার সাথে কথা বলবে।\" আমি হেসে বললাম, \"আচ্ছা ঠিক আছে, আর আমরা হয়তো কালকে চলে আসবো। ওরা না আসলেও আমি কালকে চলে আসবো এটা শিওর।\" রিশা বললো, \"ওমা কেনো? তোমরা তো অনেক দিনের জন্য গেছো, তাহলে কালকেই চলে আসবে কেনো? আর ওরা না আসলেও তুমি কেনো চলে আসবে? কি হয়েছে, আমার কাছে বলো।\" আমি বললাম, \"নাহ! তেমন কিছু না। এমনি তোমাকে ছাড়া একা একা ভালো লাগে না, তাই চলে আসবো তোমার কাছে।\" এভাবে রিশার সাথে কথা বলতে বলতে দ্রুত ওই জায়গা থেকে ফিরে এলাম। বাড়ির সদর দরজা দিয়ে ভিতরে ঢুকতে গিয়ে দেখি আম্মু, তৌহিদ, রনি আর রফিক দাদু দাঁড়িয়ে আছেন। আমি অবাক হয়ে তাদেরকে জিজ্ঞেস করলাম, \"এত রাতে তোমরা এখানে কি করছো? ঘুমাওনি তোমরা?\" আম্মু একটু ক্রুদ্ধ সুরে বললেন, \"এত রাতে তুমি কোথায় ছিলে?\" আমি দ্রুত উত্তর দিলাম, \"আরে কিছু না, আমি কিছু সময়ের জন্য বেড়িয়েছিলাম।\" রফিক দাদুও বললেন, \"জানো, আমরা তোমার জন্য কত চিন্তা করছিলাম!\" তৌহিদ আবার বললো, \" বিলেকেই তো তোর শরীর খারাপ করলো, তারপর আবার তুই একা একা কি করে বাইরে বেড় হলি?\" আমি আর কোনো উত্তর দিলাম না। বুঝতে পারলাম কাজটা আসলেই করা উচিৎ হয়নি। তখন আম্মু বললো, \"আজকে যা করেছো - করেছো আর যেনো কখনো এমন না হয়, কাল সকালে তোমার আব্বু আসবে, ব্যাগ প্যাক করে রেখো কালকেই আমরা চলে যাবো.!\" রবি একটু অবাক হয়ে বললো, \"কালকেই.!\" আম্মু বললো \"হ্যাঁ কালকেই.।\" ড্রয়িংরুমের কথোপকথন শেষ করে আমরা যে যার রুমে ঘুমতে চলে গেলাম।\nসকালে সবাই ফ্রেশ হয়ে ব্রেকফাস্ট করতে বসেছিলাম। ব্রেকফাস্টের দিকে যখন সবাই মনোযোগী, তখন আব্বু এসে হাজির হলেন। সেই মুহূর্তে আমরা সবাই আব্বুর সাথে বের হবার জন্য পরিকল্পনা করছিলাম। এমন সময় তৌহিদ বললো, \"আসলে আঙ্কেল, আপনারা যান আমি আর রনি বিকেলে আসছি!\" আব্বু একটু চিন্তিত হয়ে বললেন, \"কি বলো! তোমরা একা একা যেতে পারবে তো?\" রনি সজাগভাবে উত্তর দিলো, \"হ্যাঁ! হ্যাঁ! আঙ্কেল, আমরা চিনবো। আপনি একদম টেনশন করবেন নাহ।\" আম্মু তখন তাদেরকে সতর্ক করে বললেন, \"আচ্ছা, তাহলে তোমরা কিন্তু ঠিক মতো চলে এসো। তোমাদের সাথে কি আরিয়ানকেও রাখবে নাকী, ওকে আমাদের সাথে নিয়ে যাবো?\" তৌহিদ দ্রুত বললো, \"নাহ! নাহ! আন্টি, ওকে আপনাদের সাথেই নিয়ে যান।\" আব্বু একটু নিশ্চিত হয়ে বললেন, \"আচ্ছা, তাহলে ঠিক আছে। আমরা চলে যাচ্ছি। আর এই ধরো, আমার কার্ড। পাসওয়ার্ড হচ্ছে 67874। তোমাদের যত টাকা লাগে, খরচ করবে। ঠিক আছে?\" রনি আনন্দে জানালো, \"আচ্ছা, আঙ্কেল।\" এরপর আমি আর আব্বু-আম্মু চলে আসি, আর রনি ও তৌহিদ গ্রামে থেকে যায়। "},{"id":"1773089830012-3","title":"03","slug":"part-03","content":"রনি আর তৌহিদকে আব্বুর কার্ড দিয়ে আমরা শহরের উদ্দেশ্যে রওনা হলাম। বাড়ি ফিরতে ফিরতে বিকেল হয়ে গেলো কারণ আমরা রাস্তায় আব্বুর সাথে তার কলিগদের মিটিং অ্যাটেন্ড করেছিলাম। বিকেলে বাসায় ফিরে এসে প্রথমেই আমি গোসল করতে গেলাম। গোসল সেরে আম্মুকে রান্নার কাজে সাহায্য করলাম, তারপর একসাথে খাওয়া দাওয়া করে আমি আমার রুমে শুয়ে শুয়ে গান শুনছিলাম। হঠাৎ করে ইয়ারফোনে গান আসা বন্ধ হয়ে গেলো। চেক করে দেখলাম ফোন থেকে গান প্লে হয়ে নেই, তাই গানটা আবার চালু করে শুনতে লাগলাম। কিন্তু এবার হঠাৎ করে বেডের এক কোণে পড়ে থাকা হেডফোন থেকে গান ভেসে আসছিলো। দেখে ঘাবড়ে গেলাম, কেননা ল্যাপটপের সাথে এটি কানেক্ট নেই এবং ল্যাপটপটাও বন্ধ। তাহলে এটাতে গান বাজছে কিভাবে? কি হচ্ছে, কিছুই বুঝে উঠতে পারছিলাম না। বিছানা থেকে নেমে দাঁড়াতেই লোডশেডিং হলো। আমি ফোনের ফ্লাশ অন করলাম, কিন্তু পরক্ষণেই ফোনের ফ্লাশটা নিজেই অফ ও অন হতে লাগলো। রাগে ফোনটা আছাড় দিয়ে রুম থেকে বের হবো ভাবতেই দেখি রুমের দরজা বাইরে থেকে বন্ধ। অনেকক্ষণ দরজা ধাক্কালাম, কিন্তু খুললো না। হঠাৎ করে রুমের লাইট জ্বলে উঠলো। লাইটের আলোতে খেয়াল করলাম সেই মেয়েটিকে,  সে আমার পিছনে দাঁড়িয়ে আছে। আমি পিছন ফিরে তাকাতেই রুমের লাইট আবার নিজে নিজে জ্বলছে আর নিভছে। এবার ভয়ে আমার শ্বাস ভারি হয়ে গেলো। হঠাৎ করে মেয়েটি আমার সামনে থেকে উধাও হয়ে গেলো। কিছুক্ষণ পর মেয়েটি আমার পিছনে এসে কাঁধে হাত দিলো। পিছনে তাকিয়ে দেখি, সুকৌশলে সুন্দর মেয়েটির চেহারা বিভৎস হয়ে পচে গলতে শুরু করছে। এই দৃশ্য দেখে আমি ভয় পেয়ে চিৎকার দিয়ে অজ্ঞান হয়ে যাই।\nজ্ঞান ফিরলো রনির কলের শব্দে। মাথা তুলে দেখি আমি নিচে পড়ে আছি, এবং আমার ফোনটা এক পাশে। ফোনটা হাতে নিয়েই দেখি রনি প্রায় ৩৩ টা কল করেছে। রাত প্রায় ০৩:১৭। আমি কল ব্যাক করতেই রনি ভয় ও আতঙ্কের সাথে বললো, \"এতক্ষণে তোর কল ব্যাক করার সময় হলো?\" আমি বললাম, \"কেনো রেহ! কি হয়েছে? তোর ভয়েস এমন লাগছে কেনো?\" রনি আতঙ্কিতভাবে বললো, \"ভাই! তৌহিদ আর আব্রাহাম বেঁচে নেই! তুই যত তাড়াতাড়ি সম্ভব আমাকে এখান থেকে নিয়ে যা।\" আমি তড়িঘড়ি জিজ্ঞেস করলাম, \"কি! কি বলছিস এগুলা? কি হয়েছে ওদের? আর তুই কোথায় আছিস এখন?\" রনি বললো, \"আমি এখন পাহাড়িতলা গ্রামে আছি, প্লিজ আমাকে এখান থেকে নিয়ে যাহ!\" আমি বিস্ময়দীপ্ত হয়ে বললাম, \"তোরা এখনো ওই গ্রাম থেকে আসিসনি?\" রনি বললো, \"আর আসবো কি জানি না! সে আসতে দিবে নাহ!\" আমি জিজ্ঞেস করলাম, \"মানে! সে কে? কার কথা বলছিস তুই?\" রনি বললো, \"এতকিছু বলার সময় নেই। তুই প্লিজ তাড়াতাড়ি আয়!\" রনির কথা শুনে দ্রুত পাহাড়িতলা গ্রামের উদ্দেশ্যে বের হলাম। বাইরে বের হতে গিয়ে দেখলাম আমাদের উঠোনের এক পাশে থাকা তেঁতুল গাছের পাশে সেই মেয়েটি মাটি খুঁড়ছে এবং আমার দিকে তাকিয়ে বিভৎসভাবে হাসছে। আমি কিছু বুঝতে না পেরে জ্ঞান হারালাম।\nজ্ঞান ফিরতেই দেখি আমি আমার রুমেই আছি। প্রথমে বাড়ির বর্ণনা দিতে হয়। সদর দরজা দিয়ে ঢুকতেই বিশাল ড্রইংরুম। ড্রইংরুমের ডান পাশে ফ্যামিলির জন্য একটি বাড়তি ওয়াশরুম। প্রত্যেক রুমেই এটাস্ট ওয়াশরুম আছে। বাম পাশে কিচেন। সদর দরজা দিয়ে নাক বরাবর দুই দিকেই দুইটা সিড়ি, সিড়ি বেয়ে উপরে উঠলে ৪টা বেডরুম - একটির মালিক আমি, অন্যটি আম্মু-আব্বুর এবং দুটো গেস্টরুম।\nমূল গল্পে আসি... দিন শেষ হয়ে সন্ধ্যা নামলে বাইরে ঘুটঘুটে অন্ধকার আর প্রচুর বৃষ্টি। ফোন টিপতে টিপতে দোতলা থেকে ড্রইংরুমে এসে পা রাখতে গেলাম, ঠিক তখনই কারেন্ট চলে গেলো। সৌরবিদ্যুতের আলোয় সোফায় বসে বসে ফোন টিপছি। হঠাৎ বৃষ্টির মধ্যে দরজায় নক, কেউ চিৎকার করে বলছে, \"আরিয়ান, দরজা খোল, আমি তোর আম্মু।\" আমি দরজা খুলতে যাবো, ঠিক ওই মুহূর্তে দোতলা থেকে আম্মুর ডাক, \"যাস না, শব্দটা আমিও শুনেছি।\" আমি অবাক দৃষ্টিতে দোতলায় আম্মুর দিকে যাবো, ঠিক তখনই ড্রইংরুমের ডান পাশ অর্থাৎ ওয়াশরুমের ভিতর থেকে আম্মু চিৎকার করছে, \"আরিয়ান, আমি ওয়াশরুমে আটকে গেছি, দরজা খোল!\" আমি হতভম্ব হয়ে আতঙ্কের সাথে ওয়াশরুমের সামনে যাচ্ছি। ভাবছি, আম্মু নিজেদের ওয়াশরুম রেখে নিচতলার ওয়াশরুমে কি করছে? ওয়াশরুমের দরজাটা খুলবো, হাত বাড়াচ্ছি, ঠিক ওই মুহূর্তে কিচেন থেকে আম্মু আমাকে ডাকছে। আমি প্রায় পাগল হয়ে যাচ্ছি, কি হচ্ছে আমার সাথে? আমি কোথায় যাবো, কিছুই বুঝে উঠতে পারছি না। তাড়াহুড়ো করে কিচেনের সামনে গিয়ে দেখি আম্মু এক গ্লাস দুধ চামচ দিয়ে নাড়ছে। আমি অবাক হয়ে ভাবছি, আমি তো দুধ খাই না, তাহলে আম্মু কার জন্য দুধ ঠান্ডা করছে? আমি সামনে এগোতেই দেখি, আম্মু আলতো করে আমার দিকে তাকালো। আম্মুকে দেখে আমি শিউরে উঠলাম। এটা কে? এটা আমার আম্মু হতে পারে না, তাহলে কে এই?  আম্মুর চোখগুলো একদম কালো, মুখের রঙ ফ্যাকাসে। আমার দিকে তাকিয়ে বিদঘুটে হাসি দিতেই আমি এক চিৎকার দিলাম। চিৎকার দিয়ে ওঠার পর আম্মু বললো, \"কি হয়েছিলো তোর? সেই ভোর বেলা তোকে বাইরে অজ্ঞান অবস্থায় পেয়েছি। বাইরেই বা কেনো গিয়েছিলি? সারাদিন গেলো জ্ঞান ফিরেনি, এখন আবার চিৎকার দিয়ে উঠলি?\" আমি ফেলফেল করে আম্মুর দিকে তাকিয়ে রইলাম আর ভাবলাম, তারমানে এতক্ষণ আমি অন্য জগতে ছিলাম। তখনই আমার রনির কথা মনে পড়লো। তাড়াতাড়ি করে পাহাড়িতলা গ্রামের উদ্দেশ্যে বেরিয়ে পড়লাম। আম্মু পিছন পিছন ডাকলো, কিন্তু আমি কোনো সাড়া দিলাম না। পথ চলতে চলতে রনিকে অনেক কল দিলাম, কিন্তু কেউ কল ধরছে না। হঠাৎ রাস্তার মাঝে এক পাগল মহিলা আমার গাড়ি আটকে দাঁড়ালো। আমি গাড়ির কাঁচ তুলতেই মহিলাটি বললো, \"কোত্থাও যাসনে? নিজের বিপদ নিজেই ডেকে আনছিস! ফিরে যা বলছি!\" আমি তার কথার তোয়াক্কা না করেই গাড়ি চালিয়ে চলতে লাগলাম। অবশেষে আড়াই ঘন্টা পর গ্রামে এসে পৌঁছলাম। \nসারা গ্রাম খুঁজেও রনিকে পেলাম না। তখনই আমার মাথার টনক নড়ে উঠলো, রনি হয়তো সেই নিষিদ্ধ স্থানে আছে। কারণ সেদিন যখন আমি আর আব্রাহাম নিষিদ্ধ স্থান নিয়ে কথা বলছিলাম, তখন কেউ লুকিয়ে আমাদের কথা শুনছিলো। তাই বুঝতে পারলাম, ওই দিন তৌহিদ অথবা রনির মধ্যে কেউ একজন আমাদের কথা শুনছিলো। তাড়াতাড়ি গিয়ে পৌঁছালাম সেই নিষিদ্ধ স্থানে। গিয়ে দেখি তৌহিদ এবং আব্রাহামের মাথা বিহীন লাশ দুটি দুই দিকে পড়ে আছে। তাদের এই করুণ দৃশ্য দেখে আমি অজান্তেই কান্না করে উঠলাম। ছুটে গিয়ে তাদের পাশে বসলাম কিছুক্ষণ নির্বাক হয়ে তাদের দেখলাম। তারপর উঠে দাঁড়িয়ে খেয়াল করলাম গাছের ডালে সেই মাটির পাত্রটাও ভাঙ্গা, গাছের শরীরে বাঁধা সুতা আর তাবিজগুলোও নষ্ট হয়ে পড়ে আছে। গাছটার কাছ থেকে বেশ কিছুটা দূরে রনি অজ্ঞান হয়ে পড়ে আছে। তার এক পাশে ফোনটাও পড়ে আছে। ছুটে গিয়ে পাশে দাঁড়ালাম, এরপর ওকে তুলে গ্রামের বাড়ি নিয়ে গেলাম। আমাদের দেখে রফিক দাদু ছুটে এসে বললেন, \"এ-কি দাদুভাই, তোমরা গেলে না? রনি দাদু ভায়ের কি হয়েছে?\" আমি চুপ করে রইলাম। রফিক দাদুর সাথে কথা বলার সাহস পেলাম না। পাবোই বা কি করে? তাকে কি বলবো? তার প্রাণপ্রিয় নাতি আমাদের জন্য মারা গেছে এটাই? রফিক দাদুকে এড়িয়ে রনিকে নিয়ে রুমে চলে গেলাম। রফিক দাদুও চুপ করে আমাদের দিকে তাকিয়ে রইলো। বুঝতে পারলাম, আমার ব্যবহার দেখে তিনি কষ্ট পেয়েছেন। কিন্তু কি করবো? আসল সত্যিটা জানতে পারলে তিনি আরো বেশি কষ্ট পাবেন। রুমে গিয়ে রনিকে শুইয়ে দিলাম। কিছুক্ষণ পর রনির জ্ঞান ফিরলো। জ্ঞান ফিরে রনি যা বললো, তাতে আমি প্রায় শিহরিত হয়ে উঠলাম।"},{"id":"1773089848003-4","title":"04","slug":"part-04","content":"রুমে গিয়ে রনিকে শুইয়ে দেওয়ার পর কিছুক্ষণ পর তার জ্ঞান ফিরলো। সে ফেলফেল করে আমার দিকে তাকিয়ে আছে, কিন্তু কিছুই বলছে না। আমি তার এই অবস্থায় গভীরভাবে চিন্তিত হয়ে পড়লাম। ঠিক তখনই আমার ফোনে রিশার কল এলো। আমি কলটি রিসিভ না করে রনির কাছে গিয়ে বসে তাকে জিজ্ঞেস করলাম, “কি হয়েছে? ওদের এই হাল কে করেছে?” রনি তখন আমাকে জড়িয়ে ধরে কাঁদতে কাঁদতে বললো, “তৌহিদকে অনেকবার বারন করেছিলাম, কিন্তু সে শুনলো না আমার কথা।” আমি কৌতূহল নিয়ে জিজ্ঞেস করলাম, “কি করতে বারন করেছিলি? আর কি করেছে ওরা? একদম প্রথম থেকে বল।” রনি কিছুটা স্থির হয়ে আমার দিকে তাকালো এবং বললো, “ঠিক আছে, তাহলে শোন! ওইদিন যখন তুমি আর আব্রাহাম নিষিদ্ধ স্থান নিয়ে কথা বলছিলি, তখন আড়াল থেকে তৌহিদ সবটা শুনছিলো। ওর মনে হয়, ওই নিষিদ্ধ স্থানে হয়তো কোনো মানুষ রয়েছে, যে সবাইকে ভয় দেখায়। তার মনে হয়েছিলো যদি সেখানে ডাকাত দল থাকে, তাহলে নিশ্চয়ই সেখানে অনেক ধনসম্পত্তি রয়েছে। এই এমন একটি লোভ তার মনে ধরেছিলো। তৌহিদ আমাকে ও আব্রাহামকেও লোভ দেখিয়েছিলো, আর আমরাও তার লোভে পড়ে যাই।”।আমি স্মৃতি মনে করার চেষ্টা করলাম, “হ্যাঁ, তারপর? তোরা কালকে আমাদের সাথে না ফিরে গিয়ে সেখানে কি করেছিলি?” রনি বললো, “কালকে তোরা বের হওয়ার কিছুক্ষণ পরে আমরা সেই নিষিদ্ধ স্থানে পৌঁছাই,” রনি বললো। ঠিক সেই মুহূর্তে রিশা আবারও কল করে। আমি রনিকে থামিয়ে রিশার কল রিসিভ করলাম। রিশা জিজ্ঞেস করলো, “তুমি আবারও পাহাড়িতলা গ্রামে এসেছো?” আমি কিছুটা দ্বিধাগ্রস্ত হয়ে বললাম, “ইয়ে মানে, হ্যাঁ এসেছি।” সে বললো, “আমিও আসছি, ওয়েট করো, কিছুক্ষণের মধ্যেই পৌঁছে যাবো।” কিন্তু কথাগুলি শেষ হতেই সাইড থেকে একটি ট্রাক এসে রিশার গাড়িকে ধাক্কা দিলো। ফোনের এপাশ থেকে আমি গাড়িতে ধাক্কার শব্দ শুনতে পেলাম। আমি অবাক হয়ে গেলাম। রনি আমাকে জোরে জোরে ধাক্কা দিয়ে প্রশ্ন করতে লাগলো, “কি হয়েছে?” কিন্তু আমি যেনো ভেঙে পড়েছি। আমার চোখের সামনে আমার প্রিয় বন্ধু আর অতিথি বন্ধুর মাথাবিহীন লাশ ভেসে উঠলো, আবার আমার প্রিয় মানুষকে হারানোর ভয়ে আমার মন স্তব্ধ হয়ে গেলো।\nআমি নিচে নেমে সদর দরজা খুলতেই দেখি রিশার পুরো শরীরে আঘাতের চিহ্ন। সে খুঁড়িয়ে খুঁড়িয়ে খান ভিলার দিকে এগিয়ে আসছে। আমি তখন অতিরিক্ত মনোযোগে দৌড়ে গিয়ে রিশাকে জড়িয়ে ধরলাম এবং বললাম, “তুমি ঠিক আছো তো? জানো, আমি খুব ভয় পেয়ে গেছিলাম! আমি ভেবেছিলাম তোমাকে হয়তো হারিয়ে ফেলেছি।” রিশা উত্তর দিলো, “হ্যাঁ, আমি ঠিক আছি। গাড়িটা মাঝ রাস্তায় পার্ক করে রেখেছিলাম। দরজা খোলা ছিলো, তোমার সাথে কথা বলতে বলতে গাড়ি থেকে বের হওয়ার চেষ্টা করছিলাম, তখনই ট্রাক এসে ধাক্কা দিলো।” শুনে আমি এক মুহূর্তের জন্য মনে করলাম, আমি তাকে আর ফিরে পাবো না।\nকথাগুলি শেষ করে আমরা তিনজন আবার ভিতরে চলে গেলাম। আমি রিশাকে তৌহিদ এবং আব্রাহামের সমস্ত কাহিনী খুলে বললাম, কিন্তু গতকাল রাত থেকে আমার সাথে কি ঘটেছে তা তার কাছে গোপন রাখলাম। রিশা জিজ্ঞেস করলো, “রনি, সত্যি করে বল, তোরা কালকে ওখানে কি করেছিলি?” আমি সাথে যোগ দিলাম, “হ্যাঁ, রনি ভাই, প্লিজ সত্যি করে বল কি হয়েছিলো।” রনি কিছুটা দম নিয়ে বললো, “কালকে তোরা বের হওয়ার কিছুক্ষণ পরে আমরা সেই নিষিদ্ধ স্থানে গিয়েছিলাম। তারপর...” বলেই সে আবার চুপ হয়ে গেলো। আমি অসহিষ্ণু হয়ে বললাম, “কি হলো? চুপ করে গেলি কেনো? বল।” রনি বললো, “আমি সেই কালো সময়টাকে আর মনে করতে চাইছি না।” তার চোখে পানি এসে গেলো। রিশা বললো, “দেখ, এভাবে চুপ করে থাকলে কোনোকিছুই সমাধান হবে না!” রনির কণ্ঠে ভয়ের ছাপ স্পষ্ট, “তারপর আমরা সেখানে গেলাম। যাওয়ার পরই তৌহিদ তার হাতে থাকা বড় দা দিয়ে গাছে পেঁচানো সুতা আর তাবিজগুলোকে নষ্ট করলো। আমি আর আব্রাহাম অনেকবার নিষেধ করেছিলাম, কিন্তু তৌহিদ আমাদের কথা শোনেনি। সবশেষে তৌহিদ আব্রাহামকে বললো যে ওই মাটির পাত্রটাতে একটা ইট ছুঁড়তে হবে, হয়তো ভিতরে কিছু আছে। আব্রাহামও তৌহিদের কথা মতো একটি বড় ইটের টুকরা ছুঁড়ে মারলো। মুহূর্তেই চারপাশে বড় বড় তেলাপোকা এসে ভরে গেলো। কিছুক্ষণ পর এসব তেলাপোকা একত্র হয়ে একটি মেয়ের অবয়বে রূপ নিলো।” রিশা বিস্মিত হয়ে জিজ্ঞেস করলো, “এটাও সম্ভব? আচ্ছা তারপর কি হলো?” \nরনি কাঁদতে কাঁদতে বললো, “তারপর সেই মেয়েটি হাওয়ার বেগে আব্রাহামের কাছে গিয়েছিলো এবং মাথা টেনে ছিঁড়ে ফেললো। এসব দেখে আমি ও তৌহিদ তাড়াতাড়ি পালানোর চেষ্টা করলে সেই ডাইনী তৌহিদের মাথাও টেনে ছিঁড়ে ফেললো। ভাগ্য ভালো, আমি বেঁচে ফিরেছি।” হঠাৎ করে রফিক দাদু দরজার আড়াল থেকে বেরিয়ে এসে বললেন, “আমার নাতিটা আর বেঁচে নেই?” আমরা সবাই চুপ করে রইলাম। কি জবাব দেবো তাকে? "},{"id":"1773089864364-5","title":"05","slug":"part-05","content":"আমরা লজ্জা ও অপমানবোধে চুপ করে রইলাম। \nরফিক দাদু:- আমি আগেই জানতাম এমন কিছু একটা হবে। \nরিশা:- আগেই জানতেন মানে.?\nরফিক দাদু:- যেদিন আরিয়ান দাদুভাই প্রথম এই গ্রামে পা রেখেছিলো সেদিনই বুঝেছিলাম পিছনে ফেলে আসা অতীত এবার নতুন করে শুরু হওয়ার সময় এসেছে।\nআমি:- মানে.? পিছনে ফেলে আসা অতীত বলতে কিসের কথা বললে..? \nরফিক দাদু:- সময় হোক সব জানতে পারবে.!\nএই বলে রফিক দাদু চলে গেলো।\nঅনেক রাত হয়েছে বিধায় আমরাও ঘুমতে চলে গেলাম।\nযে যার মতো করে ঘুমচ্ছে হঠাৎ আমি দেখলাম সেই নীল নয়না মেয়েটি পায়ে ঘুঙুর পরে আমার রুম থেকে বেরিয়ে গেলো আমিও তার পিছু পিছু বের হয়ে গেলাম।\nমেয়েটি একটা বন্ধ ঘরে গিয়ে প্রবেশ করলো আমিও ওর পিছু পিছু বন্ধ ঘরে ঢুকতেই দেখি সামনে দেওয়ালে আমার একটা বড় পেইন্টিং কিন্তু আশ্চর্য করা বিষয় পেইন্টিং এর আমিটা জমিদারের পোশাক পড়া ছিলো। পাশেই আরেকটা পেইন্টিং রাখা আছে ওইটা ধুলোবালি দিয়ে একদম মাখামাখি শুধু বুঝা যাচ্ছে পেইন্টিং-এ দুটো চোখ। \nচোখ দুটো আমি এর আগেও দেখেছি, হ্যাঁ এই চোখ দুটো আমি চিনি.! এগুলো সেই নীল নয়না মেয়েটির চোখ। \nহঠাৎ করেই কেউ আমার কাঁধে হাত দিতেই আমি চিৎকার দিয়ে উঠলাম...\nরফিক দাদু:- আমি.! আমি দাদুভাই.! \nআমি:- ওহ্.! আপনি।\nরফিক দাদু:- অবশেষে তুমি তোমার অতীতের বাহুডোরে পৌঁছে গেছো.?\nআমি:- মানে.? আর এই পেইন্টিং-এ আমার মতো দেখতে এই লোকটা কে.?\nরফিক দাদু:- এটা তোমার পরদাদার বড় ভাই \"কেনান\" তুমি দেখতে অবিকল তার প্রতিচ্ছবি।  এজন্যই তোমার পিতা-মাতা তোমাকে গ্রামে নিয়ে আসতে ভয় পেতো।  কারণ তারা জানতো, তুমি গ্রামে আসলে অতীতে ঘটে যাওয়া কাহিনি নতুন করে শুরু হবে।\nআমি রফিক দাদুর কথার আগামাথা কিছুই বুঝতে পারছিলাম নাহ। তারপর রফিক দাদুর কাছে \"কেনান\" দাদুর কাহিনি জিজ্ঞেস করলে সে বললো...\nরফিক দাদু:- ধৈর্য ধরো দাদুভাই,  এই কাহিনি তুমি নিজেই জানতে পারবে কারণ এই কাহিনি তখনও শেষ হয়নি আর এতদিনেও শেষ হয়নি।\nএই বলে রফিক দাদু চলে গেলো, আমি হাত দিয়ে আমার মতো দেখতে কেনান দাদুর পেইন্টিং এর পাশে থাকা দ্বিতীয় পেইন্টিং''টি পরিষ্কার করলাম। পরিষ্কার করে পেইন্টিং''টা যেরূপ দেখলাম, কেনান দাদু একটা চেয়ারে বসে আছে আর তার পাশে সেই নীল নয়না মেয়েটি দাঁড়িয়ে আছে। \nতখন বুঝতে পারলাম,  হয়তো এই মেয়েটি আমাকে কেনান দাদু ভেবে হন্ট করছে কারণ আমি দেখতে হুবহু কেনান দাদুর মতোই।\nঅনেক চিন্তা করে রুমে গিয়ে খাটে বসলাম ফোন হাতে নিয়ে দেখি রাত প্রায় ২টার কাছাকাছি। \nতখন রিশা আমার কাছে এসে জিজ্ঞেস করে...\nরিশা:- কি হয়েছে.? \nআমি রিশার কাছে গতকাল রাত থেকে আমার সাথে কি কি ঘটে চলেছে সবটা বললাম এবং এখন আমার মতো দেখতে কেনান দাদুর কথাও খুলে বললাম। \nরিশা আমাকে অভয় দিয়ে পাশে শুয়ে পড়লো।\nযেহেতু আমরা অ্যাঙ্গেজড ছিলাম তাই এক রুমে থাকতে আমাদের কোনো অসুবিধা ছিলো নাহ।\nআমিও সব চিন্তা মাথা থেকে ঝেড়ে ফেলে একটা ঘুম দিলাম ঘুম থেকে উঠে দেখি আব্বু আম্মু পাহাড়িতলা গ্রামে এসে হাজির। \nআব্বু আমাকে ডাক দিয়ে একান্ত কিছু কথা বললো যা শুনে আমি থমকে গেলাম....\nআব্বু:- কালকে তুই যখন তোর আম্মুকে কিছু নাহ বলে চলে এলি তখন তোর আম্মু আমাকে কল দেয়, আমি তাড়াতাড়ি করে বাসায় গিয়ে তোর আম্মুকে শান্তনা দি। তারপর আমি রুমে বসে ল্যাপটপে কাজ করছিলাম কিছুক্ষণ পর তোর আম্মু আমাকে নাস্তা দিয়ে গেলো আমিও কাজ করতে করতে নাস্তা খেতে শুরু করি ৫ মিনিট পর আবার তোর আম্মু নাস্তা নিয়ে এসে আমাকে দেখে একটা চিৎকার দিয়ে বললো....\nতোর আম্মু:- তুমি এগুলো কি খাচ্ছো..?\nআমি:- তুমি নাহ নাস্তা দিয়ে গেলে.? আমি তোহ নাস্তা খাচ্ছি.!\nতোর আম্মু:- তুমি ভালো করে দেখো তুমি কি খাচ্ছো.?  আর আমি তোহ এইমাত্র এলাম তোমাকে কখন নাস্তা দিলাম আমি.?\nআমি তাকিয়ে দেখি প্লেটে মুরগির নাড়িভুড়ি আর পোকামাকড় আর ওইগুলো আমি খাচ্ছি।\nচোখ তুলে তাকাতেই দেখি তোর আম্মুর মতো দেখতে একজন মহিলা তোর আম্মুরই পিছনে দাঁড়িয়ে হাসছে.!\nআমি তোর আম্মুকে কিছুটা অভয় দিয়ে রিশাকে কল দিয়ে জানতে পারি রিশাও নাকী পাহাড়িতলা গ্রামে এসেছে কিন্তু সে''ও নাকী আসার পথে এক্সিডেন্টের মুখোমুখি হয়েছিলো কিন্তু আল্লাহর অশেষ কৃপায় সে সুরক্ষিত আছে তারপর এখানে এসে তৌহিদ আর আব্রাহামের ঘটনাও শুনলাম। \nআমি:- আচ্ছা আব্বু কেনান দাদুর কি হয়েছিলো..?\nআব্বু আমার মুখে এই প্রশ্ন শুনে চুপ হয়ে গেলো কিছুক্ষণ চুপ থেকে বললো...\nআব্বু:- এই দেখো তোর আম্মু আমাকে সেই কখন ডেকেছিলো আমাকে, আমি গেলাম কেমন..?\nএই বলে আব্বু চলে গেলো....\nকিছুক্ষণ পর রিশা আমার কাছে এসে বললো...\nরিশা:- একটা কথা বলবো...?\nআমি:- হ্যাঁ বলো.!\nরিশা:- আমার নাহ রনির কথাগুলো বিশ্বাস হচ্ছে নাহ.!\nআমি:- কি বলছো.?\nরিশা:- হ্যাঁ, আমার হচ্ছে রনি আমাদের কাছে মিথ্যা বলছে..\nআমি:- রনি যদি মিথ্যা বলতো তাহলে আমাদের সাথে যে ঘটনাগুলো ঘটছে, তৌহিদ আর আব্রাহামের লাশ আর কেনান দাদুর ছবি, কেনান দাদুর ছবির পাশে সেই মেয়েটি এগুলো কি সবটাই মিথ্যা..! \nরিশা:- কি জানি, এতকিছু বুঝি নাহ আমার মনে হচ্ছে রনি আমাদের মিথ্যা বলছে। মনে রেখে যেটা চোখের সামনে হচ্ছে সেটা সত্যি নাও হতে পারে চোখের আড়ালে যেটা হচ্ছে সেটাই সত্যি। \nএই বলে রিশা চলে গেলো। "},{"id":"1773089882096-6","title":"06","slug":"part-06","content":"রিশা চলে যাওয়ার কিছুক্ষণ পর আমি আবারও সেই রুমটিতে গেলাম যেখানে কেনান দাদুর পেইন্টিং ছিলো। \nরুমটিতে কিছুক্ষণ ঘুরাঘুরি করার পর আমি একটা ভিশন দেখতে পেলাম, ভিশনটা কিছুটা এইরকম ছিলো...\nএই বন্ধ ঘরটি কত সুন্দর করে সাজানো হয়েছে, আমি বিয়ের সাজে এই ঘরের খাটে বসে আছি  পাশে সেই নীল নয়না মেয়েটিও  হঠাৎ করে একটা কালো বিড়াল এসে আমার উপরে পড়লো এবং সাথে সাথে ভিশনটা ওইখানেই মিলিয়ে যায়। তারপর আমি কেনান দাদু আর সেই নীল নয়না মেয়েটির পেইন্টিং এর পাশে গেলাম, আমার মনে হচ্ছে মেয়েটি সত্যি সত্যি আমার দিকে তাকিয়ে আছে আমিও কিছুক্ষণ মেয়েটির দিকে তাকিয়ে রইলাম একটু পর মনে হলো মেয়েটির পেইন্টিং এর ভিতরে চোখের পলক ফেললো এটা দেখে আমি ভয়ে গেয়ে তাড়াতাড়ি ওই রুম থেকে বেরিয়ে গেলাম।\nসকালে নাস্তা করলাম, নাস্তা শেষে রিশা বলছে ওকে গ্রাম ঘুরে দেখানোর জন্য আমিও নাহ করলাম নাহ, বেরিয়ে পড়লাম ওকে গ্রাম ঘুরে দেখানোর জন্য। \nআমরা অনেকক্ষণ গ্রাম ঘুরলাম, গ্রাম ঘুরতে ঘুরতে সময় প্রায় দুপুর গড়িয়ে বিকেল হবে হবে তখন ইচ্ছে হলো একটিবার ঝর্ণার ধারে গেলে কেমন হয়...\nযেই ভাবা সেই কাজ রিশাকে নিয়ে ঝর্ণার ধারে চলে এলাম।\nরিশা আর আমি একটা পাথরের উপর বসলাম কিছুক্ষণ পর আমি আবারও একটা ভিশন দেখতে পাই...\nআমি আর সেই নীল নয়না মেয়েটি একটা নৌকায় বসে আছি, নৌকার এক কোণে আমি আর আমার থেকে কিছুটা দূরে সেই মেয়েটি, ঝর্ণা থেকে যে ধারা নামছে সেই পানি হাতে নিয়ে মেয়েটি আমার দিকে ছুড়ে মারছে আমিও ওর দিকে পানি ছেড়ে মারছি, দেখে মনে হচ্ছে আমরা একে অপরকে অনেকদিন ধরে চিনি আমরা একে অপরেকে অনেক ভালোবাসি হঠাৎ দেখলাম মেয়েটি সেই বিভৎস চেহারায় আমার দিকে তাকিয়ে হাসছে আমি ভয়ে চিৎকার দিয়ে স্বজ্ঞানে ফিরে দেখি রিশা আমাকে পানি ছুড়ে মেরেছে যার ফলে আমি ভিশন থেকে বাস্তব জগতে ফিরে আসি।\nবুঝতে পারছিলাম নাহ তখনও আমার সাথেই কেনো বার বার এমন হচ্ছে। নিজের পরদাদা''দের মতো দেখতে হওয়াটা কি অপরাধ..? \nসন্ধ্যা হওয়ার আগেই আমরা বাসায় ফিরে আসি। \nবাসায় আসার পর আম্মু আমাকে ডাক দিয়ে বললো...\nআম্মু:- আরিয়ান তোর কাছে একটা কথা বলছি মনযোগ দিয়ে শোন...\nআমি:- হ্যাঁ, আম্মু বলো...\nআম্মু:- এখান থেকে যাওয়ার পর থেকে আমাদের সাথে অদ্ভুত অদ্ভুত ঘটনা ধটছে আজকে কিছুক্ষণ আগেও আমার সাথে একটা অদ্ভুত ঘটনা ঘটলো, আমি চাই নাহ তোর আর রিশার কোনো প্রকার ক্ষতি হোক তাই জন্য তুই আর রিশা যত তাড়াতাড়ি সম্ভব বিয়ে করে ফেল..!\nআমি:- হ্যাঁ তা তোহ করবোই কিন্তু কি হয়েছিলো আজকে.?\nআম্মু:- আমি রান্নাঘরে রান্না করতে গিয়েছিলাম হঠাৎ দেখি আমার মতো কেউ নাহ আমার মতো কেউ নাহ আমি নিজেই কাঁচা মাংস চিবিয়ে চিবিয়ে খাচ্ছি, মাংস খেতে খেতে এতটাই নেশাগ্রস্ত হয়ে গেছি যে নিজেই নিজের শরীর থেকে মাংস কেটে কেটে খাচ্ছি তারপর তোর আব্বু আমাকে পিছন থেকে কাঁধে হাত দিতেই আমার হুশ ফিরলো তারপর বুঝলাম আমি এতক্ষণ জেগে জেগে দুঃস্বপ্ন দেখেছি। \nরান্না শেষ করে গোসল করে নিজের রুমে এসে ড্রেসিং টেবিলের সামনে গিয়ে দাঁড়াতেই দেখি আমি নিজের হাতে নিজের মুখের চামড়া ছিঁড়ছি এটা দেখে ভয়ে একটা চিৎকার দিতেই তোর আব্বু এসে আমাকে জড়িয়ে ধরে অভয় দিয়ে বললো এটা নাকী আমার মনের ভুল। \nআম্মুর মুখে এসব শুনে আমিও আম্মুকে কিছুটা অভয় দিয়ে বললাম...\nআমি:- অনেকক্ষণ তোহ হলো গ্রাম ঘুরে এলাম, চলো এবার খেতে যাই।\nতারপর ডাইনিং-এ গিয়ে সবার সাথে রাতের খাবার শেষ করে যে যার রুমে চলে গেলাম ঘুমনোর জন্য, আজকে রুমমেট চেঞ্জ হয়ে গেলো, আমি, আব্বু আর রনি এক রুমে থাকবো আম্মু আর রিশা পাশের রুমে থাকবে। \nযথারীতি আমরা আমাদের যে যার রুমে চলে গেলাম। \nআমরা আমাদের রুমে শুয়ে আছি, আমিও প্রায় বেঘোর ঘুমে, হঠাৎ অনুভব হলো কেউ যেনো আমার মাথায় হাত বুলিয়ে দিচ্ছে, চোখ খুলে দেখি কেউ নেই হঠাৎ.... \nসেই ছবির ঘর থেকে কান্নার শব্দ ভেসে আসছে আমি ছুটে সেই ঘরের দরজার সামনে হাজির হলাম। দরজাটা একটু ফাঁক করে ভিতরে তাকাতেই ভিতর থেকে একটা কালো অবয়ব আমি দিকে ছুটে এলো আমি ভয়ে পিছিয়ে গেলাম। \nপিছিয়ে গিয়ে দেখি আমি বন্ধ চার দেওয়ালের ভিতর আটকে আছে চারিদিকে শুধু কাঠের দেওয়াল। \nহঠাৎ করে পুরো ঘরটি কালো কাক দিয়ে ভরে গেলো, কালগুলো আমাকে ঘিরে ধরেছে, কা কা শব্দে পুরো ঘরটি মেতে উঠেছে আমি কিছু বুঝতে নাহ পেরে চিৎকার দিতেই আমার ঘুম ভেঙ্গে গেলো। \nতার মানে এতক্ষণ আমি স্বপ্ন দেখছিলাম,  ঘুম ভাঙ্গতেই দেখি রনি পাশে নেই, রনিকে খুঁজতে খুঁজতে সেই ছবির ঘরের সামনে গিয়ে থামলাম, ভিতরে উঁকি দিতেই দেখি রনি কালোজাদু করছে ওর বিপরীত পাশে অন্ধকারে কেউ একজন বসে আছে রনি সেই অন্ধকারে বসে থাকা লোকটির সাথে কথা বলছে, আমি হাল্কা উকি দিয়ে কথাগুলো শোনার চেষ্টা করলাম...\nরনি:- ভুলে যেওনা তোমার আর আমার জন্ম জন্মান্তরের সম্পর্ক,  তোমাকে আমিই মুক্তি করেছি।\nতোমার জন্য তৌহিদ আর আব্রাহামকেও বলি দিয়েছি শুধুমাত্র তোমাকে মুক্তি দিয়ে আমাদের ভালোবাসাকে পূর্ণরূপ দেওয়ার জন্য। \nএবার তোমার কাজ হলো, রিশার শরীরকে কাবু করা, তুমি রিশার শরীর কাবু করতে পারলেই আমি আরিয়ানকে বলি দিয়ে ওর রক্ত দিয়ে তোমাকে গোসল করাবো তাহলে তুমি সারাজীবনের জন্য রিশার শরীরে থাকতে পারবে।\nতুমি সারাজীবনের জন্য রিশার শরীরে থাকতে পারলেই আমরা আবার নতুন করে আমাদের জীবন শুরু করবো তারপর আমরা অনেক দূরে চলে যাবো যেখানে কেউ আমাদের খুঁজে পাবে নাহ।\nতার মানে রিশা ঠিকই বলেছিলো, রনি আমাদের মিথ্যা বলেছে, তৌহিদ আর আব্রাহামকে তাহলে রনিই খুন করেছে...?\nকিন্তু রনি কেনো এমনটা করলো আর কার জন্যই এমনটা করলো..? \nএখন কার সাথে কথা বলছে রনি..? \nকার সাথে কথা বলছে দেখার জন্য ভিতরে একটু ভালো মতো উঁকি দিতেই দেখি রনির অপর প্রান্তে রিশা বসে আছে...\nআমি প্রথম ভেবেছিলাম হয়তো রিশাও রনির সাথে মিলিত, সেও আমাকে ঠকাচ্ছে, কিন্তু নাহ..? এটা তোহ রিশা নাহ..! তাহলে কে ও...? এই রিশার চোখগুলো সম্পূর্ণ সাদা চেহারার রঙ ফেকাসে। \nহঠাৎ করে রনি বলে উঠলো...\nরনি:- \"হানা রাণী\" এবার নিজের আসল রূপে আসো.!  যেদিন রিশার শরীর নিজের বশে আনতে পারবে সেদিন নাহয় রিশা হয়ে থেকো.?\nরনি এই কথা বলার সাথে সাথে রিশার রূপ ধারণ করা মেয়ে সেই নীল নয়না মেয়েটিতে পরিনত হলো..!\nতার মানে এই নীল নয়না মেয়েটির নাম \"হানা\"। \nওর সাথে রনির কি সম্পর্ক.?  \nওর সাথে যদি রনির সম্পর্ক থেকে থাকে তাহলে ওর ছবি কেনান দাদুর পাশে কেনো..?\nওর সাথে যদি কেনান দাদুরও কোনো সম্পর্ক নাহ থাকে তাহলে আমার আর আমার পরিবারের পিছনে কেনো পড়ে আছে.?\nএটার একমাত্র কারণ কি শুধু রনির সাথে ওর প্রেম কাহিনী সম্পূর্ণ করা, তার জন্যই এতকিছু..?\nআমি কিছু বুঝে উঠার আগেই রনি আর হানা আমাকে দেখে ফেলে আমি ওদের কাছ থেকে পালানোর জন্য একটা দৌড় দিলাম....\n\n[গল্পে বিভিন্ন জায়গায় বানান ভুল হওয়ার জন্য আমি দুঃখিত]\nগল্পটা কেমন হচ্ছে ভালো নাকী খারাপ অবশ্যই জানাবে আর গল্পে আর কোন কোন ক্লাইম্যাক্স অ্যাড করলে গল্পটা আরো বেশি সুন্দর হতো সেটাও জানাতে ভুলো নাহ।\n"},{"id":"1773089911536-7","title":"07","slug":"part-07","content":"আমি কিছু বুঝে উঠার আগেই রনি আর হানা আমাকে দেখে ফেলে আমি ওদের কাছ থেকে পালানোর জন্য একটা দৌড়ে খান ভিলা থেকে বেড়িয়ে এলাম।\nপাগলের মতো রাতের অন্ধকারে এদিক সেদিন ছুটাছুটি করছি, কি করবো.? কোথায় যাবো.? \nতখনই আম্মুর কল, কল রিসিভ করতেই আম্মু বললো.....\nআম্মু:- আরিয়ান কই তোরা..?\nআমি কিছু বলার আগেই আম্মু আবার বললো...\nআম্মু:- ঘুম ভাঙ্গতেই দেখি রিশা আমার পাশে নেই কিছুক্ষণ পর তোর আব্বু আর রনি এসে বললো তুইও নাকী তোদের রুমে নেই.! \nতোরা কি একসাথে আছিস..?\nআমি কোনো উত্তর নাহ দিয়ে কল কেটে দিয়ে রাস্তার এপাশ ওপাশ এদিক সেদিন ছুটাছুটি করছি রিশাকে খুঁজার জন্য। \nহঠাৎ আমার পিছন থেকে কেউ একজন কাঁধে হাত দিলো আমি পিছনে তাকালাম, তাকিয়ে দেখি রিশা কাঁদো কাঁদো গলায় বলছে...\nরিশা:- ওহে আমার প্রাণপ্রিয় স্বামী, আপনি কোথায় যাচ্ছেন আমাকে একা রেখে.?\nএই বলে রিশা হাওয়ায় উড়তে শুরু করলো, তার চোখগুলো একদম সাদা, চুলগুলো হাওয়ায় উড়ছে। \nহঠাৎ সে আমার এক লাফে আমার কাঁধে ঝাপিয়ে পড়ে আমার গলায় একটা কামোড় দিলো আমি প্রচন্ড যন্ত্রণায় চিৎকার দিলাম।\nরিশাকে আমার ঘাড় থেকে কোনোমতে নামিয়ে আমি আবার দৌড়াতে শুরু করি, এবার দৌড়াতে দৌড়াতে আমার মাথায় মাওলানা আলতাফ সাহেবের কথা এলো...\nআমি ছুটে গেলাম আলতাফ হুজুরের বাসায়। \nবাসায় গিয়ে শুনি সে নাকী গতকাল ভোরে গ্রামের বাইরে গেছেন আসবে আজকে রাত শেষ হলে।\nআমার গলা দিয়ে প্রচন্ড রক্তক্ষরণ হচ্ছে দেখে আলতাফ সাহেবের সাগরেদ আমার গলায় একটা কাপড় পেঁচিয়ে দিলো যাতে রক্তক্ষরণ কিছুটা কমে।\nআলতাফ সাহেবের সাগরেদের কাছে পানি খেতে চাইলে সে আমাকে বসিয়ে রেখে পানি আনতে গেলো।\nমিনিট দুই-একের মধ্যে ছেলেটি পানি নিয়ে এলো আমাকে পানি দিতে যাবে তখন সেখানে হানা চলে আসে, তখনও সে রিশার শরীরেই ছিলো। \nহানা এসেই ছেলেটির ধর থেকে মাথাটা টেনে ছিঁড়ে ফেললো।\nছেলেটির মাথাটা ছেঁড়ার সময় আমার চোখে মুখে  রক্ত ছিটকে গিয়ে পড়লো, এটা দেখে হানা বললো...\nহানা:- কেমন লাগছে রক্তের স্বাদ.? খুব সুস্বাদু তাই নাহ.? \nআমি ভয়ে দৌড়ে মসজিদের ভিতরে ঢুকে বসে পড়লাম, বাইরে থেকে হানা চেচিয়ে চেচিয়ে বলছে...\nহানা:- কতক্ষণ লুকিয়ে থাকবে.? একবার নাহ একবার তোহ বের হতেই হবে তোমাকে.? \nআমি মনে মনে যা যা দোয়া পারতাম পড়তে থাকলাম, খানিকক্ষণ পর হানা কান্না করতে করতে বলছে....\nহানা:- প্রিয় কেনান মনে করো সেই দিনগুলো যখন তুমি আর আমি একসাথে কত স্বপ্ন বুনেছি, মনে করো আমাদের বিবাহে আবদ্ধ হওয়া সেই দিনটা..!  মনে করো..! মনে করো.!  মনে করো.!\nবলে চিল্লাতে চিল্লাতে এক ভয়ঙ্কর রুপে হাওয়ায় উড়তে উড়তে আমার দিকে একটা গাছের ডাল ছুড়ে মারে, ডালটা মসজিদের দরজা ভেদ করে আমার বুকে এসে লাগে আমি ছিটকে আরো ভিতরে গিয়ে পড়লাম। কিন্তু তারপরও আমি দোয়া পড়া বন্ধ করি নাহ।\nভোর হবে হবে মনে হচ্ছে কিছুক্ষণ পরই ফজরের আযান দিবে ঠিক তখনই হানা আমাকে বলছে...\nহানা:- কি ঠিক করলে এখানেই থাকবে.?  আচ্ছা থাকো এখানে আমি তোমার ভালোবাসাকে নিয়ে চলে গেলাম..!\nএই বলে হানা কোথায় যেনো গায়েব হয়ে গেলো,, কিছুক্ষণ পরেই ফজরের আযান হলো।\nবেশ কিছুক্ষণ পর দেখি আলতাফ সাহেব আসছেন।\nতাকে দেখে কিছুটা স্বস্তি বোধ করলাম।\nসে আসা মাত্রই তাকে সবটা খুলে বললাম, এসব শুনে সে বললো....\nমাওলানা আলতাফ সাহেব:- আপনাকে তোহ আগেই বলেছিলাম বড় কোনো বিপদ হওয়ার আগে এই গ্রাম ছেড়ে চলে যান...\nআমি:- ফিরেই তোহ গিয়ে ছিলাম কিন্তু রনিই তোহ আমাকে আবার গ্রামে আসতে বাধ্য করলো.!\nমাওলানা আলতাফ সাহেব:- বলেছিলাম নাহ আপনার বন্ধুই হবে আপনার বিপদের কারণ.?\nআমি:- হ্যাঁ বলেছিলেন তোহ.!কিন্তু এখন কি করা যায়, হানা তোহ রিশাকে নিয়ে চলে গেলো ওর সাথে। \nমাওলানা আলতাফ সাহেব:- এখন একটাই উপায় আছে....\nআমি:- কি উপায়.?\nমাওলানা আলতাফ সাহেব:- আপনাকে আগের জন্মের সবকিছু মনে করতে হবে.\nআমি:- মানে..?\nমাওলানা আলতাফ সাহেব:- এটা বিশ্বাস করুন আপনিই কেনান সাহেব।\nআমি:- আচ্ছা বিশ্বাস করলাম এবার আমাকে কি করতে হবে...?\nমাওলানা আলতাফ সাহেব:- চলুন আমার সাথে.. \nমাওলানা সাহেবের সাথে চলতে চলতে একসময় আমাদেরই গ্রামের বাড়ি খান ভিলায় এসে পৌছলাম। \nআমি:- আপনিও তাহলে ওদের দলেরই.?\nমাওলানা আলতাফ সাহেব:- আপনি আমাকে ভুল বুঝছেন সাহেব..!\nআমি:- আপনি ওদের দলের নাহ হলে আমাকে এখানেই কেনো ফিরিয়ে আনলেন..?\nমাওলানা আলতাফ সাহেব:- কারণ আপনার জীবন রহস্য এই বাড়িতেই দাফন করা আছে। এখানে নাহ আসলে আপনার কিছুই মনে পড়বে নাহ.!\nহুজুরের কথা মতো আবারও বাড়ির ভিতরে প্রবেশ করলাম, প্রবেশ করতেই দেখি আমার আব্বু আম্মুর মাথা বিহীন লাশ ফ্লোরে পড়ে আছে, তাদের এমন করুন মৃত্যু দেখে আমি নিজেকে সামলাতে পারলাম নাহ, নিজেকেই নিজে দোষারোপ করছি আমি যদি সেদিন গ্রামে আসার বায়না নাহ ধরতাম তাহলে এতকিছু হতো নাহ, কেনো যে সেদিন ছোট বাচ্চাদের মতো জ্বেদ ধরেছিলাম। একটা জ্বেদের জন্য আজ কতগুলো মানুষের প্রাণ গেলো.!\nআমাকে কাঁদতে দেখে মাওলানা সাহেব আমাকে শান্তনা দিয়ে বললো...\nমাওলানা আলতাফ সাহেব:- এতে আপনার কোনো দোষ নেই সাব.! এটাই আপনার নিয়তি, ভুলে যাবেন নাহ ফেলে আসা অসম্পূর্ণ অতীত সারাজীবন কিন্তু অসম্পূর্ণ থাকে নাহ।\nএখনো সময় আছে সবকিছু ঠিক করার, আর আমি জানি এই মরণ খেলা একমাত্র আপনিই বন্ধ করতে পারবেন, আপনি ভেঙ্গে পড়লে হবে নাহ.! আপনাকে শক্ত হতে হবে, এই লড়াই আপনার, আপনাকেই লড়তে হবে এই লড়াই.!\nউঠুন..সাহেব, উঠুন.! নিজেকে সামলান, হানা আর জিলানীকে আপনিই সায়েস্তা করতে পারে..!\nআমি:- জিলানী আবার কে..?\nমাওলানা আলতাফ সাহেব:- এজন্য বলেছি আগে আপনার অতীত সম্পর্কে সব জানুন তারপর যুদ্ধে নামুন.!\nআমি আমার প্রশ্নের উত্তর নাহ পেয়ে হুজুরের পিছু পিছু গেলাম।\nহুজুর আমাকে নিয়ে দোতলার সেই বন্ধ ঘরটির ভিতরে গেলেন, ভিতরে ঢুকতেই দেখি রফিক দাদু  আহত হয়ে নিচে পড়ে ছটফট করছে তার পেটে একটা ছুড়ি ঢোকানো, একটু ভালো মতো খেয়াল করে দেখলাম রফিক দাদুর হাতে একটা হেয়ার পিন টাইট করে ধরে আছে....\nআমি দৌড়ে গিয়ে রফিক দাদুর পেট থেকে ছুড়িটা বের করে রফিক দাদুকে আমার বুকের সাথে জড়িয়ে জিজ্ঞেস করলাম...\nআমি:- কি হয়েছে রফিক দাদু.?  তোমার এই হাল কে করেছে..? নিচেও দেখলাম আব্বু আম্মুকেও কেউ নৃশংসভাবে হত্যা করেছে.! কি হয়েছিল দাদু.? ওও দাদু বলো নাহ কি হয়েছিল.? \nরফিক দাদু আমাকে আরেকটু কাছে ডেকে হেয়ার পিনটা আমার হাতে দিয়ে আস্তে আস্তে বললো....."},{"id":"1773089930158-8","title":"08","slug":"part-08","content":"রফিক দাদু আমাকে আরেকটু কাছে ডেকে হেয়ার পিনটা আমার হাতে দিয়ে আস্তে আস্তে বললো.....\nরফিক দাদু:- ফজরের আযান দিচ্ছিলো তখন, হঠাৎ করে দেখি কেউ একজন তোমার আম্মুর চুল ধরে হ্যাচরাতে হ্যাচরাতে দোতলা থেকে নামছে, পিছনে তোমার আব্বু ছুটে আসছে তোমার আম্মুকে বাঁচানোর জন্য। \nকে তোমার আম্মুর চুল ধরে হ্যাচরাতে হ্যাচরাতে নিচে নামিয়ে আনলো এটা দেখার জন্য আমি লুকিয়ে পড়ি, কিছুক্ষণ পর দেখি সেটা আর কেউ নাহ, রিশা দাদুভাই। কিন্তু আমি বুঝে গেছিলাম এটা রিশা দাদুভাই নাহ এটা হানা যে রিশার রূপ নিয়ে এসব করছে।\nতারপর তোমার আব্বু রিশার কাছে অনেক কাকুতিমিনতি করে সে যেনো তোমার আম্মুকে ছেড়ে দেয় কিন্তু রিশা তা নাহ করে তোমার আব্বুর মাথাটা ধর থেকে আলাদা করে মেরে ফেললো। \nএটা দেখে আমি চিৎকার দিয়ে দোতলার দিকে দৌড়ে আসার সময় দেখি রিশা তোমার আম্মুর মাথাটাও ধর থেকে আলাদা করে ফেলে আমার পিছু পিছু আসছে।\nআমি দৌড়ে এই ঘরে এসে বহুযুগ আগে রিশার ব্যবহৃত চুলের কাঠিটা হাতে নি কারণ আমার দাদা মারা যাওয়ার আগে আমার বাবাকে বলে গিয়েছিলো রিশার ব্যবহৃত চুলের কাঠি দিয়েই তাকে হত্যা করা সম্ভব আর আমার বাবা মারা যাওয়ার আগে আমাকে বলে গিয়েছিলো।\nতারপর রিশা রূপী হানা আমার পিছু পিছু এখানে চলে আসে আমি ওর ব্যবহৃত চুলের কাঠিটা দিয়ে বার বার ওকে আঘাত করি কিন্তু কোনো কাজ হচ্ছিল নাহ বরং সে আমার পেটে ছুড়ি বসিয়ে চলে গেলো।\nএই বলে রফিক দাদু মারা যায়।\nআমি তখনও নিজেকে ক্ষমা করতে পারছিলাম নাহ, আমি আমার জীবন রক্ষা করার জন্য আমার বাবা মাকে হানার কাছে উৎসর্গ করে দিলাম।\nতখন মাওলানা আলতাফ সাহেব আমাকে বললেন...\nমাওলানা আলতাফ সাহেব:- হানা আর কেনান একে অপরকে নিজের জীবনের চাইতেও বেশি ভালোবাসতো।\nকেনান সাহেব হানাকে সবসময়ই নিজের জীবন দিয়ে আগলে রাখার চেষ্টা করতো কিন্তু হানা কেনানের সাথে বেইমানি করে, কেনানের প্রিয় বন্ধু জিলানীর সাথে সম্পর্কে জড়িয়ে পড়ে.... \nঠিক তখনই যেনো আমার সবকিছু মনে পড়ে যায়...... \nআমি:- তারা এক হওয়ার জন্য আমাকে তাদের পথ থেকে সরাতে চেয়েছি সেজন্য আমার উপর কালো জাদু করে যাতে আমি মারা যাই কিন্তু আমার সাথে হানার বিয়ে ঠিক হয়ে যায়...\nআমাদের বিয়ের দিন হানা আর জিলানী একে অপরের সাথে কথা বলছিলো...\nহানা:- আমি কেনানকে বিয়ে করতে চাই নাহ আমি তোহ তোমাকে ভালোবাসি,এখন আমি কি করবো এখন...?\nজিলানী:- তুমি চিন্তা করো নাহ, তুমি নিশ্চিতে কেনানকে বিয়ে করো, কেনানকে আমাদের রাস্তা থেকে হাটানোর দায়িত্ব আমার, কেনান মারা গেলে ওর ভাগের সম্পত্তিও তোমার হয়ে যাবে, হা! হা! হা!\n কিন্তু একটা কথা মাথায় রেখো বাসর রাতে কেনানকে পানি পান করতে দিবে নাহ।\nহানা:- আচ্ছা মাথায় থাকবে। কিন্তু কি করবে তুমি..?\nজিলানী:- সময় হলেই জানতে পারবে.!\nবিয়েটা সুন্দর মতো হয়েছিলো সেদিন, তারপর বাসর রাতে আমি হানার পাশে গিয়ে বসলাম, কিছুক্ষণ গল্প করার পর আমার অনেক তৃষ্ণা পায়।\nআমি:- তুমি একটু অপেক্ষা করো আমি পানি পান করে আসছি.!\nহানা:- আজকের মতো একটা দিনে তুমি আমাকে একা রেখে চলে যেতে চাইছো.! বুঝেছি.! তুমি আমাকে একটুও ভালোবাসো নাহ.?\nআমি:- আরে এমনটা নয়, আচ্ছা যাবো নাহ খুশি তোহ এবার.?\nহানা:- হ্যাঁ অনেক.!\nএই বলে আরো কিছুক্ষণ গল্প করে আমরা ঘুমিয়ে পড়লাম অপরদিকে জিলানী কালো জাদু চালিয়ে যাচ্ছে। \nমাঝরাতে আমার শরীর থেকে রুহ্টা বের করিয়ে নিলো পানি পান করানোর জন্য, রুহ্টা যখনই পানির পাত্রে গেলো তখনই হানা পাত্রটা ঢাকনা দিয়ে ঢেকে ফেললো...\nমাওলানা আলতাফ সাহেব:- পরদিন সকালে খান বাড়িতে দুঃখ নেমে আসে কারণ খান বাড়ির বড় ছেলে কেনান খান মারা গেছে।\nহানা কান্না করতে করতে বার বার জ্ঞান হারাচ্ছিল।\nসকল নিয়ম মেনে কেনান খানের লাশ দাফন করা হয়।\nকেনান খানের মৃত্যুর কিছুদিন পর হানাকে খান ভিলার লোকেরা দায়িত্ব নিয়ে জিলানীর সাথেই বিয়ে দেয়। \nকারণ সদ্য বিধবা হওয়া মেয়েটিকে পরিচিত কেউ ছাড়া অন্য কেউই বিয়ে করতে চাইবে নাহ।\nযেহেতু কেনান খানের ছোট ভাই হেলাল খান [আরিয়ানের পর দাদা] কেনান খানের আগেই বিয়ে করে ছিলো তাই হানাকে খান ভিলার অন্ধকার কোনো পুত্র নাহ থাকার কারণে কেনান খানের কাছের বন্ধু জিলানীর সাথেই বিয়ে দেওয়া হয় এবং তাদের আগামী জন্ম নেওয়া সন্তানের জন্য কিছু জমি এবং নগদ টাকা দেওয়া হয়।\nওদের বিয়ের মাস খানেক পর গ্রামে কোথা থেকে যেনো এক ভদ্রলোক এসে বলছে... \nএই গ্রামে অন্যায় হয়েছে, একজনকে জীবিত অবস্থায় তাকে দাফন করা হয়েছে.!\nসবাই তাকে জিজ্ঞেস করলো কাকে জীবিত অবস্থায় দাফন করা হয়েছে...\nসেই লোকটি কেনান সাহেবের কথা বললো...\nলোকটি খান ভিলার সেই ঘরটিতে যায় যেখানে কেনান আর হানার বাসর ঘর সাজানো হয়েছিলো।\n ওই ঘরের খাটের নিচ থেকে সেই পানির পাত্রটা বের করে সবাইকে বলে...\n-- এই ঘটের মধ্যেই এই বাড়ির বড় ছেলের রুহ্ এখনো আটকা পড়ে আছে।\nসাবধান! এই ঘট থেকে যেনো ওর আত্মা কখনো বের হতে নাহ পারে, যদি কখনো ভুল বসৎ কেউ এমনটা করে তাহলে গ্রামে মহামারি নেমে আসবে। কারণ ওর আত্মা ঘট থেকে বের হওয়ার পর নিজের শরীর খুঁজবে আর যদি নিজের শরীর খুঁজে নাহ পায় তাহলে গ্রামের সবাইকে শেষ করে ফেলবে...\nএই বলে সেই ভদ্রলোকটি পানির পাত্রটা গ্রামের সেই বটগাছটিতে নিয়ে বেঁধে রাখে।\nতারপর হানা হয়তো সত্যিই কেনানের শূন্যতা অনুভব করছিলো তাই জন্য একদিন রাতে পাগলের মতো ছুটে গিয়ে সেই পাত্রটার মুখ উন্মুক্ত করে দেয় সাথে সাথে পাত্র থেকে জোড়ে৷ হাওয়া প্রবাহিত হলো....\nতৎক্ষনাৎ তেমন কিছু হয়নি, হানা কেনানকেও তার আশেপাশে দেখতে নাহ পেয়ে চলে নিজের বাড়ি চলে আসে।\nআমি আবারও বললাম...\nআমি:- হানা তোহ সেদিন বাড়ি ফিরে যায়, কিন্তু আমি৷ ঘট থেকে মুক্তি পাওয়ার পর নিজের শরীর পাগলের মতো খুঁজতে থাকি কিন্তু কোত্থাও খুঁজে পাচ্ছিলাম নাহ, নিজের শরীর খুঁজে নাহ পেয়ে রাগে আর ক্ষোভে পুরো গ্রামে অভিশাপ দি।\nগ্রামের প্রতিটি নদীনালা, খাল-বিল, পুকুর, ঝর্ণা, পানির কল সব সব সব বিষাক্ত হয়ে যায়, যে''ই পানি পান করছিলো সেই জীবন হারাচ্ছিল।\nশিশু থেকে বৃদ্ধ কেউই মুক্তি পায়নি আমার অভিশাপ থেকে।\nআমার অভিশাপে অভিশপ্ত হতে লাগলো গ্রামটি।\nগ্রামের সবাই তখন নিজের জীবন বাঁচানোর জন্য পাগলের মতো গ্রাম পরিত্যাগ করতে লাগলো।\nমাওলানা আলতাফ সাহেব:- হ্যাঁ ঠিক তখনই সেই লোকটি আবারও গ্রামে এসে পৌছায়...\nএসেই লোকটি ক্ষিপ্ত হয়ে বললো....\nভদ্রলোক:- এই দঃকার্য কেনো করেছো তোমরা.? আমি বারংবার নাহ করেছিলাম কেউ যেনো এমন ভুল নাহ করে, যদি এমনটা করো তাহলে এই গ্রাম অভিশাপে লিপ্ত হবে।\nতখন গ্রামবাসীরা সবাই সেই লোকটির কাছে জানতে চায় এই কাজ কে করছে..\nলোকটি হানার দিকে আঙ্গুল তুলে বলে এই কাজটি হানা করেছে...\nতখন হানা বললো.....\nহানা:- আমি লোভে পরে জিলানীর সাথে হাত মিলিয়ে আমার ভালোবাসার মানুষকে হত্যা করি কিন্তু বিশ্বাস করুন আমি জিলানীর সাথে সুখে নেই, আমি প্রতিটা দিন কেনানের শূন্যতা অনুভব করি আমি কেনানকে ভুলতে পারছিলাম নাহ।\nআমি ভেবেছিলাম, কেনানকে মুক্তি করে দিলে হয়তো আমরা আবার এক হয়ে যাবো কিন্তু আমি বুঝতে পারিনি আমার ছোট্ট একটা ভুলে পুরো গ্রামটি অভিশাপে ভরে যাবে শত-শত মানুষ মারা যাবে।\nআপনারা আমাকে যা শাস্তি দিবেন আমি তাই মাথা পেতে নিবো, বলুন আমাকে কি করতে হবে..?\nভদ্রলোক:- তুমিই ওকে হত্যার পরিকল্পনা করেছিলে, আর তুমিই ওকে মুক্ত করেছো এখন তোমাকেই ওকে আটকাতে হবে..!\nহানা:- কি করতে হবে আমায় বলুন..?\nভদ্রলোক:- আমি যে কাজটির কথা বলবো এতে কিন্তু তোমার প্রাণ সংশয় হতে পারে। \nহানা:- আমি তাতেও রাজি.!\nভদ্রলোক:- ঠিক আছে তাহলে শুনো, আমি জানি৷  কেনান এখনো তোমাকে ভালোবাসে, আর কেনানকে যদি কেউ প্রকাশ্যে আনতে পারে সেটা একমাত্র তুমি, তোমার ভালোবাসা।\nহানা:- আচ্ছা তারপর..?\nভদ্রলোক:- তুমি কেনানকে ডেকে আনবে, তারপর আমি তোমাকে একটা থালা দিবো সেই থাকাটি ভরে পানি তোমার সামনে রাখবে, যেহেতু কেনানের উপস্থিতিতে সকল পানি বিষাক্ত হয়ে যায় সেহেতু ওই থালার পানিও বিষাক্ত হয়ে যাবে...\nকেনান তোমার সামনে হাজির হলেই তুমি সেই থালার পানিটা পান করবে যদি কেনান তোমাকে এখনো ভালোবাসে তাহলে সে তোমার কাছে ছুটে যাবে, কেনান যখন তোমার সামনে যাবে তখন তুমি কেনানকে কথায় কথায় আটকে রাখবে তারপর বাকি কাজটা আমি করবো..!"},{"id":"1773089976071-9","title":"last part 09","slug":"last-part-09","content":"হানা সেই ভদ্রলোকের কথানুযায়ী পরের দিন সন্ধ্যাবেলা তার দেওয়া থালাটি নিয়ে বের হবে তখনই জিলানী হানাকে বাঁধা দেয় সে যেনো বাড়ি থেকে এক পা-ও নাহ বের হয়।\nকিন্তু হানা অনেক জোড় জবরদস্তি জিলানীর হাত থেকে নিজেকে ছাড়িয়ে বেড়িয়ে আসে।\nতারপর হানা সেই থালাটিতে পরিষ্কার ও বিশুদ্ধ খাবার পানি রেখে কেনানের আত্মাকে আহ্বান করে।\nকিছুক্ষণ পরেই সেখানে প্রচন্ড বেগে তুফান শুরু হয় তারপরই সেখানে কেনানের উপস্থিতি হয়।\nকেনানের উপস্থিতির ফলে ওই থালাতে রাখা পানিও বিষাক্ত হয়ে যায়। \nকেনানের উপস্থিতি দেখে হানা দৌড়ে গিয়ে সেই পানি পান করে এটা দেখে কেনান ঘাবড়ে যায় এবং ছুটে যায় হানার কাছে কিন্তু ততক্ষণে হানার অবস্থা অনেক খারাপ হয়ে গেছে। \nকিন্তু হানা হাল ছাড়ে নাহ, সে ওই ভদ্রলোকটির কথানুযায়ী কেনানকে কথায় আটকে রাখার চেষ্টা করছিলো....\nহানা:- আমাকে ক্ষমা করে দিও কেনান, জায়দাদ আর ক্ষমতার লোভ আমাকে এতটাই নিচে নামিয়ে ছিলো যে আমি প্রকৃত ভালোবাসাই বুঝতে পারিনি।\nআমাকে আবারও ক্ষমা করে দিও, কারণ আমি তোমাকে দেওয়া কথা রাখতে পারিনি, আমি বলেছিলাম তোমাকে ছাড়া আর কাউকে নিজের স্বামী বলে স্বীকৃতি দেবো নাহ কিন্তু আমি জিলানীকে বিয়ে করেছি, দয়া করে আমাকে মাফ করে দিও। \nকেনান:- আজ এবং এখন থেকে আমি তোমাকে অভিশাপ দিলাম তুমি কোনোদিন নিজের জীবনে প্রকৃত ভালোবাসা পাবে নাহ এমনকি কোনোদিন কোনো পুরুষ তোমাকে ভালোবাসবে নাহ। শুধু এই জন্ম নাহ কোনো জন্মেই তুমি তোমার ভালোবাসা পারে নাহ। \nহানা:- দয়া করো আমাকে এই অভিশাপ দিও নাহ। \nএই বলে হানা সেখানেই শেষ নিঃশ্বাস ত্যাগ করে ঠিক তখনই কেনানও খুব জোড়ে বিকট শব্দে চিৎকার দিয়ে উঠে...\nকেনান পিছনে তাকাতেই দেখে সেই ভদ্রলোকটি নিজের সর্বস্ব দিয়ে কেনানের আত্মাকে মুক্তি করার চেষ্টা করছে। \nতারপর সেই ভদ্রলোকটি কেনানের মাথায় আল্লাহর পবিত্র কোরআনের কিছু অংশ জোড়ে চেপে ধরে ফলে সেখানেই কেনান নিঃশক্তি হয়ে পৃথিবী থেকে বিদায় নেয় এবং ওর আত্মার মুক্তির সাথে সাথে পাহাড়িতলা গ্রাম আবারও আগের মতো জনবহুল হয়ে যায়, চারিদিকে সবুজ আর সবুজ, পাহাড়ি ঝর্ণা, নদীনালা, খালবিল, সবকিছু আগের মতো সতেজ হয়ে যায়।\nভদ্রলোকটি নিজের কাজ করে চলে যাচ্ছিল তখনই আপনার পর দাদা হেলাল খান লোকটিকে আটকায়...\nহেলাল:- কে আপনি..?  আর কেনোই বা নিজের জীবনের ঝুঁকি নিয়ে আমাদের গ্রাম রক্ষা করলেন..?\nভদ্রলোক:- আমি মেশবার আলী! আমি একজন ইমাম, আমাকে স্বপ্নযুগে বিভিন্ন জায়গার বিপদাত্মি দেখানো হয় এবং কিভাবে সেই জায়গাটি বিপদমুক্ত করা যায় তার উপায় বলে দেওয়া হয়। আর আপনাদের গ্রামের বিপদও আমাকে স্বপ্নে দেখানো হয়েছিল এজন্যই আমি আপনাদের সাহায্য করেছি এটা আমার কর্তব্য। \nহেলাল:- আপনি চাইলে আমাদের গ্রামে থেকে যেতে পারেন..?\nমেশবার আলী:- থেকে গিয়ে কি করবো..?\nহেলাল:- আমরা আপনার উপকার সরূপ আমাদের গ্রামে আপনার নামে একটি মসজিদ স্থাপন করতে চাই এবং সেই মসজিদের ইমাম হবেন আপনি দয়া করে নাহ করবেন নাহ.!\nমেশবার আলী:- আচ্ছা আপনারা যখন এত করে বলছেন আমি আর নাহ করবো নাহ।\nমাওলানা আলতাফ সাহেব:- সেই মেশবার আলী ছিলো আমার দাদা, তিনি মারা যাওয়ার আগে আমার পিতাকে এই গ্রামের দায়িত্ব দিয়ে যান এবং আমার পিতা মারা যাওয়ার আগে আমাকে।\nআমি:- আমার তোহ আগের জন্মের কথা সবটাই মনে পড়লো, কিন্তু হানার এমন অবস্থা হলো কিভাবে, ও তোহ সেদিনই মারা গিয়েছিলো তাহলে আবার প্রেতাত্মা হয়ে ফিরে এলো কিভাবে তাও আবার এত বছর পর...?\nমাওলানা আলতাফ সাহেব:- ভুল এত বছর পর নয়, হানা সেদিনের ২ বছর পরই ফিরে এসেছিলো.! \nআমি:- মানে.? কিভাবে.? \nমাওলানা আলতাফ সাহেব:- ওইদিনের পর গ্রাম আবার আগের মতো হয়ে যায়, বহুদিন এভাবেই গ্রামে সুখ শান্তি ছিলো কিন্তু একদিন... \nএকদিন রাতে জিলানী নিজের কাজ শেষ করে বাড়ি ফিরছিলো তখন দেখে রাস্তায় একজন মহিলা কান্না করছে, সে মহিলাটির সামনে গিয়ে জিজ্ঞেস করে তার কি হয়েছে..?\nমহিলাটি মুখ তুলতেই জিলানী চমকে যায় কারণ সেই মেয়েটি ছিলো হানা....\nহানা জিলানীর দিকে তাকিয়ে হাসছে, হঠাৎ করে হানা বাসাতে উড়তে লাগে এটা দেখে জিলানী বলছে...\nজিলানী:- কি চাও তুমি..? তুমি তোহ মারা গেছো তাহলে কেনো ফিরে এসেছো আবার..?\nহানা:- তুই হ্যাঁ তুই, তুই এর জন্য দায়ী, তোর জন্য কেনান আমাকে অভিশাপ দিয়েছে যার জন্য আজ আমার এই অবস্থা, তোর কোনো ক্ষমা নেই.!\nতোর শাস্তি একটাই মৃত্যু.! \nএই বলে হানা জিলানীকে সেখানেই হত্যা করে...\nআমি:- আচ্ছা হুজুর সাহেব জিলানীও কি আবার জন্ম নিয়েছে..?\nমাওলানা আলতাফ সাহেব:- রনিই হচ্ছে জিলানী.! \nআমি:- কি.! রনিই তাহলে জিলানী.! \nমাওলানা আলতাফ সাহেব:- হ্যাঁ.! এজন্যই বলেছিলাম আপনার বন্ধুই হবে আপনার বিপদের কারণ.! \nরনির আপনার আগেই আগের জন্মের কথা মনে পড়েছিলো যার ফলে আপনারা গ্রাম থেকে চলে গেলেও সে তৌহিদকে নিজের দলে টেনে গুপ্তধনের লোভ দেখিয়ে বলায় তারা আরো পরে গ্রাম থেকে যাবে।\nতারপর তৌহিদ আর আব্রাহামকে কালো জাদু করে সেই বটগাছের সামনে গিয়ে হানাকে মুক্তি করে দেয় এবং হানার শিকার হিসেবে তৌহিদ আর আব্রাহামকে উৎসর্গ করে।\nআমি:- এতক্ষণে আমার কাছে সবটা ক্লিয়ার হলো বাট হানাকে ওই বটগাছে কে বা কিভাবে বন্দী করেছিলো..?\nমাওলানা আলতাফ সাহেব:- হানাকে আপনার পর দাদা হেলাল খান আমার দাদার সাহায্য নিয়ে ওই বটগাছে বন্দী করেছিলো। \nআমি:- কিভাবে..? \nমাওলানা আলতাফ সাহেব:- ওইদিন হানা ডায়নী হওয়ার পর জিলানীকে হত্যা করে তারপর থেকে প্রতিদিন গ্রামের একজন করে যুবক নিখোঁজ হয়ে যায় এবং পরদিন সকালে তাদের ওই বটগাছের ডালে ফাঁসিরত অবস্থায় পাওয়া যায়। \nএভাবে আবারও গ্রামে আতঙ্ক ছড়িয়ে পড়তে থাকে...\nতখন তোমার পর দাদা ছিলো এই গ্রামের জমিদার, তার জমিদার হওয়ার পূর্বে তার বড় ভাই কেনান খান ছিলো এই গ্রামের শ্রেষ্ঠ জমিদার কিন্তু তার অকাল মৃত্যুর পর গ্রামের দায়িত্ব হেলাল খানের উপর যায়।\nগ্রামের জমিদার হওয়ার কারণে তাকেই এর সমাধান খুঁজতে হয়...\nসে আমার দাদার কাছে যায়...\nহেলাল:- মেশবার আলী যেভাবেই হোক একটা উপায় বের করতে হবে এই গ্রামকে ওই ডায়নীর হাত থেকে রক্ষা করতেই হবে...!\nমেশবার আলী:- আমি যা ভাবছি সেটা করতে হলে ওই ডায়নীকে বন্দী করা যাবে, কিন্তু... \nহেলাল:- কিন্তু কি..?\nমেশবার আলী:- কিন্তু যেকোনো একজন পুরুষকে নিজের জীবন বিসর্জন দিতে হবে...\nহেলাল:- তাহলে আর দেড়ি কিসের আমি দেবো আমার জীবন বিসর্জন...\nমেশবার আলী:- কি বলছেন এসব আপনি এই গ্রামের কর্তা, আপনার কিছু হলে এই গ্রামের কি হবে...\nহেলাল:- তুমি চিন্তা করো নাহ সব ঠিক হয়ে যাবে... তুমি শুধু উপায় বলো...\nমেশবার আলী:- আপনাকে ওই ডায়নীকে প্ররোচন দিয়ে সামনে আনতে হবে,  যেহেতু সে প্রেম প্রেয়সী ডায়নী গ্রামের যুবক ছেলেদের সাথে যৌন মিলন করার পর তাদের মেরে ফেলে তাহলে আপনাকেও সেই একই রাস্তা অবলম্বন করতে হবে...\nওকে আপনার সাথে যৌন মিলন করারা জন্য প্ররোচিত করবে যাতে ও আপনার সামনে সামনে আসে...\nহেলাল:- আচ্ছা তারপর কি করবো..?\nমেশবার আলী:- দাঁড়ান আগে ওর ব্যবহৃত কোনো একটা জিনিস আমার কাছে এনে দিন...\nতারপর হেলাল খান হানার বাড়ি থেকে হানার ব্যবহৃত চুলের কাঠিটা মেশবার আলীর কাছে নিয়ে যায়... \nমেশবার আলী:- এই চুলের কাঠিটা আপনার এমন একজন বিশ্বস্ত মানুষের কাছে দিবেন যে যুগ যুগ পর্যন্ত এটা সামলে রাখতে পারবে...\nহেলাল:- কিন্তু কেনো..?\nমেশবার আলী:- কারণ আজকে আপনি এই ডায়নীকে হত্যা করতে পারবেন নাহ তবে বন্দী করতে পারবেন...\nএই ডায়নীর হত্যা একমাত্র আপনার ভাই কেনান খানই করতে পারবে...\nহেলাল:- কিন্তু আমার ভাই যে মারা গেছে আরো আড়াই বছর আগে.? \nমেশবার আলী:- সে দ্বিতীয়বার জন্ম নেবে, এই গ্রামে তাকে আবার ফিরতে হবে তার অসমাপ্ত কাহিনি সমাপ্ত করতে।\nহেলাল:- আচ্ছা ঠিক আছে। এবার আপনি উপায়টা বলুন তারপর ওকে সামনে আনার পর কি করবো..?\nমেশবার আলী:- ডায়নীটা আপনার সামনে আসার পর আপনি ওর দিকে এই পবিত্র জমজমের পানি ছিটিয়ে দিবেন তারপর বাকি কাজটা আমি করবো...\nহেলাল:- আপনাকে কিছু করতে হবে নাহ, আপনি আমাকে বলুন আমিই সবটা করবো..!\nমেশবার আলী:- নাহ, এর পরের কাজটুকু অনেক বিপদজনক আপানর জীবন সংশয় হতে পারে। \nহেলাল:- হোক তবুও আমি এই কাহটুকু করবো...\nমেশবার আলী:- ঠিক আছে তবে শুনুন...\nওর দিকে জমজমের পানি ছিটিয়ে দেওয়ার পর ওয় পাগলের মতো যন্ত্রণায় ছটফট করবে তখন ও আপনাকে আঘাত করবে আপনি আপনার রক্ত এই মাটির পাত্রটার ভিরতে ফেলবেন তখন সাথে সাথে ওই ডাইনীটাও মাটির পাত্রে বন্দী হয়ে যাবে....\nমেশবার আলীর কথা মতো পরদিন মাঝ রাতে হেলাল খান হানাকে আহ্বান করে নিজের সাথে যৌন মিলন করতে...\nহানাও তার ডাকে সাড়া দিতে চলে আসে....\nহানা তার সামনে যেতেই সে হানার দিকে জমজমের পানি ছিটিয়ে দেয় এবং হানা অসহ্য যন্ত্রণায় নিজের বড় বড় নখ দিয়ে হেলাল খানের পেটে ঢুকিয়ে দেয়, পেট থেকে নখগুলো বের করে এবার গলায় আঘাত করে... \nকিন্তু হেলাল খানও নিজের জীবনের কথা চিন্তা নাহ করে নিজের রক্ত সেই পাত্রটাতে ফেলে এবং সাথে সাথে হানার অতৃপ্ত আত্মা সেই পাত্রে বন্দী হয়ে যায়।\nহানা পাত্রটাতে বন্দী হওয়ার সাথে সাথে হেলাল খান পাত্রের মুখ আটকে দিয়ে সেখানেই নিজের শেষ নিঃশ্বাস ত্যাগ করেন।\nপরদিন গ্রামে আবারও শোকের ছায়া নেমে এলো...\nমেশবার আলী সবাই শান্তনা দিয়ে সেই ঘট''টিকে বটগাছের ডালে বেঁধে রেখে বটগাছটি বিভিন্ন শক্তির মাধ্যমে সুরক্ষিত করে রাখে এবং জায়গাটিকে নিষিদ্ধ বলে ঘোষণা করে দেওয়া হয় যাতে কেউ এটা নষ্ট করতে নাহ পারে।\nতারপর থেকে ঘটনা আজকের দিনে এসে আটকালো।\nআলতাফ সাহেব নিজের কথা শেষ করতে করতে কেউ একজন পিছন থেকে আমার মাথায় কিছু একটা দিয়ে আঘাত করে, সাথে সাথে আমি জ্ঞান হারাই।\nআমার জ্ঞান ফিরতেই দেখি আমাকে কেউ সেই বটগাছের সাথে বেঁধে রেখেছে, এবং আমার সামনে রনি বসে কালো জাদু করছে আর রিশা স্থির হয়ে বসে আছে, রিশা কোনো নড়াচড়া করছে নাহ।\nরনি:-  এই তোহ আর কিছুক্ষণ,  কিছুক্ষণ পরই হানা সারাজীবনের জন্য রিশার শরীরে থেকে যাবে আর কেউ হানাকে রিশার শরীর থেকে আলাদা করতে পারবে নাহ.! হা! হা! হা!\nআমি রনিকে উদ্দেশ্য করে বললাম...\nআমি:- যদি কারো সাহস থাকে তাহলে আমাকে বাঁধ মুক্তি করুক, লড়াই হবে দেখি কার কত জোড়।\nআমি জানতাম রনির নিজের শক্তির উপর অনেক অহংকার ছিলো সে নিশ্চয়ই ভুল পদক্ষেপ নিবে।\nঠিক, আমি ঠিক ভেবেছিলাম,  রনি ভুল পদক্ষেপটাই নিলো, সে আমাকে বাঁধ মুক্ত করে দিলো।\nআমাকে বাঁধ মুক্ত করার পর পরই আলতাফ সাহেব দৌড়ে এলেন...\nআলতাফ সাহেব:- সাব! চুলের কাঠিটা ওইখানেই পড়ে ছিলো, আমি নিয়ে এসেছি...\nআমি দৌড়ে গিয়ে মাওলানা সাহেবের হাত থেকে কাঠিটা নিলাম রনিও তার দিকে ছুটে গিয়ে তাকে লাঠি দিয়ে মারতে থাকে।\nআমি ছুটে গিয়ে রিশার বুকের বাম পাশে সেই কাঠিটা গেঁথে দিলাম সাথে সাথে ওই জায়গায় তুফান শুরু হলো... \nমনে হলো এক অশুভ শক্তির বিনাশ হলো...\nকিন্তু তখনই রিশা ছটফট করছে আমি তাকে আমার বুকের সাথে জড়িয়ে ধরে আছি কিছুক্ষণ পর রিশাও আমার বুকে শেষ নিঃশ্বাস ত্যাগ করে পরলোক গমন করলো।\nআমি রাগে হাতে দা''টা নিয়ে পিছন থেকে রনিকে একটা কোপ দি রনিও সেইখানেই মৃত্যু বরণ করে।\nতারপর আলতাফ সাহেবকে জিজ্ঞেস করলাম সে ঠিক আছে কি নাহ।\nএই বলেই আমি কান্না করতে শুরু করি, আজ আমি সব হারালাম, একটা জ্বেদের জন্য সবাইকে হালরালাম, প্রতিটা প্রিয় মানুষকে হারালাম। \nআমার সাথেই কেনো এমনটা হলো.?\n কি দোষ করেছিলাম আমি.?\nএত কষ্টের মাঝেও একটা শান্তির সুভাষ পাচ্ছিলাম যেনো আজ সকল অশুভ শক্তির বিনাশ করতে পেরেছি।\nThe End.... "}],"comments":0,"is_featured":false,"read_time":null,"season":1,"status":"published","submitted_by":"primary-admin","date":"2026-03-09T20:59:53.199Z","updated_at":"2026-04-01T19:53:27.512Z"}','2026-03-09T20:59:54.890Z','2026-04-01T19:53:27.505Z');
