INSERT INTO "app_table_rows" ("pk","table_name","row_json","created_at","updated_at") VALUES(3488322,'stories','{"id":"1775075674101","title":"অবক্ষয় রহস্য ভয় ও বিস্ময়","excerpt":"__MAHEAN_META__:{\"status\":\"published\",\"submittedBy\":\"primary-admin\",\"author\":\"রিয়াদ ইসলাম আযান\",\"category\":\"ছোট গল্প\",\"categories\":[\"ছোট গল্প\",\"ভৌতিক\"],\"coverImage\":\"/uploads/stories/covers/2026/04/4922a1b7-b9d0-4221-86cc-ce5f393d200d.png\",\"slug\":\"অবক্ষয়-রহস্য-ভয়-ও-বিস্ময়\",\"parts\":[{\"id\":\"1\",\"title\":\"01\",\"slug\":\"part-01\",\"content\":\"\"},{\"id\":\"1775075523994-2\",\"title\":\"02\",\"slug\":\"part-02\",\"content\":\"\"},{\"id\":\"1775075540827-3\",\"title\":\"03\",\"slug\":\"part-03\",\"content\":\"\"},{\"id\":\"1775075559402-4\",\"title\":\"04\",\"slug\":\"part-04\",\"content\":\"\"},{\"id\":\"1775075612853-5\",\"title\":\"05\",\"slug\":\"part-05\",\"content\":\"\"},{\"id\":\"1775075628216-6\",\"title\":\"06\",\"slug\":\"part-06\",\"content\":\"\"}],\"comments\":0,\"season\":1}:__MAHEAN_META_END__বিকেলের নরম আলো চারপাশে ছড়িয়ে আছে। পশ্চিম আকাশে সূর্য হেলে পড়েছে, হালকা বাতাসে গাছের পাতারা দুলছে। শহরের টিটিসি থেকে বেরিয়ে একটি কালো রঙের সেডান দ্রুতগতিতে ছুটে চলেছে ফাঁকা রাস্তায়।","content":"","author_id":"1773089545405","author":"রিয়াদ ইসলাম আযান","category_id":"ছোট গল্প","category":"ছোট গল্প","views":0,"image":null,"cover_image":"/uploads/stories/covers/2026/04/4922a1b7-b9d0-4221-86cc-ce5f393d200d.png","slug":"অবক্ষয়-রহস্য-ভয়-ও-বিস্ময়","tags":[],"parts":[{"id":"1","title":"01","slug":"part-01","content":"বিকেলের নরম আলো চারপাশে ছড়িয়ে আছে। পশ্চিম আকাশে সূর্য হেলে পড়েছে, হালকা বাতাসে গাছের পাতারা দুলছে। শহরের টিটিসি থেকে বেরিয়ে একটি কালো রঙের সেডান দ্রুতগতিতে ছুটে চলেছে ফাঁকা রাস্তায়। স্টিয়ারিংয়ের সামনে বসে আছে তাজ, একজন তরুণ, যার রক্তে বেপরোয়া উত্তেজনা। তার পাশে বসে আছেন মিস্টার সালমাত, টিটিসির অভিজ্ঞ ড্রাইভিং প্রশিক্ষক। বহু শিক্ষার্থীকে সঠিকভাবে গাড়ি চালানো শিখিয়েছেন তিনি, কিন্তু তাজের বেপরোয়া মনোভাব তাকে বারবার শঙ্কিত করে তুলছে। \"তাজ! সাবধানে! এভাবে ড্রাইভ করো না। এ*ক্সি*ডেন্ট হতে পারে!\" আতঙ্কিত গলায় বলে ওঠেন মিস্টার সালমাত। তাজ হেসে বলে, \"আরে সালমাত স্যার, আপনি ভয় পাবেন না, কিচ্ছু হবে না!\" তার কথা শেষ হওয়ার আগেই সামনে কিছু একটা নজরে আসে। চমকে ওঠে তাজ, দ্রুত স্টিয়ারিং সামলানোর চেষ্টা করে, কিন্তু ততক্ষণে দেরি হয়ে গেছে। গাড়ি সজোরে ধাক্কা খায় রাস্তার পাশের কংক্রিটের ওয়ালে। মুহূর্তের মধ্যে বিকট শব্দে বি*স্ফো*রণ ঘটে, আগুনের ফুলকি ছড়িয়ে পড়ে চারপাশে। পুরো এলাকা ধোঁয়ায় ছেয়ে যায়, বিকেলের আকাশ যেনো হঠাৎ অন্ধকার হয়ে ওঠে। শব্দ শুনে আশেপাশের মানুষ ছুটে আসে, আগুনের লেলিহান শিখায় জ্বলতে থাকা ধ্বং*সস্তূ*পের দিকে তাকিয়ে সবাই স্তব্ধ হয়ে যায়। মুহূর্তের বেপরোয়া উচ্ছ্বাস কতটা ভয়ংকর হতে পারে, তা যেনো বাস্তব হয়ে ধরা দেয় সবার সামনে।\n_____________________________\nধোঁয়ায় ঢাকা সবকিছু। চারপাশটা ঝাপসা হয়ে উঠেছে, যেনো কোনো কিছুই স্পষ্ট নয়। শুধু একটি ছায়ামূর্তি দেখা যাচ্ছে, কিছুটা দূরে। তার শরীরের গঠন লম্বা ও শক্ত, তবে তার প্রতিটি পদক্ষেপে যেনো কোনো ভয় বা সংকোচ। কাশির সঙ্গে সঙ্গে সে হাঁটু গেড়ে মাটিতে বসে পড়ে, ক্লান্তি ও অবসাদে ভরা। দুই হাত দিয়ে সে নিজের মুখ চেপে ধরে, যেনো তার য*ন্ত্র*ণাকে কোনোভাবে দমন করতে পারে। তবে হাত দু’টো ধীরে ধীরে সরিয়ে তাকে দেখতে হলো, যেনো পৃথিবীটা কেমনভাবে তার চারপাশে মুছে যাচ্ছে। হাত দু’টো রক্তে ভেসে যাচ্ছে, লাল হয়ে উঠেছে। চোখগুলো মুহূর্তেই ছানাবড়া হয়ে যায়, ভয় আর আ*তঙ্কের চিহ্ন ফুটে ওঠে চোখে। কিন্তু সে কিছুই করতে পারে না, শুধু কাশি থেমে থেমে বের হতে থাকে। এবার কাশির সাথে তার মুখ দিয়ে গলগল করে র*ক্ত পড়তে শুরু করে, যেনো পৃথিবীটা তার জন্য আরও অন্ধকার হয়ে যাচ্ছে। শরীরের শক্তি শেষ হয়ে আসছে, ক্লান্তি তাকে গ্রাস করছে। চোখের কোণে অন্ধকারের শাসন আসে, আর মাটি তার পায়ের তলা থেকে সরে যায়। সে মাটিতে লুটিয়ে পড়ে, চোখগুলো একে একে হারিয়ে যায় অন্ধকারের গভীরে।\nচারপাশে ঘুটঘুটে অন্ধকার, যেনো পৃথিবীটুকুও অদৃশ্য হয়ে গেছে। কোথাও কোনো আলো নেই, যেনো সবকিছু শ্বা*সরু*দ্ধ হয়ে গেছে। অন্ধকারে একটি শীতল, গা ছমছমে পরিবেশ তৈরি হয়েছে। হঠাৎ, সেই অন্ধকারের ভেতর থেকে এক গ*ম্ভীর কণ্ঠস্বর ভেসে আসে, যেনো মাটি থেকে উঠে আসছে, \"সময় হয়ে গেছে। এবার আমাকে প্রস্তুত হতে হবে।\" কণ্ঠস্বরটি যেনো সময়ের সঙ্গে সঙ্গতি রেখে, মহাকালের গভীর থেকে উঠে এসেছে। কিছু মুহূর্ত পরই, সেই ভ*য়ংকর কণ্ঠস্বর আবার অন্ধকারের গহ্বরে মিলিয়ে যায়। মুহূর্তেই চারপাশে ফিরে আসে সেই নিরব, থমথমে অবস্থা। গা ছমছমে পরিবেশ আরও তীব্র হয়ে ওঠে, যেনো কিছু ভ*য়ানক ঘটতে চলেছে। আবারও সবকিছু তলিয়ে যায় অন্ধকারের অতলে, যেনো পুরো পৃথিবী এক গভীর নীরবতায় ডুবে গেছে। সময় থেমে থাকে, আর সেই নিস্তব্ধতা যেনো অবিরাম।\nনিস্তব্ধতা যেনো এক শান্ত সমুদ্র। চারপাশ ডুবে আছে গাঢ় অন্ধকারে, যেনো সময় থমকে গেছে, আর পৃথিবীটা ঘুমিয়ে আছে এক গভীর নীরবতায়। হঠাৎ, সেই নীরবতা ভেঙে তীক্ষ্ণ রিংটোনের শব্দে জুনায়েদের ঘুম ভেঙে গেলো। চোখের পাতা দুটি যেনো রাজ্যের ক্লান্তি নিয়ে এসেছে, শরীর আর মন তখনও ঘুমের ঘোর থেকে সম্পূর্ণ মুক্তি পায়নি। \nঅলস হাতে ফোনটা তুলতেই আলোটা চোখে বাঁধলো। স্ক্রিনে ফুটে উঠল পরিচিত একটি নাম – ফুফা। দৃষ্টি তখনও ঝাপসা। ফোন কানে তুলতেই ওপাশ থেকে গমগমে কণ্ঠস্বর, \"জুনায়েদ, কি করছো?\" ঘুম জড়ানো গলায় জুনায়েদ জবাব দিলো, \"ঘুমাচ্ছিলাম আঙ্কেল। কিছু বলবেন?\" মাঝহার আলী শাহ-র কণ্ঠ শান্ত, \"আরে, তোমার তো এইচএসসি পরীক্ষা শেষ হলো, ভালো রেজাল্টও করেছো। শুনলাম এখন বেকার বসে আছো। আমাদের শোরুমে একজন ম্যানেজার দরকার। যদি চাও, তাহলে এই কাজটি করতে পারো।\" জুনায়েদ কিছুক্ষণ চুপ থেকে এদিক-ওদিক তাকালো, যেনো তার ভেতরের দ্বিধাটা অনুভব করার চেষ্টা করছে। তারপর বললো, \"আঙ্কেল, চাইলেই তো সব হয় না। আমি আব্বু-আম্মুর সঙ্গে কথা বলে আপনাকে জানাচ্ছি।\" মাঝহার আলী শাহ আর কোনো কথা না বলে ফোন কেটে দিলেন। জুনায়েদ আবারও ঘুমের গভীরে তলিয়ে গেলো, তার চিন্তাভাবনার মাঝেই হয়তো উঁকি দিচ্ছিলো নতুন এক দিগন্তের হাতছানি।\nসকাল তখন সাড়ে দশটা। মিষ্টি রোদ এসে পড়েছে জুনায়েদের ঘুমন্ত চোখে। \"জুনায়েদ! এই জুনায়েদ! উঠ!! ক''টা বাজে দেখেছিস? সাড়ে দশটা বাজে। তাড়াতাড়ি উঠ!\" মায়ের ডাকে ঘুম ভেঙে যায় তার। ধড়মড়িয়ে বিছানা থেকে উঠে, তাড়াহুড়ো করে ফ্রেশ হতে বাথরুমে ঢোকে জুনায়েদ।\nফ্রেশ হয়ে এসে, সকালের নাস্তার টেবিলে বসে মায়ের সাথে কথা বলতে শুরু করে জুনায়েদ। \"আম্মু! ফুফা কল দিয়েছিলো সকালে। বললো, তাদের শোরুমে নাকী ম্যানেজার লাগবে, সেই পোস্টে আমাকে জয়েন করতে।\" জুনায়েদের মা, জোহরা বেগম একটু অবাক হয়ে বললেন, \"বেশ তো! তোর ইচ্ছে হলে করবি। আমি আর তোর বাবা তো কোনোদিন তোকে জোর করে কিছু করতে বলি না।\" জুনায়েদ একটু শঙ্কিত হয়ে বললো, \"কিন্তু আম্মু, আমি চাকরি করতে চাই না। আমি বিজনেস করতে চাই, তা-ও নিজের যোগ্যতায়।\" জোহরা মুচকি হেসে উত্তর দিলেন, \"ঠিক আছে। তাহলে তোর ফুফাকে বলে দিস, তুই কাজটি করবি না। তাহলেই তো হয়।\" জুনায়েদ এবার একটু শান্ত হয়ে বলল, \"থ্যাংক ইউ, আম্মু। কাগজপত্র সবকিছু গুছিয়ে রেখেছো তো?\" জোহরা একটি ফাইল উঁচু করে ধরে বললেন, \"হ্যাঁ! এই যে, তোর সব কাগজপত্র এখানে। দেখ কি হয়।\" নাস্তা শেষ করে, জুনায়েদ জোহরার হাত থেকে ফাইলটা নিয়ে বললো, \"টিটিসি থেকে কম্পিউটার কোর্সটা কমপ্লিট করি, এরপর দেখি কি হয়। আপাতত এই কথা কাউকে বলার দরকার নেই। তুমি, আমি, আর আব্বুর মধ্যেই থাকুক।\" জোহরা, জুনায়েদের মাথায় হাত বুলিয়ে বললেন, \"আমাদের একমাত্র সন্তান তুই। তোর কোনো শখ আমরা অপূর্ণ রাখিনি, বাবা। এখন শুধু এটুকু দোয়া করি, তুই যেনো তাড়াতাড়ি সফল হতে পারিস।\" জুনায়েদ একগাল হেসে, ফাইল হাতে নিয়ে ঘর থেকে বেরিয়ে গেলো, তার ভবিষ্যৎ স্বপ্নের পথে এগিয়ে যাওয়ার প্রত্যয় নিয়ে।\nজুনায়েদের টিটিসিতে ভর্তি হওয়ার পর প্রথম দিনটি ছিলো বেশ উত্তেজনাপূর্ণ। টিটিসির গেট দিয়ে প্রবেশ করতেই তার চোখে পড়ে আধুনিক স্থাপত্যের এক বিশাল ভবন, যা তার কল্পনার থেকেও অনেক বেশি উন্নত। ক্লাসরুমগুলো ছিলো সুসজ্জিত, যেখানে অত্যাধুনিক কম্পিউটার এবং মাল্টিমিডিয়া প্রজেক্টর বসানো ছিলো। শিক্ষকদের আন্তরিক ব্যবহার এবং পড়ানোর মনোমুগ্ধকর পদ্ধতি জুনায়েদের মন জয় করে নেয়। ভর্তি হয়ে টিটিসি থেকে বাসায় ফিরে দেখে জুনায়েদের ফুপি জাহানারা খাতুন তাদের বাসায় এসেছে। \"আসসালামু আলাইকুম ফুপি! কেমন আছো?\" জিজ্ঞেস করলো জুনায়েদ। \"আলহামদুলিল্লাহ ভালো আছি। তুমি কেমন আছো?\" জাহানারা জিজ্ঞেস করলো। \"জ্বি ফুপি আমিও আলহামদুলিল্লাহ ভালো আছি।\" এতটুকু বলে জুনায়েদ নিজের রুমে যাবে তখনই জাহানারা পিছু ডাকে \"শুনলাম, তুমি নাকী টিটিসি''তে ভর্তি হয়েছো?\" জুনায়েদ শান্ত গলায় জবাব দিলো, \"হ্যাঁ ফুপি।\" জাহানারা আবারও বললো, \"তুমি তো জানো, ওই টিটিসি''টা ভালো না। ওখানে একবার গাড়ি এ*ক্সিডে*ন্টে শিক্ষার্থী আর স্যার মা*রা যাওয়ার পর থেকে অনেকে অনেক ভাবে ভয় পায়। টিটিসি''টা এত উন্নত হওয়া সত্ত্বেও মানুষ এত কম হয় কেনো? কারণ টিটিসি''টা ভালো না। আমিও তো তোমার ফুফাতো ভাই, সৃজনকে বাইরে থেকে ড্রাইভিং শিখিয়েছি। যেখানে এই টিটিসি কাছে। বাবা! তুমি ওই টিটিসি''তে আর যেও না।\" জুনায়েদ কোনো কথা না বলে নিজের রুমে চলে গেলো।  ফুপির কথায় জুনায়েদ কিছুটা দ্বিধাগ্রস্ত হলেও, টিটিসির পরিবেশ এবং সেখানকার মানুষের আন্তরিকতায় সে মুগ্ধ ছিলো।\nপরের কয়েকদিন জুনায়েদ টিটিসির প্রতিটি দিক ভালোভাবে পর্যবেক্ষণ করে। সে দেখে, ক্লাসে সবসময় শিক্ষার্থীদের উপচে পড়া ভিড়, সবার মধ্যে কাজ শেখার আগ্রহ, হাসি-ঠাট্টা আর বন্ধুত্বপূর্ণ সম্পর্ক। টিটিসির পরিবেশ সম্পর্কে ফুপির উদ্বেগের সঙ্গে বাস্তবতার কোনো মিল খুঁজে পায় না জুনায়েদ।\nপ্রতিদিনের মতো আজও ক্লাস শেষে জুনায়েদ বাড়ির উদ্দেশ্যে রওনা হয়। টিটিসি থেকে বের হয়ে সে মেইন রোড ধরে উত্তর দিকে হাঁটা শুরু করে। পাঁচ মিনিটের হাঁটা পথে সে একটা সরু ব্রিজের কাছে এসে পৌঁছায়। ব্রিজটি পেরোলেই শুরু হয় কাঁচা পথ, যা গ্রামের সবুজ আর শান্ত প্রকৃতির প্রতিচ্ছবি। আরও পাঁচ মিনিট হেঁটে সে একটা বিশাল ধানক্ষেতের কাছাকাছি আসে। দু''পাশে সবুজ ধানের ক্ষেত, মাঝে সরু পথ যেনো প্রকৃতির এক মনোমুগ্ধকর দৃশ্য। ক্ষেতের মাঝামাঝি স্থানে রয়েছে পুরনো একটি কব*রস্থান। জায়গাটা বেশ নির্জন এবং কিছুটা ছমছমে। দিনের আলোতেও অনেক মানুষ এখানে যেতে ভয় পায়। জুনায়েদ দ্রুত পায়ে কব*রস্থানটি পার হয়। এরপর ক্ষেতের পথ ধরে আরও সাত মিনিট হেঁটে সে অন্য একটি ছোট কব*রস্থানের সামনে এসে দাঁড়ায়। জায়গাটা আগেরটির মতোই শান্ত, তবে এর নীরবতা জুনায়েদের মনে অন্যরকম অনুভূতি দেয়। কব*রস্থানটি পেরিয়ে পাঁচ মিনিটের হাঁটা পথে সে তার নিজের বাড়ির কাছাকাছি পৌঁছে যায়। বাড়ির কাছাকাছি আসতেই তার মনে হয়, ফুপির উদ্বেগের কোনো ভিত্তি নেই। টিটিসি''র পরিবেশ, সেখানকার মানুষের আন্তরিকতা, আধুনিক শিক্ষা ব্যবস্থা সবকিছু জুনায়েদের কাছে দারুণ লাগে।\nজুনায়েদ রাতে শুয়ে আছে। চোখ বন্ধ দেখার মতো ভাব বী*ভৎ*স করতে শুরু করেছে। তার মনে আসছে, \"ওইদিন সকালে যখন আমি টিটিসি''তে ভর্তি হতে যাই তখন তো শুধুমাত্র আম্মুকেই বলে গেছিলাম। অথচ ফুপি কিভাবে জানলো যে আমি টিটিসি''তে ভর্তি হয়েছি?\" এই পরস্পরবিরোধী তথ্যগুলোকে ব্যাখ্যা করতে করতে, ভীষনভাবেই শুয়ে শুয়ে জুনায়েদ ভাবতে শুরু করে। পরক্ষণেই জুনায়েদ আবারও ভাবতে শুরু করে, \"আব্বু আর আম্মুর মুখে শুনেছিলাম, ফুপির সাথে জ্বি*ন আছে। সে নাকী জ্বি*ন পোষে। এক কথায় তাকে নাকী সবাই কবিরাজ নামে চিনতো। ফুফার দ্বিমতের কারণেই নাকী ফুপি কবিরাজি ছেড়ে দেন, কিন্তু এখনো নাকী তার সাথে জ্বি*ন আছে। হয়তো এই জ্বি*নের সাহায্যেই জানতে পেরেছেন।\" এসব ভাবতে ভাবতে জুনায়েদ কখন ঘুমিয়ে পড়ে নিজেও টের পায় না।"},{"id":"1775075523994-2","title":"02","slug":"part-02","content":"সকালের স্নিগ্ধ আলো তখনও পুরো ক্লাসরুমে পৌঁছায়নি, কিন্তু জুনায়েদ এর ক্লাস করতে আসা চাই। ক্লাসরুমে পা রাখতেই কেমন যেনো একটা অদ্ভুত নীরবতা অনুভব করলো সে। সাধারণত এই সময়ে ক্লাসরুম শিক্ষার্থীদের কোলাহলে মুখরিত থাকে, কিন্তু আজ… পুরো ক্লাস ফাঁকা! একটা মানুষও নেই! প্রথমে একটু অবাক হলো জুনায়েদ, তারপর ধীরে ধীরে তার কপালে চিন্তার ভাঁজ পড়তে শুরু করলো। সে কি তবে ভুল ক্লাসে এসে পড়েছে? নাকী আজ কোনো বিশেষ ছুটি? দ্রুত পায়ে নিজের সিটের দিকে এগিয়ে গেলো সে। সিটে বসতেই কেমন যেনো একটা শীতল অনুভূতি তার মেরুদণ্ড বেয়ে নামতে লাগলো। নিজের খাতা-কলম বের করে যখন সে কাজে মন দিয়েছে, ঠিক তখনই কানে এলো একটা শব্দ। প্রথমে মৃদু, কিন্তু কয়েক মুহূর্তের মধ্যেই তা স্পষ্ট হয়ে উঠলো, আর্তনাদ! শত শত মানুষের কান্নার শব্দ যেনো একসাথে মিশে যাচ্ছে। বুকটা ধড়ফড় করে উঠলো জুনায়েদের। শব্দটা আসছে কোথা থেকে? আশেপাশে তাকিয়েও কাউকে দেখতে পেলো না সে। আতঙ্কটা যখন গাঢ় হতে শুরু করেছে, তখনই ঘটলো সেই ভয়ঙ্কর ঘটনাটা। জুনায়েদের দৃষ্টি আটকে গেলো তার ডেস্কে। হ্যাঁ, ঠিক তার ডেস্কে! সে স্পষ্ট দেখতে পেলো, পুরো ক্লাসের মানুষগুলো তার বন্ধু, শিক্ষক, এমনকি যাদের সে ভালো করে চেনে না, তারাও!  সবাই যেনো আটকা পড়েছে ডেস্কে বন্দী অবস্থায়। তারা মুক্তি চাইছে, বাঁচানোর জন্য চিৎকার করছে, আর তাদের আর্তনাদ যেনো আকাশ-বাতাস ভারী করে তুলছে। \"বাঁচাও! প্লিজ, আমাদের বাঁচাও!\" কথাগুলো যেনো জুনায়েদের কানে অবিরাম বাজতে লাগলো। তার হাত-পা ঠান্ডা হয়ে এলো, শরীর কাঁপতে শুরু করলো। কি করবে বুঝতে পারছিলো না সে। কিভাবে বাঁচাবে তাদের? ডেস্কে বন্দী মানুষগুলোর অসহায় মুখগুলো যেনো তাকে পাগল করে তুলছিলো। সময় যেনো তার কাছে থমকে দাঁড়িয়েছে। আর্তনাদ বাড়ছে, আর সেই সাথে বাড়ছে জুনায়েদের অস্থিরতা। কপাল বেয়ে ঘাম ঝরতে শুরু করলো, হৃদস্পন্দন বেড়ে চললো কয়েকগুণ। মনে হচ্ছিলো, এই বুঝি তার কান ফেটে রক্ত বের হয়ে আসবে। ঠিক তখনই কেউ একজন তার কাঁধে হাত রাখলো। ভয়ে জমে গিয়েছিলো জুনায়েদ। আতঙ্কের চরম মুহূর্তে, তার শরীর যেনো পাথর হয়ে গিয়েছিলো। ধীরে ধীরে, কম্পিত হাতে সে পিছনে তাকালো। আর! তাকানোর পরেই তার মুখ দিয়ে একটা আর্তচিৎকার বেরিয়ে এলো……এবং তার চোখ খুলে গেলো।\nক্লাসের নিজের সিটে বসা অবস্থায় হাঁপাতে লাগলো জুনায়েদ। সারা শরীর ঘামে ভিজে গেছে। বুকের ধুকপুকুনি তখনও স্বাভাবিক হয়নি। পুরো ক্লাসটা তার কাছে কেমন যেনো অচেনা লাগছিলো। স্বপ্নের সেই বিভীষিকা এখনও তার মনে গেঁথে আছে। সে কি তবে কোনো ভয়ঙ্কর দুঃস্বপ্ন দেখছিলো? নাকি…\nসকালের মৃদু আলো তখন সবে চিরচেনা ভাব দেখা দিতে শুরু করেছে, বাইরে মিষ্টি সুরে ডেকে ওঠা পাখির কূজন জানান দিচ্ছিলো ঘুমের বিভীষণা কাটিয়ে ওঠা জুনায়েদ। কিছু মুহূর্ত আগের ঘটনার রেশ তখনও কাটেনি। সবে ঘুম থেকে উঠা শরীরটা হালকা ঘোরেও চিন্তার জাল বুনেছিলো। তখনও দুঃস্বপ্ন থেকে আসা আবেশ কাটাতে পারেনি। আচমকা কানে আসে এক বিকট শব্দ। মৃদু গোলের শব্দ শুনেই জুনায়েদ বুঝতে পারে কিছু একটা ঘটেছে। শব্দটা আসছে দোতলা থেকে। দোতলার ক্লাসরুম থেকে। ঘুমের ঘোর তখনও পুরোপুরি কাটেনি, এমন অবস্থায় জুনায়েদ উঠে দাঁড়ালো। চোখের ঘুম ঘুম ভাব নিয়েই সে দ্রুত সিঁড়ি বেয়ে নিচে নামতে শুরু করে। নিচে গিয়ে দেখে অনেকেই ব্যস্ত ভঙ্গিতে ছোটাছুটি করছে। তাদের মধ্যে কেউ একজনের কাছে এগিয়ে গিয়ে জিজ্ঞেস করলো। \"কি হয়েছে? কি হয়েছে?\" আতঙ্কিত কণ্ঠে ছেলেটি জবাব দিলো, \"সুইং মেশিনের ক্লাসে, একজন প্রশিক্ষণার্থী ইনজুরড হয়েছে। মেশিনের সমস্যা সারানোর সময় ঘটনাটি ঘটে। ঘটনার পর তার হাতের আঙ্গুলগুলো থেঁতলে গেছে।\" কথাগুলো তখনও শেষ না হতেই জুনায়েদ দৌড়ে সুইং মেশিনের ক্লাসে যায়। ছুটে গিয়ে দেখে, ক্লাসরুমের ভেতরের দৃশ্যটা ভয়াবহ। সেখানে সবাই ভীড় করে আছে, আর আহত অবস্থায় পড়ে আছে একজন। তার হাতের আঙ্গুলগুলো দিয়ে রক্ত ঝরছে। চারিদিকে একটা ভীতিকর নীরবতা বিরাজ করছে। আহত অবস্থায় থাকা ছেলেটিকে ধরাধরি করে হাসপাতালে নিয়ে যাওয়া হলো। চারিদিকে আতঙ্কের রোল। সেই ভয়াবহ দৃশ্যটা দেখে জুনায়েদের শরীর এখনো শিরদাঁড়া দিয়ে বয়ে যাওয়া ঠান্ডা স্রোত অনুভব করছে।\nসকালের মিষ্টি আলো তখনও পুরো ক্লাসরুম জুড়ে ভালো করে ছড়াতে পারেনি, এর মধ্যেই শেষ হওয়া ক্লাস থেকে বের হয়ে আসে জুনায়েদ। ঘড়িতে তখন বেলা প্রায় বারোটা। আকাশের কড়া রোদ উপেক্ষা করে, সে যখন গেটের দিকে যাচ্ছিলো, তখন তার চোখ আটকে গেলো একটা ব্যানারের উপর। \"অ্যাসেট প্রজেক্ট\"। প্রথমে বিষয়টা তার কাছে পরিষ্কার ছিলো না, কিন্তু ভালোভাবে দেখার পর জানতে পারলো, এই প্রজেক্টে প্রশিক্ষণ নিলে, পরীক্ষার পর সরকার কিছু টাকা দেবে। জুনায়েদের বুকের ভেতরটা কেমন যেনো কৌতূহলে ভরে উঠলো। আজই ছিলো ফরম জমা দেওয়ার শেষ তারিখ। জুনায়েদ দেরি না করে, দ্রুততার সাথে একটা ফরম সংগ্রহ করলো। ফরম পূরণ করে, সে দ্রুত তা জমা দিয়ে আসে। জুনায়েদের চোখেমুখে তখন রাজ্যের বিস্ময়। ফর্ম জমা দেওয়ার পর, জুনায়েদের মনে হলো, এবার হয়তো জীবনটা একটু অন্যরকম হবে। সে এখন নিয়মিত কম্পিউটার কোর্সের ছাত্র। সকাল নয়টা থেকে দুপুর বারোটা পর্যন্ত চলে তার ক্লাস। কিন্তু এবার সে ইলেকট্রিক্যাল কোর্সেও নাম লিখিয়েছে। আগামী মাসের দুই তারিখ থেকে এই কোর্স শুরু হবে। দুপুর বারোটা থেকে সন্ধ্যা ছয়টা পর্যন্ত চলবে ক্লাস। দুই তারিখ থেকে সকাল নয়টা থেকে সন্ধ্যা ছয়টা পর্যন্ত তার ক্লাস চলবে। একদিকে যেমন কাজ শেখা হবে, তেমন অন্যদিকে কিছু টাকাও পাওয়া যাবে।\nক্লাস শেষ করে ক্লান্ত জুনায়েদ প্রতিদিনের মতোই বাড়ির পথ ধরে। বাইরের কোলাহল আর গরম আবহাওয়া থেকে মুক্তি পেতে তার মনটা ব্যাকুল হয়ে উঠে। দরজার ওপাশে একটু শান্তির আশায় সে দ্রুত পায়ে ঘরে ঢোকে। ভেতরে ঢুকতেই দেখে, তার ফুপি জাহানারা এসেছেন। জাহানার গম্ভীর মুখ, চিন্তিত দৃষ্টি আর উদ্বেগের ছাপ স্পষ্ট। তার উপস্থিতি যেনো একটা সতর্কবার্তার মতো। \"সুইং মেশিনের ক্লাসে একজন ইনজুরি হয়েছে?\" উদ্বেগের সঙ্গে জাহানারা প্রশ্ন করেন। জুনায়েদের কণ্ঠস্বর কিছুটা দ্বিধাগ্রস্ত, \"হ্যাঁ\"। জাহানারা উদ্বেগের স্বরে বাধা দিয়ে বলেন, \"এখনও সময় আছে, ওই টিটিসি ছেড়ে দে। সামনে যে তোর কোনো বিপদ হবে না, তার কি কোনো নিশ্চয়তা আছে? তুই আমার ভাইয়ের একমাত্র ছেলে, তোর কিছু হলে আমার ভাইটা আর বাঁচবে না। আমি আর কিছু বলতে চাই না। তোর তো এখন যথেষ্ট বয়স হয়েছে, ভালো-মন্দ বোঝার মতো।\" তার প্রতিটি কথায় গভীর আবেগ, ভাইয়ের প্রতি ভালোবাসা আর জুনায়েদের ভবিষ্যতের চিন্তা ফুটে উঠে। জাহানারা আঁচল দিয়ে মুখ ঢেকে চলে যায়। জাহানারা চলে যাওয়ার পর, জুনায়েদের মা জোহরা সেখানে আসেন। জোহরার চোখেমুখে উদ্বেগের ছাপ, তবে কণ্ঠ শান্ত। তিনি প্রশ্ন করলেন, \"কি বলছিলো তোর ফুপি?\" জুনায়েদ মায়ের উদ্বেগকে হালকা করার জন্য কণ্ঠে দৃঢ়তা নিয়ে বললো, \"তেমন কিছু না। শোনো, আগামী মাস থেকে আমি দুপুর বারোটা থেকে আরও একটা কোর্স করবো।\" এই কথা বলার পর, সে আর কোনো কথা বাড়ায় না। নিজের ঘরে চলে যায়, যেনো তার ভেতরের দ্বিধা আর উদ্বেগকে কিছুটা আড়াল করতে চায়।\n___________________\nরাত তখন এগারোটা ছুঁই ছুঁই। জুনায়েদের অস্থির মনটা কিছুতেই শান্ত হতে চাচ্ছিলো না। তার মনে হচ্ছিলো, ঘরবন্দী জীবন তাকে অতিষ্ঠ করে তুলেছিলো। অথচ সে সবসময় নিজের স্বাধীনতা নিয়েই চলাফেরা করে বড় হয়েছে। আজও তার ব্যতিক্রম হলো না, তাই একটু মুক্ত বাতাসের খোঁজে সে ঘর থেকে বের হলো। উদ্দেশ্য, রাতের নিস্তব্ধতা উপভোগ করা আর প্রকৃতির কাছাকাছি আসা। মাঠ-ঘাট ঘুরে, রাতের স্নিগ্ধতা অনুভব করে জুনায়েদের মনটা কিছুটা শান্ত হলো, কিন্তু পুরোপুরি শান্তি যেনো পাচ্ছিলো না। \nফিরে আসার পথে, যখন ঘড়ির কাঁটা সাড়ে বারোটা ছুঁই ছুঁই, এলাকাটা জনমানবশূন্য হয়ে আসছিলো। রাস্তার পাশে পুরনো বিশাল গাছগুলো রাতের অন্ধকারে গাঢ় ছায়া ফেলছিলো, আর জঙ্গলের ঝোপঝাড়গুলো যেনো এক রহস্যময় পরিবেশ সৃষ্টি করছিলো। হঠাৎ, জুনায়েদের কানে এলো একটা কান্নার আওয়াজ। শব্দটা আসছিলো রাস্তার পাশের সেই গাছগুলোর দিক থেকে। একজন মহিলার কণ্ঠস্বর, তীব্র আর্তনাদ যেনো রাতের নীরবতাকে খান খান করে দিচ্ছিলো। আশ্চর্যজনক ব্যাপার হলো, এত রাতে সেখানে কোনো মানুষের চিহ্ন নেই। আশেপাশে জনবসতিও তেমন একটা নেই যে কেউ জেগে থাকবে। জুনায়েদের শিরদাঁড়া দিয়ে একটা শীতল স্রোত বয়ে গেলো। ভয়ে বুকটা ধড়ফড় করতে শুরু করলো। কান্নার আওয়াজটা একটানা বাজছে, একটুও কমছে না। জুনায়েদ সেখান থেকে দ্রুত পালাতে চাইলো, কিন্তু তার পা যেনো মাটির সাথে গেঁথে গেছে। শরীর অবশ হয়ে আসছিলো, যেনো অদৃশ্য কোনো শক্তি তাকে সেখানে আটকে রেখেছে। যেনো অন্য কোনো জগতে প্রবেশ করেছে সে। সময় যেনো থমকে দাঁড়িয়েছে। টেনশনে তার অবস্থা কাহিল হয়ে উঠলো। কান্নার আওয়াজ ক্রমশ বাড়ছে, আর সেই সাথে অদৃশ্য কোনো হাত যেনো তার পা-গুলো আরও শক্ত করে চেপে ধরছে। জুনায়েদ প্রাণপণে নিজেকে মুক্ত করার চেষ্টা করতে লাগলো, কিন্তু কিছুতেই পারছিলো না। অনেকক্ষণ পর, এক অলৌকিক শক্তির টানেই হয়তো, সে সেই ঘোর থেকে মুক্তি পেলো। কোনোমতে দৌড়ে সে বাসায় ফিরে এলো। শরীরে তখন রাজ্যের ক্লান্তি, যেনো বিশাল এক বোঝা কাঁধ থেকে নামিয়ে রেখেছে। কারো সাথে কোনো কথা বলার শক্তিটুকুও যেনো তার ছিলো না। সোজা নিজের ঘরে ঢুকে, বিছানায় এলিয়ে পড়লো জুনায়েদ।\nক্লান্ত শরীরে জুনায়েদ বিছানায় আশ্রয় নিলো। ক্লান্ত শরীরেও ঘুমের লেশমাত্র নেই তার চোখে। বিছানার একপাশে সে শুয়ে ছিলো, মাঝখানে কোলবালিশ আর অন্য পাশটা ফাঁকা। গভীর রাতেও তার ঘুম আসছে না। অবশেষে, অনেক চেষ্টার পর যখন একটু ঘুম ঘুম ভাব এলো, রাত তখন দেড়টা বাজে। ঘুমের মধ্যেই হঠাৎ জুনায়েদ শুনতে পেলো, তার কোলবালিশের ওপরের পাশে, যেনো কোনো মেয়ে, নাকি-সুরে কাঁদছে। ভয়ে জুনায়েদের হাত-পা ঠান্ডা হয়ে এলো। এত''টাই ভয় পেয়েছিলো যে, সে কোলবালিশের ওই দিকে তাকানোর সাহসটুকুও পাচ্ছিলো না। সময় যত যাচ্ছিলো, কান্নার শব্দটা যেনো আরো তীব্র থেকে তীব্রতর হচ্ছিলো। শরীর যেনো বরফের মতো ঠান্ডা হয়ে যাচ্ছিলো, আর বুকের ভেতরটা ধুকপুক করতে শুরু করলো। মনে হচ্ছিলো, এই বুঝি হৃদস্পন্দন বন্ধ হয়ে যাবে। ভয়ে দিশেহারা হয়ে জুনায়েদ চিৎকার করতে যাবে, ঠিক তখনই অনুভব করলো কেউ যেনো তার মুখ চেপে ধরেছে। কোনো শব্দ বের হচ্ছে না, নিস্তব্ধতা যেনো আরও গভীর হলো। জুনায়েদ অনুভব করলো, তার শরীর ক্রমশ অবশ হয়ে আসছে। মনে হচ্ছিলো, এই বুঝি তার হৃৎস্পন্দন থেমে যাবে। হঠাৎ, কান্নার শব্দটা ক্ষীণ হয়ে এলো, যেনো দূরে সরে যাচ্ছে। জুনায়েদ তখনও নড়াচড়া করতে পারছিলো না। কিছুক্ষণ পর, পরিস্থিতি শান্ত হয়ে এলো, যেনো কিছুই ঘটেনি। জুনায়েদ কোনোমতে ফোনটা হাতে নিয়ে ফ্ল্যাশ অন করলো, পুরো ঘরটা ভালো করে দেখলো। সবকিছু স্বাভাবিক। এরপর, নিজেকে শান্ত করে এক গ্লাস পানি খেলো এবং আবার বিছানায় ফিরে এলো। রাতের নীরবতা তখনও ভাঙেনি, তবে জুনায়েদের মনে অজানা এক আতঙ্ক বাসা বেঁধেছিলো।"},{"id":"1775075540827-3","title":"03","slug":"part-03","content":"কাটাখালীর বিশাল মাঠে আজ অনেক দিন পর বের হলো জুনায়েদ। মাঠের সৌন্দর্য ছিলো অপরূপ। সোনালি রোদ্দুরে স্নিগ্ধ ঘাসের ওপর জলবিন্দুর মতো ঝরে পড়ছিলো সকালবেলা। পাখিদের গান সব মিলিয়ে একটি শান্তির আবহ তৈরি করেছিলো। কিন্তু জুনায়েদের মনে ছিলো একটি অস্বস্তি, তার মানসিক চাপ যেনো এই পবিত্র পরিবেশকেও ভীষণ অশান্ত করে রেখেছিলো।\nহঠাৎ, মাঠের এক প্রান্তে শ্রবণেন্দ্রিয়কে আঘাত করলো গরুর জবাইয়ের দৃশ্য। কিছু লোক মিলে একত্রে একটি গরু জবাই করছিলো।  জুনায়েদ অস্থির হয়ে অন্য দিকে মুখ ঘুরালো। দৃষ্টি চলে গেলো মাঠের অপর প্রান্তের দিকে, যেখানে কিছু মানুষ কারো একজনের জানাজা পড়াচ্ছিলো। হৃদয়ের চাপবোধে সে সেদিকে এগিয়ে গেলো। কিন্তু অদূরে গিয়ে দেখলো, জানাজা শেষ হয়ে গেছে।\nআচমকা, সে দেখতে পায়, চার পাঁচজন লোক মিলে লাশটিকে দুলাতে দুলাতে একটি ট্রাকের দিকে নিয়ে যাচ্ছে। সুন্দরতাটি দ্রুত তার চোখের সামনে অধঃপাতে গেলো। লাশটি ট্রাকে মধ্যে ধপাস করে ফেলে দিলো। আর অস্বাভাবিক হাসিতে চারপাশে গমগম করে উঠলো। জুনায়েদ আতঙ্কিত হলো। কী এমন অমানবিকতায় তারা মত্ত! সে লাশটার পরিচয় খুঁজতে তাড়াহুড়া করে এগোতে শুরু করলো। সেই মুহূর্তে, তার চোখের সামনে একটি বিশাল দরজা উঠলো, আর বাইরে থেকে মানুষগুলো তা বন্ধ করার প্রস্তুতি নিতে লাগলো। জুনায়েদ দ্রুত দৌড়াতে লাগলো। এই সময়ে সাত আটটি শক্তিশালী হাত পিছন থেকে ধরে ফেললো। একই সঙ্গে অস্বাভাবিক হাসির আওয়াজ তার কানে আসতে লাগলো। তাদের ভাষা ছিলো অচেনা, কিন্তু আসল কথা হলো, সেখান থেকে তাকে মুক্ত হওয়া সম্ভব ছিলো না। বরাবরই জীবন থেকে মুক্ত হয়ে যাওয়ার অতুলনীয় বর্তমান অনুভূতির জন্য সে ঝাপটাঝাপটি করতে থাকলো। কয়েক মুহূর্ত পেরিয়ে গেলে, অবশেষে সে নিজেকে মুক্ত করতে সক্ষম হলো। দরজা বন্ধ হওয়ার আগে দ্রুত ট্রাকের সামনে গিয়ে দাঁড়ালো। ঠাণ্ডার ঘাম কপাল থেকে পড়তে থাকলো। সে হাত বাড়িয়ে লাশের মুখ থেকে কাপড়টি সরিয়ে দিলো। কাপড় সরিয়ে জুনায়েদ দেখতো পায় এটা তার নিজেরই লাশ। ভয়াবহ আতঙ্কে সে এক চিৎকার দেয়। আচমকা তার চোখ খুলে গেলো। সে নিজের ঘরে, নিঃশব্দ। বুঝতে পারলো, এটি ছিলো কেবল একটি দুঃস্বপ্ন। \nহঠাৎ ঘুম ভাঙতেই জুনায়েদ অস্থির হয়ে হাঁপাতে থাকে। তার কপাল বেয়ে হিমশীতল শ্রোত বইছে। নাকের ডগায় শিশিরবিন্দুর মতো ছোট ছোট ঘামের ফোঁটা দেখা যাচ্ছে। ঘন ঘন নিঃশ্বাস ফেলছে। নিজেকে শান্ত করার জন্য বার বার ঢোক গিলে। ভয়টা কিছুতেই কাটছে না। নিজেকে কিছুটা সান্ত্বনা দিয়ে আবারও ঘুমানোর চেষ্টা করে, তখনই শুনে বাইরে কারো কান্নার আওয়াজ। একটু হতবাক হয়ে মনে মনে ভাবলো, \"ওইদিন টিটিসি''তে দূর্ঘটনা ঘটার পর থেকেই আমার সাথে এমন আজগুবি ঘটনা ঘটছে। তাহলে কি ফুপির বলা কথাগুলো সত্যি ছিলো? আমার কি ফুপির কথা শোনা উচিৎ ছিলো?\" এসব ভাবতে ভাবতে জুনায়েদ নিজের ঘর থেকে বের হয়, কান্নার শব্দটা কোত্থেকে আসছে দেখার জন্য।  \nবাইরে ঘুটঘুটে অন্ধকার। রাত তখন গভীর।  কান্নার কান্নার শব্দটা তখনও ভেসে আসছে। শব্দের পিছু ছুটতে ছুটতে বাসা থেকে বের হয়ে রাস্তার ধারে এসে দাঁড়ায় জুনায়েদ। রাস্তার পাশ ধরে হাঁটছে, তার চোখ জোরা সেই কান্নার উৎস খুঁজে বেড়াচ্ছে। তখনই জুনায়েদের ফোনটা বেজে উঠলো। ফোনের স্ক্রিনে দেখতে পেলো \"সৃজন\" কল করেছে। জুনায়েদের ফুফাতো ভাই। তাড়াতাড়ি কল রিসিভ করলো জুনায়েদ।  \n\"কিরে ঘুমাসনি?\" কল রিসিভ করার সাথে সাথে প্রশ্ন করলো সৃজন।\n\"ঘুমিয়ে থাকলে কি তোর কল রিসিভ করতাম?\" পাল্টা প্রশ্ন করলো জুনায়েদ। \n\"তা অবশ্য ঠিক। তুই ঘুমিয়ে থাকলে কখনোই কল রিসিভ করিস না। তা কি করছিস এখন?\" আবারও প্রশ্ন করলো সৃজন। \n\"এই তো একটু বাইরে দাঁড়িয়ে আছি। খোলা আকাশের নিচে। তুই কি করিস? এত রাতে এখনো ঘুমাসনি কেনো?\" রাস্তার ধারে সবুজ ঘাসের ক্রোড়ে বসতে বসতে বললো জুনায়েদ। \n\"আ-আমার ঘুম আসছিলো না। গেম খেলছিলাম। ভাবলাম তোকে একটা কল করি। যাই হোক, এত রাতে বাইরে কি করছিস?\" সৃজন আবারও প্রশ্ন করলো।\nসৃজনের প্রশ্নটা জুনায়েদ খেয়াল করলো না। তার মনে হলো, এই মাত্র তার সামনে দিয়ে কেউ একজন হেঁটে গেলো। সাদা জোব্বা পরিহিত লম্বা কোনো পুরুষাবয়ম। মাথায় বড় রুমাল পেঁচানো। যেনো কোনো সূফী সাহেব। হাতে একটা বড় লাঠি। যেনো কাউকে ধাওয়া করছে। জুনায়েদ অপলকভাবে তাকিয়ে রইলো সেই পুরুষাবয়ম''টার দিকে।\n\"কিরে? কথা বলছিস না কেনো?\" সৃজনের কথায় আবারও হুঁশ ফিরলো জুনায়েদের। \n\"হ্যাঁ? কিচ্ছু বললি আমায়?\" আমতা আমতা করে জিজ্ঞেস করলো জুনায়েদ। \n\"এতক্ষণ তাহলে কার সাথে কথা বলছি আমি? জিজ্ঞেস করলাম তুই নাকী টিটিসি''তে অ্যাসেট ব্যাচে ভর্তি হয়েছিস?\" একটু কঠিন স্বরে জিজ্ঞেস করলো সৃজন। \n\"হ্যাঁ! আজাইরা সনয় কাটে না, তাছাড়া ওখানে খুব মজা হয়। কাল থেকে অ্যাসের ব্যাচের ক্লাস শুরু।\" উত্তরে বললো জুনায়েদ। \n\"আচ্ছা! মন দিয়ে ক্লাস কর। আর যত্ন নিস নিজের। আল্লাহ হাফেজ।\" কথা শেষ করেই কল কেটে দিলো সৃজন।\nসৃজনের কল কাটার পর জুনায়েদ কিছু মুহূর্ত পূর্বের কথা মনে কথা লাগলো। আসলেই কি কেউ তার সামনে দিয়ে হেঁটে গেলো নাকী সবটাই তার মনের ভুল?\n_\n\"আম্মু! আমি ক্লাসের জন্য বের হচ্ছি। দুপুরে লাঞ্চ ব্রেকে আসতেও পারি আবারও না-ও আসতে পারি।\" বাসা থেকে বের হতে হতে মাকে ডেকে বলে যাচ্ছে জুনায়েদ। \n\"আচ্ছা! সাবধানে যাস।\" ছেলের ডাকে সায় দিয়ে জানান দিলো জোহরা। \nমাকে বিদায় জানিয়ে টিটিসি''র উদ্দেশ্যে বের হলো জুনায়েদ। টিটিসি''তে পৌঁছেই কম্পিউটার ক্লাস অ্যাটেন্ড করলো জুনায়েদ। কিছুক্ষণ পরেই ইলেকট্রিক্যাল ক্লাস শুরু হবে তার। আজকে প্রথম দিন। খুব উৎসুক হয়ে আছে জুনায়েদ। \n_\nদুপুর বারোটা বেজে ছয় মিনিট। জুনায়েদ বসে আছে নতুন ক্লাসে। পুরো ক্লাসে ত্রিশ জনেরও বেশি মানুষ উপস্থিত। ক্লাস টিচার সাইদুল সিকদার লেকচার দিচ্ছেন, এখানে কি কি কাজ শেখানো হবে, কোন কোন কাজ কতদিন ধরে শেখানো হবে, আর সব রুলস ও রেজুলেশন সবাইকে বুঝিয়ে দিচ্ছে। জুনায়েদ মনযোগ দিয়ে সব কথা শুনছে। বরাবরই সে একজন মনোযোগী ছাত্র। কম্পিউটার ক্লাসে ভর্তি হয়ে নতুন নতুন অনেক মানুষের সাথে বন্ধুত্ব হয়েছে। এখানে অসংখ্য নতুন মুখ দেখতে পাচ্ছে জুনায়েদ।  তবে, এই মুখগুলো যেনো একে অপরকে নিয়ে একটু বেশিই ব্যস্ত। তারা যেনো আগে থেকেই একে অপরকে চিনে। মুহূর্তেই বুঝতে পারলো, এরা আসলেই সবাই সবাইকে চিনে। তাদের মধ্যে আগে থেকেই পরিচিত। তাদের দিক থেকে একমাত্র নতুন মুখ হচ্ছে জুনায়েদই। প্রথম ক্লাসটা কোনো রকম শেষ হয়ে গেলো। \nবিকেল গড়িয়ে সন্ধ্যা নেমে এসেছে। জুনায়েদ ধীরে ধীরে বাড়ির পথ জমিয়েছে। আপন মনে গান গাচ্ছে। হাঁটতে হাঁটতে যখন সে ক্ষেতের মাঝের কবরস্থানের সামনে গিয়ে পৌঁছায় তখন তার শরীর আচমকা অস্বাভাবিক ভাবে ভারি হতে শুরু করে, যেনো কেউ শক্ত করে তার শরীরে আটকে আছে। এরপরও নিজেকে স্থির করে পা বাড়ায় জুনায়েদ। হাঁটতে হাঁটতে হঠাৎ পিছন থেকে কেউ যেনো তাকে ডাকছে। সবকিছু উপেক্ষা করে সে বাড়ি পৌঁছায়।\n_\n\"আম্মু! আম্মু! আমার ফোনটা কোথায়? খুঁজে পাচ্ছি না তো?\" সজোরে চিৎকার করে ডেকে চলেছে জুনায়েদ।\n\"দেখ তোর পড়ার টেবিলের উপর রেখেছি।\" রান্নাঘর থেকে জোহরা জবাব দিলেন। মায়ের কথা মতো পড়ার টেবিলের উপর তন্নতন্ন করে খুঁজেও ফোন পেলো না জুনায়েদ। বাধ্য হয়ে নিজের ঘরের প্রতিটা কোণা খুঁজে দেখলো। তা-ও কোত্থাও পেলো না। এরপর মায়ের ঘরে গিয়ে খুঁজে। সেখানেও পাচ্ছে না। \n\"আশ্চর্য! ফোনটা গেলো কোথায়? আম্মু! আমি কিন্তু এখনো ফোনটা পাইনি।\" রাগান্বিত কণ্ঠে চেচাচ্ছে জুনায়েদ। \n\"তোর পড়ার টেবিলের উপরে দেখ ভালো করে।\" উত্তরে বলে জোহরা। এবার জুনায়েদ একটু ক্ষিপ্ত সুরে বলে, \"পুরো বাড়ি তন্নতন্ন করে খুঁজেও পেলাম না তো। ক্লাসের জন্য দেরি হয়ে যাচ্ছি তো!\" বলেই নিজের ঘরে পা বাড়ায় জুনায়েদ। ঘরে পা রাখতেই তার চোখ আটকে যায় পড়ার টেবিলের উপর। ফোনটা টেবিলের উপরেই পড়ে আছে। কিন্তু কিছুক্ষণ আগেও তো এই জায়গায় তন্নতন্ন করে খুঁজলো। \"যাই হোক, হয়তো খেয়াল করিনি। আম্মুওওওও! ফোন পেয়েছি। আমি টিটিসি''তে গেলাম।\" মাকে ডেকে বিদায় জানালো জুনায়েদ। \nকাঁধে ব্যাগ ঝুলিয়ে ধীর পায়ে হাঁটতে লাগলো জুনায়েদ। প্রতিটা সকাল তার কাছে এক নতুন পথচলা। \"জীবন যদি সত্যিই এতটাই সহজ হতো, যতটা সহজ ভাবে আমরা কল্পনা করি।\" হঠাৎ মাঝপথে থেমে গিয়ে মনে মনে বললো জুনায়েদ। তার চোখে আটকে গেলো, দূরের গাছের মগডালে বসে থাকা একজোড়া পাখি। \"যদি পুনর্জন্ম বলে কিছু থেকে থাকে, তাহলে আমি চাইবো পাখি হয়ে জন্মাতে। ডানা মেলে অসীম আকাশে উড়ে বেড়াবো। যখন যেখানে খুশি উড়ে উড়ে চলে যাবো। বাঁধা দেওয়ার কেউ থাকবে না। অতিথি পাখি হয়ে দেশ-দেশান্তরে ঘুরবো।\" একটু শব্দ করে হেসে উঠলো জুনায়েদ। \"কল্পনা সত্যি কত সৌখিন হয় তাই না, আমরা কল্পনায় নিজের সুখ খুঁজে নিতে পারলেও বাস্তবে পারি না।\" নিষ্পলক দৃষ্টিতে এখনো পাখি জোড়ার দিকে তাকিয়ে আছে জুনায়েদ। \"এতটুকু জীবনে বুঝতে পেরেছি, চলার পথে একটা বিশ্বস্ত কাঁধের প্রয়োজন। যে কাঁধ আমার ক্লান্তিকর মাথাকে আশ্রয় দিবে। ঠিক যেমন একটি পাখি আরেকটি পাখির ডানায় মুখ লুকায়।\" কথাটুকু বলতে বলতেই পাখি দু''টো ডাল ছেড়ে উড়ে চলে গেলো। জুনায়েদও নিজের পথে চলতে লাগলো। চলতে চলতে সে তার গন্তব্যস্থানে পৌঁছায়। \"আমরা কি অদ্ভুত! যখন যে জায়গায় যাই, ওই জায়গাকেই গন্তব্য বলে দাবী করি। অথচ আমাদের আসল গন্তব্য কোথায় নিজেরাও জানি না।\" এক গাল মুচকি হেসে টিটিসি''তে প্রবেশ করলো জুনায়েদ।  \nপ্রথমেই সে কম্পিউটার ক্লাসে গেলো। আজকে পুরো ক্লাসটা একটু অন্য রকম লাগছে। সবকিছু ঠিকই আছে তবুও তার কাছে নতুন মনপ হচ্ছে। বাইরে থেকে এক ঝলক বিস্মিতা আলো প্রবেশ করেছে জুনায়েদের ডেস্কে। হাতের কাজ থামিয়ে দিয়ে, জানালা দিয়ে বাইরে তাকায়। আকাশের মেঘগুলো স্থির হয়ে আছে। সূর্যটা ঝলমল করছে। \"একটা পর্যায়ে গিয়ে আমরা প্রত্যেকেই ওই মেঘের মতোই থমকে যাই। ঠিক যখনই নিজেকে সামলে নিতে পারি তখনই সূর্যের মতো ঝলমলে হাসতে পারি।\" আজকে যেনো জুনায়েদ নিজেকে নতুন রূপে রূপান্তরিত করছে। তার কাছে সবকিছুই নতুন মনে হচ্ছে। তার ভাবনাগুলো নতুন রঙ খুঁজে পাচ্ছে। যা দেখছে তাই ভালো লাগছে। \n_\nবারোটা আঠারো! ইলেকট্রিক্যাল ক্লাসে বসে বসে সার্কিট ডায়াগ্রাম আঁকছে জুনায়েদ। সাইদুল স্যার এলইডি টিভিতে দেখিয়ে দিচ্ছে কিভাবে আঁকতে হবে সার্কিট ডায়াগ্রাম। সেটাই দেখাদেখি করে সবাই আঁকছে। তবে প্রথম দিন যেমন ত্রিশ জনের উপরে মানুষ হয়েছিলো, তেমনই দ্বিতীয় দিন থেকে মানুষ কমতে শুরু করে। বর্তমানে তাদের ক্লাসে একুশ জন ছাত্র আছে। কিছুক্ষণ আগেই সাইদুল স্যার সবাইকে বললো, পঁচিশ ছাত্র পূরণ হলেই উনি রেজিস্ট্রেশনের কাজ শুরু করবে। প্রত্যেকটা ট্রেডে রেজিষ্ট্রেশন শুরু হয়ে গেছে। শুধুমাত্র ইলেকট্রিক্যাল ট্রেডেই স্টুডেন্টের সংখ্যা কম থাকায় রেজিষ্ট্রেশন শুরু হয়নি। \nইলেকট্রিক্যাল ক্লাসে ভর্তি হওয়ার পর কারো সাথেই তেমন আলাপ হয়নি জুনায়েদের। সবাই সবার মতো ব্যস্ত। অতি প্রয়োজন হলে একজন আরেক জনের সাথে কথা বলে।  \"চারপাশে মানুষ আছে মানেই আমি কোলাহলে নেই। মনের মধ্যে যদি একাকিত্ব বাস করে তাহলে বাইরের কোলাহল কিছুতেই মনকে হালকা করতে পারে না।\" কি মনে করে যেনো জুনায়েদ কথাটুকু তার খাতার প্রথম পৃষ্ঠা বড় বড় অক্ষরে লিখলো। \nআজকে ক্লাস শেষ হতে হতে অনেকটা দেরি হয়ে গেছে। সন্ধ্যা গড়িয়ে আকাশে রাতের আঁধার নেমে আসছে। হালকা হালকা কুয়াশা দেখা দিয়েছে। শীতের নরম ছোঁয়া লাগছে প্রকৃতিতে। এক অন্য রকম ভালো লাগা কাজ করে। \"শীতের সন্ধ্যা মানেই স্নিগ্ধ চাঁদের আলোয় কুয়াশাময় পথের বাঁকে শিশিরবিন্দুর ছোঁয়া।\" একটা মুচকি হাসি দিয়ে বললো জুনায়েদ। \nআনমনে পথ চলছে জুনায়েদ। পথ চলতে চলতে সে এখন ক্ষেতের খুব কাছাকাছি। মৃদু চাঁদের আলোয় চারিপাশটা একটু অদ্ভুত সুন্দর লাগছে। \"জীবন যদি আঁধারের অতলে হারিয়ে যায়, চাঁদের এই মৃদু আলোই আমাকে পথ দেখায়।\" মনে মনে বললো জুনায়েদ। আবারও এক পা এক পা করে এগোতে থাকে। হঠাৎ তার কানের সামনে ফিসফিসে গলায় কেউ বলছে, \"যাস না! যাস না! বিপদ আছে। যাস না!\" বারংবার শব্দটা তার কানে ভাসতে থাকে। সে নিজের মনের ভুল ভেবে উপেক্ষা করে বিষয়টা। সামনে এগিয়ে যায়। যখন সে ক্ষেতের মাঝের কবরস্থানের পাশে এসে থামে তখন, \"এই সময় এখানে কি করছো তুমি?\" একজন মধ্যবয়স্ক লোক, সাদা জোব্বা পরিহিত, হাতে লাঠি মাথায় বড় রুমাল পেঁচানো। জিজ্ঞেস করলো জুনায়েদকে। \n\"আ-আমি বাসায় যাচ্ছি।\" জুনায়েদ একটু চমকে গিয়ে বললো। \n\"তুমি জানো না, এই জায়গাটা ভালো না? এই সময় এখান দিয়ে কেনো এসেছো?\" লোকটা আবারও প্রশ্ন করলো।\n\"হ্যাঁ, জানি। আর আমার বাসা সামনেই। আমার কোনো সমস্যা হবে না আশা করি।\" উত্তরে বললো জুনায়েদ। \n\"সমস্যা কার কখন কিভাবে হয়ে যায় তা তো আমরা বলতে পারি না। কেউ রাজ কপাল নিয়ে জন্মেও ভিক্ষা করে খায় আবার কেউ ভিক্ষারির ঘরে জন্ম নিয়েও পুরো বিশ্ব রাজত্ব করে।\" মুচকি হেসে উত্তর দিলো লোকটা। উনার কথায় জুনায়েদ একটু ইতস্তত বোধ করছে। \"তুমি কিছু মনে না করলে, আমার সাথে চলো। আমি তোমাকে অন্য পথে বাড়ি পৌঁছে দিচ্ছি।\" জুনায়েদ কিছু বলার আগেই লোকটা আবারও বললো। \"কি ভাবছো?\" \n\"প্রয়োজন নেই। আমি এলাকারই ছেলে। সব রাস্তাই আমি চিনি, আমার আপনার সাহায্যের দরকার নেই। ধন্যবাদ। আপনি আসতে পারেন।\" এক দমে বলে গেলে জুনায়েদ। \n\"ঠিক আছে। তবে সাবধানে যেও।\" লোকটা এটুকু বলেই বিপরীত পথ ধরে চলে গেলো। জুনায়েদ কিছুক্ষণ উনার পথপানে তাকিয়ে রইলো। এরপর নিজ পথে হাঁটা শুরু করলো। \nকিছু মুহূর্ত পূর্বের মতো এবারও তার মনে হচ্ছে কেউ তার কানে ফিসফিস করে বলছে, যেনো সে না যায় এই পথে। ব্যাপারটা আমলে না নিয়ে এগিয়ে যাচ্ছে। ক্ষেতে শেষ সীমানায় এসে পৌঁছায়। সামনের পথ ধরে হাঁটলেই বাড়ির রাস্তা, ওই রাস্তার পাশে আরেকটা সামাজিক কবরস্থান। এরপরই ওদের বাড়ি। ক্ষেতের শেষ সীমানায় আসার পর জুনায়েদ খুব ভালো করে লক্ষ্য করে, কিছুটা দূরে বিশাল খাম্বার মতো একটা মানুষ দাঁড়িয়ে আছে। এটা মানুষ নাকী খাম্বা সে সঠিক ভাবে বলতে পারছে না। তার পা যেনো সামনে এগোতে চাইছে না। তবুও মনে সাহস জমিয়ে এগিয়ে গেলো। \n\"কিরে!\" একটা কর্কশ কণ্ঠ ভেসে এলো জুনায়েদের কানে। স্থির হয়ে দাঁড়িয়ে রইলো সেখানেই। পা কাঁপছে, ঠোঁট জোড়া খসখসে হয়ে এসেছে। \"তোকে কতবার বারণ করেছে, এই পথে না আসার জন্য। তারপরও কেনো এসেছিস?\" বিশাল দেহী লোকটা জুনায়েদকে উদ্দেশ্য করে বললো।\n\"এই পথ কি কারো বাপের নাকী যে, বারণ করবে আর আমি আসবো না।\" মনে সাহস জুগিয়ে উত্তর দিলো জুনায়েদ। তার এখনো মনে হচ্ছে সে কল্পনায় আছে।\n\"তুই জানিস আমি কে?\" জুনায়েদকে আবারও বললো লোকটা।\n\"আপনি কি কোনো সেলিব্রিটি?  দেখুন ভাই, আমি সেলিব্রিটিদেরও তেমন চিনি না। তাই আপনি যদি কোনো সেলিব্রিটি হোন তবুও আমি আপনাকে চিনবো না। রাস্তা ছাড়ুন আমার দেরি হয়ে যাচ্ছে।\" ক্ষিপ্ত সুরে বললো জুনায়েদ। \n\"বেশি বারাবাড়ি করছিস তুই, তোকে দেখে নিবো।\" লোকটা বললো।\n\"আমারও চোখ আছে, আমিও দেখে নিবো।\" বড় বড় চোখে লোকটার দিকে তাকিয়ে পাশ কেটে চলে গেলো জুনায়েদ। কয়েক কদম এগিয়ে পিছন ঘুরে তাকিয়ে দেখে লোকটা নেই। \"আজব তো! লোকটা গেলো কোথায়? হয়তো মনের ভুল ছিলো।\" মনে মনে বলে বাসায় চলে যায়।  বাড়ি গিয়ে এসআ ঘটনা কাউকেই জানায় না জুনায়েদ। "},{"id":"1775075559402-4","title":"04","slug":"part-04","content":"দুপুরের স্নিগ্ধতায় জলের ঢেউগুলো চকমক করছে। থেমে থেমে জল স্পর্শ করছে জুনায়েদের পায়ে। উদাস মনে পুকুরপাড়ে পা ভিজিয়ে বসে আছে জুনায়েদ। কিছু দিন ধরে কোনো কাজেই মন বসাতে পারছে না। অতিরিক্ত মন খারাপ হলেই পুকুরপাড়ে এসে পা ভিজিয়ে বসে থাকে। এতে এক অন্য রকম প্রশান্তি কাজ করে অন্তরে। \n\"শত উদাসীনতা বিলিয়ে দিলাম জলের মাঝে, কেউ যদি খুঁজতো আমায় সন্ধ্যা সাঝে।\" দীর্ঘশ্বাস ছেড়ে বিরবির করে বললো জুনায়েদ। \nআজ সে কম্পিউটার ক্লাসে যায়নি। বাসা থেকে বের হয়েছিলো ঠিকই কিন্তু আর ক্লাসে যাওয়া হলো না। মনের মধ্যে অজানা এক ক্লান্তি নিয়ে এসে বসেছে পুকুরপাড়ে। প্রায় তিন ঘন্টা হলো এখানে বসে আছে। দূরে কিছু ছেলেমেয়ে পুকুরের পানিতে কত আয়েশ করে গোসল করছে। \n\"রঙিন শৈশবের স্মৃতি ভোলা যায় না, আহ! কত সুন্দর ছিলো দিনগুলো। ভাবতে বসলে এখনো চোখ দিয়ে পানি ঝড়ে। তখন বুঝতাম না, বাস্তবতা কি। আপন মনে জীবন উপভোগ করতাম। মাঝে মাঝে ভাবি, বড় হওয়াটাই জীবনের সবচেয়ে বড় ভুল। কিন্তু মানুষ না চাইতেও তাদের বড় হতে হয়, বাস্তবতার মুখোমুখি হতে হয়।\" আনমনে আবারও বিরবির করলো জুনায়েদ। \nপুকুরের ঠিক মাঝ বরাবর একটা শুকনো বাঁশ দাঁড়িয়ে আছে। বাঁশটার একদম মগে বসে আছে পানকৌড়ি। একটু পর পর পানিতে ডুব দেয়, মুখে করে মাছ নিয়ে ফিরে আসে। খুব তৃপ্তি করে বাঁশের উপরে বসে মাছটা আহার করে। জুনায়েদ আপন দৃষ্টিতে তাকিয়ে ছিলো। হঠাৎ হুঁশ ফিরলো। পিছন থেকে কেউ তার কাঁধে হাত দিয়েছে। একটু চমৎকৃত হয়ে পিছনে তাকায়। \n\"জুনায়েদ! কি হয়েছে তোমার?\" পিছনে থেকে জুনায়েদের পাশাপাশি পানিতে পা ভিজিয়ে বসে জিজ্ঞেস করলো ইকরাম। \n\"ক-কই কিছু হয়নি তো ইকরাম ভাই। আপনি এখানে কি করছেন?\" পাল্টা প্রশ্ন করলো জুনায়েদ। \n\"ভালো লাগছিলো না, তাই পুকুরপাড়ে আসলাম। এসে দেখি তুমিও এখানেই। যাই হোক, কম্পিউটার ক্লাসে আসলে না কেনো আজকে?\" দীর্ঘশ্বাস ছেড়ে জিজ্ঞেস করলো ইকরাম।\n\"জানি না ভাই! কি যেনো হয়েছে আমার। কোনোকিছু ভালো লাগে না। সবসময় মন খারাপ হয়ে থাকে। অথচ মন খারাপের কোনো কারণ খুঁজে পাই না। সবকিছু ঠিকঠাক আছে, তবুও...\" বলেই চুপ হয়ে গেলো জুনায়েদ। \n\"মন খারাপ না হলে তুমি কোনোদিন বড়ই হও''নি। তোমার মন খারাপ হয় মানেই তুমি বাস্তবতা বুঝতে শিখেছো।\" এতটুকু থামলো। আবারও বললো, \"মাঝে মাঝে এমন হয়। এতে চুপ হয়ে যেতে নেই। এগুলোকে স্বাভাবিক ভাবে নিতে শিখো।\" জুনায়েদের দিকে তাকিয়ে একটু মুচকি হাসি দিলো ইকরাম।\nপুরো টিটিসি''তে একমাত্র ইকরামের সাথেই জুনায়েদের একটু বন্ধুসুলভ সম্পর্ক। এই মানুষটা জুনায়েদের চেয়ে অনেক বড়, কিন্তু তার ব্যবহার আচরণ সবটাই যেনো সমবয়সী বন্ধু ন্যায়। \n\"ইকরাম ভাই! সত্যি বলতে এই সময়টাতে আমার ঠিক এমনই সাপোর্টের দরকার ছিলো। আমি আসলে নিজের ভিতর থেকে মচকে গেছি। সারাক্ষণ ভিতরে একটা ভয় কাজ করে। নিজেকে পরাজিত মনে হয়। মনে হয় নিজেকে শেষ করে দিলেই যেনো মুক্তি।\" এক দমে বলে গেলো জুনায়েদ। \n\"প্রতিটা পরাজয় তোমাকে জেতার জন্য অনুপ্রেরণা দিবে। যাতে তুমি পরবর্তী সুযোগটা সুন্দর মতো কাজে লাগাতে পারো। পরাজয় মানেই সবকিছু শেষ নয়, পরাজয় মানে নতুন করে শুরু করা। যারা পরাজিত হয়েও রুখে দাঁড়ায় তারাই আসল বিজয়ী।\" জুনায়েদ লক্ষ্য করলো, ইকরামের কণ্ঠস্বরে এক সংগ্রামী আওয়াজ। তার চোখ চকচক করছে। চুপ করে রইলো জুনায়েদ। \n\"শুনো জুনায়েদ! চলো ক্লাসে চলো।  ইলেকট্রিক্যাল ক্লাসটা মিস দিও না।\" নরম কণ্ঠে বললো ইকরাম।\n\"আজকে অনেকটা দেরি হয়ে গেছে। আজ আর যাবো না।\" মর্জি সুরে বললো জুনায়েদ। \n\"তো কি হয়েছে? আমিও তো এখানে সময় নষ্ট করলাম। দেরি একা তোমার হয়নি, আমারও হয়েছে। চলো একসাথেই যাবো৷ স্যার কিচ্ছু বলবে না।\" আড়দৃষ্টিতে তাকিয়ে বললো ইকরাম। জুনায়েদ আর না করলো না। গুটি গুটি পায়ে তারা টিটিসি''র গেট অতিক্রম করে ভিতরে প্রবেশ করলো।\n_\nইকরাম আর জুনায়েদকে দেরিতে ঢুকতে দেখে সাইদুল স্যার বললেন, \"আজকে এত দেরি হলো কেনো তোমাদের?\" জবাবে জুনায়েদ চুপ করে রইলো। ইকরামই বললো, \"স্যার একটু কাজ ছিলো। আসলে সকালে না খেয়ে এসেছিলাম। হোটেল থেকে খেয়ে আসতে আসতে দেরি হয়ে গেলো।\" ইকরামের জবাব শুনে সাইদুল স্যার আর কথা বাড়ালেন না। ইকরাম নিজের জায়গায় বসে পড়লো। জুনায়েদ সিটের ব্যাগ রাখার সময় একটা বিষয় লক্ষ্য করলো, অন্য দিনের তুলনায় আজ ক্লাসটা একটু বেশিই শান্ত। বাকি সব দিন তো ক্লাসে হৈ-হুল্লোড় লেগেই থাকে। আজ একদম তার ব্যতিক্রম। তিন দিন আগেই ইকরাম''সহ আরো তিনজন ইলেকট্রিক্যাল ক্লাসে ভর্তি হয়েছে। ক্লাসে চব্বিশ''জন ছাত্র থাকার কথা, তবে আজ পঁচিশ''জন দেখা যাচ্ছে।  তাহলে বোধহয় আজকে নতুন একজন ভর্তি হয়েছে। সে আবারও আঙুল দিয়ে গুনে গুনে দেখছে। হঠাৎ তার দৃষ্টি আটকায় সামনের বেঞ্চে। একজন বসে আছে। একদম ভিন্ন। সবার চেয়ে আলাদা। উজ্জ্বল শ্যামবর্ণ গায়ের রঙ,  সাদা পাঞ্জাবি পাজামা পরিহিত, চোখে সাদা ফ্রেমের চশমা। হাতে সোনালী ঘড়ি। ঠোঁটের কোণে মৃদু হাসি। বয়স আর কত হবে? —এই বিশ থেকে একুশ। ডান হাতে কলম ধরে খাতার পৃষ্ঠায় কি যেনো আঁকিবুঁকি করছে। তার কাছে লোকটাকে আজব মনে হলো। সে পিছনের সারি থেকে উঠে সামনের সারিতে ওই লোকটার পাশাপাশি বসলো। লোকটা এক চুলও তার দিকে তাকালো না। যেনো সে নিজের ভাবনায় ডুবে আছে। এতটা ভাবনাগ্রস্ত মানুষ আগে কখনো দেখেনি জুনায়ে। নিষ্পলকে কেউ নিজের কাজে কিভাবে অটুট থাকে? এই প্রশ্নটাই বার বার তার মাথায় আসছে। \n_\nদুপুর একটা বেজে পনেরো মিনিট। ক্লাসে এখন টিফিন টাইম। যে যার মতো টিফিন নিয়ে এসেছে। রুমের এক কোণে সবাই মিলেমিশে টিফিন ভাগাভাগি করে খাচ্ছে। একই সময়ে জুনায়েদ বাইরে থেকে খাবার খেয়ে ক্লাসে ঢুকলো। ঢুকেই তার কাছে ক্লাসটা অপরিচিত মনে হতে লাগলো। যেখানে সবাই মিলেমিশে এক কোণে সেখানেই ক্লাসের আরেক কোণে চুপটি করে সেই লোকটি বসে আছে। খাতা কলমে লিখালিখি করছে। জুনায়েদ বরাবরই সব জিনিসে আগ্রহী বেশি। সে ধীরে ধীরে সামনে এগিয়ে গেলো। নিজের সিটে বসলো। পাশের সিটেই ওই লোকটা বসে খাতা কলমে লিখালিখি করছে। জুনায়েদ ঘুরে ঘুরে তার দিকে তাকাচ্ছে। ক্লাস বাকিরাও জুনায়েদকে পরখ করলো। আবার যে যার খাবারে লক্ষ্য স্থির করলো। জুনায়েদ একটু ঝুকে তার দিকে তাকালো। লোকটা এখনো আপন মনে কাজ করছে। জুনায়েদ একবার তার খাতার দিকে তাকালো। এক অচেনা ভাষায় কিছু লিখছে। মনে হয়, কোনো গল্প বা অন্য কিছু। আরেকটু ঝুঁকে লক্ষ্য করলে স্পষ্ট দেখতে পায়, খাতায় হিন্দি ভাষা লিখছে। জুনায়েদ অবাক সুরে জিজ্ঞেস করে, \"আ-আপনি হিন্দি লিখতে পারেন?\" জুনায়েদ যেনো বিস্মৃত হলো, তার এই গুনটা দেখে। লোকটা এক নজর জুনায়েদের দিকে তাকালো। একটা মুচকি হাসি দিলো, আবার লিখা শুরু করলো। \"হ্যালো! আমি জুনায়েদ। আর আপনি?\" নিজের সিট থেকে উঠে লোকটার সামনে দাঁড়িয়ে বন্ধুত্বের হাত বাড়িয়ে দিলো জুনায়েদ। লোকটা যেনো বরাবরই জুনায়েদকে উপেক্ষা করছে। \"হ্যালোওওওও!\" একটু সজোরেই বললো। ক্লাসের বাকিরা এখন টিফিন ক্যারি বক্স গোছাতে ব্যস্ত। এত ব্যস্ততার মাঝেও এক পলক এদিকে তাকালো। জুনায়েদ কিছুটা সংকোচ বোধ করলো। গিয়ে নিজের সিটে বসে পড়লো। তার চোখে মুখে আঁধার দেখা দিলো। \"আমি আযান\" পাশের সিট থেকে একটা গম্ভীর কণ্ঠস্বর ভেসে এলো। জুনায়েদের কানগুলো যেনো শীতল হয়ে গেলো এই কণ্ঠস্বরে। এই কণ্ঠস্বর যতটা ভয়ংকর ততটাই মাধুর্যতা বহন করে। \"আপনি এত চুপচাপ থাকেন কেনো?\" একটু উত্তেজিত হয়ে বললো জুনায়েদ। \n\"চুপচাপ সবাই থাকতে পারে না। যারা চুপচাপ থাকে, তারা মূলত অসংখ্য শব্দহীন কথা বলে। যে কথা আশেপাশের কেউ শুনতে পারে না।\" কথাটা শেষ করে জুনায়েদের দিকে চোখ তুলে তাকালো আযান। জুনায়েদ যেনো ভয়ভীত হলো আযানের চাহনিতে। চশমার ভেতরে একজোড়া চোখ দেখা যাচ্ছে। তার চোখজোড়াই যেনো হাজারটা কথা বলে। এক মুহূর্তের জন্য জুনায়েদের মনে হলো, এই চোখের দিকে তাকালে যে কেউ হার মানতে বাধ্য হবে। এক অগ্নিস্ফুলিঙ্গ তার চোখে। \n\"আপনি কি সবসময়ই একা থাকেন? কারো সাথে মিশেন না?\" নরম গলায় আবারও প্রশ্ন করলো জুনায়েদ। \n\"ভালো সম্পর্ক সবার সাথেই রাখি। তবে এতটাও ঘনিষ্ঠ হই না যতটা ঘনিষ্ঠ হলে চলতে অসুবিধা হবে।\" নিষ্পলক দৃষ্টিতে তাকিয়ে থেকে বললো আযান।\n\"আচ্ছা! আচ্ছা! আপনি কোথায় থাকেন?\" এক গাল মুচকি হেসে জানতে চাইলো জুনায়েদ। \n\"আমি টঙ্গীবাড়ী উপজেলায় থাকি।\" জবাবে বললো আযান।\n\"কি বলছেন! এত দূর থেকে প্রতিদিন যেয়ে এসে কোর্স করবেন?\" অবাক হয়ে আবার জিজ্ঞেস করলো জুনায়েদ। \n\"আমি না আসতে চাইলেও যে আমাকে আসতেই হতো। কোনো না কোনো ভাবে তো এখানে আসা হতো আমার।\" কথাটুকু শেষ করে আবার নিজের লিখায় মন দিলো আযান।\n\"মানে?\" আযানের কথাটা যেনো জুনায়েদের কানে বিঁধতে লাগলো। \n\"কিছু না! সব প্রশ্নের উত্তর হয় না। আমরা কোথাও হয় বাধ্য হয়ে যাই। নয়তো কারো জন্য। আর নয়তো নিজের জন্য।\" চোখ তুলে তাকালো আযান। \n\"তা অবশ্য ঠিক। আচ্ছা যাই হোক, আপনার অসুবিধা হবে তো নিশ্চয়ই!\" সাধারণ ভাবে বললো জুনায়েদ। \n\"হ্যাঁ সমস্যা তো হবেই। দেখি এদিকে কোনো বাসা ভাড়া পাই কি-না। তাহলে আর কষ্ট করতে হবে না।\" মুখ ফুটে হাসতে না চাইলেও জোর করেই হাসলো আযান। জুনায়েদ আর কথা বাড়ালো না। কিছুক্ষণের মধ্যেই ক্লাস শুরু হয়ে গেলো। যে যার মতো ক্লাস করতে ব্যস্ত।\n__\n\"স্যার আমি পরীক্ষা দিবো না। আমার ভালো লাগছে না।\" খিটখিটে মেজাজ নিয়ে বললো জুনায়েদ। \n\"কি হয়েছে জুনায়েদ? পরীক্ষা দিবে না কেনো?\" পাশ থেকে ইকরাম প্রশ্ন করলো।\n\"কিছু না। আমার কিছুই ভালো লাগছে না। স্যার আমি পরীক্ষা দিবো না প্লিজ\" আবারও অনুরোধ করলো জুনায়েদ। \n\"ঠিক আছে। পরীক্ষা না দিলে চলে যাও।\" অনেকক্ষণ চুপ থেকে সাইদুল স্যার বললেন। সবাই হা হয়ে তাকিয়ে রইলো। জুনায়েদ কোনো কথা না বাড়িয়ে ক্লাস রুম থেকে বেরিয়ে গেলো। ধীর গতিতে সিঁড়ি বেয়ে নিচে নামছে, হঠাৎ তার পা পিছলে যায়। তার মনে হতে থাকে সে যেনো আকাশ থেকে পড়ছে। \"আআআআআআআআ\" এক আর্তচিৎকার দিয়ে সে টিটিসি''র বাগানে গিয়ে পড়লো। এত উপর থেকে পড়েও সে অক্ষত আছে। এটা ভেবেই সে অবাক। এদিক সেদিক তাকিয়ে দেখতে দেখতেই বৃষ্টি শুরু হলো। দুই হাত মাথায় রেখে উঠতে যাবে তখনই একজন প্রশিক্ষনার্থীর গাড়ি সোজা এসে জুনায়েদকে ধাক্কা দেয়। দ্বিতীয় বারের মতো এক আর্তচিৎকার দিয়ে তার ঘুম ভেঙে যায়। তার মানে এতক্ষণ সে দুঃস্বপ্ন দেখছিলো। তার সারা শরীর ঘেমে একাকার। দীর্ঘশ্বাস ছাড়ছে বার বার। ড্রিম লাইটের মৃদু আলোও যেনো তার কাছে গভীর অন্ধকার মনে হচ্ছে। বাইরে ঝিরঝিরে বৃষ্টি হচ্ছে। ইচ্ছে করছে উঠে গিয়ে বৃষ্টিতে ভিজতে। \"না! যাই হোক। মনটা হালকা করতে হবে।\" মনে মনে নিজের সাথে কথা বলেই বেরিয়ে গেলো ঘর থেকে। দরজা খুলে এসে বাইরে দাঁড়ালো জুনায়েদ। মুশলধারে বৃষ্টি হচ্ছে। এই শীতের সময় বৃষ্টি দেখাই যায় না। মনে মনে কত ভাবনা ভেবে আনমনে পা বাড়ালো বৃষ্টির পানিতে নিজেকে ভিজিয়ে দিতে। ছোট ছোট ফোঁটা এসে ভিজিয়ে দিচ্ছে জুনায়েদের শরীর। ঠান্ডা অনুভব হচ্ছে খুব। এরপরও যেনো ভালো লাগা কাজ করছে। চোখ বন্ধ করে গিয়ে উঠোনে দুই হাত মেলে দাঁড়িয়ে রইলো। \"বৃষ্টির এই কোমলতা, মৃদু তার ছোঁয়া। বিষিয়ে থাকা মনটা হয়েছে আনমনা।\" আবারও বিরবির করে বললো জুনায়েদ। \n__\nসূর্যের আলোয় স্পষ্ট দিক বেদিক। পাখিদের কোলাহল। মন মাতিয়ে তোলা হাওয়া। কম্পিউটার ক্লাস শেষ করে জুনায়েদ বসে আসে টিটিসি''র ছাঁদে। একাকী সময় কাটাতে সে প্রায়ই এখানে এসে বসে থাকে। \n\"তুমি জানো! যখন মানুষের মন খারাপ থাকে, তখন আকাশের দিকে তাকিয়ে থাকতে ভালো লাগে। কারণ মানুষ ভাবে, ওই সময়টাতে মানুষের হৃৎস্পন্দনও আকাশের মতো ধীরে ধীরে চলতে থাকে। তাদের নিঃশ্বাস প্রশ্বাস সবটাই যেনো তখন আকাশ সমপরিমাণ হয়ে উঠে।\" পিছন থেকে বলে উঠলো ইকরাম।\n\"আরে ইকরাম ভাই আপনি?\" আকস্মিক প্রশ্ন করলো জুনায়েদ। \n\"হ্যাঁ! অনেকক্ষণ আগেই এসেছি। দেখলাম আনমনে আকাশের দিকে তাকিয়ে আছো। তাই আর ডিসটার্ব করিনি। কি হয়েছে তোমার? আমাকে বলতে পারো!\" সামনে গিয়ে জুনায়েদের পিঠে হাত রাখলো ইকরাম।\n\"আমি নিজেও জানি না ইকরাম ভাই। আমার সবকিছুই ঠিক আছে, বাসায় কোনো প্রবলেম না, লাইফও সুন্দর মতোই চলছে —তবুও কেনো এত মন খারাপ হয়?\" নিষ্পাপ চোখে তাকিয়ে রইলো আকাশের দিকে।\n\"অজানা মন খারাপ খুব কষ্টদায়ক। মানুষকে ভালো থাকতে দেয় না। যাই হোক, চলো ক্লাস শুরু হয়ে যাবে।\" ইকরামের কথা মতো উঠে এলো জুনায়েদ। \nক্লাসরুমে ঢুকেই জুনায়েদ সামনে এগিয়ে যেতে থাকে। ইকরাম একটু অবাকই হলো। এতক্ষণ একসাথে এসে, হুট করে জুনায়েদ তাকে উপেক্ষা করছে। \"ইকরাম ভাই। এদিকে আসুন।\" জুনায়েদের ডাকে সামনে এগিয়ে যাচ্ছে ইকরাম।\n\"হ্যাঁ বলো।\" শান্ত সুরে বললো ইকরাম।\n\"আযান ভাই! কেমন আছেন?\" মুচকি হেসে জিজ্ঞেস করলো জুনায়েদ। আযান নিজের মতো বসে আছে। যেনো সে জুনায়েদকে দেখতেই পাচ্ছে না। \n\"জুনায়েদ? কি হয়েছে তোমার? এই ছেলেটা তোমার সাথে কথা বলতে চায় না।\" জুনায়েদকে টেনে পাশে নিয়ে বললো ইকরাম। \n\"না! না! ইকরাম ভাই। উনি আসলে বেশি কথা বলে না। এজন্য এমন করছে। আসুন আমার সাথে।\" এই বলে ওরা দু''জন আবারও আযানের সামনে গিয়ে দাঁড়ালো। \n\"মানুষকে এতটাও আপন ভাবা ঠিক না। মানুষ হচ্ছে সবচেয়ে বড় বিশ্বাসঘাতক।\" গভীর কণ্ঠে বলে উঠলো আযান। ইকরাম আর জুনায়েদ হতবাক হয়প তাকিয়ে রইলো। চশমার ভিতরে লুকিয়ে থাকা চোখগুলো যেনো কত-শত প্রশ্নের উত্তর দিয়ে দিচ্ছে। \n\"আ-ম! আ-যান ভাই।\" আমতা আমতা করে বললো জুনায়েদ। \n\"আমি ভালো আছি। তুমি কেমন আছো?\" আগের সুরেই জবাব দিলো আযান। ইকরাম এখনো বুঝতে পারছে না, জুনায়েদ কেনো ওর সাথে মিশতে চাইছে। ছেলেটা বরাবর তাদের উপেক্ষা করছে। আযান এক প্রকার বিরক্ত লাগতে শুরু করে ইকরামের কাছে। \n\"আ-আমিও আলহামদুলিল্লাহ ভালো আছি।\" হাসি মুখে বললো জুনায়েদ। সবাই চুপচাপ। কেউ কোনো কথা বলছে না। নিস্তব্ধতা ভেঙে জুনায়েদ আবারও বললো, \"আযান ভাই। চলেন একটু বাইরে যাই।\" আযান চোখ তুলে তাকালো জুনায়েদের দিকে। ছেলেটা খুব উৎসুক। \n\"বাইরে যাবে?\" একটু থেমে আবার বললো, \"বাইরের জগতটা যতটা সুন্দর ততটাই বিষাক্ত। একজন বিষাক্ত মানুষের জন্য সবাইকে বিষ মনে হবে এবং একজন সরলের জন্য সবাইকে বোকা মনে হবে। তবে, বাইরের জগতটা দেখা উচিৎ। নয়তো বুঝা যায় না, মানুষের আসল রূপ কেমন। মানুষ রূপী অসংখ্য নরপশু আছে এই দুনিয়া। সবাইকে চেনা না গেলেও আশেপাশে যারা থাকে তাদের চিনে রাখা দরকার।\" এক সুরে বলে চললো আযান। এতক্ষণ পর এই একটা কথাই যেনো ইকরামের ভালো লাগলো। সে মনে মনে উপলব্ধি করলো, আযান কেনো এত চুপচাপ থাকে। যখনই বলে, তখনই তার কথার এক অন্য রকম মাধুর্য খুঁজে পাওয়া যায়।"},{"id":"1775075612853-5","title":"05","slug":"part-05","content":"স্নিগ্ধ দুপুর বেলা মনোরম করা হাওয়া বইছে। মুহূর্তেই যেকোনো বিষন্ন মনকে ভিজিয়ে দিবে উষ্ণতার রঙিন জলে। সূর্যের উত্তাপে ক্লান্ত মুখগুলো স্পষ্ট দেখা যাচ্ছে ব্রিজের পাশে ছোট্ট পুকুরপাড়ে বসে আছে।\n\"তার মানে, আযান ভাই এতদূর থেকেই যাতায়াত করবেন?\" মৃদু সুরে প্রশ্ন করলো ইকরাম। আযান কিছুটা নিস্তব্ধ থেকে বললো, \"যাতায়াত তো করতেই হবে। যাতায়াত না করলে মানুষ চিনবো কিভাবে?\" জুনায়েদ এবং ইকরাম দু''জনই যেনো বিস্মৃত হলো। \"মানে?\" ভ্রু কুচকে বললো জুনায়েদ। \n\"না! কিছু না!\" আযানের কথা শুনেই বুঝা যাচ্ছে সে কিছু একটা লুকাচ্ছে। কিন্তু কি? \n\"আযান ভাই, এই কোর্সটা করার উদ্দেশ্য কি আপনার?\" সবকিছু হেসে উড়িয়ে দিয়ে আবারও প্রশ্ন করলো ইকরাম। \n\"এই কোর্সটা করার কোনো উদ্দেশ্য নেই আমার। আসল উদ্দেশ্য হলো এখানে আসা।\" আনমনে বিরবির করে বললো আযান।\n\"আযান ভাই? কি বলছেন?\" ইকরাম এবং জুনায়েদ দু''জনই একসাথে বলে উঠলো। আযান একটু নড়ে বসলো। \n\"না! না! তেমন কিছু না।\" সেই শীতল চাহনি তার চোখে মুখে দেখা যাচ্ছে। \n\"আচ্ছা শুনুন! আপনি তো ওইদিন বললেন যে এদিকে থাকার জায়গা খুঁজছেন। আপনি চাইলে আমাদের পুরনো বাড়িতে থাকতে পারেন।\" হঠাৎ বলে উঠলো জুনায়েদ। \n\"পুরনো বাড়ি?\" জুনায়েদের দিকে তাকিয়ে রইলো ইকরাম।\n\"হ্যাঁ! আযান ভাই তো বলছিলো এদিকে একটা ব্যবস্থা করবে। যেহেতু এদিকে বাসা ভাড়া পাওয়াটা খুব কষ্টের তাই উনি চাইলে আমাদের পুরনো বাড়িতে থাকতে পারে।\" আযানের দিকে তাকিয়ে থেকে বললো জুনায়েদ। \n\"ভাড়া কত দিতে হবে?\" এতক্ষণে আযান মুখ ফুটে কিছু জিজ্ঞেস করলো।\n\"ভাড়া? কিসের ভাড়া? আপনি ওখানে থাকবেন আমার গেস্ট হিসেবে। আমাদের বর্তমান বাড়ির পাশেই। পাঁচ মিনিটের রাস্তা। আপনি চাইলে আজকে সন্ধ্যার পর আমার সাথে গিয়ে দেখতে পারেন। আশা করি আপনার পছন্দ হবে।\" এক গাল মুচকি হেসে বললো জুনায়েদ। \n\"হ্যাঁ! হ্যাঁ!  আযান ভাই। আমার মনে হয় আপনার যাওয়া উচিৎ।\" ইকরামও সায় জানালো।\n\"ঠিক আছে।\" একবার জুনায়েদ আরেক বার ইকরামকে পরখ করে তারপর বললো আযান।\n\"আপনার নাম্বারটা দিন তাহলে। সেভ করে রাখি।\" বললো জুনায়েদ। \n\"হ্যাঁ আমিও সেভ করে রাখি তাহলে।\" বলেই হেসে দিলো ইকরাম। এরপর ওরা একে অপরের নাম্বার নিজেদের কাছে রেখে দিলো। নিজেদের মধ্যে টুকিটাকি কথপোকথন শেষ করে ক্লাসে চলে গেলো ওরা।\n_\nমুহূর্ত কিছু পূর্বে মাগরিবের আযান হয়েছে। আযানের সুমধুর ধ্বনিতে মুগ্ধ ছিলো পরিবেশ। সূর্যাস্তের শেষ মুহূর্তের লালচে ধূসর আকাশে তাকালে এখনো দেখা যায় দূর দূরান্তে একটি করে পাখি উড়ে চলে যাচ্ছে। ক্লাস শেষে জুনায়েদ আযানকে তার সঙ্গে করে নিয়ে যাচ্ছে। আযানও যাবে বলেছে। \n\"দেখুন আযান ভাই। এটা হচ্ছে শহরের গলি পেড়িয়ে আমাদের গ্রামের ছোট্ট খেতের পথ। জায়গাটা যেমন জনমানবহীন তেমনই অপরূপ। রাতের বেলা একটা গা ছমছমে ঠিকই কিন্তু দিনের আলো ফুটলে এই জায়গার রঙ একদম পাল্টে যায়।\" আযান তার পিছু পিছু হাঁটছে। একটা শব্দও করছে না। জুনায়েদ আবারও বলতে লাগলো, \"আমার নিত্য দিনের পথ এটাই। যখন একটু বেশি মন খারাপ থাকে, তখন ওইইইই জায়গায় দাঁড়িয়ে দীর্ঘশ্বাস ছাড়লেই মন ভালো হয়ে যায়।\" হাতের ইশারায় নির্দিষ্ট স্থান দেখিয়ে বললো জুনায়েদ। এবারও পিছন থেকে কোনো শব্দ ভেসে এলো না। \"আযান ভাই? আপনি কি বিরক্ত হচ্ছেন?\" প্রশ্ন করলো জুনায়েদ। না! পিছন থেকে এবারও কোনো শব্দ আসছে না। হাঁটারও কোনো আওয়াজ পাওয়া যাচ্ছে না। এতক্ষণ ধরে কথা বলে যাচ্ছে অথচ পিছে কোনো টু শব্দ পর্যন্ত পাওয়া যাচ্ছে না। বিষয়টা সন্দেহজনক মনে হতেই পিছে ফিরে তাকালো জুনায়েদ। \"আযান ভাইইই!\" একটু ভয়ার্ত সুরে ডাকলো। কিন্তু পিছনে কেউ ছিলো না। \"এতক্ষণ তাহলে কার সাথে কথা বলছিলাম?\" মনে মনে বলছে জুনায়েদ। ভয় ভয় লাগছে তার। এতদিন ধরে এই পথ ধরে যাচ্ছে, এমন ভয় কোনোদিন লাগেনি তার। হঠাৎ মনে পড়ে গেলো সেই রাতের ঘটনা। \"বেশি বারাবাড়ি করছিস তুই, তোকে দেখে নিবো।\" অদ্ভুত সেই লোকটা বলেছিলো এই কথাটা। ভাবতেই তার লোম দাঁড়িয়ে গেলো। যেনো সুচ হয়ে ফুটছে তার গায়ে। ঘন ঘন নিঃশ্বাস নিচ্ছে। কপাল বেয়ে এক ফোটা ঘাম পড়লো। বাম হাত দিয়ে কপালের ঘাম মুছে সামনে এগিয়ে যাচ্ছে। কিন্তু তার পা যেনো সামনে এগোতে নারাজ। এক পা-ও নড়তে চাইছে না তার শরীর। এমন সময়ই তার ফোনটা বেজে উঠলো। স্ক্রিনে স্পষ্ট দেখা যাচ্ছে আযানের নাম। চোখ দুইটা বড় বড় হয়ে যাচ্ছে জুনায়েদের। ঢোক গিলে কলটা রিসিভ করলো। \n\"হ্যাঁ! হ্যালো। আযান ভাই।\" কাঁপা কাঁপা গলায় বললো জুনায়েদ। \n\"হ্যাঁ জুনায়েদ আমি বাসায় পৌঁছে গেছি। কালকে তোমাদের বাসা দেখতে যাবো। আর ধন্যবাদ তোমাকে আমার জন্য এতটা ভাবার জন্য।\" সেই চিরচেনা গম্ভীর কণ্ঠে এক মিনিট কথা বললো আযান। প্রতুত্তরের আশা না করেই কল কেটে দিলো ওপাশ থেকে। জুনায়েদ অবাক হয়ে রইলো। বিকেলে যখন আযান আসার জন্য রাজি হয়েছিলো তখন পর্যন্ত সবকিছু ঠিকঠাক ছিলো। এরপর যখন ছুটি হয় তখন হঠাৎ আযানের কোনো একটা দরকারি কাজে তাড়াতাড়ি বাসায় চলে যেতে হয়। কিন্তু জুনায়েদ যে এতক্ষণ আযানের সাথে ছিলো, এটা কি মিথ্যা? তার শরীর আবারও কাঁপছে। কি করবে দিশা পাচ্ছে না। \nসামনের দিকে এগিয়ে যাওয়ার সাহস পাচ্ছে না।  এখান থেকে দেখা যাচ্ছে ক্ষেতের মাঝের সেই কবরস্থানে কয়েকজন লোক একসাথে দাঁড়িয়ে আছে। এতক্ষণে যেনো জুনায়েদ একটু সাহস ফিরে পেলো। তড়িঘড়ি করে এগিয়ে গেলো। মুহূর্তেই লোকগুলোর সামনে এসে পৌঁছায়। দূর থেকে তিন চারজন মনে হয়েছিলো। আসলে এখানে দুইজন লোক। শরীর স্বাস্থ্য স্বাভাবিকের তুলনায় একটু তরতাজা। \"কি ভায়া? যাচ্ছেন কোথায়?\" প্রশ্ন করলো লোকগুলোর মধ্যে একজন। জুনায়েদ ভয় পেয়েছে। কিন্তু তাদের বুঝতে দিতে চাইছে না। হাসিমাখা গলায় উত্তর দিলো, \"এইতো ভাই বাসায় যাচ্ছি। আপনাদের তো চিনলাম না? এখানে কি নতুন নাকী?\" প্রশ্ন করে কিছুটা শান্ত হলো জুনায়েদ। \"হ্যাঁ ভাই। ওই তো সামনেই এসেছি একটা কাজে। ক্ষেতের কবরস্থান পার করে উপরের পথে আরেকটা কবরস্থান আছে সেখানেই যাচ্ছি।\" দ্বিতীয় লোকটি উত্তরে বললো। \n\"তাহলে তো আপনারা আমার বাড়ির পথেই যাচ্ছেন। চলেন একসাথে যাই।\" বুকে সাহস সঞ্চয় করলো জুনায়েদ। এতক্ষণে যেনো সে সাহস ফিরে পেলো। \n\"হ্যাঁ ভাই। চলেন তাহলে।\" লোক দুইটা একসাথে বললো৷ \"ভাই! এটা যেহেতু আপনারই এলাকা আপনিই না-হয় আমাদের পথ চিনিয়ে নিয়ে চলুন। আমরা তো আর সব রাস্তাঘাট চিনি না।\" একজন বলে উঠলো। জুনায়েদ কণ্ঠ শুনে বুঝতে পারলো এটাই সেই লোকটা,  যে প্রথমে কথা বলেছিলো। \"হ্যাঁ! হ্যাঁ!  চলুন তাহলে। আমিই চিনিয়ে নিয়ে চলি।\" বলেই আগে আগে হেঁটে চললো জুনায়েদ। হাঁটতে হাঁটতে সে অনেক বার অনুভব করেছে পিছনে লোক দুইটা ফিসফিস করে কি যেনো কথা বলছে। কিন্তু তার কান অব্দি পৌঁছাচ্ছে না। সে-ও পিছে তাকিয়ে জিজ্ঞেস করার সাহস পাচ্ছে না। হাঁটতে হাঁটতে তারা কবরস্থান ছাড়িয়ে চলে এসেছে। আর একটু পথ হাঁটলে তারা উপরের পথে উঠবে। \"ভা.....\" পিছনে তাকিয়ে উনাদের ডাকতে যাবে তখনই জুনায়েদ একটা গর্তে পড়ে যায়। তার মনে হচ্ছে সে কোনো ভেজা গর্তে পড়ে গেছে। মাটি থেকে কেমন এক বিশ্রী গন্ধ ভেসে আসছে তার নাকে। হাত দিয়ে নিজেকে আটকে রাখার বৃথা চেষ্টা করতে করতে সে সোজা গর্তের অন্তরালে পড়ে যায়। হঠাৎ সে শুনতে পাচ্ছে গর্তের উপরে বড় বড় দুইটা কুকুর লাফালাফি করছে। নিভু নিভু চোখে উপরে তাকাবে তখনই কুকুর দুইটা তার উপর ঝাপিয়ে পড়লো। কুকুর দুইটা নিচে নামতেই সে উপলব্ধি করলো, এগুলো কোনো কুকুর না। এরা হচ্ছে ওই দুই ভদ্র লোক। উনারা শক্ত করে জুনায়েদকে ধরে রেখেছে। অজানা কোনো ভাষায় একে অপরের সাথে কথা বলছে। জুনায়েদ সবকিছুই বুঝতে পারছে কিন্তু কিছু করার মতো ক্ষমতা তার মধ্যে অবশিষ্ট নেই। যেনো তাকে কেউ মন্ত্রজালে আটকে রেখেছে। শরীরে কোনো প্রকার শক্তি খুঁজে পাচ্ছে না সে। মুখ দিয়েও কোনো শব্দ বের হচ্ছে না। কি করবে এই মুহূর্তে সে কিছুই বুঝতে পারছে না। হঠাৎ সে লক্ষ্য করলো লোক দুইটা তার দিকে তাকিয়ে বিকট শব্দে হাসছে। তার কান রিতীমতো স্তব্ধ হয়ে যাচ্ছে। সে বার বার অনুভব করছে তার কান ফেটে যাবে৷ অসহ্য যন্ত্রণায় চোখ বন্ধ করে সজোরে এক চিৎকার দিতেই চারপাশে হাসির শব্দ বন্ধ হয়ে যায়। গর্তপর ভিতর জুনায়েদ একা। লোক দুইটা নেই তার পাশে। হামাগুড়ি দিয়ে গর্ত থেকে বের হতেই তার শরীর দিয়ে হিমশীতল স্রোত বইতে লাগলো। সে নিজের আনমনেই কবরস্থানের ভিতরে চলে এসেছে। হাত মুখের ভিতরে গুঁজে কোনো রকম সাহস সঞ্চয় করে দৌঁড়ে কবরস্থান থেকে বেরিয়ে এলো। বুকের বাম পাশটা ধুকপুক করছে। মনে হচ্ছে হৃৎপিণ্ডটা এক্ষুণি ব্লাস্ট করবে। দৌঁড়ে উপরের পথে চলে এলো। এতক্ষণ খেয়ালই করেনি তার শরীর ভর্তি ময়লা। দুই হাত দিয়ে শরীর থেকে ময়লা ঝাড়তে গিয়ে বুঝতে পারলো তার জামার এক কোণা থেকে বেশ কিছুটা অংশ কেটে নেওয়া হয়েছে। অবাক চোখে কিছুক্ষণ তাকিয়ে রইলো। এরপর মাথায় হাত দিতেই বুঝতে পারলো তার চুলেরও একই অবস্থা।  কিন্তু এমনটা তো হওয়ার কথা ছিলো না? এমনটা হলো কেনো? কিছু তো একটা ঘটছে, কিন্তু কি?\n_\n\"আম্মু! আমার মাথা ফেটে যাচ্ছে। আমার আর সহ্য হচ্ছে না।\" যন্ত্রণায় চিৎকার করছে জুনায়েদ। \n\"একটু সহ্য কর বাবা। ঔষধ খাওয়ালাম তো মাত্র। সব ঠিক হয়ে যাবে।\" গতরাত থেকে ছেলের ধুম জ্বর দেখে জোহরা খুবই চিন্তিত। ছেলের অসুস্থতায় যেনো সে সবচেয়ে বেশি কাতর হয়ে যায়। \n\"আমার ভালো লাগছে না আম্মু। দেখো... আমার পায়ের সামনে বিশাল বড় একটা কুকুর বসে আছে। এটাকে সরাও এখান থেকে। আমাকে কামোর দিবে।\" বাচ্চাদের মতো কান্না করছে জুনায়েদ। \n\"কোথায় কুকুর? এখানে তো শুধু আমি আছি। কোনো কুকুর নেই। তোমার মনের ভুল। তুমি ঘুমাও বাবা, আমি একটু কাজ করি গিয়ে।\" ছেলের মাথায় হাত বুলিয়ে দিতে দিতে বলছে জোহরা।\n\"না! না আম্মু! তুমি এখান থেকে যেও না। তুমি চলে গেলেই কুকুরটা আমাকে কামড়াবে।\" শক্ত করে মায়ের হাত ধরে রেখেছে জুনায়েদ। জোহরা একটা জোর করেই ছেলের হাত ছাড়িয়ে চলে গেলো। \nসরু হাওয়া বইছে ঘরটিতে। আলোছায়ার আধার মেলা, দিনের আলোও যেনো ঘরটির অন্ধকারে আলো ফুটাতে পারছে না। নিষ্পাপ শিশুর ন্যায় খাটের এক পাশে ঘুমিয়ে আছে জুনায়েদ। জ্বরে গা পুড়ে যাচ্ছে। গতরাত থেকে কিছুই খেতে পারছে না। যা-ই মুখে দিচ্ছে বমি করে ফেলে দিচ্ছে। সকালে জোর করে জোহরা একটা পরোটা খাইয়ে তারপর ঔষধ খাওয়ায়। এখন কি সুন্দর ঘুমাচ্ছে ছেলেটা। \n\"উমম! আম্মু চুলে হাত দিও না। তোমার হাতগুলো অনেক ভারী।\" ঘুমের তালে ফিসফিস কণ্ঠে বলছে জুনায়েদ। \n\" আ-আম্মু! তোমাকে তো বললাম, তোমার হাতগুলো অনেক ভারী।\" কথাটুকু শেষ করতেই জুনায়েদ অনুভব করলো, সেই ভারী হাতগুলো মাথা থেকে নিচ দিকে নেমে আসছে। তার বুকের উপর এসে থেমেছে। বুকের উপর এত চাপ আগে কোনোদিন সৃষ্টি হয়নি তার। দম বন্ধ হয়ে আসছে তার। মনে হচ্ছে এক্ষুণি নিঃশ্বাস বন্ধ হয়ে মুখ দিয়ে রক্ত বমি শুরু হবে। ছটফট করতে করতে জুনায়েদ চোখ মেলে তাকায়। সে দেখতে পায় অন্ধকারের সেই লোক দুইটা তার বুকের উপর বসে আছে। তবে তাদের মাথা ছিলো কুকুরের মতো। এতটা বিভৎস দেখতে লাগছিলো। এটা সহ্য করা কোনো সাধারণ মানুষের পক্ষে সম্ভব না। এক ঝটকায় খাটের এক কিনারায় মুখ নিয়ে আসে। ভিতর থেকে যেনো সব বেরিয়ে আসছে, নাড়িভুড়ি সহ। চোখ দিয়ে টপটপ করে পানি পড়ছে, চোখের পানিতে অস্পষ্ট দেখতে পেলো সে বমি করছে। অনেক বেশি বমি করছে। বাম হাতে চোখের জল মুছে ভালো মতো তাকিয়ে দেখলো, শুধু বমি না। তার নাক মুখ দিয়ে টকটকে রক্ত বের হচ্ছে। ডান হাত ও বাম হাত দিয়ে মুখের আশেপাশে লেগে থাকা রক্ত স্পর্শ করে চোখের সামনে তুলে ধরলো। চোখগুলো যেনো তার মার্বেলের মতো চকচক করছে। জোরে একটা চিৎকার দিলো, \"আম্মুওওও\" তার চিৎকারে জোহরা ছুটে এসে দেখে জুনায়েদ বিছানায় লুটিয়ে আছে। খাটের এক কিনারায় জমে আছে রক্ত। "},{"id":"1775075628216-6","title":"06","slug":"part-06","content":"রাতের আকাশে আজ যেনো চাঁদের দেখা নেই। আকাশে কোনো তারা''ও নেই। শীততাপ প্রকৃতি আজ একটু বেশিই শান্ত। শান্ত হয়ে লুটিয়ে আছে জুনায়েদ। শরীরের অবস্থা এখন আর দেখার মতো নেই। এক দিনেই চোখ মুখ ফ্যাকাসে হয়ে গেছে। চোখের নিচে কালো দাগ পড়ে গেছে। গাল দুটো একেবারে ভেঙে গেছে। যেনো কত বছরের অসুস্থতায় ভুগছে। রাত গভীর হলে তার শরীরের যন্ত্রণাও যেনো আরো বাড়ে। কিন্তু আজ সে নিশ্চিন্তে একটু ঘুমাচ্ছে। এই ঘুম কি আসলেই নিশ্চিন্তের? \n_\nখোলা মাঠ, দূর দূর পর্যন্ত নেই কোনো গাছগাছালির চিহ্ন। উত্তপ্ত রোদে গা পুড়ে যাওয়ার মতো অবস্থা। সেই রোদের তেজস্ক্রিয় রোশ্মিকে গায়ে মাখিয়ে ছুটে চলেছে জুনায়েদ। কোথায় যাচ্ছে জানে না সে। কেনোই বা ছুটছে এটাও জানে না। শুধু ছুটছে তো ছুটছে। ক্লান্ত শরীর নিয়ে হাঁপাতে হাঁপাতে থামলো পথিমধ্যে। কপাল বেয়ে ঘাম ঝড়ছে তার। নাকের ডগায় এক ফোটা ঘামের চিহ্ন দেখা গেলা। তেষ্টা পেয়েছে খুব। এ-যেনো এক মরুভূমিতে এসে পৌঁছেছে জুনায়েদ। পানির কোনো হদিশ নেই। পানির খোঁজে এদিক ওদিক হাঁটছে, কিন্তু পানি নেই কোত্থাও। সরু পথ ধরে এগিয়ে যাচ্ছে। পুরো জায়গায় জীবিত প্রাণী বলতে শুধু এই একজনই। না!  আর দাঁড়িয়ে থাকা সম্ভব না। আবারও হাঁটছে, কোথায় যাচ্ছে?  কেনো যাচ্ছে? কোনো উত্তর নেই। হাঁটতে হাঁটতে হঠাৎ হোঁচট খেয়ে পড়ে গেলো। মুখ থুবড়ে মাটিতে গড়াগড়ি খাচ্ছে। শক্তি প্রয়োগ করে নিজেকে থামালো। শরীর ঝাকড়া দিয়ে উঠতে যাবে তখনই মাটির নিচ থেকে কিছু একটা তার পা ধরে রাখে শক্ত করে। অনেক জোরাজুরি করছো পা ছাড়ানোর। কিন্তু সব বৃথা। সে যখন নিজের পা ছাড়াতে ব্যস্ত তখন তার কানে আসে একটা উদ্ভট শব্দ। শব্দের উৎস খুঁজতে এদিক ওদিক তাকিয়ে বুঝতে পারে, সেই অন্ধকার রাতের বিশাল দেহী লোকটা এক দিক থেকে তেড়ে আসছে। ভয় ও আতঙ্কে জুনায়েদের শরীর জড়োসড়ো হয়ে যাচ্ছে। কি করবে ভেবে পাচ্ছে না। এমন সময় দেখতে পায় অপর দিক থেকে গত তিন দিন আগের রাতে দেখা হওয়া সেই লোক দু''জনও তেড়ে আসছে। এবারও তাদের মুখ কুকুরের মতো। বিভৎস দেখতে এক চেহারা নিয়ে দৌঁড়ে আসছে। \"ওরা সামনে আসার আগেই আমাকে উঠতে হবে।\" মনে মনে বলছে জুনায়েদ। কিন্তু মাটির নিচ থেকে কিছুতেই নিজের পা ছাড়াতে পারছে না। কি করবে, মাথা কাজ করছে না? \nসর্বশক্তি দিয়ে নিজেকে ছাড়ানোর আপ্রাণ চেষ্টায় জারি। ওদিকে ওরা সবাই সামনে এগিয়ে আসছে। ঘন ঘন নিঃশ্বাস নিচ্ছে জুনায়েদ। বাতাসের প্রবণতা বেড়ে গেছে। বাতাসও যেনো ভারী হয়ে উঠেছে। হঠাৎ মাটির নিচ থেকে ঠান্ডা অনুভব করলো। চারপাশ থেকে পানির ঢল বইতে লাগলো। এত পানি কোত্থেকে এলো? মুহূর্তেই ভাসিয়ে নিয়ে গেলো জুনায়েদকে।\n\"নাআআআআআ!\" এক আর্তচিৎকার দিয়ে আবারও ঘুম ভাঙলো জুনায়েদের। ঘুম ঘুম চোখে তাকিয়ে দেখলো সে তার ঘরেই আছে। তার মানে আরো একটা দুঃস্বপ্ন ছিলো এটা। ড্রিম লাইটের মৃদু আলোয় বুঝতে পারছে, তার শরীর ঘেমে একাকার। পানি পিপাসা লেগেছে। খাট থেকে নেমে টেবিলের উপরে রাখা পানির জগে দেখলো পানি নেই। ওয়াটার বোতল নিয়ে রুম থেকে বেরিয়ে এলো জুনায়েদ। ধীরে ধীরে হাঁটছে। প্রতিটা পদক্ষেপে মনে হচ্ছে  তার পিছনে কেউ আছে। প্রতি বারই পিছন ঘুরে তাকিয়ে দেখে কেউ নেই। আবারও রান্নাঘরের দিকে পা বাড়ায়। এবারও কেউ তার পিছু পিছু হাঁটছে। রান্নাঘরে প্রবেশ করলো। ওয়াটার বোতলে পানি ভরে, পান করছে। এমন সময় পিছন থেকে শীতল স্পর্শ অনুভব করলো। চোখ কপলাে উঠার মতো হয়ে গেছে। ওয়াটার বোতল থেকে তার মুখে অনবরত পানি পড়তেই আছে। সে-ও চুপচাপ গিলছে। আড়চোখে পিছনে তাকাতেই তার শরীর কেঁপে উঠলো। সেদিন রাতেই সেই বিশাল দেহী লোকটা। ভয়ে ওয়াটার বোতল ফেলে ছুটে রান্নাঘর থেকে বের হবে তখনই রান্নাঘরের দরজা বন্ধ হয়ে যায়। বার বার দরজা ধাক্কায় তবুও খুলছে না। লোকটা এক পা এক পা করে জুনায়েদের দিকে এগোচ্ছে। একদম সামনে চলে এসেছে। আরো সামনে। আরো সামনে। এখন একদম সামনে। এক বিশ্রী হাসি দিয়ে কর্কশ কণ্ঠে বললো, \"তোকে বলেছিলাম। কাজটা ঠিক করিসনি। এবার ভোগান্তি তো ভোগ করতেই হবে।\" এটা বলেই জুনায়েদের গলা টিপে ধরে। দম বন্ধ হয়ে আসছে জুনায়েদের। হাত পা অবশ হয়ে আসছে। নিঃশক্তি হয়ে গেছে সে। এমন সময় সে দেখতে পায়, সেই ভদ্রলোকটিকে, যে তাকে পথ দেখানোর কথা বলেছিলো। সাদা জোব্বা পরিহিত লম্বা লোকটি। মাথায় বড় রুমাল পেঁচানো। যেনো কোনো সূফী সাহেব। হাতে একটা বড় লাঠি। হ্যাঁ!  এই লোকটাকে ওইদিনের আগে আরো একবার দেখেছিলো সে। যেদিন সৃজনের সাথে রাতে কথা বলছিলো। একই দেখতে সেই পুরুষাবয়ম যেনো কাউকে লাঠি হাতে ধাওয়া করছিলো। আজও উনিই এসেছে। সাদা জোব্বা পরিহিত। মাথায় বড় রুমাল পেঁচানো। হাতে সেই লাঠিটাও আছে। জুনায়েদের দিকে তাকিয়ে একটা মুচকি হাসি দিলো। সঙ্গে সঙ্গে বিশাল দেহী লোকটা কোথায় যেনো উধাও হয়ে যায়। জুনায়েদ কাশতে লাগলো। কাশতে কাশতে আবারও তার মুখ দিয়ে রক্ত পড়তে লাগে। রক্ত ভেজা হাত চোখের সামনে তুলে ধরলো জুনায়েদ। অজান্তেই চোখ দিয়ে টপটপ করে পানি পড়লো। এরপর পাশে তাকিয়ে দেখলো সেই ভদ্রলোকটাও নেই। আশ্চর্য! কোথায় গেলো? \n_\nভোরের আলো ফুটেছে সাথে কুয়াশার মিশ্রণ। শীত শীত সকালে ফুরফুরে বাতাস যেনো এক অন্য রকম শিহরণ। ঘুম থেকে রান্নাঘরের উদ্দেশ্যের ধীরে ধীরে হেঁটে আসছে জোহরা। রান্নাঘরের সামনে আসতেই যেনো তার আকাশ পাতাল সব এক হয়ে যায়। শরীর থরথর করে কাঁপতে থাকে। নিজের চোখকে বিশ্বাস করতে অবিশ্বাস হচ্ছে। চোখের সামনে জুনায়েদ মাটিতে লুটিয়ে আছে। ছুটে গিয়ে জুনায়েদের মাথার পাশে গিয়ে বসলো। আলতো হাতে মাথা তুলে নিজের কোলো রাখলো। \"জুনায়েদ! জুনায়েদ! কি হইছে বাবা? ছোখ খোল?\" কান্নামাখা গলায় ডেকে যাচ্ছে জোহরা। অথচ ছেলের কোনো সারা নেই। ওদিকে পুরো বাড়িতে জোহরা একাই। জুনায়েদের অসুস্থতার দিন থেকে তার বাবা দরকারি কাজে ঢাকা গেছে। ছেলের অসুস্থতার কথা এখনো জানে না সে। জোহরা কাঁদো কাঁদো গলায় ডেকেই চলেছে। চোখ দিয়ে অজান্তেই টপটপ করে অঝোরে পানি ঝরছে। \n\"আমি আগেই বলেছিলাম, এমনটাই হবে।\" উঠোন থেকে অস্পষ্ট এক নারী কণ্ঠস্বর ভেসে এলো। জোহরা চোখ তুলে উঠোনের দিকে তাকিয়ে দেখে জাহানারা এসেছে। \n\"জা-হানারা আপা। দেখেন না জুনায়েদের কি হয়েছে। আজ কয়েক দিন ধরে ধুম জ্বর। ঘন ঘন রক্ত বমি করছে। চেহারা-ছবির কি অবস্থা হয়ে গেছে। আমার ছেলেটার কি হয়ে গেলো আপাআআ।\" জাহানারকে দেখেই হাউমাউ করে কেঁদে দিলো জোহরা। \n\"আমি তো বলেই ছিলাম। ওই টিটিসি ভালো না। ওখানে গেলে কেউই জীবিত থাকে না। আমার কথা তো শুনো নাই।\" গম্ভীর কণ্ঠে বললো জাহানারা। \n\"আপা! কিছু একটা করেন। আমার ছেলেটার এই অবস্থা দেখতে পারছি না আমি।\" কাঁদতে কাঁদতে বলছে জোহরা।\n\"হুম।  দেখছি কি করা যায়। ধরো ওকে। রুমে নিয়ে যাই।\" \nধরাধরি করে জুনায়েদকে তার ঘরে আনা হলো। শুইয়ে দিলো তার খাটে। ঘুমন্ত মানুষকে বুঝি এতটাই মায়াবী মনে হয়। যে সে নিষ্পাপ কোনো প্রাণ। \n\"ক-কি করছেন জাহানারা আপা?\" কাঁপা গলায় জিজ্ঞেস করলো জোহরা। জাহানারা এক রাগান্বিত চোখে তাকালো জোহরার দিকে। আবারও বিরবির করে কি যেনো পড়ছে। খানিকক্ষণ পর পর জুনায়েদের শরীরে দম ফুক করছে। এভাবে প্রায় তিন বার দম ফুক করার পর বললো, \"এখন আমি একটা তাবিজ দিয়ে যাচ্ছি। ওটা পড়ানোর এক ঘন্টার মধ্যে ওর জ্ঞান ফিরে আসবে।\" এই বলেই তার ব্যাগ থেকে একটা তাবিজ বের করে জুনায়েদের ডান হাতে বেঁধে দিলো। \n_\nআজ অনেক দিন পর ইলেকট্রিক্যাল ল্যাবে এসেছে জুনায়েদ। আশপাশটা একটু বেশিই ধূসরাজ্জ্বল। চোখ ধাধালো আলো সোজা চোখে বিধছে। স্যারের দেখানো ডায়াগ্রাম অনুযায়ী সবাই কাজ করছে যে যার বোর্ডে। আশ্চর্য করা বিষয়, এতদিন পর জুনায়েদ ল্যাবে ঢুকলো অথচ কেউ একটি বারও তার সাথে কথা বলছে না। যেনো কেউ তাকে দেখতেই পাচ্ছে না। সবকিছু উপেক্ষা করে জুনায়েদ নিজের মতো কাজ করছে। নিজের বোর্ডে একের পর এক ফিটিংস আর ফিকচার্স লাগানো শেষ। পুরো ডায়াগ্রাম অনুযায়ী ওয়্যারিং করাও শেষ। এবার কানেকশন দিতে হবে। এনার্জি মিটারে বিদ্যুৎ সংযোগ দিলো। সার্কিট ব্রেকার অন করতেই ধুম করে ব্লাস্ট করলো। পুরো ল্যাবে আগুন ধরে গেলো। জুনায়েদের মুখের একপাশ পুড়ে গেছে। ছিটকে পড়ার সময় পিছনের বোর্ডে ধাক্কা লেগে পিঠে মারাত্মক আঘাত পায়। ফ্লোরে পড়ে আছে। কাতরাচ্ছে। কেউই এগোচ্ছে না। ফ্লোর ভেদ করে একজোড়া পঁচাগলা হাত জুনায়েদকে ঝাপটে ধরে। নিজেকে ছাড়ানোর আপ্রাণ চেষ্টা করছে। চিৎকার করছে গলা চিঁড়ে। চোখ মেলে উপরে তাকাতেই দেখে সেই বিশাল দেহী লোকটা তার বড় বড় পায়ে জুনায়েদের মুখ বরাবর সেপ্টে দিলো। এক ভয়ংকর আর্তচিৎকারের সাথে এবারও তার ঘুম ভাঙলো। এটাও ছিলো একটা দুঃস্বপ্ন। বিছানার এক কোণে জড়োসড়ো হয়ে বসে আছে জুনায়েদ। হৃৎস্পন্দনের গতি বেড়ে গেছে। নিঃশ্বাস প্রশ্বাস চলছে অনবরত। \n\"জুনায়েদ!  তোর জ্ঞান ফিরেছে।\" জুনায়েদের চিৎকার শুনে জোহরা ছুটে এসেছে। দৌঁড়ে গিয়ে ছেলেকে জড়িয়ে ধরলো। জুনায়েদ কিছু বলবে এমন সময় দেখে তার মায়ের পিছনে সেই বিশাল দেহী লোকটা দাঁড়িয়ে কর্কশ কণ্ঠে হাসছে। তার খাটের দুই পাশ থেকে কর্কশ কণ্ঠের হাসি ভেসে আসছে। চোখ বুলিয়ে দেখতেই বুঝতে পারলো, সেই দুই লোক। যাদের চেহারা দেখতে কুকুরের মতো। অসহ্য যন্ত্রণা হচ্ছে তার। ওদের হাসির এক একটা শব্দ যেনো জুনায়েদের জান চিঁড়ে বেরিয়ে যাচ্ছে। এই অসহ্য যন্ত্রণা সহ্য করতে না পেরে দুই হাতের আঙ্গুল দুই কানে চেপে ধরলো জুনায়েদ। সে অনুভব করছে তার বমি পাচ্ছে। আটকে রাখার চেষ্টা করছে কিন্তু পারছে না। গলগল করে আবারও বমি করতে লাগলো। জোহরা মৃদু ছোঁয়ায় জুনায়েদের পিঠে হাত বুলাচ্ছে। দু''জনই কেঁপে উঠলো, যখন তাদের চোখে পড়লো রক্ত। হ্যাঁ! এবারও জুনায়েদ রক্ত বমি করছে। মুখ তুলে মায়ের দিকে তাকলো জুনায়েদ। জুনায়েদের চেহারা দেখে জোহরা এক চিৎকার দিলো। জুনায়েদের চেহারা দেখতে এই মুহূর্তে অতিব ভয়ংকর লাগছে। তার দুই চোখ বেয়ে রক্ত পড়ছে। নাক দিয়ে রক্ত পড়ছে। ফ্যাকাসে হয়ে যাওয়া গায়ের রঙ, চোখের নিচে কালো দাগ। নিজের ছেলোকে আজলের মতো কুৎসিত অবস্থায় এর আগে কোনোদিন দেখেনি জোহরা। \n_\nগোধূলি বিকেল পেরিয়ে আকাশ বেয়ে সন্ধ্যা নেমেছে। ঘর অন্ধকার করে শুয়ে আছে জুনায়েদ। ঘুম আসছে না তাই বিছানা ছেড়ে উঠে দাঁড়ালো। ঘরের মধ্যে পায়চারি করছে। কিছুই ঠিক লাগছে না। মনের মধ্যে এক অস্বস্তির আধার। এই কোণ ওই কোন পায়চারি করতে করতে খাটের একপাশে পা ঝুলিয়ে বসলো। নিভৃতে কাঁদে উঠলো জুনায়েদের মন। কেনো কাঁদছে? জানে না সে। ঘরের মধ্যে আলা আধারের খেলা। সবকিছু স্পষ্ট না আবার অস্পষ্টও না। হঠাৎ মনে হতে লাগলো খাটের নিচ থেকে কেউ যেনো গুনগুন করছে। উঁকি দিবে? না থাক। উঁকি দিবে ভেবেও দিলো না। তাকিয়ে আছে স্টাডি টেবিলটার দিকে। মনে হচ্ছে কতদিন বসে না এই টেবিলটাতে। উঠে এক পা টেবিলের দিকে এগোতেই খাটের নিচ থেকে কেউ পা টেনে ধরলো। ধপাস করে পড়ে গেলো সে। সামনে তাকিয়ে দেখে সেই বিশাল দেহী লোকটা দাঁড়িয়ে। তার দুই পাশে দাঁড়িয়ে আছে ওই কুকুরের মতো দেখতে লোক দুইটা। \n\"জুনায়েদ! সন্ধ্যা হয়ে গেছে বাবা, উঠ। ঘর অন্ধকার করে বসে আছিস কেনো?\" জোরে জোরে কথা বলতে বলতে জুনায়েদের ঘরে প্রবেশ করলো জোহরা। ঘরে ঢুকেই লাইট জ্বালিয়ে দিলো। লাইটের আলো পুরো ঘরে ছড়িয়ে পড়ার সাথে সাথে জোহরা ছিটকে গেলো দুই পা। জুনায়েদ ফ্লোরে বসে ঝিমাচ্ছে। জোহরা এক পা এক পা করে সামনে এগিয়ে গিয়ে জুনায়েদের কাঁধে হাত রাখলো। জুনায়েদ পিছে তাকাতেই যেনো জোহরা কেঁপে উঠলো। তার চোখ বেয়ে রক্ত পড়ছে। চোখের মনি ধবধবে সাদা। \"জু-জু-জুনায়েদ?\" কাঁপা গলায় নাম ধরে ডাকতেই জুনায়েদ ঝাপিয়ে পড়লো জোহরার উপর। শক্ত হাতে চেপে ধরলো জোহরার গলা। যেনো এক্ষুণি গলা টিপে হত্যা করবে।\nজুনায়েদ তার চোখে এক অদ্ভুত অগ্নিকুণ্ড ধারণ করে ছিলো। তার পুরো শরীর সজাগ ছিলো, যেনো কোন এক অতিপ্রাকৃত শক্তি তাকে শাসন করছে। এক হাতে জোহরার গলা চেপে ধরে, আরেক হাতে দেওয়ালে শক্ত করে আঁকড়ে ধরে রেখেছিলো। জোহরা কোনো ভাবেই তার শক্তির সাথে পেরে উঠছিলো না। তার গলা যেনো প্রায় থেমে এসেছে, নিঃশ্বাস অদৃশ্য হয়ে যাচ্ছিলো। চোখের সামনে অন্ধকার ঘনিয়ে আসছিলো, আর শরীর পুরো অবশ হয়ে যাচ্ছিলো।\nসেই মুহূর্তে, ইকরাম আর আযান সেখানে পৌঁছালো। তারা দেখলো, জুনায়েদ সম্পূর্ণ উন্মাদ হয়ে গেছে, তার দৃষ্টি ছিলো একেবারে মূর্ত, খুনের নেশায় টগবগ করছে তার শরীর। তার হাতে আটকে থাকা জোহরা ক্রমশ শ্বাসহীন হয়ে পড়ছিলো, একটানা অশ্রু ঝরছিলো চোখ থেকে। এমন দৃশ্য দেখে আযান ও ইকরাম ধস্তাধস্তি করে জুনায়েদকে শান্ত করার চেষ্টা করছিলো, কিন্তু সে যেনো কিছুই শুনছিলো না। তার চোখের ভেতরে এক অদ্ভুত ঘৃণা আর রাগের তীব্রতা ফুটে উঠছিলো।\n\"জুনায়েদ! থামো!\" আযান চিৎকার করে বললো, \"এই মুহূর্তে একদম নিজেকে হারাবে না। নিজেকে হারালে চলবে না। তুমি শক্ত না থাকতে পারলে অশরীরী তোমাকে কাবু করে ফেলবে।\"\nকিন্তু জুনায়েদ কোনো কিছুতেই কান দিচ্ছিলো না। তার শ্বাসপ্রশ্বাস ছিলো ভারী। পুরো ঘর এক উত্তপ্ত পরিবেশে ভরে গিয়েছিলো। তার হাতের শক্তি যেনো একটা নীল অগ্নির মতো লেগে গিয়েছিলো। ইকরাম এবং আযান একে অপরকে জড়ো করে জুনায়েদকে শক্ত করে ধরে ফেললো। জুনায়েদ তখনো ছিলো বিক্ষিপ্ত। সেই এক অজানা শক্তির ঝড় তাকে পাগল করে রেখেছিলো।\nআযান আর ইকরাম একযোগে শক্তি প্রয়োগ করলো, একে অপরকে সাহায্য করে জুনায়েদকে শক্তভাবে খাটের সাথে বেঁধে রাখলো। এরপর এক দীর্ঘ নীরবতা নেমে আসে।\n\"ত-তোমরা কারা?\" মিনমিন করে জিজ্ঞেস করলো জোহরা।\n\"এখন এসব কথা বলার সময় না আন্টি। আমরা জুনায়েদের সাথেই টিটিসিতে পড়ি। কয়েকদিন ধরে জুনায়েদ যাচ্ছে না, ভেবেছিলাম অসুস্থ। কিন্তু আজ আযান ভাই কিছুটা জোর করেই আমাকে আপনাদের বাসায় আসতে বাধ্য করলো। বার বার বলছিলো, এখন যদি না আসি তাহলে একটা অনর্থক হয়ে যাবে। সত্যিই যদি না আসতাম কিছু একটা হয়ে যেতো।\" এক দমে বললো ইকরাম।\n\"আলো যাদের জন্য, তারা কখনো অন্ধকারের দাম বোঝে না। আমি সেই অন্ধকার, যে সত্যকে আলোতে নিয়ে আসে।\" জুনায়েদের দিকে তাকিয়ে থেকে বললো আযান। ইকরাম ও জোহরা অবাক হয়ে তাকিয়ে রইলো। \nকিছু বুঝার আগেই জুনায়েদ আবারও অস্বাভাবিক আচরণ করতে শুরু করে। তার চোখে এক অদ্ভুত উন্মাদনা, এবং তার শরীর যেনো এক অচেনা শক্তির অধিকারী হয়ে উঠেছিলো। তার হাত পা কাঁপছিলো, মুখে এমন এক অসহনীয় রাগ যেনো তাকে নিজের থেকেই বিচ্ছিন্ন করে ফেলা হচ্ছে। জুনায়েদের চোখের মধ্যে এক ভয়ংকর অন্ধকার ছিলো, যা দেখলে যে কেউ ভয় পেতে বাধ্য হবে।\nআযান খুব ভালো করে জানে, এমন পরিস্থিতিতে যেকোনো মুহূর্তে খারাপ কিছু ঘটতে পারে। সে জানতো যে, জুনায়েদকে এরকম অবস্থায় শারীরিকভাবে শান্ত করার চেয়ে বেশি প্রয়োজন ছিল আত্মিক শান্তি এবং আল্লাহর সাহায্য।\n“আমরা এখন একমাত্র আল্লাহর সাহায্যেই জুনায়েদকে সুস্থ করতে পারবো। তুমি কি প্রস্তুত?” ইকরামের দিকে শীতল চোখে তাকিয়ে বললো আযান। ইকরাম কিছুটা দ্বিধায় ছিলো, তবে আযানের দৃঢ়তায় সে সায় দিলো।\n__\nইকরাম ধীরে ধীরে অন্ধকার গ্রামের সেই নীরব কবরস্থানের দিকে রওনা হয়। চারপাশে ঘন কুয়াশা। ঝোপঝাড়ে ভরপুর, শেয়ালের কান্নায় এক অদ্ভুত পরিবেশ তৈরি করেছে। কিছুদূর যাওয়ার পর ইকরাম সেই পুরনো কবরটার সামনে দাঁড়ায়। কবরটা অনেক পুরনো, মাটিতে ফাটল ধরেছে, আর একপাশে শুকিয়ে যাওয়া পাটপাতার স্তূপ। ইকরাম মাটি খুঁড়তে শুরু করে। ঠিক তখনই হঠাৎ পেছন থেকে গর্জনের মতো শব্দ শোনা যায়।\nসে ঘাড় ঘুরিয়ে দেখে, দুইটি বিকৃত, কুকুরের মতো দেখতে লোক তার দিকে ধেয়ে আসছে! তাদের চোখ আগুনের মতো লাল, দাঁতগুলো ধারালো, গলা থেকে বের হচ্ছে ঘন ঘন গোঁ গোঁ শব্দ। তারা ঠিক মানুষ নয়, আবার পুরোপুরি পশুও নয়। ইকরাম সাধ্যমতো প্রতিরোধ করার চেষ্টা করে। কিন্তু ওদের শক্তি অস্বাভাবিক। তার শরীর প্রায় অবশ হয়ে আসছিলো। লোক দুইটা ইকরামকে শক্ত করে ধরে রেখেছে। মাটির ভিতরে প্রায় ইকরামের মাথা গুঁজে দিচ্ছে। ইকরাম কিছুই করতে পারছে না এই মুহূর্তে। \nতখনই হঠাৎ এক অদ্ভুত প্রশান্তি ছড়িয়ে পড়ে কবরস্থানে। দূর থেকে দেখা যাচ্ছে,  সাদা জোব্বা পরা, মাথায় বড় রুমাল পেঁচানো এক ভদ্রলোক ধীরে ধীরে কুয়াশার ভেতর থেকে সামনে আসছে। তার হাতে লম্বা একটি লাঠি, চোখে তীব্র তেজ। তিনি মুচকি হেসে ইকরামের দিকে তাকান, আর কিছু না করেই শুধুমাত্র তার উপস্থিতিতে কুকুরের মতো দেখতে মানুষ দুইটি চিৎকার করে গায়েব হয়ে যায়! ইকরাম অবাক হয়ে তাকিয়ে থাকে। কিছু বলার আগেই সেই ভদ্রলোক পেছন ঘুরে ধীরে ধীরে চলে যেতে থাকেন, এবং কুয়াশার মাঝে মিলিয়ে যান। যেনো কখনো ছিলেনই না।\nইকরাম নিঃশ্বাস ছেড়ে আবার মাটি খুঁড়তে শুরু করে। কিছুক্ষণ পর মাটির নিচে স্পর্শ পায় এক ছোট্ট কাপড় মোড়ানো পুটলির। পুটলি হাতে নিয়ে ইকরাম ছুটে ফিরে আসে আযানের কাছে।\nইকরাম ফিরে আসার পর আযান প্রথমে নিয়ত করলো, “আল্লাহর রাহমত ও সাহায্যের মাধ্যমে, আমি জুনায়েদকে শারীরিক ও মানসিক সুস্থতার জন্য রুকাইয়া করছি।”\nতারপর আযান অতি ধীরে, গভীর মনোযোগ সহকারে সূরা আল-ফাতিহা পাঠ করলো। সূরার তিলাওয়াতে এমন এক শক্তি ছিলো যে, জুনায়েদের শরীরে একটু একটু করে প্রশান্তি ছড়িয়ে পড়ছিলো।\nআযান আস্তে আস্তে পড়তে থাকল সূরা আল-ইখলাস, আল-ফালাক, এবং আল-নাস। তিনটি সূরা একসাথে পড়ার পর, তার হাতে এক অদৃশ্য শক্তির অনুভব হচ্ছিলো। আযান জানতো, আল্লাহর বাণীই সবথেকে বড় শক্তি, যা সবকিছুর ঊর্ধ্বে।\nআযান তারপর দোয়া পড়তে লাগলো।\n\"اللهم إني أعوذ بك من الشيطان الرجيم\"\n\"হে আল্লাহ, আমি শয়তান থেকে তোমার আশ্রয় চাই।\"\n\"اللهم اشفِ عبدك شفاءً لا يغادر سقماً\"\n\"হে আল্লাহ, তোমার বান্দাকে এমন একটি আরোগ্য দাও, যা কোনো অসুখ রেখে যায় না।\"\nএমনকি আযান নিজ হাতে ফুঁ দিয়ে জুনায়েদের শরীরে হাত বুলিয়ে দিলো। জুনায়েদলর চোখে তখন আর আগের মতো ভয় বা উন্মাদনা ছিলো না। জুনায়েদের শরীরে কিছুটা শান্তি ফিরছিলো।\nএখন আযান হাত তুলে আল্লাহর কাছে একটি বিশেষ দোয়া করতে লাগলো।\n\"اللهم عافه في دينه ودنياه وآخرته\"\n\"হে আল্লাহ, তাকে তার ধর্ম, দুনিয়া এবং আখিরাতে সুস্থ করে দিন।\"\nদোয়া শেষে আযান দেখল, জুনায়েদের শরীর একটু নরম হয়ে এসেছে। তার শ্বাসপ্রশ্বাস এখন সহজ হয়ে গেছে, এবং তার চোখে আবার এক শান্তি ফিরে এসেছে। কিছুক্ষণ পর, জুনায়েদ সম্পূর্ণভাবে শান্ত হয়ে পড়লো। জোহরা অবাক চোখে সবকিছু পরখ করলো শুধু। কি হচ্ছে, কেনো হচ্ছে জানে না সে। এরপর আযান, ইকরামের কাছ থেকে সেই পুটলিটা নিলো। পুটলিটা খুললো। পুটলিটার ভেতরে ছিলো কুকুরের দাঁত, মানুষের চুল, জুনায়েদের জামার কিছু অংশ, ছোট হাড়, ও রক্তে ভেজা কিছু লেখা কাগজ। \n\"ভয়ংকর কালো যাদু করা হয়েছিলো জুনায়েদকে।\" বিস্মৃত সুরে বললো আযান। এতক্ষণে যেনো ইকরাম আর জোহরা নড়ে বসলো।  আযান আবারও পুটলিটা গুছিয়ে হাতে নিয়ে চোখ বন্ধ করে কিছু দোয়া পড়ে, তারপর এক টুকরো শুকনো কাঠে আগুন ধরিয়ে দেয়। দোয়ার সুরে যেনো বাতাস ভারি হয়ে আসে। আগুনে পুটলিটা ছুঁইয়ে দিতেই দপ করে এক লাল শিখা জ্বলে উঠে, চারপাশে ছড়িয়ে পড়ে এক অদ্ভুত গন্ধ। সেই মুহূর্তে জুনায়েদের চোখ খুলে যায়। তার শরীর ধীরে ধীরে স্বাভাবিক হয়ে আসে। সেই ভয়ঙ্কর উন্মাদনা আর নেই, তার চোখে ফিরে আসে চিন্তার ছায়া।\nআযান মুখ তুলে এক গভীর নিঃশ্বাস ফেলে বলে, \"আযান নামটা ওরা কখনো ভুলে যাবে না। কারণ আমি ওদের সবচেয়ে সুন্দর ভুলগুলো ঠিক করতে এসেছি, নিজের নিয়মে।\" \nইকরাম অবাক হয়ে বললো, \"কিসের ভুল?\" \n\"যুদ্ধ শুরু করিনি আমি, কিন্তু শেষটা আমার ইচ্ছেমতো হয়েছে।\" মুচকি হাসি গেলে আছে আযানের মুখে।\n\"কি হয়েছে? কিসের যুদ্ধ? কিসের ভুল? আমাকে একটু বুঝিয়ে বলবে?\" জোহরা কাঁদতে কাঁদতে বলছে। \n\"তারা ভাবে আমি নায়ক হবো। অথচ ওরা জানেই না, নায়ক হবার ইচ্ছা আমার কখনোই ছিলো না। আমি শুধু প্রতিশোধ নিতে জানি। শান্ত, ধৈর্যশীল, নির্মম।\" দীর্ঘশ্বাস ছাড়লো আযান।\n\"হেয়ালি কথাগুলো ভালো লাগছে না।\" বিরক্ত নিয়ে বললো জোহরা। তখনই খাটের উপর থেকে জুনায়েদ বললো, \"আযান ভাই! আপনি এখানে?\" সবাই ওদিকে তাকালো। \n\"আলোতে যারা খেলে, তারা ছায়ার গভীরতা বোঝে না। আমি সেই ছায়া, যে কাউকে ছাড়ে না।\" এটুকু বলে থামলো আযান। এরপর আবারও বলা শুরু করলো। \n\"আমি এখানে আসার আগে থেকেই জানতাম জুনায়েদের প্রাণ সংশয় হতে চলেছে। প্রথমে আমি আমার সাহায্যকারী জ্বিনকে পাঠাই। তার আগমনে খুব একটা কাজ হয়নি। এজন্য আমাকেই আসতে হলো। এমন মরন ফাঁদ পেতেছিলো, ওর ভাগ্য ভালো আল্লাহর ইচ্ছায় আমি ওকে সাহায্য করেছিলাম। নয়তো এতদিনে ওকে ইহলোকে খুঁজে পাওয়া যেতো না। ভেবেছিলাম, আমার উপস্থিতি টের পেয়ে ওরা এসব বন্ধ করে দিবে। কিন্তু তারা আরো উঠে পড়ে লেগেছে। এবার মজা বুঝুক।\" শান্ত ও শীতল কণ্ঠে বলে থামলো আযান।\n\"কারা? কারা এসব করেছে?\" প্রশ্ন করলো ইকরাম। জোহরাও অধীর আগ্রহ নিয়ে বসে আছে জানার জন্য। জুনায়েদও জানতে চায়, কে বা কারা ওর সাথে এমন অন্যায় করেছে।\n\"রক্তের সম্পর্ক থাকেই কেউ আপন হয় না। আপন হতে লাগে আত্মার সম্পর্ক।\" এটুকু বলে থামলো। এরপর আবারও বলা শুরু করলো, \"জুনায়েদের ফুফা আর ফুফু চেয়েছিলো ও যেনো ঢাকা ওর ফুফার শো-রুমে কাজ করতে যায়। ও ওখানে গেলে কোনো একটা চক্রান্ত করে সেখানেই ওকে মেরে ফেলতো। কিন্তু ওদের পরিকল্পনায় পানি ফেলে দিলো জুনায়েদ। এজন্যই ওর ফুফু দ্বিতীয় পরিকল্পনা করে, ওকে কালো যাদু করার। আর এসবের পিছনে দায়ী করা হয়েছে টিটিসির সেই অনাকাঙ্ক্ষিত ঘটনাকে। সে প্রমাণ করতে চেয়েছিলো, টিটিসির সেই ঘটনার পর থেকেই যে ওখানে যায় তার সাথেই এমন ঘটনা ঘটে। সবকিছু প্রমাণ করার জন্য টিটিসি''তে একের পর এক দূর্ঘটনা সে-ই ঘটায় তার পোষা বাধ্য জ্বিন দ্বারা। অতিমাত্রায় মন খারাপ থাকতো, কিন্তু মন খারাপের কোনো কারণ খুঁজে পেতো না। ঘন ঘন দুঃস্বপ্ন। সবকিছু যখন আমি মিটিয়ে দিচ্ছিলাম তখন সে তার বড় চাল চাললো।\" গম্ভীর কণ্ঠটা এবার থামলো। সবাই হতবাক। \n\"কিন্তু জাহানারা আপা এমনটা কেনো করবে? জুনায়েদ তো তারই রক্ত?\" বলেই চুপ করে গেলো জোহরা। মনে পড়লো আযানের একটু আগে বলা কথাটা। \"রক্তের সম্পর্ক থাকলেই কেউ আপন হয় না।\" \n\"আপনাদের একমাত্র ছেলে। ওর বাবার আর কোনো ভাই নেই, আছে একটা বোন। সেই বোনেরও একটাই সন্তান। যদি আপনার সন্তান মারা যাওয়ার শোকে আপনার স্বামীও মারা যায়? তাহলে এই সম্পত্তি কার হতো?\" প্রশ্ন করলো আযান। সবাই চুপ। কেউ কিছুই বলছে না।\n_\nআযানের সাথে যোগাযোগ নেই প্রায় এক বছর হয়ে গেলো। লোকটাকে ওইদিনের পর আর দেখা যায়নি। কোথায় আছে কেউ জানে না। তার বলা ঠিকানায় অনেক বার তার খোঁজ করেছে জুনায়েদ ও ইকরাম। কিন্তু পায়নি তাকে। হয়তো হারিয়ে গেছে। মানুষ কি এভাবেই হারিয়ে যায়? হয়তো! ওইদিনের পর থেকে জুনায়েদের ফুফু আর তার পরিবার কারে সাথেই কোনো সম্পর্ক রাখেনি কেউ। সপ্তাহ খানেক পর জানা যায়, জুনায়েদের ফুফা অ্যাক্সিডেন্টে করে। দুই পা একদম ভেঙে চুরমার হয়ে গেছে। তবুও ওদের বাড়ি থেকে কেউ যোগাযোগ করেনি। করার কথাও না৷ এতটা আপন হয়েও যদি কেউ এমন বিশ্বাসঘাতকতা করে তাহলে কেউই করবে না। \n_\nবিকেলের ফুরফুরে বাতাস। গোধূলি আকাশ। পাখিদের ফিরে যাওয়া। সব''টাতেই যেনো এক অপরূপ সৌন্দর্য ফুটে উঠেছে। এমন সময় সাইকেলে করে এক মাঝবয়েসী লোক এলো। জুনায়েদকে দেখে সাইকেল থামায়। \n\"এই নাও তোমার চিঠি।\"  এই বলে জুনায়েদের হাতে একটা খাম ধরিয়ে দিলো। জুনায়েদ ভাবনাগ্রস্ত হয়ে চিঠি খুলে খুলে দেখলো। কারো নাম লিখা নেই। কয়েকটা লাইন আছে।\n\"চশমার নিচে ঢাকা পড়া চোখ__\nভিড়ের মধ্যে একা হয়ে যাওয়া লোক।\nঅবসাদ কোনো কুশলকাব্য নয়,\nচড়া আলোতেও মন খারাপের ভয়।\nখুব একা লাগছে—\nকিছু কথা মনে পড়ছে,\nযদিও তারা হারিয়ে গেছে।\"\nচিঠির লিখার ধরন দেখে বুঝতে বাকি রইলো না, এটা কার চিঠি হতে পারে। তার মানে কেউ হারায় না। \"কেউ হারায় না, কেউ শুধু পথ বদলায়। সময়ের সঙ্গে সঙ্গে কেউ আমাদের গল্পে থাকে, কেউ হয়ে যায় স্মৃতি।\" মনে মনে এটা বলে চিঠি হাতে চলে গেলো সেই ব্রিজের পাশে থাকা ছোট্ট পুকুরপাড়ে।\nTHE END"}],"comments":0,"is_featured":false,"read_time":null,"season":1,"status":"published","submitted_by":"primary-admin","date":"2026-04-01T20:34:34.101Z","updated_at":"2026-04-01T20:39:57.168Z"}','2026-04-01T20:34:34.273Z','2026-04-01T20:39:57.758Z');
