INSERT INTO "app_table_rows" ("pk","table_name","row_json","created_at","updated_at") VALUES(3488336,'stories','{"id":"1775076214147","title":"অভিশপ্ত হাসি","excerpt":"__MAHEAN_META__:{\"status\":\"published\",\"submittedBy\":\"primary-admin\",\"author\":\"রিয়াদ ইসলাম আযান\",\"category\":\"ছোট গল্প\",\"categories\":[\"ছোট গল্প\",\"ভৌতিক\"],\"coverImage\":\"/uploads/stories/covers/2026/04/35bd9100-7286-4ef6-a618-e77389780fcb.png\",\"slug\":\"অভিশপ্ত-হাসি\",\"parts\":[{\"id\":\"1\",\"title\":\"01\",\"slug\":\"part-01\",\"content\":\"\"},{\"id\":\"1775076166917-2\",\"title\":\"02\",\"slug\":\"part-02\",\"content\":\"\"},{\"id\":\"1775076183022-3\",\"title\":\"03\",\"slug\":\"part-03\",\"content\":\"\"},{\"id\":\"1775076197409-4\",\"title\":\"04\",\"slug\":\"part-04\",\"content\":\"\"}],\"comments\":0,\"season\":1}:__MAHEAN_META_END__ তৃণা মায়ের কাছে এসো, মায়ের খুব কষ্ট হচ্ছে। \nখাটের উপর আমার ফোনটা নিয়ে পুলিশকে একটা কল দাও মা। \nআমি মরতে চাই নাহ, আমি তোমাদের নিয়ে বাঁচতে চাই।","content":"","author_id":"1773089545405","author":"রিয়াদ ইসলাম আযান","category_id":"ছোট গল্প","category":"ছোট গল্প","views":0,"image":null,"cover_image":"/uploads/stories/covers/2026/04/35bd9100-7286-4ef6-a618-e77389780fcb.png","slug":"অভিশপ্ত-হাসি","tags":[],"parts":[{"id":"1","title":"01","slug":"part-01","content":"তৃণা মায়ের কাছে এসো, মায়ের খুব কষ্ট হচ্ছে। \nখাটের উপর আমার ফোনটা নিয়ে পুলিশকে একটা কল দাও মা। \nআমি মরতে চাই নাহ, আমি তোমাদের নিয়ে বাঁচতে চাই।\nমায়ের এমন কথা শুনে ভয়ে রুমের দরজা বন্ধ করে চলে আসে ৭ বছরের ছোট্ট মেয়ে তৃণা।\nতৃণার মা মিসেস শ্রেয়সী দ্বিতীয় বিয়ে করেছিলেন কারণ তৃণা ও নয়না যখন ছোট তখনই ওদের নিজের বাবা গাড়ি এক্সিডেন্টে মারা যান।\nএই ছোট্ট ছোট্ট মেয়ে দুটোর মুখের দিকে তাকিয়ে শ্রেয়সী দ্বিতীয় বিয়ে করে। \nনয়নার যখন ১০ বছর হয় তখন নয়নাকে বোর্ডিং-এ পাঠিয়ে দেয় এখন তৃণাকে নিয়েই৷ তাদের ছোট্ট সংসার। \nশ্রেয়সীর যেদিন আত্মহত্যা করেন ওইদিন সকালে শ্রেয়সীর দ্বিতীয় স্বামী মিস্টার হিদায়তের সাথে অনেক ঝগড়া হয়।\nস্বামীর সাথে ঝগড়ার পর নিজেকে অপরাধী বোধ করে তখন অনেকগুলো ঘুমের ঔষধ খেয়ে শ্রেয়সী আত্মহত্যা করেন কিন্তু যখন তার শরীরে ঘুমের ঔষধ অতিমাত্রায় প্রভাব বিস্তার করতে থাকে তখন তিনি বাঁচার জন্য তৃণাকে বলে পুলিশকে কল করতে কিন্তু তৃণা ভয় পেয়ে তার মাকে রুমের মধ্যে দরজা বন্ধ করেই পালিয়ে যায়।\n২০ বছর পর....\nতৃণা আজ একটা সরকারি হাসপাতালে সাইক্রেটিস্ট ডাক্তার হিসেবে সবাইকে চিকিৎসা প্রদান করে।\nকিন্তু আজও তার মায়ের মৃত্যুর জন্য নিজেকে দায়ী মনে করে, যদি সে ওইদিন ভয় পেয়ে নাহ পালাতো তাহলে হয়তো তার মা মারা যেতো নাহ।\nদিনটা ছিলো সোমবার, হাসপাতালে আজ অনেক ভিড়, রোগী দেখা শেষ হলে তৃণা সেই হাসপাতালের প্রধান ডাক্তার হাম্মামের সাথে দেখা করে। তৃণাকে দেখে হাম্মাম কিছুটা ক্রুদ্ধ গলায় বললো....\nহাম্মাম:- দেখো তৃণা, তুমি একজন খুব ভালো ডাক্তার,  হাসপাতালে তোমার চেম্বারের রোগীর সংখ্যা বেশি। তুমি যদি তাদের বিনামূল্যে চিকিৎসা নাহ করে কিছু টাকার বিনিময়ে চিকিৎসা করো তাহলে আমাদের রোজগারটাও একটু বেশি হয়। \nতৃণা:- সরি স্যার, আমার যদি টাকা রোজগারের এত শখ থাকতো তাহলে আমি সরকারি চাকরি করতাম নাহ।\nআমি সরকারি চাকরি নিয়েছি যাতে গরীবদের বিনামূল্যে চিকিৎসা করতে পারি।\nতখন হঠাৎ করে কেবিন নাম্বার ৯৯ এর পেসেন্ট জ্যাকসন হাম্মামের চেম্বারে ঢুকে চিৎকার করতে করতে এসে তৃণার গলা চেপে ধরে তাকে উদ্দেশ্য করে বলে...\nজ্যাকসন:- তুই মরবি, তুই মরবি, হা! হা! হা! তুই মরবি, কেউ বাঁচাতে পারবে নাহ তোকে..\nতৃণা:- ওয়ার্ড বয়.! ওয়ার্ড বয়! কি আশ্চর্য রোগীরা কেবিন থেকে বের হয় কিভাবে..?\nহাম্মাম:- দাঁড়াও, তৃণা..\nজ্যাকসন কি হয়েছে তুমি ওকে এসব বলছো কেনো....\nজ্যাকসন:- ও মরবে!  ও মরবে!\nতখন দুইজন ওয়ার্ড বয় এসে জ্যাকসনকে নিয়ে যায়।\nতৃণা:- স্যার, জ্যাকসন তোহ কখনো এমন করে নাহ আজ হঠাৎ এমন করলো কেনো..?\nহাম্মাম:- কি জানি.? তুমি একটু সাবধানেই থেকো।\nতৃণা:- আচ্ছা স্যার ঠিক আছে। \nতখন তৃণার ফোনে একটা ইমার্জেন্সি কল আসে, কলটা রিসিভ করতেই....\nতৃণা:- হ্যালো, কে.?\nতিতির:- আরে, আমি তিতির, তাড়াতাড়ি ক্লিনিকে আয় একটা পেসেন্ট এসেছে.. \nতৃণা:- ১৫ মিনিট অপেক্ষা করতে বল আমি এক্ষুনি আসছি...\n১৫ মিনিট পর তৃণা পাশের ক্লিনিকে গিয়ে হাজির হলো...\nসে তার চেম্বারে গিয়ে বসলো, কিছুক্ষণ পর একটা ১৮-১৯ বছরের মেয়ে তার সামনে এসে বসলো...\nতৃণা:- কি নাম তোমার..?\nহোপ:- হোপ!\nতৃণা:- হোপ,  বাহ্ খুব সুন্দর নাম তোহ তোমার.! \nহোপ:- হ্যাঁ, ধন্যবাদ। \nতৃণা:- হোপ সোনা তুমি কি জানো তোমার নামের মিনিং কি..?\nহোপ:- হ্যাঁ জানি...\nতৃণা:- তাহলে বলো তোহ...\nহোপ:- হোপ অর্থ আশা। \nতৃণা:- বাহ্ খুব সুন্দর। \nআচ্ছা তাহলে বলো তোমার কি সমস্যা..?\nহোপ:- আমি চারপাশে শুধু একটা বিদঘুটে হাসি দেখতে পাই...\nতৃণা:- কেমন হাসি.? আর কবে থেকে তোমার এই সমস্যা..? \nহোপ:- একটা মানুষ যখন সয়তানি হাসি দেয় তখন তাকে দেখতে যেমন ভয়ংকর লাগে ঠিক ওই রকম হাসি...\nতৃণা:- কবে থেকে তুমি এমন হাসি দেখতে পাচ্ছো.??\nহোপ:- যেদিন থেকে আমার প্রফেসর আমার সামনে এই হাসি দিয়ে আত্মহত্যা করেছিলো ওইদিন থেকে আমি প্রতিনিয়ত এটা ফেস করছি...\nআমি সবাইকে বলেছি কিন্তু কেউ আমার কথা বিশ্বাস করে নাহ,  আমি জানি তুমিও আমাকে বিশ্বাস করছো নাহ...\nতৃণা:- হোপ সোনা তুমি শান্ত হও, কাম ডাউন... \nহোপ:- সবার মতো তুমিও আমাকে পাগল ভাববে আমি জানি,  কিন্তু আমি পাগল নই...\nতৃণা:- হোপ সোনা প্লিজ কাম ডাউন... \nহঠাৎ হোপ চিৎকার দিয়ে বলছে..\nহোপ:- তুমিও! তুমিও সেই বিদঘুটে হাসি দিচ্ছো...\nতোমরা সবাই একই রকম সবাই! সবাই! সবাই!\nহঠাৎ করে তৃণা হোপকে কোথাও দেখতে পাচ্ছে নাহ...\nকোথায় গেলো মেয়েটি..?\nতৃণা তাড়াতাড়ি করে সিকিউরিটি গার্ডদের কল দিয়ে পেছনে তাকাতেই দেখে হোপ তার সামনে দাঁড়িয়ে আছে, হোপের হাতে এক টুকরো কাচ...\nহোপ তৃণাকে উদ্দেশ্য করে বললো...\nহোপ:- কেউ বাঁচবে নাহ, তুমিও বাঁচবে নাহ। \nএই বলে হোপ তৃণার দিকে তাকিয়ে সেই বিদঘুটে হাসিটা দিয়ে তার হাতে থাকা কাচের টুকরোটা দিয়ে নিজের গলা কেটে ফেললো।\nএটা দেখে তৃণা একটা চিৎকার দিয়ে চেম্বার থেকে বেরিয়ে এসেই অজ্ঞান হয়ে যায়।\nকতক্ষণ অজ্ঞান হয়ে ছিলো তৃণার মনে নেই, যখন চোখ খুলে তাকালো তখন সে নিজেকে সিনিয়র ডাক্তার হাম্মাম সাহেবের কেবিনে আবিষ্কার করে।\nএবং তার চারপাশে দাঁড়িয়ে আছে হাম্মাম সাহেব, তিতির,  সাবইন্সপেক্টর ফুয়াদ ও সিনিয়র ইন্সপেক্টর শরাফত। \nতৃণা:- স্যার! স্যার! কি থেকে কি হয়ে গেলো.?  আমি কিছুই বুঝে উঠতে পারলাম নাহ.! মেয়েটার হাসিটা কি অদ্ভুত আর কি ভয়ংকর! স্যাররররর আহ্ হা হা আআআ!\nশরাফত:- আপনারা সবাই একটু বাইরে যান, উনার সাথে আমাদের একটু আলাদা ভাবে কথা বলা দরকার... \nশরাফতের কথা অনুযায়ী সবাই বাইরে চলে গেলো...\nভিতরে শুধু ফুয়াদ, তৃণা আর সিনিয়র ইন্সপেক্টর শরাফত আছেন।\nশরাফত:- তোহ ডাক্তার তৃণা বলুন কি হয়েছিলো আপনার চেম্বারে...?\nতৃণা:- স্যার মেয়েটি আমাকে ওর সমস্যার কথা বলছিলো কিন্তু হঠাৎ করে কি হলো ও নিজেই আমার সামনে সুইসাইড করলো...\nআমার খুব ভয় হচ্ছে স্যার, আমার খুব ভয় হচ্ছে.... \nফুয়াদ:- ভয়ের কিছু নেই, অ্যানকুয়ারি চালু থাকবে যতদিন নাহ মেয়েটির খুনের রহস্য সামনে আসছে...\nতৃণা:- মেয়েটি খুন হয়নি মেয়েটি সুইসাইড করেছে বিশ্বাস করো আমার কথা প্লিজ.....\nফুয়াদ:- কেউ কি করে তোমার কথা বিশ্বাস করবে বলো...? কোনো পেসেন্ট ডাক্তারের কাছে এসে কেনো সুইসাইড করবে..?\nতৃণা:- দেখো তোমার সাথে আমার ব্রেক আপ হয়েছে তাই বলে এই নাহ যে তুমি অন্যায় ভাবে আমাকে দোষারোপ করবে।\nফুয়াদ:- এখানে রিলেশন অথবা ব্রেক আপের প্রশ্ন আসছে নাহ, এখানে একটা মানুষের মৃত্যুর প্রসঙ্গ নিয়ে কথা হচ্ছে, আর একজন পুলিশ হিসেবে সবাইকে সন্দেহের চোখে দেখাই আমার কাজ।\nতৃণা:- প্লিজ আমাকে বিশ্বাস করো, আমি ওকে খুন করিনি ও সুইসাইড করেছে।\nশরাফত:- আচ্ছা বুঝলাম ও সুইসাইড করেছে...\nকিন্তু কেনো..? কোনো ক্লু আছে বা ও সুইসাইড করার আগে এমন কোনো কথা বলেছে আপনার কাছে..?\nতৃণা:- হ্যাঁ!  ও বলেছিলো ওর প্রফেসর ওর সামনে একই ভাবে গলা কেটে সুইসাইড করার পর থেকে ও সব জায়গায় ওর প্রফেসরকে দেখতে পেতো।\nফুয়াদ:- স্যার, তৃণার কথা যদি সত্যি হয়ে থাকে তাহলে তোহ এটা কোনো ভৌতিক ক্যাস বলে মনে হচ্ছে... \nশরাফত:- দেখো ফুয়াদ এখন এসব ভৌতিক ব্যাপার নিয়ে আলোচনা করার সময় নাহ, আমাদের এখন এটা প্রমাণ করতে৷ হবে মেয়েটি কি সত্যি সত্যি সুইসাইড করেছে কি নাহ।\nতৃণা:- উফ স্যার আপনারা কেনো আমাকে বিশ্বাস করছেন নাহ, মেয়েটি সত্যি সত্যি সুইসাইড করেছে।\nএক মিনিট.... \nলাশটার পাশে গেলেই তোহ জানতে পারবেন এটা সুইসাইড নাকী খুন...\nওরা সবাই লাশটির পাশে গেলে তৃণা সবাইকে বলে...\nতৃণা:- দেখুন স্যার কাঁচের টুকরোটা এখনো হোপের হাতেই আছে,  আর ওর গলায় কাটার চিহ্নটা খেয়াল করুন বাম পাশে মোটা ডান পাশে সরু।\nফুয়াদ:- আচ্ছা ধরে নিলাম এটা সুইসাইড, তাহলে তোমার সামনে এসেই কেনো ওকে সুইসাইড করতে হবে..?\nতৃণা:- সেটাই তোহ আমি বুঝতে পারছি নাহ.?\nহঠাৎ করে তৃণা লক্ষ করে তিতির সেই বিদঘুটে হাসিটা দিয়ে তৃণার দিকে তাকিয়ে আছে।\nএটা দেখে তৃণা ভয়ে একটা চিৎকার দিয়ে এদিক সেদিক ছুটতে থাকে তখন ফুয়াদ তাকে জড়িয়ে ধরে শান্ত করে বলে...\nফুয়াদ:- কি হয়েছে এমন করছো কেনো..?\nতৃণা:- তিতির সেই বিদঘুটে হাসিটা দিয়ে আমার দিকে তাকিয়ে ছিলো..!\nশরাফত:- সেই বিদঘুটে হাসি মানে কোন বিদঘুটে হাসি.? \nতৃণা:- এটা সেই বিদঘুটে হাসি যেটা হোপের প্রফেসর ওর দিকে তাকিয়ে দিয়েছি এবং নিজে সুইসাইড করেছিলো আর হোপ আমার সামনে।\nআমি বুঝতে পারছি আমিও মামা যাবো, আমাকে কেউ বাঁচাতে পারবে নাহ।\nএই বলে তৃণা কান্না করতে থাকে।\nএভাবে আরো কিছুক্ষণ তৃণার সাথে ওদের কথোপকথন হলো, তারপর তৃণাকে ফুয়াদ বাড়ি পৌঁছে দিয়ে আসার দায়িত্ব ফুয়াদকেই দেওয়া হয়...."},{"id":"1775076166917-2","title":"02","slug":"part-02","content":"তৃণাকে নিয়ে ফুয়াদ গাড়ির সামনে চলে এলো..\nতৃণা গাড়ির পেছনের সিটে বসার জন্য গাড়িতে উঠতে যাবে তখনই ফুয়াদ বলে উঠে...\nফুয়াদ:- আমি তোমার ড্রাইভার নাহ, সামনের সিটে এসে বসো।\nতৃণা ভ্রু কুঁচকে এসে সামনের সিটে বসলো। \nফুয়াদ ড্রাইভ করছে ও পাশে তৃণা বসে আছে। \nকিছুটা পথ নিঃশব্দে যাওয়ার পর তৃণা কাঁদো কাঁদো গলায় বলে...\nতৃণা:- বিশ্বাস করো ফুয়াদ আমি হোপকে খুন করিনি, ওর মৃত্যুটা অস্বাভাবিক একটা মৃত্যু, এমন মৃত্যু এর আগে আমি কখনো দেখিনি। \nআমি জানি নাহ, কিন্তু ওর বলা প্রত্যেকটা কথা আমার এখন বিশ্বাস হচ্ছে, কারণ ও আমার সামনে সুইসাইড করার পর আমিও সেইম একই জিনিস চোখের সামনে দেখতে পাচ্ছি। \nফুয়াদ, শুনতে পাচ্ছো তোহ..?\nপ্লিজ বিলিভ মীহ্..!\nফুয়াদ:- দেখো তৃণা, তোমার কথাগুলো নাহয় আমি বিশ্বাস করলাম কিন্তু এগুলো তোহ আদালতে প্রমাণ করতে হবে..?\nতৃণা:- কি! এই সামান্য একটা বিষয়কে তোমরা আদালত অব্দি নিতে চাচ্ছো..?\nফুয়াদ:- এটা তোমার কাছে সামান্য মনে হতে পারে কিন্তু আমাদের কাছে অনেক কিছু।\nতৃণা:- প্লিজ ফুয়াদ কিছু একটা করো, বিশ্বাস করো আমি খুন করিনি। \nফুয়াদ:- আচ্ছা ওইসব আমার উপর ছেড়ে দাও, এখন শুনো তোমাকে একটা কথা বলতে চাই...\nতৃণা:- হ্যাঁ বলো..?\nফুয়াদ:- আমার লাইফে কি আবার কাম ব্যাক করা যায় নাহ.?\nতৃণা:- নাহ, এটা কখনোই সম্ভব নাহ। আমি এখন নতুন সম্পর্কে আছি আমি তাকে কিছুতেই ঠকাতে পারবো নাহ।\nফুয়াদ:- আচ্ছা যাই হোক, তোমার যেকোনো বিপদে আমাকে পাশে পাবে শুধু একটা ডাক দিও।\nতৃণা:- ঠিক আছে। \nএসব কথা বলতে বলতে তৃণা নিজের বাড়ি পৌঁছে গেলো...\nবাসায় এসে দেখে পুরো বাড়ি অন্ধকার, ভাবলো হয়তো লোডশেডিং হয়েছে।\nপরে ফোনের টর্চ জ্বালিয়ে লাইটের সুইচ চাপতেই পুরো ঘরে আলো জ্বলে উঠে। \nলাইটের আলোয় খেয়াল করলো তৃণার জামায় রক্ত লেগে আছে, জামায় রক্ত দেখে তৃণা কিছুটা ভয় পেয়ে যায়।\nএতক্ষণ সে খেয়াল করেনি যে তার জামায় রক্তের দাগ ছিলো হঠাৎ বাড়ি আসার পরই কেনো খেয়াল হলো যে তার জামায় রক্ত। \nহাজারটা চিন্তা মাথায় নিয়ে তৃণা ড্রেস চেঞ্জ করার জন্য কাবাড থেকে ড্রেস বের করার সময় দেখে কাবাডের মধ্যে হোপ বসে আছে তৃণাকে দেখে সেই বিদঘুটে হাসিটা দিলো।\nতৃণা প্রচন্ড ভয়ে একটা চিৎকার দিয়ে নিজের ঘরে থেকে বের হয়ে ড্রয়িংরুমে চলে আসে... \nড্রয়িংরুমে এসে দেখে হোপ সোফায় বসে তাকে দেখে সেই বিদঘুটে হাসিটা দিয়ে হাসছে।\nতৃণা এবারও ভয়ে চিৎকার দিয়ে ওখানেই জ্ঞান হারায়।\nকিছুক্ষণ পর তৃণার জ্ঞান ফিরলে দেখে সে এখনো ড্রয়িংরুমে পরে আছে।\nততক্ষণে তৃণার খুব ক্ষুধা লেগেছিলো তাই সে কিচেনে যায় কিছু খাবার খেতে।\nসে যখন ফ্রিজ থেকে খাবার বের করছিলো তখন মনে হচ্ছে কেউ তার পিছনে দাঁড়িয়ে আছে, সে পিছনে ঘুরতেই দেখে তার প্রেজেন্ট বয়ফ্রেন্ড \"ঋ\" দাঁড়িয়ে আছে। \nএতক্ষণে যেনো তৃণার শরীরে প্রাণ ফিরে পেলো।\nঋ''কে দেখে তৃণা প্রথমে কিছুটা ভয় পেলেও পরে একটা স্বস্তির নিঃশ্বাস ফেলে তার সাথে কথা বলে।\nতখন ঋ বলে...\nঋ:- তোমার জন্য একটা সারপ্রাইজ আছে..\nতৃণা:- কি সারপ্রাইজ..?\nঋ:- চলো আমার সাথে... \nতৃণা:- কোথায় যাবো..?\nঋ:- আরে চলোই নাহ..!\nতৃণা:- দাঁড়াও আমার খুব ক্ষুধা লেগেছে কিছু খেয়ে নি.?\nঋ:- উফ বাদ দাও এসব চলো আমার সাথে.. \nতৃণা:- আচ্ছা ঠিক আছে, একটু দাঁড়াও আমি ড্রেস চেঞ্জ করে আসছি।\nতারপর তৃণা ঋ-এর সাথে বেরিয়ে পরে।\nকিছুক্ষণ পর তৃণা ও ঋ একটা ফাইভ স্টার রেস্টুরেন্টে যায়, সেখানে গিয়ে তৃণা একদম সারপ্রাইড হয়ে যায় কারণ সেখানে তৃণার বড় বোন নয়না ও তার হাসবেন্ড অ্যারিক ছিলো।\nতৃণা দৌড়ে গিয়ে নয়নাকে জড়িয়ে ধরে বললো...\nতৃণা:- আপু.! কেমন আছিস তুই.? কতদিন পর তোর সাথে দেখা.!\nনয়না:- ভালো আছি, তুই কেমন আছিস.? থাকি তোহ একই শহরে কিন্তু আমার ডাক্তার বোনটা যে এত ব্যস্ত বোনের খোঁজটুকু নেওয়ার সময় পায় নাহ।\nতৃণা:- আমিও ভালো আছি। হ্যাঁ রেহ আপু সরকারি হাসপাতাল বুঝিসই তোহ।\nনয়না:- এজন্যই তোহ তোর দুলাভাই তোকে একটা প্রাইভেট হসপিটালে জব দিতে চেয়েছিলো কিন্তু তুইই তোহ সরকারি হাসপাতালে জয়েন করলি।\nতৃণা:- আপু..! তুই তোহ আমার ইচ্ছা সম্পর্কে জানিসই..?\nনয়না:- হ্যাঁ!  যাই হোক এসব বাদ দে তোর সাথে ইম্পর্ট্যান্ট কথা আছে..\nতৃণা:- কি কথা রেহ আপু..?\nনয়না:- আমাদের যেই ফার্ম হাউসটা আছে নাহ ওইটা বিক্রি করে দেবো ভাবছি...\nতৃণা:- কি বলছিস এসব.? তোর মাথা ঠিক আছে তোহ.? আপু ওই ফার্ম হাউসটাতেই আমাদের শৈশব কেটেছে, ওই ফার্ম হাউসেই আমাদের মায়ের শেষ স্মৃতি আছে। আর তাছাড়া ওই ফার্ম হাউসটা বিক্রি করলে কত টাকাই বা পাবো।\nআমি এসব সম্পর্কে কিছুই বলতে পারবো নাহ,৷ তোর যা ইচ্ছে কর।\nনয়না:- কিন্তু... \nতৃণা:- কোনো কিন্তু নাহ আপু, অন্য কোনো কথা থাকলে বল...\nনয়না:- পরশু আমার ছেলের বার্থডে চলে আসিস।\nতৃণা:- ঠিক আছে, এখন আমি গেলাম।\nঅ্যারিক:- আরে কোথায় যাচ্ছো.? ডিনার করে যাও.?\nতৃণা:- আর ডিনার করে কি হবে জিজু..?\nঅ্যারিক:- তোমার বোনের কথা বাদ দাও তোহ, ও কখন কি বলে নিজেই জানে নাহ.!\nঋ:- জিজু এত করে বলছেন ডিনারটা করেই যাও, তাছাড়া তুমি তোহ কিছুই খাওনি...\nতৃণা:- আচ্ছা ঠিক আছে। \nডিনার শেষে তৃণা কারো সাথে কোনো কথা নাহ বলে চলে আসে..\nতৃণার এমন আচরণ দেখে সবাই হতভম্ব হয়ে গেলো, কারণ এত শান্ত শিষ্ট মেয়েটা হঠাৎ করে এত রেগে যেতে পারে কেউ কখনো কল্পনাও করতে পারেনি।\nডিনার শেষে তৃণা বাড়ি চলে আসে....\nবাড়ি এসে তৃণা নিজের ড্রেস চেঞ্জ করে এসে ড্রেসিং টেবিলের সামনে নিজেকে দেখছিলো হঠাৎ সে লক্ষ করে আয়নার ভিতরে থাকা তার প্রতিবিম্বটা সেই বিদঘুটে হাসি দিয়ে স্থির হয়ে দাঁড়িয়ে আছে।\nসে ভয়ে ড্রেসিং টেবিলের সামনে থেকে সরে যায়।\nএবার আর কোনো দিক নাহ চিন্তা করে সে ঘুমনোর চেষ্টা করতে লাগলো।\nচোখ দু''টো ঘুমে বন্ধ হয়ে আসছিলো তখন সে অনুভব করে তার অপর পাশে কেউ শুয়ে আছে, সে পিছন ফিরতেই দেখে হোপ তার দিকে তাকিয়ে সেই বিদঘুটে হাসিটা দিয়ে তার সাথে একই বিছানায় শুয়ে আছে।\nতৃণা এবারও ভয়ে চিৎকার দেয়, সাথে সাথে হোপ উধাও হয়ে যায়।\nসারারাত ঠিক মতো ঘুমতে পারেনি তৃণা।\nপরদিন সকালে ঘুম থেকে উঠে ব্রেকফাস্ট করে তৃণা হসপিটালের উদ্দেশ্যে রওনা হয়..."},{"id":"1775076183022-3","title":"03","slug":"part-03","content":"পরদিন সকালে তৃণা সময় মতো হসপিটালে নিজের চেম্বারের সামনে যেতেই দেখে ওর চেম্বারে তালা দেওয়া.... \nতৃণা:- কি ব্যাপার.?  আমার চেম্বারে তালা দেওয়া কেনো..?\nছুটে চলে গেলো হসপিটালের সিনিয়র ডাক্তার হাম্মাম সাহেবের কেবিনে। \nতৃণা:- স্যার, আমার চেম্বারে তালা দেওয়া হয়েছে কেনো..?\nহাম্মাম:- ৭ দিনের জন্য তোমার ডাক্তারি লাইসেন্স বাতিল করা হয়েছে.!\nতৃণা:- কি.! কেনো এমনটা করলো..?\nহাম্মাম:- তুমি জানো নাহ কেনো এমনটা করা হলো..?\nতৃণা:- কিন্তু স্যার.. \nহাম্মাম:- তৃণা, যা হয়েছে ভুলে যাও ৭ দিন পর থেকে আবার জয়েন করবে এখন তুমি আসতে পারো...\nতৃণা:- স্যার, আমার লাইসেন্স বাতিল করার খবর কে দিয়েছে আপনাকে..?\nহাম্মাম:- সাব ইন্সপেক্টর ফুয়াদ\nতৃণা চলে আসবে তখন আবারও জ্যাকসন তৃণার গলা চেপে ধরে হাসতে হাসতে বলতে থাকে...\nজ্যাকসন:- তুই মরবি, তুই মরবি,  হা! হা! হা!\nহাম্মাম কোনোমতে জ্যাকসনের হাত থেকে তৃণাকে ছাড়িয়ে নেয়, তৃণা আড় দৃষ্টিতে জ্যাকসনের দিকে তাকিয়ে চলে গেলো।\nকিছুক্ষণ হসপিটালের বাইরে বসে থেকে তৃণা ভাবলো ফুয়াদের সাথে কথা বলা উচিৎ তাই সে পুলিশ স্টেশনে গেলো ফুয়াদের সাথে দেখা করতে...\nপুলিশ স্টেশনে গিয়ে শুনে ফুয়াদ আজকে অফ ডে''তে আছে সে ছুটি নিয়েছে ২ দিনের।\nতৃণা এবার ঠিক করলো ফুয়াদের বাসায় যাবে, তৃণার কাছে ফুয়াদের বাসায় যেই ঠিকানা ছিলো ওই ঠিকানা অনুযায়ী গেলে তৃণা জানতে পারে ফুয়াদ কিছু মাস আগেই সেই বাসা ছেড়ে নতুন বাসায় সিফট হয়েছে...\nতারপর তৃণা আবারও পুলিশ স্টেশনে গিয়ে থানার হাবিলদার বারীরের কাছ থেকে ফুয়াদের নাম্বার ও বাড়ির ঠিকানা নেয়।\nএবার সে সঠিক ঠিকানায়ই এসেছে।\nদরজার সামনে গিয়ে কলিং বেল চাপার কিছুক্ষণ পর কেউ একজন দরজা খুললে দেখতে  পারে ফুয়াদ নিজেই দরজা খুলেছে...\nতৃণাকে দেখে ফুয়াদ বললো...\nফুয়াদ:- তৃণা! তুমি.? ভেতরে আসো.!\nতারপর তৃণা ভেতরে গিয়ে ফুয়াদের বাসায় আসার জন্য তাকে কতখানি পরিশ্রম করতে হয়েছে সবটা জানায়।\nতারপর তৃণা ফুয়াদকে বলে...\nতৃণা:- আমার লাইসেন্সটা বাতিল করার কি খুব জরুরি ছিলো..?\nফুয়াদ:- তৃণা, তুমি বুঝতে পারছো নাহ.?\nআমি চাই নাহ এই সামান্য একটা কেইসের জন্য তোমার ক্যারিয়ারে কোনো দাগ পরুক তাই কেইসটা সম্পূর্ণ ডিসমিস করে দিয়েছি আর আদালত থেকে রান এসেছে ৭দিন তোমার ডাক্তারি লাইসেন্স বাতিল। \nতৃণা:- কি! সত্যি.? কেইসটা সম্পূর্ণ ডিসমিস হয়েছে...?\nফুয়াদ:- হ্যাঁ সত্যি। \nতৃণা খুশিতে ফুয়াদকে জড়িয়ে ধরে, তারপর দুইজনই হতভম্ব হয়ে গেলে তৃণা ফুয়াদকে দূরে সরিয়ে দেয়।\nতারপর ফুয়াদ তৃণাকে লাঞ্চের অফার করলে তৃণা রাজি হয়ে যায়...\nতৃণা ফুয়াদকে এটাও জানায় যে আজকে তার বোনের ছেলের জন্মদিন,  লাঞ্চ শেষে যেনো ফুয়াদ তাকে গিফট কিনতে হেল্প করে।\nতারপর তৃণা আর ফুয়াদ একটা রেস্টুরেন্টে গিয়ে লাঞ্চ করে।\nলাঞ্চ শেষে তারা একটা খেলনার দোকানে গিয়ে এক্সপেন্সিভ মডেলের একটা গাড়ি কিনে আনে।\nগিফট কেনা শেষে তৃণা ফুয়াদকে থ্যাংকস জানিয়ে সেখান থেকে বিদায় নেয়।\nফুয়াদকে বিদায় জানিয়ে সে একটা ক্যাট হাউস থেকে তার পোষা বিড়ালের জন্য কিছু খাবার কিনে নেয়।\nতৃণার বাড়ি ফিরতে ফিরতে সন্ধ্যা হয়ে গেলো।\nবাড়ি এসে তৃণা তার বিড়ালটির জন্য খাবার রেডি করছিলো তখন সে পেছনের দরজা খোলার শব্দ পায়, প্রথমে ভাবে হয়তো কোনো চোর এসেছে তাই হাতে একটা ছুড়ি নিয়ে পেছনের দরজার সামনে যায়,  গিয়ে দেখে দরজাটা খোলা...\nসে দরজা বন্ধ করে পেছন ফিরে তাকাতেই দেখে হোপ তার দিকে তাকিয়ে সেই বিদঘুটে হাসি দিচ্ছে.. \nহঠাৎ হোপ তৃণার হাত থেকে ছুড়িটা নিয়ে আবারও নিজের গলা কাটছে, তৃণা চিৎকার দিতেই সব উধাও হয়ে যায় এবং দেখে ছড়িটাও তার হাতেই... \nতারপর তৃণা তার বিড়ালটিকে খুঁজে খাবার খাওয়ার জন্য কিন্তু বিড়ালটি কোথায় খুঁজে পাচ্ছিল নাহ তাই সে দরজার বাইরে খাবারের বাটি রেখে ভিতরে চলে যায়।\nএবার সে তার বোনের বাসায় যাওয়ার জন্য ড্রেস বের করছিলো তখন দেখতে পায় হোপ কাবাডের উপর বসে পা দোলাচ্ছে তার হাসছে...\nতৃণা আবারও ভয়ে ঘরে থেকে ছুটে বাইরে চলে আসতে যাবে তখনই ঋ-এর সাথে ধাক্কা লাগে এবং সে সাথে সাথে অজ্ঞান হয়ে যায়।\nঋ তার চোখে মুখে পানি ছিটিয়ে দিলে তৃণার জ্ঞান ফিরে তারপর সে ঋ-এর কাছে সবটা খুলে বলে, কিন্তু ঋ তাকে বিশ্বাস করে নাহ।\nতৃণা:- বিলিভ মীহ্ ঋ ওইদিনের পর থেকে আমার সাথেও একই ঘটনা ঘটছে যেমনটা হোপ আমাকে বলেছিলো...\nঋ:- এসব তোমার মনে ভুল, তুমি এগুলো নিয়ে ভাবছো বলেই তোমার চোখের সামনে এগুলো ভাসছে...\nতৃণা:- প্লিজ অ্যারিক বিলিভ মীহ্ \nঋ:- দেরি হয়ে যাচ্ছে চলো এবার.. \nতৃণা:- তুমি আমাকে বিশ্বাস করো তাই তোহ.?\nঋ:- দেরি হয়ে যাচ্ছে বললাম তোহ, যাও তাড়াতাড়ি রেডি হয়ে আসো...\nতৃণা:- আমি কোত্থাও যাবো নাহ, তুমি যাও..\nতখনই তৃণার ফোনের নয়নার কল.. \nনয়না:- হ্যাঁ, হ্যালো! তৃণা কিরে কই তোরা তাড়াতাড়ি আয়, তোদের জন্য বান্টি ওয়েট করছে তোরা নাহ আসলে ও কেক কাটবে নাহ।\nতৃণা:- আসছি আপু কিছুক্ষণ অপেক্ষা কর।\nনয়না:- আচ্ছা তাড়াতাড়ি আয়।\nঋ:- যাও এবার তাড়াতাড়ি রেডি হয়ে আসো...\nতৃণা তাড়াতাড়ি রেডি হয়ে অ্যারিকের সাথে বেরিয়ে পরে...\nকিছুক্ষণ পরই তারা নয়নার বাড়ি পৌঁছে যায়, তৃণা আর ঋ নিজেদের হাতে থাকা গিফটগুলো বান্টির হাতে দিলো।\nবান্টি গিফটগুলো একটা টেবিলে রেখে কেক কাটতে চলে এলো।\nকেক কাটা শেষে বান্টি সবার দেওয়া গিফটগুলো খুলছিলো,  তৃণার দেওয়া গিফটটা খুলা মাত্রই বান্টি ভয়ে গিফটটা ফেলে দেয়..\nগিফট ফেলে দেওয়ার পর সবাই দেখতে পায় গিফটটের প্যাকেটে তৃণার পোষা বিড়ালের লাশ।\nএসব কর্মকাণ্ড দেখে তৃণাকে সবাইকে বকতে থাকে...\nঋ:- এসব কি তৃণা..?\nতৃণা :- আমি জানি নাহ.!\nনয়না:- তোর মিনিমাম কমন সেন্সটুকু নেই, একটা ছোট্ট বাচ্চাকে তুই এসব দিস, ছিহ্!\nতৃণা:- বিশ্বাস কর আপু আমি এসব কিছুই করিনি..\nনয়না:- একদম চুপ, তুই কোনো কথা বলবি, আজকের পর থেকে যেনো তোকে আমার এবং আমার ছেলের আশেপাশেও নাহ দেখি।\nতৃণা নিজের আপন মায়ের পেটের বোনের মুখে এসব কথা শুনে কান্না করতে লাগলো হঠাৎ সে দেখে তাদের মধ্যে একজন মহিলা চেয়ারে বসে সেই বিদঘুটে হাসিটা দিয়ে তৃণার দিকে তাকিয়ে আছে, তৃণা ভয়ে এক পা দু-পা করে পিছতে পিছতে তার পিছনে থাকা কাচের টি টেবিলের উপর পরে যায় সাথে সাথে সে অজ্ঞান হয়ে যায়।\nজ্ঞান ফিরতেই দেখে সে হসপিটালে ভর্তি।"},{"id":"1775076197409-4","title":"04","slug":"part-04","content":"তৃণার জ্ঞান ফিরলে দেখে সে হসপিটালে ভর্তি।\nকিছুক্ষণ পর তৃণার কেবিনে তার বয়ফ্রেন্ড আসে.. \nঋ:- দেখো তুমি এখন অনেক পাগলামো করছো আমার পক্ষে তোমার সাথে এই রিলেশনটা এগিয়ে নেওয়া পসিবল নাহ, সো ব্রেক আপ...\nতৃণা:- হ্যাঁ, আমাকে এমন একটা সিচুয়েশনে রেখে তোমরা সবাই যে যার মতো চলে যাচ্ছো, কোনো সমস্যা নেই একদিন আমারও সময় আসবে...\nঋ:- গুড বাই এন্ড টেক কেয়ার ইউর-সেলফ\nঋ চলে গেলে তৃণাও নিজেকে ডিসচার্জ করে বাড়ি চলে আসে।\nএবার সে মনে মনে বলতে থাকে, যেভাবেই হোক সে এই মৃত্যুর খেলাকে হারাবে।\nএটার রহস্য সে ভেদ করবে।\nতৃণা এবার ফুয়াদকে কল দিয়ে তার সাথে দেখা করতে বলে...\nবেশ কিছুক্ষণ পর ফুয়াদ আর তৃণা একে অপরের সাথে দেখা করে, তৃণা ফুয়াদকে সবটা খুলে বলে, তারপর তৃণা ফুয়াদের কাছে কিছু সাহায্য চায়...\nতৃণা:- ফুয়াদ আমার এখন তোমার কিছু সাহায্যের প্রয়োজন.. \nফুয়াদ:- কেমন সাহায্য বলো..\nতৃণা:- আমাকে একবার হোপের বাড়ির লোকদের সাথে কথা বলাতে পারবে..?\nফুয়াদ:- হ্যাঁ পারবো..\nতৃণা:- তাহলে এক্ষুনি চলো..\nতৃণা আর ফুয়াদ হোপের বাড়ির লোকদের সাথে কথা বলতে তাদের বাড়ি যায়...\nহোপের আব্বুর মিস্টার পিটারের সাথে তাদের দেখা হয়... \nতৃণা:- আমার আপনার কিছু হেল্প প্রয়োজন প্লিজ নাহ করবেন নাহ..\nপিটার:- কেমন হেল্প..? \nতৃণা:- হোপ আপনাদের কাছে যে হাসিটার কথা বলতো ওইটা একদম মিথ্যা নয়, ওইটা সত্যি! \nহোপ আমার সামনে সুইসাইড করার পর থেকে আমি এখন প্রতিনিয়ত এটা ফেস করছি। \nআপনি প্লিজ হোপের প্রফেসরের সম্পর্কে কিছু তথ্য দিন আমাকে প্লিজ... \nপিটার:- আমি যতটুকু জানি হোপের প্রফেসরের নাম ছিলো জ্যাস পল... \nএর বাইরে আমি আর কিছুই জানি নাহ, আর হ্যাঁ! উনার লিখা অনেক বইও পাবলিশড আছে তার মধ্যে একটি হলো \"U Turn\"  \nতৃণা:- আচ্ছা আপনাকে অনেক অনেক ধন্যবাদ। \nতৃণা আর ফুয়াদ হোপের বাবার সাথে কথা বলে চলে আসে...\nতৃণা:- ফুয়াদ তুমি এবার তোমার বাড়ি যাও আবার প্রয়োজন হলে তোমাকে কল করবো,  আর হ্যাঁ আমার এই সময়টাতে আমার পাশে থাকার জন্য তোমাকে অসংখ্য ধন্যবাদ... \nফুয়াদ:- ধন্যবাদ দিয়ে ছোট করছো আমায়, একজন পুলিশ অফিসার হিসেবে এটা আনার দায়িত্ব। \nতোমার যখন যেকোনো দরকারে আমাকে একটা কল দিলেই আমি চলে৷ আসবো..\nতৃণা:- আচ্ছা। \nতৃণা এবার নিজের বাড়িতে বসে ল্যাপটপে জ্যাস পল সম্পর্কে রিসার্চ করে জানতে পারে,  সে একজন বিখ্যাত রাইটার্সের পাশাপাশি প্রাইভেট স্কুলের প্রফেসর। \nসে একদিন হঠাৎ করেই নিজেই নিজের গলা কেটে সুইসাইড করে।\nসে সুইসাইড করার আগে বার বার একটা বিদঘুটে হাসির কথা বলতো...\nতৃণা ওয়েবসাইট থেকে জ্যাস পলের বাড়ির ঠিকানা নিয়ে সেখানে চলে যায়।\nতৃণা জ্যাস পলের বাড়ি গিয়ে নিজেকে একজন সাংবাদিক হিসেবে পরিচয় দেয়।\nওখানে গিয়ে জানতে পারে প্রফেসর মারা যাওয়ার পর তার স্ত্রী \"ডায়না\" একদম একা হয়ে গেছে, সে কারো সাথে তেমন মিশে নাহ, সারাক্ষণ নিজেকে ঘরেই বন্দী করে রাখেন।\nতৃণা প্রফেসরের স্ত্রীকে তার মৃত্যু সম্পর্কে জিজ্ঞেস করলে ডায়না বলে...\nডায়না:- মানুষটা অনেক ভালো ছিলো, হঠাৎ একদিন রাতে সে বাসায় আসার সময় তার গাড়ির সামনে একজন মহিলা এসে দাড়ায় সে মহিলাটির কাছে যেতেই মহিলাটি নাকী তার দিকে তাকিয়ে একটা বিদঘুটে হাসি দিয়ে নিজের গলা কেটে সুইসাইড করে। \nএরপর থেকে সে সর্বক্ষণ একটা কথা বলতে থাকতো, বিদঘুটে হাসি আর বিদঘুটে হাসি। \nউনি সেই হাসিটির একটা পেইন্টিং-ও করপছেন.।\nতৃণা:- আমি কি দেখতে পারি সেই পেইন্টিং-টি।\nতারপর ডায়না তৃণাকে সেই পেইন্টিং''টি দেখায়।\nপেইন্টিং-টি দেখে তৃণা ভয়ে চিৎকার দিয়ে বলে...\nতৃণা:- আপনার স্বামী মিথ্যা বলেনি, এটা সত্যি উনি কোনো মিথ্যা বলেননি, উবার জন্য এখন আমি এই অভিশপ্ত হাসির অভিশাপে ভুগছি।\nতৃণার মুখে এসব কথা শুনে প্রফেসর জ্যাস পলের স্ত্রী ভয়ে তৃণাকে বাড়ি থেকে বের করে দেয়।\nপ্রফেসরের বাড়ি থেকে আসার পর তৃণার ফোনে ফুয়াদের কল...\nফুয়াদ:- তৃণা তাড়াতাড়ি একবার দেখা করতে পারবে...\nতৃণা:- এখন..?\nফুয়াদ:-  হ্যাঁ এখন..\nতৃণা ফু্য়াদের বাড়ি গেলে ফুয়াদ তৃণাকে বলে...\nফুয়াদ:- লুক, তৃণা  আমি এই কেসটা নিয়ে ঘাটাঘাটি করে ২০টা ডায়েরি পেয়েছি, তার মধ্যে ১৯জন মারা গেছে আর একজন জেলে আছে...\nওই লোকটির নাম হ্যারিস, ২ বছর আগে নিজের বন্ধুকে খুন করার দায়ে জেল খাটছে।\nতৃণা:- তার মানে ওই একজনই জানে কিভাবে এই অভিশাপ কাটানো যায়, ফুয়াদ তাড়াতাড়ি আমাকে ওই লোকটির কাছে নিয়ে চলো...\nফুয়াদ:- আচ্ছা চলো।\nতৃণা:- দাঁড়াও.. \nফুয়াদ:- আবার কি..\nতৃণা:- ফুয়াদ এই মৃত্যুগুলো একটা প্যাটার্নে চলছে...\nপ্রফেসরের সামনে এক অচেনা মহিলা সুইসাইড করার পর থেকে প্রফেসর এমন উদ্ভট আচরণ করতে শুরু করে, তারপর উনি হোপের সামনে সুইসাইড করার পর হোপ এমন আচরণ করে, সবশেষে হোপ আমার সামনে সুইসাইড করার পর আমিও।\nফুয়াদ আমি মরতে চাই....\nফুয়াদ:- এমন কিছুই হবে নাহ, আমরা দু''জন মিলে এটার সমাধান বের করবো...\nতুমি ভয় পেয়ো নাহ...\nকিছুক্ষণ পর ফুয়াদ আর তৃণা হ্যারিসের কাছে যায়...\nতৃণা হ্যারিসের কাছে জানায় তার একজন পেসেন্ট এখন এমন সিচুয়েশনে আছে তাই সে হ্যারিসের কাছে জানতে এসেছে কিভাবে এই অভিশাপ কাটানো যায়...\nহ্যারিস:- আগে তোমার সাথে আসা পুলিশ অফিসারকে এখান থেকে যেতে বলো...\nতারপর ফুয়াদ বাইরে চলে যায়....\nহ্যারিস:- আমি একটা অফিসে কাজ করতাম ওই অফিসের একটা স্টাফ আমার সামনে একই ভাবে সুইসাইড করেছিলো সে বার বার বলতো তার সামনে আমাদের অফিসের বস এভাবে নিজের গলা কেটে সুইসাইড করেছিলো তাই সে প্রতিদিন বসকে দেখতো, পরে জানা যায় বসের সামনে তার ওয়াইফ সুইসাইড করেছিলো আর তার ওয়াইফের সামনে এক অচেনা লোক।\nতৃণা:- তাহলে আপনি বেঁচে আছেন কিভাবে...?\nহ্যারিস:- হয় নিজে মরো নয়তো কাউকে খুন করো, হা! হা! হা! আমি আমার এক বন্ধুকেই খুন করে ফেলি...\nতখন তৃণা কান্না করতে করতে চিৎকার দিয়ে বলে...\nতৃণা:- আমি কাউকে খুন করতে পারবো নাহ...\nহ্যারিস:- তার মানে.? এই অভিশাপ এখন তোমার মধ্যে...? \nতারপর হ্যারিস ভয়ে চিৎকার করতে করতে বলে...\nহ্যারিস:- এই মেয়েকে কেউ এখান থেকে নিয়ে যাও ও অভিশপ্ত ওকে কেউ বাঁচাতে পারবে নাহ নিয়ে যাও ওকে....\nওখান থেকে তৃণা ফুয়াদকে কিছু নাহ বলেই নিজের বাড়ি চলে যায়।\nপরদিন সকালে তৃণা নিজের গাড়ি নিয়ে হসপিটালে যায়।\nহসপিটালের সামনে গাড়ি দাড় করিয়ে গাড়ির ড্রয়ার থেকে একটা ছুড়ি নিয়ে হসপিটালের ভিতরে চলে গেলো।\nহসপিটালের ভিতরে গিয়ে তৃণা জ্যাকসনকে বার বার ছুড়ি দিয়ে আঘাত করতে থাক, ওদের চেচামেচির শব্দ শুনে সিনিয়র ডাক্তার হাম্মাম ছুটে এসে দেখে তৃণা জ্যাকসনকে ছুড়ি দিয়ে আঘাত করছে।\nডাক্তার হাম্মাম তৃণাকে অনেক টানাটানি করেও আটকাতে পারে নাহ।\nপরক্ষণেই তৃণা খেয়াল করলো ডাক্তার হাম্মাম তৃণার দিকে তাকিয়ে সেই বিদঘুটে হাসিটা দিয়ে নিজেই নিজের মুখের চামড়া টেনে তুলছে।\nডাক্তার হাম্মামের এই অবস্থা দেখে তৃণা ভয়ে চিৎকার দিতেই দেখে সে এখনো গাড়ির ভিতরেই বসে আছে....\nতার মানে ওই সয়তানি আত্মাটা তৃণার মাইন্ড নিয়ে খেলছে।\nতৃণাকে গাড়ির মধ্যে বসে থাকতে দেখে ডাক্তার হাম্মাম ওর দিকে আসতেই তৃণা ভয়ে গাড়ি স্টার্ট দিয়ে ওখান থেকে চলে আসে। \nতৃণা মনে করছে হয়তো এবারও ডাক্তার হাম্মামের রূপ নিয়ে ওই আত্মাটা ওর সামনে আসতে চাইছে।\nতখনই তৃণার ফোনে ফুয়াদের কল আসে....\nফুয়াদ:- তৃণা, কোথায় আছো তুমি..?\nতৃণা:- আমাকে এখন একা থাকতে হবে ফুয়াদ, আমি কারো সামনে যাবো নাহ তাহলে সুইসাইডও করতে পারবল নাহ আর এই অভিশাপটাও আর কারো শরীরে যেতে পারবে নাহ।\nফুয়াদ:- এই কাজটা আমরা একসাথে থেকেও করতে পারি।\nকিন্তু তৃণা ফুয়াদের কল কেটে দিয়ে নিজেদের সেই ফার্ম হাউসে চলে যায় যেখানে তার মা মিসেস শ্রেয়সী আত্মহত্যা করেছিলো। \nবাড়ির সামনে যেতেই তৃণার অতীতের সব কথা মনে পড়ে গেলো, যদি সেদিন সে ভয় নাহ পেতো তাহলে হয়তো তার মা আজ বেঁচে থাকতো।\nএসব ভাবতে ভাবতে তৃণা বাড়ির ভিতরে ঢুকে।\nভিতরে ঢুকে সে একটা হারিকেন জ্বালিয়ে তার মায়ের ঘরে যায় সেখানে গিয়ে তৃণা কান্না করতে থাকে তখন সে দেখে তার মা তার সামনে এসে বলছে....\nশ্রেয়সী:- তুই আমার মেয়ে, তোকে আমি সবসময় আগলে রাখতাম তোকে কত ভালোবাসতাম কিন্তু তুই ওইদিন আমাকে বাঁচাসনি কেনো...?\nতৃণা:- আমি জানি তুমি সত্যি নও, চলে যাও তুমি, চলে যাও..... \nতখনই তৃণা লক্ষ করে তার মা তার দিকে তাকিয়ে সেই বিদঘুটে হাসি দিয়ে নিজের ভয়ংকর রূপে এসে তৃণার গলা চেপে ধরে বললো....\n-- তুমি অনেক দূর্বল, তুমি আমাকে তোমার মাইন্ড নিয়ে খেলতে দেয়েছো তাই তোমাকে কেউ বাঁচাতে পারবে নাহ আমার হাত থেকে... \nতখন তৃণা নিজেকে শক্ত করে এবং সেই অভিশপ্ত আত্মার হাত ভেঙ্গে তার দিকে হারিকেনটা ছুঁড়ে দিয়ে বাইরে চলে আসে।\nঅবশেষে তৃণা এই অভিশাপ থেকে রক্ষা পেলো।\nএই অভিশাপ আর কারো জীবন নষ্ট করতে পারবে নাহ।\nকিছুক্ষণ পর তৃণা ফুয়াদের বাসায় যায়...\nতৃণা:- আমি এখনও বিশ্বাস করতে পারছি নাহ অবশেষে আমি এই অভিশাপ থেকে মুক্তি পেয়েছি...\nআর তোমাকে অনেক ধন্যবাদ, আমি কখনো এটাও আশা করিনি তোমাকে আমার পাশে পাবো...\nফুয়াদ:- আমি সারাজীবন তোমার পাশে আছি, কখনো তোমাকে ছেড়ে যাবো নাহ..\nএই বলে ফুয়াদ সেই বিদঘুটে হাসিটা দিয়ে তৃণার দিকে এগিয়ে আসতে লাগে....\nতখনই তৃণার মোহ কাটে এবং দেখতে পায় সে এখনো তার মায়ের ঘরেই আছে...\nসে ভয়ে চিৎকার দিয়ে বাইরে বেরিয়ে আসে, বাইরে এসে ফুয়াদকে দেখতে পায় তৃণা এবারও মনে করে এটা সেই অভিশপ্ত আত্মার কোনো চাল এজন্য সে ছুটে আবারও তার মায়ের ঘরে চলে যায়...\nতৃণা ঘরে ঢুকতেই দেখে এক বিশাল আকৃতির দানব শরীর থেকে যেনো তার চামড়া টেনে তোলা হয়েছে দেখতে কেমন কুৎসিত। \nসেই কুৎসিত দানবটা তার দু হাত দিয়ে তৃণার মুখ চেপে ধরে মুহুর্তেই তৃণার মুখের ভিতরে ঢুকে যায়...\nতখনই আসল ফুয়াদও তৃণার পিছু পিছু বাড়ির ভিতরে ঢুকে দেখে তৃণা নিজের শরীরে কেরাসিন তেল ঢেলে তার দিকে তাকিয়ে হাসি দিয়ে নিজের শরীরে আগুন লাগিয়ে দেয়....."}],"comments":0,"is_featured":false,"read_time":null,"season":1,"status":"published","submitted_by":"primary-admin","date":"2026-04-01T20:43:34.147Z","updated_at":"2026-04-01T20:43:34.147Z"}','2026-04-01T20:43:34.134Z','2026-04-01T20:43:34.134Z');
