INSERT INTO "app_table_rows" ("pk","table_name","row_json","created_at","updated_at") VALUES(3488340,'stories','{"id":"1775076354182","title":"এগারো নাম্বার রুম","excerpt":"__MAHEAN_META__:{\"status\":\"published\",\"submittedBy\":\"primary-admin\",\"author\":\"রিয়াদ ইসলাম আযান\",\"category\":\"ছোট গল্প\",\"categories\":[\"ছোট গল্প\",\"ভৌতিক\"],\"coverImage\":\"/uploads/stories/covers/2026/04/1f74b075-cb11-4079-80f3-6b5f803a6398.png\",\"slug\":\"এগারো-নাম্বার-রুম\",\"parts\":[{\"id\":\"1\",\"title\":\"01\",\"slug\":\"part-01\",\"content\":\"\"},{\"id\":\"1775076302181-2\",\"title\":\"02\",\"slug\":\"part-02\",\"content\":\"\"},{\"id\":\"1775076317444-3\",\"title\":\"03\",\"slug\":\"part-03\",\"content\":\"\"},{\"id\":\"1775076332450-4\",\"title\":\"04\",\"slug\":\"part-04\",\"content\":\"\"}],\"comments\":0,\"season\":1}:__MAHEAN_META_END__আমি নীলা, কলেজ লাইফ শেষ করে ইউনিভার্সিটিতে পড়ার জন্য শহরে এসেছি। কিছুদিনের মধ্যে ইউনিভার্সিটিতে ভর্তি হয়ে গেলাম, থাকার জন্য ইউনিভার্সিটিতে অ্যাপ্লাই করলাম কিন্তু মানুষ বেশি থাকার কারণে চান্স পেলাম নাহ।","content":"","author_id":"1773089545405","author":"রিয়াদ ইসলাম আযান","category_id":"ছোট গল্প","category":"ছোট গল্প","views":0,"image":null,"cover_image":"/uploads/stories/covers/2026/04/1f74b075-cb11-4079-80f3-6b5f803a6398.png","slug":"এগারো-নাম্বার-রুম","tags":[],"parts":[{"id":"1","title":"01","slug":"part-01","content":"আমি নীলা, কলেজ লাইফ শেষ করে ইউনিভার্সিটিতে পড়ার জন্য শহরে এসেছি। কিছুদিনের মধ্যে ইউনিভার্সিটিতে ভর্তি হয়ে গেলাম, থাকার জন্য ইউনিভার্সিটিতে অ্যাপ্লাই করলাম কিন্তু মানুষ বেশি থাকার কারণে চান্স পেলাম নাহ। খুব চিন্তা নিয়ে একটা গার্লস হোস্টেলে উঠলাম। আমার ইউনিভার্সিটির অনেক মেয়েরা ওই হোস্টেলে থাকতে আসার কারনে আমার তেমন খারাপ লাগলো নাহ। আস্তে আস্তে সবার সাথে পরিচয় হলো, হোস্টেলের সকল স্টাফদের সাথেও খাতির হলো।\nকিন্তু আমি এবং আমার দুই বান্ধবী রোকেয়া আর সুরাইয়া খেয়াল করলাম আমাদের হোস্টেলে যে মহিলা রান্না করে সে কারো সাথে তেমন মিশে নাহ, কথাও বলে নাহ, আর আজব বিষয় হলো এই গরমের মধ্যেও সে ফুল হাতা জামা পড়ে রান্না করে।\nএই বিষয়টা নিয়ে আমরা তিন বান্ধবী অনেক হাসাহাসি করতে লাগলাম, ওনাকে বোকাও বলতে থাকি। [ আসলে আমরা মানুষরা বড়ই অদ্ভুত কারো ব্যাপারে ভালো করে নাহ জেনেই মনে যা আসে তাই বলতে থাকি]\nযাই হোক, ইউনিভার্সিটি টাইম ছাড়া হোস্টেল থেকে বের হওয়া নিষেধ থাকায় আমাদের প্রয়োজনীয় জিনিসপত্র হোস্টেলের দারোয়ান ''রফিক চাচা'' দিয়ে আনাতাম। [ কাজেই নিজেদের প্রয়োজনীয় জিনিসপত্র আনাতে আনাতে রফিক চাচার সাথে অনেক ভাব হয়ে যায় ]\nএকদিন জানতে পারলাম আমাদের হোস্টেলের রান্নার খালা নাকী রফিক চাচার ভাবি হয়।\nআস্তে আস্তে সময় কাটতে থাকে, একদিন আমরা তিন বান্ধবী নিচে ডাইনিং-এ খেতে এসেছিলাম তখন হঠাৎ রোকেয়া রান্নার খালাকে জিজ্ঞেস করে বসলো_____\nরোকেয়াঃ- আচ্ছা খালা সারাদিন ফুল হাতা জামা পড়ে থাকতে আপনার গরম লাগে নাহ...?\nখালাঃ- ওমা! গরম লাগবে কেনো.? আমি মাঝে মাঝেই শুনি তোমরা আমার ফুল হাতা জামা পড়া নিয়ে হাসাহাসি করো,  আমাকে বোকা বলো। আমি তোমাদের বলতেই পারি আমি কেনো ফুল হাতা জামা পড়ি, কিন্তু বললে তোমরা হয়তো আমাকে অবিশ্বাস করবে এবং আমাকে পাগল ভাব্বে। \nএই বলে খালা চলে যাবে ঠিক তখনই আমি অনেক কৌতুহল নিয়ে জিজ্ঞেস করি___\nআমিঃ- কেনো পড়েন প্লিজ বলেন খালা...?\nখালাঃ- বাদ দাও।\nএই বলে খালা চলে গেলেন।\nআমরা তিনজন নিজেদেরকে অপরাধী বোধ করলাম এবং আমাদের মধ্যে অনেক কৌতুহল কাজ করছে খালার কাহিনিটা জানার জন্য। \nতখনই আমার মনে পড়লো, রফিক চাচা তোহ রাধুনি খালার দেবর, আমরা যদি তার কাছে জিজ্ঞেস করি😀\nযেই ভাবা সেই কাজ___\nআমরা তিনজনই রফিক চাচার কাছে এসে রাধুনি খালার কথা জিনিস করাল।\nসুরাইয়াঃ- রফিক চাচা একটা কথা বলতে চাই..?😐\nরফিক চাচাঃ- কি কথা বলো.!?\nআমিঃ- আসলে চাচা রাধুনি খালার ফুল হাতা জামা পড়ার কাহিনি কি 🙂\nতখন রফিক চাচা বললো____\nরফিক চাচাঃ- আমি এখন কিছুই বলতে পারবো নাহ, এখন আমি ডিউটিতে আছি তোমরা যদি কাহিনি জানতে চাও তাহলে কালকে ৮ টার দিকে ডাইনিং-এ আসবে তাহলেই আমি সব বলতে পারবো।\nআর আমার কিছু শর্ত আছে..!\nআমরা তিনজন চমকে গিয়ে বলি কি শর্ত চাচা..?\nরফিক চাচাঃ- আমি যা যা বলবো তা কাউকে বলতে পারবে নাহ আর আমার কাহিনি শোনার পর তোমাদের অনেক কৌতুহল জাগবে কিন্তু কোনো মূল্যে তোমাদের ওই কৌতুহলকে কাজে লাগাতে পারবে নাহ।\nআমরা তিনজনই রাজি হয়ে চলে আসলাম, এসে যে যার রুমে শুয়ে পড়লাম।"},{"id":"1775076302181-2","title":"02","slug":"part-02","content":"আমরা তিনজনই রাজি হয়ে চলে আসলাম, এসে যে যার রুমে শুয়ে পড়লাম.।\nচাচার কথা মতো পরদিন ইউনিভার্সিটি থেকে এসে ৮ টার মধ্যে ডাইনিং-এ খেতে চলে যাই।\nখাওয়া শেষে আমরা সবাই রফিক চাচাকে জিজ্ঞেস করলাম, চাচা এবার বলেন রাধুনি খালার ফুল হাতা জামা পড়ার কারণ কি..?\nরফিক চাচাঃ- এই কাহিনি আজকের নাহ আজ থেকে আরো ১৭ বছর আগের কাহিনি এটা.।\nআমরা অবাক হয়ে বললাম ১৭ বছর😲\nতারপর রফিক চাচা বললেন.......\nরফিক চাচাঃ- ১০ বছর আগে আমার বড় ভাইয়ের বিয়ে হয়,  ২ বছর পর তাদের ফুটফুটে একটা মেয়ে হয় তার ৩ বছর পর একটা ছেলে হয়,  আমার বড় ভাই পেশায় একজন ট্রাক ড্রাইভার ছিলেন। ভাগ্য দোষে একদিন আমার বড় ভাই ট্রাক অ্যাক্সিডেন্টে মারা যান। \nতারপর থেকে আমাদের সংসার চালাতে অনেক কষ্ট হতো,  আমি তখন এই হোস্টেলেই কাজ করতাম, আমার যা রোজগার হতো তা দিয়ে আমাদের সংসার কোনোরকম চলতো কিন্তু ২ টা ছোট ছোট বাচ্চা আমি ভাবি আর আমার মা কিছুতেই একা পেরে উঠতাম নাহ।\nতারপর শুনতে পেলাম আমাদের হোস্টেলে নাকী কাজের মানুষের দরকার....\nআমি তখন ভাবিকে এখানে কাজে লাগিয়ে দি, তারপর হোস্টেল কর্তৃপক্ষ ভাবিকে কাজ বুঝিয়ে দিলেন যে সে সকল রুম পরিষ্কার করবেন আর সকল রুমের চাবি দিলেন,  ভাবি লক্ষ করলো এখানে রুম ২৫ টা কিন্তু চাবি দেওয়া হলো ২৪ টা, এটা দেখে ভাবি হোস্টেল কর্তৃপক্ষকে জিজ্ঞেস করলেন....\n ভাবিঃ- বাকি একটা রুমের চাবি তোহ দিলেন নাহ..?\nহোস্টেল কর্তৃপক্ষ আমতা আমতা করে বললেন...\nহোস্টেল কর্তৃপক্ষঃ- ওই রুমটা নষ্ট হয়ে গেছে ওখানে কেউ থাকে নাহ তুমি ওইসব নিয়ে ভেবো নাহ তুমি তোমার কাজ করো।\nকাজের প্রথম দিন যখন সকল রুম ঝাড় দিতে যায় তখন ভাবি খেয়াল করে ১১ নাম্বার রুমের  চাবি নেই, সে ভাবলো তার কাছে যে ২৪ টি চাবি দেওয়া হয়েছে তার মধ্যে এই রুমের চাবি নেই। তারপর ডাইনিং পরিষ্কার আর রুম ঝাড় দেওয়া এসব কাজ নিয়েই ভাবি দিন কাটাতেন। \nএকদিন হোস্টেলে দুর্গা পুজার বন্ধ পরে, সব মেয়েরা হোস্টেল ছেড়ে যে যার বাসায় চলে যায়। ভাবিরও ওইদিন বিধবা ভাতা আনতে যাওয়ার তারিখ পড়েছে।\nভাবি ভেবেছিলো সব রুম ঝাড় দিয়ে সে ভাতার টাকা আনতে যাবে....\nসব মেয়েরা চলে যাওয়ায় আমার ডিউটি শেষ হয়ে যায় তাই আমি তাড়াতাড়ি বাড়ি চলে যাই, \nসাধারণত ভাবির আসতে সন্ধ্যা ৭ টার বেশি হয় নাহ,  কিন্তু ওইদিন ৭ টা পেরিয়ে ৮ বেজে গেলো কিন্তু ভাবি এখনও আসছে নাহ এটা দেখে আমার মা অনেক চিন্তিত হয়ে পড়ে আর বলে...\nমাঃ- ওরে রফিক তোর ভাবি এখনও আসছে নাহ কেনো.?  একটু খোঁজ নিয়ে দেখ বাবা।\nআমিও ভাবলাম ৯ পর্যন্ত দেখি তারপর আমি বেড় হবো..\n৯ বেজে গেলো কিন্তু ভাবি এখনও আসছে নাহ, এবার আমি বেড় হলাম সাথে হোস্টেলের আর একজন স্টাফকেও খবর দিলাম..। \nআমি আর ওই স্টাফ দেখলাম হোস্টেলের সব রুম তালা দেওয়া। \nআস্তে আস্তে আমরা ৩ তলা উঠলাম সব রুমে তালা দেওয়া কিন্তু রুম নাম্বার ১১''র তালা খোলা,  আমরা তাড়াতাড়ি করে দরজার সামনে গেলাম আর যা দেখলাম........"},{"id":"1775076317444-3","title":"03","slug":"part-03","content":"আস্তে আস্তে আমরা ৩ তলা উঠলাম সব রুমে তালা দেওয়া কিন্তু রুম নাম্বার ১১''র তালা খোলা,  আমরা তাড়াতাড়ি করে দরজার সামনে গেলাম আর যা দেখলাম, ঘরে এক কোণ থেকে কেউ একজন গোঙ্গাচ্ছে....\nআমরা তাড়াতাড়ি করে ঘরের ভিতর গিয়ে দেখি আমার ভাবি পরে আছে, আর তার হাতে সে নিজেই কামোড় দিয়ে ধরে আছে আর সে নিজের হাতের গোস্তো নিজেই খেয়ে ফেলেছে......\n=> সবাই অনেক ভয় পেয়ে যাই,  একদম নিস্তব্ধতায় মগ্ন হয়ে গেছে ১১ নাম্বার রুমটা।\nআমি একটু ধমকের সরে বললাম...!\nআমিঃ- ভাবি, এসব কি...?  কি করেছো এসব...?\nতখন ভাবি একটু মোটা গলায় বলছে এমন মনে হচ্ছে ভাবির সাথে আরো একটা মহিলা মিলিত হয়ে আছে.....\nভাবিঃ- কি করবো..? খিদে পেয়েছে, বহুদিন কিছু খাই নাহ, তাই নিজের গোস্তো নিজেই খাচ্ছি.। \nএই বলে ভাবি অজ্ঞান হয়ে গেলো।\nআমরা ৩ জন ধরাধরি করে ভাবিকে হাসপাতালে নিয়ে গেলাম..... \nডাক্তার এ অবস্থা দেখে বললো..\nডাক্তারঃ- এক্ষুনি অপারেশন করতে হবে, আর অপারেশন করলেও তার হাতের শেফ অনেক ভয়ংকর হয়ে যাবে.।\nআমিঃ- যেমনই হোক ডাক্তার আমার ভাবিকে বাঁচান.। \nতারপর অপারেশন করতে নিয়ে গেলো,  টানা ৮ ঘন্টা পর অপারেশন সাকসেস হয়, কিন্তু আমার ভাবির হাতের শেফ অনেক ভয়ংকর হয়ে যায়.।\n২ ঘন্টা পর যখন ভাবির জ্ঞান ফিরে তখন ভাবিকে জিজ্ঞেস করলাম কি হয়েছিল....?\nভাবিঃ- আমি সব রুম পরিষ্কার করে যখন চলে আসবো তখন দেখি রুম নাম্বার ১১''র তালা খোলা, আমিও ভাবলাম রুমের তালা যখন খোলাই আছে আমি রুমটা ঝাড় দিয়ে যাই....!\nরুম ঝাড় দেওয়ার জন্য ভিতরে ঢুকলাম,  রুমে একটু ঝাড় দিচ্ছিলাম তখন এক কোণ থেকে কেউ খুব ক্ষিপ্ত হয়ে বললে উঠলো.....\nকেউ একজনঃ- একি করছো তুমি, আমার এতদিনের সব সাজানো গুছানো জিনিসগুলো নষ্ট করে দিলে...?\nআমিঃ- কে আপনি..? আমি তোহ শুধু পরিষ্কার করতে এসেছিলাম.।\nতখন দেখি আমার সামনে একটা বৃদ্ধ মহিলা এসে দাড়িয়েছে আর বলছে....\nবৃদ্ধ মহিলাঃ- তুই আমার ঘরটা নষ্ট করে দিয়েছিস এর শাস্তি তোকে পেতে হবে..\nহঠাৎ আমার চোখ বন্ধ হয়ে এলো আর আমি আমার হাতে অনেক ব্যাথা অনুভব করলাম, যখন আমি চোখ খুলি তখন দেখি আমি নিজেই নিজের হাতে কামোড় দিয়ে আছি.!\nএরপর আমার আর কিছু মনে নেই.।\nভাবির কথা শুনে আমরা হোস্টেল কর্তৃপক্ষের কাছে গেলাম তাকে এসব জিজ্ঞেস করতে কিন্তু সে কিছুই বলতে চাইলো নাহ...\nতারপর তাকে পুলিশের ভয় দেখানোয় সে মুখ খুলে আর বলে.....\nহোস্টেল কর্তৃপক্ষঃ- তোমরা হোস্টেলে কাজ করতে আসার আগে এখানে একটা বৃদ্ধ মহিলা কাজ করতো, তার মেজাজ খুব চড়া ছিলো,  এমন ভাবে আচরণ করতো তা দেখে বোঝাই যেতো নাহ  সে এখানে কাজ করে নাকী এখানকার মালিক।\nসকালে সে রুম পরিষ্কার করতে গিয়ে যদি দেখতো রুম বন্ধ বা মেয়েদের রুমের দরজা খুলতে দেরি হচ্ছে তাহলে সে যা ইচ্ছা তাই বলে গালিগালাজ করতে থাকতো।\nতাকে নিয়ে অনেক অভিযোগ আসতো, আমরাও তাকে কাজ ছাড়াতে বলতাম কিন্তু সে কাজ ছাড়তে চাইতো নাহ..।\nএকদিন হোস্টেলে ৭ দিনের ছুটি পরলো সবাই সবার বাসায় যাওয়ার জন্য বের হয়, বৃদ্ধ মহিলাও সব রুম পরিষ্কার করে নিজের বাসায় চলে যাবে.। \nবেশি অর্ধেক রুম পরিষ্কার করে সে যখনই ৩ তলার ১১ নাম্বার রুম পরিষ্কার করতে গেলো ঠিক তখনই হোস্টেলের কিছু মেয়ে বৃদ্ধ মহিলাকে ১১ নাম্বার রুমে তালা বন্ধ করে চলে যায়........।\nহোস্টেল ছুটির ৩-৪ দিন পর বৃদ্ধ মহিলার ছেলে আর ছেলের বৌ আসে বৃদ্ধার খোঁজ করতে, বৃদ্ধাকে নাকী খুজে পাওয়া যাচ্ছে নাহ..।\nআমরা হোস্টেলের সকল রুম তালা দেওয়া দেখে বলে দিলাম বৃদ্ধা এখানে নেই।\nআমরাও মনে মনে খুশি হলাম যাক আপদ বিদায় হয়েছে...😁\nতারপর হোস্টেলের ছুটি শেষ হলো,  আমরা সকল রুমের তালা খুলছিলাম যখন ৩ তলার ১১ নাম্বার রুমের সামনে গেলাম তখন ভেতর থেকে একটা বাজে গন্ধ আসছে, তাড়াতাড়ি করে রুমের তালা খুলে ভেতরে যেতেই দেখলাম......"},{"id":"1775076332450-4","title":"04","slug":"part-04","content":"তারপর হোস্টেলের ছুটি শেষ হলো,  আমরা সকল রুমের তালা খুলছিলাম যখন ৩ তলার ১১ নাম্বার রুমের সামনে গেলাম তখন ভেতর থেকে একটা বাজে গন্ধ আসছে, তাড়াতাড়ি করে রুমের তালা খুলে ভেতরে যেতেই দেখলাম, বৃদ্ধ মহিলার লাশ পড়ে আছে, আর তার দুই হাতের গোস্তোগুলো নেই শুধু হাড়গুলো আছে।\nএই করুন দৃশ্য দেখে সবার চোখে পানি চলে এলো।\nতারপর বৃদ্ধ মহিলার বাড়িতে খবর দিলাম আর বললাম পুলিশের কাছে যেনো নাহ যায়, হোস্টেলটা এমনিতেই নতুন নতুন হয়েছে এর মধ্যে যদি থানা পুলিশ হয় হোস্টেলের নাম খারাপ হয়ে যাব..।\nতারাও রাজি হলো।\n১১ নাম্বার রুমে একটা মেয়ে থাকতো নাম ছিলো সৃষ্টি,   কিছুদিন পর রাতে হঠাৎ ওর চিৎকার শুনতে পেয়ে আমরা সবাই দৌড়ে গিয়ে দেখি ও নিজে নিজের হাতে কামোড় দিয়ে আছে...।\nসৃষ্টি ভয়ে ১১ নাম্বার রুম ছেড়ে দেয়, তারপর আমরা অন্য একটা মেয়েকে রুম দি, কিন্তু এরপরও আরো ২ জন মেয়ের সাথে এমন হওয়ায় আমরা ঠিক করলাম কবিরাজ ডেকে আনবো....\nতারপর কবিরাজ আনলাম,\nকবিরাজঃ- এখানে একটা অনেক খারাপ আর ভয়ংকর শক্তি আছে, কিন্তু ওর এখানে আসার কথা ছিলো নাহ। আমি ওকে তাড়াতে পারবো নাহ।\nএই বলে কবিরাজ চলে গেলো....\nতারপর আমরা একটা হুজুর আনলাম,\nহুজুরঃ- কি হয়েছিলো সব খুলে বলুন..? \nআমরা সব ঘটনা খুলে বললাম।\nহুজুরঃ- এই বৃদ্ধ মহিলা টানা ৭ দিন অনাহারী ও বিনা গোসলে ছিলো যার ফলে এই ঘরে এক খবিশের আগমন হয় আর ওদের পছন্দ অপরিষ্কার জিনিস, কিন্তু এখানে ওদের আসার কথা ছিলো নাহ তাই ওরা বৃদ্ধ মহিলার ভিতর প্রবেশ করে ওর শরীরের গোস্তো খায়,\nওকে তাড়ানোর ক্ষমতা আমার নেই,  আপনারা এই রুমটা বন্ধ করে দিন আমি কিছু দোয়া পড়ে রুমটা বন্ধক করে দিয়ে যাই।\nএই বলে হুজুর ১১ নাম্বার রুমটা বন্ধক করে দিয়ে যান আর আমরা ৩ তলা সম্পূর্ণ বন্ধ করে দিলাম।\nএই বলে রফিক চাচা নিজের বক্তব্য শেষ করে বলে দেখতে চাও কি হাল হয়েছিলো আমার ভাবির..?\nএই বলে রফিক চাচা ওনার ভাবির অমতে তার হাতটা দেখালো,  ওনার হাতগুলো এতোটাই ভয়ংকর ছিলো যে আমি এবং আমার বান্ধবীরা ৩ রাত ভালো করে ঘুমোতে পারিনি।\nরফিক চাচার কাছ থেকে কাহিনি শুনার পর অনেক কৌতুহল হয় ৩ তলার ১১ নাম্বার রুমে যাওয়ার কিন্তু তখনই মনে পড়লো ওই রুমে ৪ জনের জীবন নেওয়ার চেষ্টা হয়েছিলো ভাগ্যের জোড়ে বেঁচে গেছে, কে জানে আমরা গেলে আমাদের ভাগ্যে কি হয়।\nজানি নাহ ভবিষ্যতে ওই ১১ নাম্বার রুম আবারো কারো উপর আক্রমণ করে কি নাহ।\nএটা ভাবতে ভাবতে ইউনিভার্সিটির ৪ বছর পার করে আমি ও আমার বান্ধবীরা হোস্টেল ছেড়ে চলে আসি।\nThe End....."}],"comments":0,"is_featured":false,"read_time":null,"season":1,"status":"published","submitted_by":"primary-admin","date":"2026-04-01T20:45:54.182Z","updated_at":"2026-04-01T20:45:54.182Z"}','2026-04-01T20:45:54.420Z','2026-04-01T20:45:54.420Z');
