INSERT INTO "app_table_rows" ("pk","table_name","row_json","created_at","updated_at") VALUES(3488344,'stories','{"id":"1775076510851","title":"কথানদী","excerpt":"__MAHEAN_META__:{\"status\":\"published\",\"submittedBy\":\"primary-admin\",\"author\":\"রিয়াদ ইসলাম আযান\",\"category\":\"ছোট গল্প\",\"categories\":[\"ছোট গল্প\",\"ভৌতিক\"],\"coverImage\":\"/uploads/stories/covers/2026/04/65f3cc19-35b9-44dd-a6e8-d93a2fb884a8.png\",\"slug\":\"কথানদী\",\"parts\":[{\"id\":\"1\",\"title\":\"01\",\"slug\":\"part-01\",\"content\":\"\"},{\"id\":\"1775076466712-2\",\"title\":\"02\",\"slug\":\"part-02\",\"content\":\"\"}],\"comments\":0,\"season\":1}:__MAHEAN_META_END__রাতের অন্ধকারে কানাই নামে এক লোক এক হাতে মশাল এবং আরেক হাতে একটা পুঁটলি নিয়ে গ্রামের জঙ্গলের দিকে যাচ্ছে... \nজঙ্গলের ভিতরে গিয়ে সে মাটি খুঁড়তে লাগলো...\nতার পুঁটলিতে কি ছিলো এবং সে কেনো মাটি খুঁড়ছে এটা আমরা মূল গল্পে জানতে পারবো।","content":"","author_id":"1773089545405","author":"রিয়াদ ইসলাম আযান","category_id":"ছোট গল্প","category":"ছোট গল্প","views":0,"image":null,"cover_image":"/uploads/stories/covers/2026/04/65f3cc19-35b9-44dd-a6e8-d93a2fb884a8.png","slug":"কথানদী","tags":[],"parts":[{"id":"1","title":"01","slug":"part-01","content":"ঘটনা:০১\nরাতের অন্ধকারে কানাই নামে এক লোক এক হাতে মশাল এবং আরেক হাতে একটা পুঁটলি নিয়ে গ্রামের জঙ্গলের দিকে যাচ্ছে... \nজঙ্গলের ভিতরে গিয়ে সে মাটি খুঁড়তে লাগলো...\nতার পুঁটলিতে কি ছিলো এবং সে কেনো মাটি খুঁড়ছে এটা আমরা মূল গল্পে জানতে পারবো।\n☞ঘটনা:০২\nঅন্য এক গ্রামের এক মহিলা নাম তার পদ্মাবতী। সে যখনই রাস্তা দিয়ে হাটে তার পিছু পিছু একটা চালতা ফল গড়াতে গড়াতে যায়।\nতার পিছনে পিছনে চালতা ফলটা কেনো যায় সেটাও আমরা মূল গল্পে জানতে পারবো। \nঘটনা:০৩\nঅন্য এক গ্রামের ১৫ বছরের মেয়ে দোলা ছুটে নদীর ধারে যাচ্ছে কারণ নদীর ধারে তার সৎমা রুক্মিণী আর তার বাবা কৃষ্ণা দাঁড়িয়ে আছে। \nদোলা সেখানে যেতেই তার বাবা তাকে ও রুক্মিণীকে বিদায় জানিয়ে বাণিজ্যের উদ্দেশ্য রওনা হলো...\nদোলার বাবা বাণিজ্য করতে কোথায় যাচ্ছে সেটাও আমরা মূল গল্পে জানতে পারবো। \nঘটনা:-০৪\nদোলাদের গ্রামের জমিদার রামকৃষ্ণ ও তার বাড়ির কাজের লোকেরা রাতের অন্ধকারে জঙ্গলে কিছু একটা ধরে পুঁটলিতে ভরে গরুর গাড়িতে করে বাড়ি নিয়ে যাচ্ছে। \nতারা পুঁটলিতে করে কি নিয়ে যাচ্ছে সেটাও মূল গল্পে জানা যাবে।\nমূল গল্প- ঘটনা:-২ ও ঘটনা:-৩ সম্পৃক্ত... \n[  ] রুক্মিণী আর দোলাকে বিদায় জানিয়ে বাণিজ্যের উদ্দেশ্যে রওয়ানা দিলো কৃষ্ণা।\nকৃষ্ণা প্রথমে পণ্য সামগ্রী ক্রয় করার জন্য পদ্মাবতীর বাড়ি যায় কারণ কৃষ্ণার বাণিজ্যের জন্য পণ্য সামগ্রী তৈরির দায়িত্ব এবার পদ্মাবতীই পায়।\nকৃষ্ণা যখন পদ্মাবতীর বাড়ি যায় তখন দেখে পদ্মাবতী নিজের ঘর থেকে পণ্য নিয়ে বের হওয়ার সময় তার পিছু পিছু সেই চালতা ফলটা আসছে এটা দেখে কৃষ্ণা পদ্মাবতীকে জিজ্ঞেস করে চালতা ফলটা নিচে থেকে কিভাবে নড়ছে কিন্তু পদ্মাবতী তার কথার জবাব নাহ দিয়ে তাকে পণ্যগুলো দিয়ে এবং তার কাছ থেকে পণ্যের টাকা নিয়ে ঘরে চলে যায়।\nএবারও একই ভাবে পদ্মাবতীর পিছু পিছু সেই চালতা ফলটাও ঘরে চলে গেলো।\nপণ্য নিয়ে ফেরার পথে কৃষ্ণা তার পাশের লোকটিকে পদ্মাবতী ও সেই চালতা ফলটির কথা জিজ্ঞেস করলে সেই লোকটি জানায় ওই চালতা ফলটি নাকী পদ্মাবতী গর্ভের সন্তান পদ্মাবতী এমন সন্তান জন্ম দেওয়ার কারণে গ্রামের সবাই তাকে ডায়নী বলতে শুরু করে এবং তাদের একঘেয়ে করে দেয়।\nকিন্তু ওদের এমন দুর্দশা দেখে আমার অনেক খারাপ লাগে এজন্য তোমাকে বললাম পদ্মাবতীর কাছ থেকে শাড়ি কিনতে যাতে ওদের কিছুটা উপকার হয়।\nএটা শুনে কৃষ্ণা আগ্রহের সাথে সবটা জানতে চাইলে লোকটি তাকে বলে যে....\nপদ্মাবতী যখন ৬ মাসের গর্ভবতী ছিলো তখন তাদের সংসারের অবস্থাও খুব খারাপ ছিলো, তারা দিন আনতো দিন খেতো।\nহঠাৎ একদিন একটা ভিক্ষুক পদ্মাবতীর দুয়ারে এসে খাবার চায় কিন্তু পদ্মাবতী তখনও রান্না বসায়নি তাই সে ভিক্ষুককে বলে কিছুক্ষণ অপেক্ষা করুন আমি রান্না শেষ করেই আপনাকে খেতে দিচ্ছি... \nসংসারে অভাব অনটন থাকলে কি হবে পদ্মাবতী ছিলো করুণাময় ও মমতাময়ী কেউ ওর কাছে হাত পাতলে নাহ করতো নাহ।\nকিন্তু সেদিন রান্না করতে করতে পদ্মাবতীর অনেক বেলা বয়ে যায় এবং সেই ভিক্ষুকটি পদ্মাবতীকে অভিশাপ দেয় \"তুই যেমন আমাকে খাবারের জন্য অপেক্ষা করালি তেমনই তুই তোর সুখের জন্য অপেক্ষা করতে থাক এত সহজে তোর কপালে সুখ জুটবে নাহ\" এই বলে ভিক্ষুকটি চলে যায়। \nপদ্মাবতী তাকে অনেক ডাকে কিন্তু সে আর ফিরে আসে নাহ।\n[  ] এবার আসি ঘটনা:-০১ এর কাছে..\nদেড় বছর পর পর টানা সাড়ে চার বছর কানাই রাতের অন্ধকারে জঙ্গলে মাটি খুঁড়ে তার সদ্য জন্ম নেওয়া ফুটফুটে শিশুদের জ্যান্ত কবর দিতো। \n☞ কানাই এর বিয়ে পরেই তাদের পরিবারের সবাই ডায়রিয়া নামে এক মহামারিতে প্রাণ হারায় এরপর তাদের আপন বলতে একটা বৃদ্ধ কাকু বেঁচে আছেন। \nতিনি কানাইকে বলে দিয়েছেন তোদের সন্তান জন্ম নেওয়ার পর আমার কাছে নিয়ে আসবি আমি তাদের ভবিষ্যৎ বাণী করবো।\nযেহেতু কানাই এর কাকু একজন কবিরাজ ছিলো সেহেতু সে কানাই ও তার স্ত্রী কুন্ডলার সুখের কথা ভেবে তাদের সন্তানের ভবিষ্যৎ বাণী করতে চাইতো যাতে আগামী দিনে কানাই ও তার স্ত্রীর কষ্ট নাহ হয়।\nআর কানাই এতদিন যে সন্তানগুলোকে জ্যান্ত কবর দিয়েছে তারা নাকী কানাই ও তার স্ত্রীর জন্য বিপদ ছিলো তারা বেঁচে থাকলে তাদের ক্ষতি ছাড়া কখনোই ভালো হতো নাহ।\n[  ]  এবার আসি শেষ ঘটনার কাছে...\n☞ জমিদার রামকৃষ্ণ তার ছোট মেয়ে কাঁকনের বিয়ে দেওয়ার জন্য জঙ্গল থেকে একটা বিশাল অজগর সাপ ধরে আনে।\nবছর দুই এক আগে জমিদারের বড় মেয়ে রাশি স্বপ্নে দেখছিলো তাকে একটা অজগর সাপ বিয়ে করবে এবং সেই সাপটিকে তাদের গ্রামের জঙ্গলে পাওয়া যাবে।\nতার স্বপ্নের কথা শুনে রামকৃষ্ণ জঙ্গলে গিয়ে সেই সাপটিকে ধরে আনে এবং অনেক ধুমধাম করে রাশি ও সেই অজগর সাপটির বিয়ে দেয়।\nপরদিন সকালে সেই সাপটিকে আর খুঁজে পাওয়া যায় নাহ কিন্তু রাশির সারা শরীর সোনার অলঙ্কার দিয়ে ভরিয়ে দিয়ে গেছে। \nএই কাহিনি দেখে জমিদারের ছোট বউ হৈমন্তীও নিজের মেয়ের বিয়ে একটা অজগর সাপের সাথে দিতে চায় যাতে তার মেয়েও রাশির মতো সোনার অলঙ্কারে ভরে যায়।\n[  ] ঘটনা:-০১\nকৃষ্ণা বাণিজ্যে যাওয়ার পর, রুক্মিণী দোলার খাবারে ঘুমের ঔষধ মিশিয়ে দিয়ে দোলাকে ঘুম৷ পাড়িয়ে দিয়ে সে বেড়িয়ে নদীর ধারে চলে আসে...\nনদীর ধারে গিয়ে সে একটি নৌকায় গিয়ে উঠলো, সে নৌকায় উঠতেই একটা দানব আকৃতির লোক৷ এসে রুক্মিণীকে জড়িয়ে ধরে বলে...\n\"আজ অনেক দিন পর তুই আমার কাছে এসেছিস\" তারপর তারা দুইজন নিজেদের প্রেম লীলায় লিপ্ত হয়ে পরে।\n[  ] ঘটনা:-০২\nএকদিন রাতে পদ্মাবতীর স্বামী বলরাম একটা চারকোনা পাত্রে কিছু আটা রেখে তার মধ্যে চালতা ফলটা রেখে দিয়ে পদ্মাবতীকে বলে, যদি সত্যি সত্যি এই ফলের ভেতর কোনো শিশু সন্তান থাকে তাহলে আজকেই তা প্রমাণ হবে...\nশিশুটি বের হলে যদি সে প্রতিদিনের মতো আজকেও রান্না করা খাবার খেতে বের হয় তাহলে সারা ঘরে আটার চিহ্ন পড়ে যাবে আর আমরাও আমাদের সন্তানকে দেখতে পারবো।\nকিন্তু পরদিন সকালে পদ্মাবতী ঘুম থেকে দেখে পুরো বাড়ি জুড়ে কোত্থাও সেই চালতা ফলটা নেই, এই কান্ড দেখে সে তার স্বামীকে বলে...\nচালতা ফলটা মনে হয় আমাদের কথা বুঝে গেছে এজন্য সে বাড়ি ছেড়ে পালিয়েছে।\nপদ্মাবতী ও বলরাম পুরো এলাকা খুঁজেও ফলটা পাচ্ছিল নাহ,  অন্য পাশের গ্রামের এক মহিলা চালতা বাগানে গিয়ে চালতা কুড়বার সময় সেই চালতাটিকে ধরার চেষ্টা করে কিন্তু কিছুতেই ধরতে পারে নাহ। \nযখনই মহিলাটি চালতাটা ধরবে তখনই বলরাম এসে চালতাটা ধরে তার সাথে করে নিয়ে যায়।\n[  ] ঘটনা:-০১\nকুন্ডলা আবারও গর্ভবতী হয়।  এবার সে ৮ মাসের গর্ভবতী কিছুদিন পরই তার প্রসব হবে। এবার সে কানাইকে সরাসরি বলে দেয়...\nএবার কানাই এর কাকু যেমনই ভবিষ্যৎ বাণী করুক নাহ কেনো এবার আর সে তাদের সন্তানকে জ্যান্ত কবর দিতে দিবে নাহ।\nপর পর তিনটি সন্তানকে জ্যান্ত কবর দিয়েছে। তারা এখন অব্দি তাদের সন্তানদের আদর করতে পারেনি, সন্তানের মুখে বাবা মা ডাক শুনেনি।\nএবার আর কিছুতেই সে তাদের সন্তান কবর দিতে দিবে নাহ।\n[  ] ঘটনা:-\nজমিদার রামকৃষ্ণের প্রথম স্ত্রী রানীমালা বার বার করে জমিদারের ছোট স্ত্রী হৈমন্তীকে বারণ করছিলো যাতে সে কাঁকনের বিয়ে অজগরের সাথে নাহ দেয়, কারণ রাশির যে সাপটির সাথে বিয়ে হয়েছিলো সেটি ছিলো একটা দেবদূত আর তাদের যে বিয়ে হবে এটা আগে থেকেই রাশিকে স্বপ্নে দেখিয়েছিলো।\nএখন তারা যে সাপটি ধরে এনেছে এটা কোনো দেবদূত নয় এটা একটা জংলী সাপ।\nকিন্তু জমিদারের ছোট স্ত্রী হৈমন্তী কিছুতেই রানীমালার কথা শুনতে চায় নাহ, সে মনে করে রানীমালা হয়তো চাচ্ছে নাহ তার মেয়ের মতো হৈমন্তীর মেয়েও সোনার অলঙ্কার পাক।\nসে রানীমালাকে অনেক কিছু বলে অপমান করে তারপরও সে তার মেয়ের বিয়ে অজগরের সাথেই দিবে।"},{"id":"1775076466712-2","title":"02","slug":"part-02","content":"[  ] ঘটনা:-০৩ ও ঘটনা:-০৪ সম্পৃক্ত \nজমিদারে ছোট মেয়ে কাঁকনের বিয়ের দিন সকাল বেলা যখন দোলা নিজের ঘরে ঘুমচ্ছিল তখন রুক্মিণী তাকে জাগিয়ে তোলার জন্য লাথি ও ঝাঁটার বারি দিচ্ছে। \nলাথি আর ঝাঁটার বারির আঘাতে দোলার ঘুম ভাঙ্গে। \nরুক্মিণী দোলাকে তার মায়ের শাড়িটা দিয়ে বলে, এই নেহ ধর এটা আমার মায়ের শাড়ি এটা পড়েই তুই আজকে কাঁকনে বিয়েতে যাবি। \nআর শোন আবারও বলছি এটা কিন্তু আমার মায়ের শাড়ি এটা যেনো নষ্ট নাহ হয়।\nদোলা শাড়িটা নিয়ে জমিদার বাড়ি চলে যায়। \nতখনই বুঝা যায় রুক্মিণীকে ও তার ওই প্রেমিক বলেছে যদি সে তার সতিনের মেয়েকে সায়েস্তা করতে পারে তাহলে তাকে সে অনেক ধনসম্পদ দিবে। \nরুক্মিণী সেই সম্পদের লোভে একটা ফন্দি আটে এবং দোলাকে যে শাড়িটা দিয়েছে ওই শাড়ির মধ্যে একটা ইদুর রেখে দিয়েছে যাতে ইদুরটা শাড়িটা নষ্ট করতে পারে এবং সে দোলাকে সায়েস্তা করতে পারে।\nদোলা শাড়িটা নিয়ে জমিদার বাড়ি আসে।\nজমিদারের মেয়ে কাঁকনের সাথে কথা বলছে কাঁকনের স্বামী দেখতে কেমন.? কি করে.?\nতারপর কাঁকন দোলাকে বলে আমার স্বামী একজন দেবদূত অজগর সাপ। \nএর আগেও একজন দেবদূত আমার দিদিকে বিয়ে করে তাকে সোনায় ভড়িয়ে দিছে এবার আমাকেও সোনায় ভড়িয়ে দিবে।\nআমি জানি সে আমাকে অনেক ভালোবাসবে।\nএইরে অনেক দেড়ি হয়ে গেলো আমি সাজতে গেলাম যা তুইও সেজে আয়।\nএই বলে কাঁকন সাজতে চলে যায় এবং দোলাও সাজার জন্য একটা ঘরে যায়।\nঘরে গিয়ে শাড়িটা বের করতেই একটা ইদুর লাফ দিয়ে বের হয়, সে তাড়াতাড়ি শাড়িটা বের করে দেখে ইদুরটা শাড়িটাকে একদম নষ্ট করে দিয়েছে।\nদোলা অনেক ভয়ে কাউকে কিছু নাহ বলে শাড়িটা নিয়ে দৌড়ে বাড়ি চলে যায় এবং সে তার মাকে সবটা জানায়...\nওই মুহুর্তে রুক্মিণী দোলাকে কিছু বলে নাহ, সে শাড়িটা নিয়ে নিশ্চুপ হয়ে কাঁদতে কাঁদতে নিজের ঘরে চলে যায়। \nদোলাও ভয়ে ভয়ে নিজের ঘরে চলে যায়। \n[  ] ঘটনটা:-০১\nদেখতে দেখতে কুন্ডলা একটা ফুটফুটে কন্যা সন্তানের জন্ম দিলো।\nএবারও কানাই আর কুন্ডলা তাদের সন্তানকে নিয়ে কাকুর বাড়ি যাবে তাদের সন্তানের ভবিষ্যৎ বাণী করতে। \nকিন্তু কুন্ডলা এবার ঠিক করে নিয়েছে কাকু যদি এবারও তাদের সন্তানকে কবর দিতে বলে তাহলে কাকুকে সে খুন করবে।\nকুন্ডলা তার হাতে লুকিয়ে একটা ছুড়ি নিয়ে গেলো।\n[  ] ঘটনা:-০৩ ও ঘটনা:-০৪ সম্পৃক্ত \nকাঁকন ও অজগরের বিয়ের জন্য একজন পুরোহিত আনা হয় কিন্তু সেই পুরোহিত কিছুতেই সাপ ও মানুষের বিয়ে দিতে রাজি হয় নাহ।\nতখন জমিদারের ছোট স্ত্রী হৈমন্তী পুরোহিতকে বলে, তুমি বিয়ে নাহ করালে নেই আমি অন্য পুরোহিত আনবো তাও আমার মেয়ের বিয়ে ওই অজগর সাপের সাথেই দিবো। \nতারপর অন্য একজন পুরোহিত এনে কাঁকন ও অজগরের বিয়ে দেওয়া হয়।\nরাতে কাঁকন ও হৈমবতী একই ঘরে থাকে।\nকাঁকন ও অজগর সাপ বিছানায় আর হৈমবতী নিচে শুয়ে ছিলো।\nঅজগর সাপটি যখন কাঁকনকে একটু পর পর পেঁচিয়ে ধরছিলো তখন সে বার বার হৈমন্তীকে ডাকে আর হৈমবতী বলে, মা তুই ভয় পাসনে জামাই তোকে আদর করছে, একটু পর দেখবি সে তোকেও অনেক সোনাদানা দিবে।\nআস্তে আস্তে সাপটি কাঁকনকে পেঁচিয়ে ধরে গিলতে শুরু করে।\nএকটু একটু করে সাপটি কাঁকনকে পুরো গিলে ফেলে।\nঅন্যদিকে মাঝ রাতে রুক্মিণী দোলাকে ডেকে ঘুম থেকে তুলে বলে তাড়াতাড়ি ঢেকুরের সামনে আয় চাল গুঁড়ো করতে হবে...\nদোলাও তার মায়ের কথা মতো ঢেকুরের কাছে যায়, রুক্মিণী চাল গুঁড়ো করতে করতে দোলার ডান হাতে ঢেকুর চালাতে শুরু করে।\nদোলা প্রচন্ড ব্যথায় যখন কাতরাতে থাকে তখন রুক্মিণী দোলার বাম হাত তারপর এক এক করে ডান পা ও বাম পা''ও ঢেকুরে চেপে ভেঙ্গে ফেলে।\nসবশেষে ঢেকুরের নিচে দোলার মাথাটা রেখে মাথাটাও গুঁড়ো গুঁড়ো করে ছোট্ট দোলাকে মেরে ফেলে।\n[  ] ঘটনা:-০১\nঅন্য দিকে কানাই ও তার স্ত্রী কুন্ডলা তাদের কাকুর কাছে যায় ভবিষ্যৎ বাণী করতে। \nকাকু ঘর থেকে বেড়িয়ে এসে কানাই এর সন্তানের কপালে হাত রেখে ভবিষ্যৎ বলতে যাবে তখন কুন্ডলা আচলে লুকিয়ে রাখা ছুড়িটা বের করে ঠিক ওই মুহুর্তে কানাই এর কাকু বলে উঠে, এটাই হবে তোদের সৌভাগ্যের প্রতীক এই মেয়েই দূর করবে তোদের সকল কষ্ট। \nকানাই এর কাকু অন্ধ ছিলো তাই কিছু দেখতে পারতো নাহ কিন্তু সে আন্দাজ করতে পারতো।\nতারা তাদের সন্তানকে নিয়ে ফিরে আসবে তখন কাকু বলে আমাকে মারার জন্য ছুড়ি এনেছিলি মা কুন্ডলা।\nআমি কি তোদের ক্ষতি চাই বল.?\nতোদের ভালো চাই বলেই তোহ তোদের তিনটা সন্তানকে জ্যান্ত কবর দিতে বলেছি।\nআমার কথা বিশ্বাস নাহ হলে তোরা তোদের সেই তিন সন্তানের কবরের গিয়ে দেখিস ওরা তোদের সাথে কথা বলবে...\n[  ] ঘটনা:-০২\nঅন্যদিকে একদিন রাতে পদ্মাবতীর হঠাৎ ঘুম ভেঙ্গে যায়, ঘুম ভাঙ্গতেই দেখে একটা ছোট্ট ২ বছরের শিশু তাদের রান্না করা খাবার খাচ্ছে। \nশিশুটি দেখতে একদম ধবধবে ফর্সা, চুলগুলো সোনালী।\nপদ্মাবতী ছুটে সেই চালতা ফলটার কাছে যায় গিয়ে দেখে ফলটা দুই টুকরো হয়ে পরে আছে।\nপদ্মাবতী টুকরো করা চালতাটি আগুনে পুড়িয়ে ফেলে।\nএবং ওই শিশু আর চালতা ফলে প্রবেশ করতে পারে নাহ তাই জন্য সে এবং পদ্মাবতী ও বলরামের সাথেই থাকে।\nওই দিনের পর পদ্মাবতী ও বলরাম তাদের সন্তান নিয়ে সুখে শান্তিতে দিন কাটায়।\n[  ] ঘটনা:-০১\nঅন্ধ কাকুর কথা মতো কানাই ও তার স্ত্রী কুন্ডলা তাদের সন্তানদের কবরের কাছে যায়, কবরের সামনে যেতেই তারা দেখে কবরের ভিতর থেকে ছোট্ট ছোট্ট তিনটা শিশু সন্তান বের হয়ে বলে...\nআমরা যদি এতদিন বেঁচে থাকতাম তোদের অনেক ক্ষতি করতাম, তোদের অনেক কষ্ট দিতাম।\nতোরা যা করেছিস ভালোই করেছিস।\nএরপরই তারা ওইখান থেকে চলে আসে এবং তাদের নতুন সন্তান নিয়ে সুখে জীবন কাটাতে থাকে।\n[  ] ঘটনা:-০৩ ও ঘটনা:-০৪ সম্পৃক্ত \nরুক্মিণী দোলাকে ঢেকুরে পিসে মারার পর দোলার মৃত লাশটাকে জঙ্গলে নিয়ে পুতে ফেলে, লাশটা মাটিতে পুতার সময় সেই দানব আকৃতির লোকটা রুক্মিণীর পাশেই দাড়িয়ে থাকে কিন্তু রুক্মিণীকে সাহায্য করে নাহ।\nতখন রুক্মিণী বুঝতে পারে এটা তাহলে কোনো মানুষ বা অন্য জগতের কেউ নাহ এটা তার মনের ভুল ছিলো।\nসে যত খারাপ চিন্তা করতো সব চিন্তার ফলে এই দানব আকৃতির লোকটাকেও সে চিন্তা করতো এবং তার সাথেই সে মনে মনে সংসার করতো।\nরুক্মিণী দোলাকে মাটিতে কবর দিয়ে সেখানেই ঘুমিয়ে পড়ে।\nপরদিন সকালে জমিদার বাড়িতে শুনতে পাওয়া যায় অজগর সাপটি কাঁকনকে গিলে খেয়ে ফেলেছে।\nসাপটির পেট কেটে কাঁকনের লাশ বের করা হয়।\nঅন্য দিকে ঘুম ভাঙ্গতেই রুক্মিণী দেখে হঠাৎ করে দোলার কবর থেকে একটা ফুলগাছ বের হয়। \n The End...."}],"comments":0,"is_featured":false,"read_time":null,"season":1,"status":"published","submitted_by":"primary-admin","date":"2026-04-01T20:48:30.851Z","updated_at":"2026-04-01T20:48:30.851Z"}','2026-04-01T20:48:31.245Z','2026-04-01T20:48:31.245Z');
