INSERT INTO "app_table_rows" ("pk","table_name","row_json","created_at","updated_at") VALUES(3488348,'stories','{"id":"1775076597422","title":"ছুটির ঘন্টা","excerpt":"__MAHEAN_META__:{\"status\":\"published\",\"submittedBy\":\"primary-admin\",\"author\":\"রিয়াদ ইসলাম আযান\",\"category\":\"অণুগল্প\",\"categories\":[\"অণুগল্প\"],\"coverImage\":\"/uploads/stories/covers/2026/04/40c3e1fe-6185-4cd3-b0b8-427712f74408.png\",\"slug\":\"ছুটির-ঘন্টা\",\"parts\":[{\"id\":\"1\",\"title\":\"01\",\"slug\":\"part-01\",\"content\":\"\"}],\"comments\":0,\"season\":1}:__MAHEAN_META_END__\"বাবু! এই বাবু! উঠ! উঠ! তাড়াতাড়ি উঠ৷ স্কুলে যেতে হবে না?\"\nমায়ের ডাকে ঈষৎ বিরক্ত হলো বাবু। আজ তার শরীরটা ম্যাচ ম্যাচ করছে। কিছুতেই উঠতে মন চাচ্ছে না।\n\"মা। আজকে স্কুলে যাবো না।\" ","content":"","author_id":"1773089545405","author":"রিয়াদ ইসলাম আযান","category_id":"অণুগল্প","category":"অণুগল্প","views":0,"image":null,"cover_image":"/uploads/stories/covers/2026/04/40c3e1fe-6185-4cd3-b0b8-427712f74408.png","slug":"ছুটির-ঘন্টা","tags":[],"parts":[{"id":"1","title":"01","slug":"part-01","content":"\"বাবু! এই বাবু! উঠ! উঠ! তাড়াতাড়ি উঠ৷ স্কুলে যেতে হবে না?\"\nমায়ের ডাকে ঈষৎ বিরক্ত হলো বাবু। আজ তার শরীরটা ম্যাচ ম্যাচ করছে। কিছুতেই উঠতে মন চাচ্ছে না।\n\"মা। আজকে স্কুলে যাবো না।\" \nঘুম ঘুম চোখে আকুতি কণ্ঠস্বরে বলে আবার কাঁথা মুড়ি দিয়ে শুয়ে রইলো। বাবুর মা রুবাইয়া বেগম বেশ বিরক্ত হলো।  কড়া গলায় ডাকলো, \n\"কিরে উঠবি? প্রতিদিন তোর এই জ্বালা জ্বালা আর সহ্য হয় না। আমাকে এবার একটু রেহাই দে।\"\nবাবু আর কোনো উপায় না পেয়ে চোখ ডলতে ডলতে ওয়াশরুমে চলে গেলো। \n__\n\"আপা, বাড়ি ভাড়াটা কি দিবেন না?\"\nসকাল সকাল বাড়িওয়ালা এসে হাজির হলো। গতকালই মাস শেষ হলো, আর আজই এসে হাজির। রুবাইয়া গ্লাসে পানি ঢালতে ঢালতে বললো,\n\"বিকেলে আমি গিয়ে দিয়ে আসবো। আপনার কষ্ট করে আর চাইতে হবে না।\"\n\"বলছেন যখন, তাহলে ঠিক আছে।\" এটুকু বলেই করিম সাহেব চলে যাচ্ছিলেন। আবারও পিছন ঘুরে দাঁড়িয়ে বললেন,\n\"এক কাপ চা.....\"\nলোকটাকে থামিয়ে দিয়ে রুবাইয়া বললো, \"ঘরে চা পাতা নেই।\"\nকরিম সাহেব মুখ কালো করে চলে গেলেন। বুঝাই যাচ্ছে একরাশ বিরক্তি ভর করেছে তার মধ্যে। \nরুবাইয়া শাড়ির আঁচলে হাত মুছতে মুছতে বাবুকে ডাকলো, \"কিরে বাবু, হলো তোর?\"\nবাবু স্কুল ইউনিফর্ম পড়ে, গলায় স্টুডেন্ট আইডি কার্ড ঝুলিয়ে নিজের ঘর থেকে বের হলো। মায়ের সামনে এসে দাঁড়ালো। রুবাইয়া যত্ন করে ছেলের চুল আঁচড়ে দিলো৷ \n\"শোন বাবু, স্কুল থেকে প্রায়ই তোর নামে কমপ্লেইন আসে। এখন থেকে শান্তশিষ্ট হয়ে থাকবি। ভুলে যাস না, তোর বাবা নেই।\"\nকথাটা বলতেই যেনো রুবাইয়ার ভেতরটা কেঁপে উঠলো। তার কণ্ঠস্বর কাঁপছে। \n\"বাবা তো আছে।\"\nবাবুর কথাটা রুবাইয়াকে আরো আঘাত করলো। চোখের জল মুছতে মুছতে বললো,\n\"আছে, না থাকার মতো৷ কোনোদিন তো আমাদের খোঁজ খবর''টুকুও নেয়নি৷ নিয়েছে কি?\"\n\"না। নেয়নি।\"\n__\n\"এই গান্ডু! এই সীটে বসবি না, এখানে আমি আর আমার বন্ধু বসবো।\"\nবেঞ্চ থেকে বাবুর ব্যাগটা ছুঁড়ে ফেলে দিলো তুষার। বাবু প্রতিদিন সামনের সীটে বসে৷ আজকে তুষার আর তার বন্ধুরা এই সীটে বসবে। যার কারণে তারা বাবুর উপর হামলে পড়েছে।\n\"এখানে বসবি, সুন্দর মতো বললেই তো হয়?\"\n\"আবার মুখে মুখে কথা বলে! দাঁড়া, দেখ কি করি তোকে।\"\nবলেই বাবুর তলপেটে পর পর তিন চারটে কষে ঘুষি দিলো। বাবু তলপেটে হাত দিয়ে ফ্লোরে বসে কাঁদছে। আশেপাশের ছাত্র ছাত্রীরা চেয়ে চেয়ে দেখছে অথচ কেউ এগিয়ে আসছে না। বাবুর গাল গড়িয়ে টপটপ করে পানি ঝড়ছে। \n__\nক্লাস শুরু হয়ে গেছে। শ্রেণী শিক্ষক আব্দুল শহীদ ক্লাসে উপস্থিত। বাবু ব্যাগে মুখ লুকিয়ে ফুপিয়ে ফুপিয়ে কাঁদছে। বিষয়টা ক্লাসের সবাই উপেক্ষা করলেও, শহীদ স্যার উপেক্ষা করতে পারেনি। এগিয়ে গেলো বাবুর দিকে,\n\"কি হয়েছে? কাঁদছো কেনো তুমি?\"\nবাবু চোখ তুলে তাকালো। শহীদ স্যার হতবাক হয়ে তাকিয়ে রইলো। কাঁদতে কাঁদতে চোখ লাল হয়ে গেছে। পরক্ষণেই তার চোখ পড়লো বাবুর পেটের দিকে। বাবু শক্ত করে তলপেট চেপে রেখেছে। \n\"পেটে যন্ত্রণা হচ্ছে?\"\nবাবু মাথা কাঁত করলো। \"ফুড পয়েজিং হয়েছে বোধহয়। বাসায় চলে যাবে?\"\nপাশ থেকে ইরফান দাঁড়িয়ে ভীতু কণ্ঠে বললো,\n\"স্যার। ওকে তুষার মেরেছে।\" \nশহীদ স্যার অবাক চোখে তাকালো তুষারের দিকে। এত বড় একটা অপরাধ করার পরও তার চোখে এতটুকু দ্বিধাবোধ নেই৷ কোনো অনুতপ্ত বোধ হচ্ছে না তার৷ \n\"তুষার কেনো মেরেছো ওকে?\"\nতুষার মিথ্যা কাহিনী বানাতে চাইলো। পারলো না। ক্লাসের বাকিরাও ওর বিরুদ্ধে সাক্ষী দিতে শুরু করলো। \n__\n\"ছুটির পর তোকে দেখে নিবো।\" শহীদ স্যার চলে যেতেই তুষার আর ওর বন্ধুবান্ধব ঘিরে ধরলো বাবুকে। যেনো বাবু বিশাল বড় কোনো পাপ করে ফেলেছে। \nবাবুকে চোখ রাঙিয়ে ওরা নিজেদের সীটে গিয়ে বসলো। ক্লাস করাতে এলো কামিনী ম্যাডাম। শিক্ষার্থীদের সাথে তার খুব ভাব। বাচ্চাদের কোন বিষয়ে আগ্রহ, অনাগ্রহ সবটাই তিনি খেয়াল রাখেন। এজন্যই বাচ্চারা তাকে এতটা ভালোবাসেন। \nআজও তিনি সবাইকে বুঝিয়ে, হাসি মুখে ক্লাস করাচ্ছেন। আর কিছু মুহূর্ত পরই স্কুল ছুটি হবে। \nক্যাম্পাসে অভিভাবকদের আনাগোনা শুরু হয়েছে। বাবুর মনটাও কু ডাকছে। আজকে নিশ্চয়ই তুষার আর ওর বন্ধুবান্ধব তাকে উদোম মার মারবে। আজ হয়তো তার মা-ও তাকে নিতে আসবেন না। একা একা বাড়ি ফেরার পথে যদি ওরা বাবুকে মারে? এই ভয়টা বাবুকে ঘিরে ধরলো। \nবাকি বাচ্চারা ছুটি কখন হবে বলে চেচামেচি করতে লাগলো। বাবু বার বার মনে মনে বলছে, \"আজ যেনো ছুটির ঘন্টা না বাজে।\"\nরুবাইয়ার কাজ আজকে তাড়াতাড়ি শেষ হয়ে গেছে। তাই মাইলস্টোন স্কুল অ্যান্ড কলেজে এসেছে, ছেলেকে নিয়ে ফিরবে। ছুটির আর মাত্র পনেরো মিনিট বাকি৷ \nক্যাম্পাসের অভিভাবকরা একে অপরের সাথে ভাব বিনিময় করছে। সবাই সবার খোঁজ খবর নিচ্ছে। আজকের পরিবেশটা একদম শান্ত৷ এই আবহাওয়ার সাথে বেমানান। রুবাইয়া চুপটি করে এক জায়গায় বসে রইলো। \nহঠাৎ নিস্তব্ধতা কাটিয়ে উঠলো এক ভয়ংকর বিস্ফোরণে৷ ধ্বংসস্তূপ ধসে পড়ছে। রুবাইয়া অনেকটা দূরে ছিটকে পড়ে আছে। শরীরে সহস্র জখমের চিহ্ন। মিটিমিটি চোখে তাকিয়ে দেখলো, বাবুর ক্লাসটা যে ভবনে, সেই ভবনটা আস্ত নেই। ভেঙে পড়েছে। দাউদাউ করে আগুন জ্বলছে। ভেতর থেকে কোনো সাড়াশব্দও আসছে না। শুধু শুনা যাচ্ছে আশপাশ থেকে লোকজনের আহাজারি, কান্না, আর ধ্বংসাবশেষ শব্দ। রুবাইয়া আর শক্তি পাচ্ছিলো না চোখ খুলে রাখার। মুহূর্তেই তার চোখ দু''টো গভীর আঁধারে তলিয়ে গেলো।"}],"comments":0,"is_featured":false,"read_time":null,"season":1,"status":"published","submitted_by":"primary-admin","date":"2026-04-01T20:49:57.422Z","updated_at":"2026-04-01T20:49:57.422Z"}','2026-04-01T20:49:58.088Z','2026-04-01T20:49:58.088Z');
