INSERT INTO "app_table_rows" ("pk","table_name","row_json","created_at","updated_at") VALUES(3488351,'stories','{"id":"1775076644357","title":"নৃত্যশিল্পী","excerpt":"__MAHEAN_META__:{\"status\":\"published\",\"submittedBy\":\"primary-admin\",\"author\":\"রিয়াদ ইসলাম আযান\",\"category\":\"অণুগল্প\",\"categories\":[\"অণুগল্প\"],\"coverImage\":\"/uploads/stories/covers/2026/04/5e83fbbf-80f7-4f48-ab45-fcf05e88f345.png\",\"slug\":\"নৃত্যশিল্পী\",\"parts\":[{\"id\":\"1\",\"title\":\"01\",\"slug\":\"part-01\",\"content\":\"\"}],\"comments\":0,\"season\":1}:__MAHEAN_META_END__ঘটনাটি ঘটে আমার এক দুঃসম্পর্কের আন্টির সাথে। তার নাম শিউলি,  যখন তিনি ২০ বছর বয়সী ছিলো তখনকার ঘটনা। তার পিতা [ মোবারক আলী ] একজন সরকারি চাকুরিজীবী ছিলেন। কাজের জন্য  বিভিন্ন  জায়গায় ট্রান্সফার হতে হয় শিউলি আন্টির পিতাকে।","content":"","author_id":"1773089545405","author":"রিয়াদ ইসলাম আযান","category_id":"অণুগল্প","category":"অণুগল্প","views":0,"image":null,"cover_image":"/uploads/stories/covers/2026/04/5e83fbbf-80f7-4f48-ab45-fcf05e88f345.png","slug":"নৃত্যশিল্পী","tags":[],"parts":[{"id":"1","title":"01","slug":"part-01","content":"ঘটনাটি ঘটে আমার এক দুঃসম্পর্কের আন্টির সাথে। তার নাম শিউলি,  যখন তিনি ২০ বছর বয়সী ছিলো তখনকার ঘটনা। তার পিতা [ মোবারক আলী ] একজন সরকারি চাকুরিজীবী ছিলেন। কাজের জন্য  বিভিন্ন  জায়গায় ট্রান্সফার হতে হয় শিউলি আন্টির পিতাকে।\nপ্রতিবারের মতো এবারও শিউলি আন্টির পিতাকে কাজের জন্য ট্রান্সফার করা হয়, ভালুকা শহর। সেই শহরের কোনো এক গ্রামে তারা খুব কম খরচের মধ্যে একটা বসতবাড়ি পেয়ে যায়। \nএখানে এসে শিউলি আন্টিকে ইউনিভার্সিটি ফার্স্ট ইয়ারে এবং তার ভাই মাসুমকে ইন্টার সেকেন্ড ইয়ারে ভর্তি করে দেয় তাদের পিতা মোবারক আলী। বাড়িতে উঠেছে আজ তাদের ৭ দিন। দুপুরে সবাই বাসায় যে যার মতো কাজ করছে হঠাৎ সবাই খেয়াল করে শিউলি আন্টি ইউনিভার্সিটি থেকে দৌড়ে এসে তার ঘরের দরজা বন্ধ করে দিয়েছে।\nকেউ তেমন পাত্তা দিলো নাহ, কিন্তু তারা আবারও খেয়াল করলো ৩০ মিনিট হয়ে গেলো শিউলি আন্টি দরজা খুলছে নাহ তারা সবাই দজরা ধাক্কাচ্ছে কিন্তু শিউলি আন্টি দরজা খুলছে নাহ । এর কিছুক্ষণ পর তার ছোট ভাই মাসুম জানালা দিয়ে লুকিয়ে লুকিয়ে তাকিয়ে দেখে শিউলি আন্টি ঘরের দরজা বন্ধ করে সাজুগুজু করছে। হঠাৎ শিউলি আন্টি দরজা খুলে বাইরে এসে সবাইকে বলে...\nশিউলি আন্টিঃ- কি হয়েছে..?\nশিউলি আন্টির মাঃ- তুই দরজা বন্ধ করে কি করছিলি.?\nশিউলি আন্টিঃ- কিছু নাহ [ একটু রাগী কণ্ঠে ]\nবিকেলে যখন সবাই শিউলি আন্টিকে জিজ্ঞেস করে সে দরজা বন্ধ করে ভিতরে সাজুগুজু করছিলো তখন শিউলি আন্টির কিছুই মনে ছিলো নাহ।\nপরের দিন সন্ধ্যা বেলা একি ভাবে শিউলি আন্টি দৌড়ে এসে ঘরের দরজা বন্ধ করে ভিতরে চলে যায়।\nতখন বাসার সবাই ভেতর থেকে একটা সুন্দর ঘ্রাণ পায় ঠিক যেনো বেলি ফুলের। \nতারপর ভেতর থেকে শুনতে পায় গুনগুন করে কেউ গান গাচ্ছে আর পায়ে ঘুঙ্গুর পড়ে নাচ করছে।\nহঠাৎ করে নাচের শব্দ বন্ধ যায় এটা শুনে সবাই দরজা ধাক্কায় কিন্তু শিউলি আন্টি দরজা খুলছে নাহ। \nশিউলি আন্টি দরজা খুলছে নাহ দেখে তারা দরজা ভেঙ্গে ভেতরে ঢুকে দেখে... \nখাটের এক কোণে শিউলি আন্টি বসে আছে তার চোখগুলো বড় বড় হয়ে লাল বর্ণ ধারণ করেছে। এটা দেখে সবাই অনেক ভয় পায়। তার আম্মু দৌড়ে গিয়ে শিউলি আন্টিকে ধরতেই সে অজ্ঞান হয়ে যায়। \nতারপর তার চোখে-মুখে পানি দিয়ে জ্ঞান ফেরানো হয়। তাকে যখন নাচের কথা জিজ্ঞেস করা হয় তখন তার কিছুই মনে ছিলো নাহ। \nওইদিন আর কোনো সমস্যা হয়নি, পরেরদিন রাত ঠিক ১২ টা তখন শিউলি আন্টি ছাঁদের উপর চলে যায় আর ওখানে তিনি ঘুঙ্গুর পড়ে নাচ শুরু করে আর ঘুঙ্গুরের শব্দ শুনে যখন সবার ঘুম ভেঙ্গে যায় তখন তারা ছাঁদে গিয়ে দেখে শিউলি আন্টি ছাঁদের একদম কার্ণিশে দাড়িয়ে আছে।\nএটা দেখে সবাই চিৎকার করা শুরু করে তাদের চিৎকার শুনে আশেপাশের কিছু প্রতিবেশী চলে আসে,  এত লোকজন দেখে শিউলি আন্টি ছাঁদ থেকে ঝাপ দিয়ে যেনো উড়ে উড়ে নিচে পড়ছে।  নিচে পড়েই সে বাড়ির বাইরে যাওয়ার জন্য যখনই দৌড় দেয় ঠিক তখনই ওই পাড়ার এক লোক তাকে ধরে ফেলে আর সে অজ্ঞান হয়ে যায়। \nপরের দিন তার পিতা আর সময় নষ্ট নাহ করে তাকে একটা হুজুরের কাছে নিয়ে যায় তারপর হুজুর বলে...\nহুজুরঃ- কোনো এক খারাপ জ্বিন বা খারাপ ছায়ার নজর পড়েছে।\nমোবারক আলীঃ- এখন কি করা যায়.?\nহুজুরঃ- আমি একটা তাবিজ দিচ্ছি আশা করি আর সমস্যা হবে নাহ.।\nতারপর হুজুরের থেকে তাবিজ আনার পর আর কোনো সমস্যা হয় নাহ। \nকিন্তু কিছুদিন পর শিউলি আন্টির আম্মু স্বপ্নে একজন মহিলাকে দেখে বয়স আনুমানিক ২০-২২ বছর হবে সে নৃত্যশিল্পীদের মতো সেজে আছে আর তার ঘাড় বাকিয়ে আছে মুখ দিয়ে রক্ত পড়ছে চোখগুলা বড় বড় হয়ে লাল হয়ে আছে এবং তাকে বলছে...\nমহিলাঃ- আমার সাথে ও কাজটা ঠিক করেনি। আমি কি দোষ করেছিলাম। ও আমার জীবনটা নষ্ট করে দিলো। ছাড়বো নাহ আমি ওকে ছাড়বো নাহ।\nএই বলে মহিলাটি হাওয়ায় মিলিয়ে যায়।\nএরপর তারা ঠিক করে ওই বাসা ছেড়ে দেবে এবং তারা ওই বাসা ছেড়েও দেয়। \nছেড়ে চলে আসার আগে ওই এলাকার কিছু লোকের কাছে তারা শুনতে পায়....\nএই বাড়িতে একটা পরিবার ছিলো, ওই পরিবারে একটা মেয়ে খুব ভালো নাচ করতো, মেয়েটার নাম ছিলো মেঘা। কিন্তু একদিন বাড়িতে মেঘার ফাঁসি দেওয়া লাশ পাওয়া যায় এবং তার ১ সপ্তাহ পর জানা যায়, মেঘার নৃত্য শিক্ষক আসিফ তাকে প্রতিদিন শারীরিকভাবে অত্যাচার করতো যার ফলে সে আত্মহত্যা করতে বাধ্য হয়।\nএসব শোনার পর মেঘার পরিবার ওই শিক্ষকের বিরুদ্ধে আইনী পদক্ষেপ নেয় এবং তারা এই বাড়ি বিক্রি করে চলে যায়।\nতারা চলে যাওয়ার পর শিউলি আন্টিরাই ছিলো ওই বাড়ির প্রথম ভাড়াটিয়া। \nপরে আর জানা যায়নি মেঘার জীবন নষ্ট করে দেওয়া ওই নৃত্য শিক্ষক আসিফের কি হয়েছে। \nআদোও কি মেঘা আর প্রতিশোধ নিতে সক্ষম হয়েছে নাকী সে আজও ওই বাড়িতে প্রতিশোধের আগুনে আরো ভয়ংকর প্রেতাত্মাতে রূপান্তরিত হয়েছে।"}],"comments":0,"is_featured":false,"read_time":null,"season":1,"status":"published","submitted_by":"primary-admin","date":"2026-04-01T20:50:44.357Z","updated_at":"2026-04-01T20:50:44.357Z"}','2026-04-01T20:50:44.342Z','2026-04-01T20:50:44.342Z');
