INSERT INTO "app_table_rows" ("pk","table_name","row_json","created_at","updated_at") VALUES(3488357,'stories','{"id":"1775076772350","title":"নিশিরাতের হাতছানি","excerpt":"__MAHEAN_META__:{\"status\":\"published\",\"submittedBy\":\"primary-admin\",\"author\":\"রিয়াদ ইসলাম আযান\",\"category\":\"অণুগল্প\",\"categories\":[\"অণুগল্প\"],\"coverImage\":\"/uploads/stories/covers/2026/04/4b4d165d-63bb-42ca-b9a4-e57f664580ee.png\",\"slug\":\"নিশিরাতের-হাতছানি\",\"parts\":[{\"id\":\"1\",\"title\":\"01\",\"slug\":\"part-01\",\"content\":\"\"}],\"comments\":0,\"season\":1}:__MAHEAN_META_END__চৈত্র মাসের প্রথম দিকের উত্তপ্ত রোদের তাপে বাড়ির পাশের ছোট পুকুরটিতে ফাটল ধরেছিলো। হঠাৎ করেই মাসের শেষ দিকে সেই ছোট পুকুরটি ভরে উঠে জোয়ারের টলমল পানিতে। আম গাছের ডালে সবেমাত্র মুকুল ধরেছে।","content":"","author_id":"1773089545405","author":"রিয়াদ ইসলাম আযান","category_id":"অণুগল্প","category":"অণুগল্প","views":0,"image":null,"cover_image":"/uploads/stories/covers/2026/04/4b4d165d-63bb-42ca-b9a4-e57f664580ee.png","slug":"নিশিরাতের-হাতছানি","tags":[],"parts":[{"id":"1","title":"01","slug":"part-01","content":"চৈত্র মাসের প্রথম দিকের উত্তপ্ত রোদের তাপে বাড়ির পাশের ছোট পুকুরটিতে ফাটল ধরেছিলো। হঠাৎ করেই মাসের শেষ দিকে সেই ছোট পুকুরটি ভরে উঠে জোয়ারের টলমল পানিতে। আম গাছের ডালে সবেমাত্র মুকুল ধরেছে।  শরীর জুড়িয়ে দেওয়ার মতো দক্ষিণা বাতাস বইছে চারিদিকে। রাতের পরিবেশটা যেনো আরো মুখরিত। বৃষ্টির কোনো চিহ্নও খুঁজে পাওয়া যায় না। আকাশ ভরা ছোট বড় তারা জ্বলজ্বল করছে। মধ্যকাশে আলোকিত চাঁদ তাকিয়ে আছে পৃথিবীর পৃষ্ঠে। দুই মাসের ছোট শিশু সন্তানের বুকের উপর আঁচল উপচে ফেলে আপন মনে ঘুমিয়ে আছে ময়না। বেঘোর ঘুমে বিঘ্ন ঘটে ছেলের হাসির শব্দ শুনে। হাসি শুনে মনে হচ্ছে ছেলের সাথে কেউ খেলা করছে। অথচ একা ঘরে মা ছেলে ব্যাতিত তৃতীয় কোনো ব্যক্তি থাকার প্রশ্নই আসে না। ঘুম ঘুম চোখে তাকিয়ে দেখে ছেলের মাথার পাশে দাঁড়িয়ে আছে বিশাল এক কালো ছায়া। ভয়ের সীমা যখন স্বল্পতা ছাড়ায় তখন আঁচল টেনে বুক ঢেকে নিঃশব্দে ঢোক গিলে। দোচালা টিনের ঘর চারিদিকে মুলিবাঁশের ব্যাড়া। কালো ছায়াটি সুযোগ বুঝে হাওয়ার বেগে বাচ্চা ছেলেকে ভাসিয়ে নিয়ে গেলো দরজার উপরে থাকা ছোট্ট ফাঁকা দিয়ে। এহেন দৃশ্য দেখে মমতাময়ী মা ঠিক থাকতে না পেরে ছায়ার পিছু করার উদ্দেশ্যে দরজা খুলে বেরিয়ে ছুটতে থাকে। ছেলে হাওয়ায় ভাসতে ভাসতে ছোট পুকুরের ধারে চলে যাচ্ছে। এদিকে ময়নাও মাটিতে আঁচল বিছিয়ে পা*গ*লে*র মতো ছুটে যাচ্ছে সন্তানের দিকে। ছুটতে ছুটতে ময়না যখন পুকুরের দারপ্রান্তে এসে হাজির হয় তখন সচক্ষে দেখলো জোয়ারের পানিতে ইয়া বড় বড় দুইখানা বোয়াল মাছ হা''রত অবস্থায় তার ছেলের দিকে ভেসে আসছে। এমন বিশাল বোয়াল মাছ এর আগে কোনো দিন দেখেনি ময়না। আর দেখেনি বোয়াল মাছের হা''রত দৃশ্য। মুখের গহ্বরে স্পষ্ট দেখা যাচ্ছে লাল টকটকে আলজিভ। ক্ষুধার্ত মাছগুলো আজ বোধহয় তার ছেলেকেই গিলে খাবে। নিরুপায় ময়না অশ্রুমুখী চোখে ছেলেকে দেখছে। মুহূর্তেই কোথা থেকে যেনো ময়নার বাবা আবুল বাশার সেখানে উপস্থিত হয় এবং বোয়াল মাছের মুখ থেকে নাতিকে খাপ্পা দিয়ে কেড়ে এনে মেয়ে বুকে ছুুড়ে দিয়ে বলে \"মা''রে ওরে নিয়া এইহানতে পলা। সাবধানে রাখিস ওরে মা! সাবধানে রাখিস! বাপে কিন্তু হগ্গল সময় থাকবো না তোগোর পাশে\" ছেলেকে নিজ বুকে ফিরে পেয়ে খুশিতে আ*ত্ম*হা*রা হয়ে ঘরের দিকে ছুটে আসছে ময়না। হোঁচট খেয়ে আঁ*চ*ড়ে পরে গেলো ময়না। কোল থেকে বিচ্ছিন্ন হলো তার সন্তান। হাত বাড়িয়ে কান্নামাখা গলায় ছেলের নাম ধরে চিৎকার দেয় ময়না \"মানিকককককককককক\" সঙ্গে সঙ্গে ঘুম ভেঙ্গে যায় ময়না। ঘেমে একাকার হয়ে গেছে। আঁচল দিয়ে কপালের ঘাম মুছে ছেলের দিকে তাকিয়ে দেখে চারপাশে ছেলের সুরক্ষার জন্য রেখে দেওয়া জালের সাথে পুরোপুরি প্যাঁচিয়ে আছে দুই মাসের শিশু মানিক। অদ্ভুত এই স্বপ্ন যেনো উতলা করে তুললা মাতৃহৃদয়কে। কোলে তুলে ছেলেকে একের পর এক চুমু খাচ্ছে ময়না। \"আল্লাহ যেনো তোরে কোনো সময় আমার কাছ থাইকা দূরে না নেয় বাজান।৷ তুই যে আমার সাত রাজার ধন মানিক। তোরে ছাড়া আমি কেমনে বাঁচুম বাজান।\" \nসকাল পেরিয়ে দুপুর হয়ে গেছে। বাড়ির কর্তার এখনো আসার কোনো নাম নেই। এদিকে রান্না করার মতো ঘরে কিচ্ছুটি নেই। কি দিয়ে কি করবে ভেবেই শি*উ*রে উঠছে ময়না। \"বাপের বাড়িতও কষ্ট করছি এহন হৌড় বাড়িতও কষ্ট করন লাগে। আমার বিয়ার পর তো এহন বাপ ভাইয়ের টাকায় আমার ভাই বোনগুলান ভালোই আছে। আমার বেলায় যত অভাব। বাপে যেমন দেইখ্যা বিয়া দিছে ঘানিও কম টানে না। মানুষটা যদি একটু কাম-কাজ করতো তাইলে কি আর সংসারে অভাব অনটন থাকতো। আমি আর মাইনষের ধারে যাইতে পারুম নাহ ধারদেনা করতে। ধারদেনা করতে করতে ঝোলা হয়ে যায় হেরপর আইসা আমার বাপ সব ধারদেনা শোধ করে। আইজ আসুক বাড়িত। না খাওয়াইয়া রাখুম।\" সংসারের অভাব বোধ করতে করতে অতিষ্ঠ হয়ে গেছে ময়না। স্বামীর একটা মুদির দোকান ছিলো। বেচাকেনা ভালোই হতো। সেই দোকান দেখেই আবুল বাশার মেয়ের দায়িত্ব তুলে দিয়েছিলো করিম মিয়ার হাতে। দোকানে দুই বার চুরি হওয়ার পর থেকে ছয় হাজার টাকায় সেই দোকান বিক্রি করে দেয় করিম মিয়া। এখন সারাদিন ঘুরে আর দাবা খেলে। এই করেই দিন পার করে। ঘরে বউ বাচ্চার কি হলো সেদিকে কোনো ধ্যান খেয়াল নেই করিম মিয়ার৷ \"আইজ তোর ভাবি এই মাছ''খান দেখলে যে কি খুশি অইবো।\" হাতে বড় একখানা বোয়াল মাছ নিয়ে দুলাতে দুলাতে আসছে করিম মিয়া। \"শুধু মাছ দেইখ্যাই খুশি অইবো''নি। আমারে দেইখ্যা খুশি অইবো না মনে হয়।\" করিম মিয়ার মাথায় ঠোনকা মে*রে বললো ফিরোজ। \"অইবো! অইবো! দশটা না পাঁচটা না একটা মাত্র দেওর তুই। তোরে দেইখ্যা খুশি অইবো তো কারে দেইখ্যা অইবো ক?\" করিম মিয়ার তালে তাল মিলিয়ে হাসতে হাসতে বললো ফিরোজ \"হ! হ! তুই তো বিয়া শাদী করলি এবার আমারও করতে অইবো। তোর কোনো শালি আছে''নি\"  ফিরোজের কথার কোনো প্রতুত্তর না করে দুই বন্ধু এসে হাজির হয় করিম মিয়ার বাড়ি। \"কই গো! মানিকে মা!  ওওও মানিকে মা কই গেলা\" রাস্তার মোড়ে দাঁড়িয়ে ময়নাকে ডাকছে করিম মিয়া। \"কি অইছে! ওমন ষাঁড়ের মতোন চিল্লাইতাছো কিল্লাগা?\" ঘর থেকে চেঁচাতে চেঁচাতে বেরিয়ে এলো ময়না। ঘর থেকে বেরিয়ে দেখে করিম মিয়ার সাথে ফিরোজও এসেছে। \"আরে ফিরোজ ভাই আপনে! কেমনে মনে পরলো আমগো কথা?\" এক গাল মুচকি হেসে বললো ফিরোজ \"তেমন কিছু না ভাবি। মনে অইলো কতদিন ধইরা আপনাগো লগে দেখা সাক্ষাৎ নাই একটু দেখা কইরা যাই। তাছাড়া আমার তো আপনাগো বাড়ির পাশের সিনেমা হলে চাকরি অইছে।\" ফিরোজে কথা শুনে ময়না করিম মিয়াকে বললো \"এই লোক এহনো বিয়া করে নাই অথচ কাজ-কামের কত গর্জ। আর তোমার ঘরে বউ বাচ্চা আছে তাও সারাডা দিন টই-টই করে ঘুরো। ক্যান একটু কাজ-কাম করলে কি হয়।\" ময়নার কথা শুনে মাথা নিচু করে রইলো করিম মিয়া এবং ফিরোজ দু''জনই। \"আরে ভাবি! বকেন ক্যা? দেখেন করিম কি আনছে?\" করিম মিয়া দাঁত বের করে একটা হাসি দিয়ে হাতে থাকা বোয়াল মাছটা উঁচিয়ে দেখায় \"এই দেহো মানিকের মা! বোয়াল মাছ আনছি\" বোয়াল মাছ দেখে ময়নার গতরাতের সেই ভ*য়*ঙ্ক*র স্বপ্নের কথা মনে পরে যায়। তরতর করে কাঁপছে ময়নার সারা শরীর। কপাল বেয়ে ঘাম পরছে। \"কি গো? কি ভাবো?\" ময়না ক্রুদ্ধ কণ্ঠে জানায় \"মাছ যে আনছো খাইবা কি দিয়া? ঘরে তো কিচ্ছু নাই। চাউল, ডাইল তরিতরকারি কিচ্ছু নাই।\" মুহূর্তেই গলার স্বর নরম করে মুখে আঁচল গুঁজে ঘরে ছুটে গেলো ময়না। \"এহনো সময় আছে মন দিয়া কাম কর। বউ বাচ্চারে এমনে কষ্ট দিস না। আর আমিও দেখি সিনেমা হলের চাকরিটা তোরে যোগাড় কইরা দিতে পারি কি-না।\" এই বলে চলে গেলো ফিরোজ। করিম মিয়া হাতে মাছ নিয়ে ঠাঁই দাঁড়িয়ে রইলো।\n\"সাহানার মা ঘরে আছো''নি? সাহানার মা?\" পাশের বাসার সাহানার মায়ের কাছে গেলো ময়না চাউল ধার করতে। সাহানাদের পরিবার মধ্যবিত্ত হলেও তিন বেলা পেটপুরে খেতে পারে। সাহানার বাবার তেমন আয় রোজগার না থাকলেও সাহানার মামা বাড়ি থেকে ভালোই সাহায্য পায় যা দিয়ে ওদের দিন কেটে যায়। লোকমুখে শোনা যায় সাহানার মা সায়েরার নাকী চুরি করার স্বভাব আছে। সবাই বললেও ময়না বিশ্বাস করে না কারণ সে নিজের চোখে কোনোদিন দেখেনি। তার সাফ কথা \"যেদিন নিজের চোখে দেখুম সেদিন বিশ্বাস করুম\" ময়নার সাথে সাহানার মায়ের ভালোই মিল। ময়না কিছুর জন্য হাত পাতলে সায়েরা মানা করে না। তার একমাত্র কারণ হলো ময়না যতই ধারদেনা করুক সময় মতো ময়নার বাবা এসে তা পরিশোধ করে দিয়ে যান। ময়নার ডাক শুনে চৌচালা পাকা ভিটি ঘর থেকে বেরিয়ে এলো সায়েরা \"হ গো! ঘরেই আছি। কিল্লাগা গো কোনো দরকার\" ময়না দুই কদম এগিয়ে গিয়ে বলো \"আমারে দুই পোয়া চাউল দিবার পারবা। ঘরে কিচ্ছুটি নাই।\" সায়েরা কিছুক্ষণ ময়নার দিকে তাকিয়ে থেকে বললো \"তুমি বহো! তা রান্দনের কোনো তরকারি আছে''নি?\" ময়না আঁচলে আঙ্গুল প্যাঁচাতে প্যাঁচাতে বললো \"না ভাবি! কিচ্ছুটি নাই\" সায়েরা একটা মৃদু হাসি দিয়ে বললো \"বহো আমি আইতাছি\" ময়নাকে বাইরে বসিয়ে রেখে সায়েরা ভিতরে চলে গেলো। কিছুক্ষণ পর কাপড়ের ভাঁজে চাউলসহ আরো কিছু তরিতরকারি নিয়ে এলো সায়েরা। \"এই লও! চার পোয়া চাউল দিলাম। লগে পুইশাক আর তোমার ভাসুর লাউ আনছিলো হেই লাউয়ের অর্ধেকখান তোমারে দিলাম।\" ময়না খুশিতে সায়েরার কাছ থেকে তা গ্রহণ করলো। \"তোমারে যে কি কইয়া ধন্যবাদ দিবাম। তাইলে এহন যাই আমি\" এই বলে চলে গেলো ময়না।\nদিনের আলো মিলিয়ে যখন সন্ধ্যা ঘনিয়ে আসে তখনই যেনো রাতের অন্ধকারকে পিছনে ফেলে দেওয়ার জন্য দূর আকাশে উঁকি দেয় চৈত্রমাসের শেষ পূর্ণিমার চাঁদ। একা ঘরে ছেলেকে পায়ে দোল দোলাতে দোলাতে গুনগুন করছে ময়না। উত্তুরে হাওয়া এসে পুরো ঘর শীতল করে দিচ্ছে। সবেমাত্র সন্ধ্যা হলো এজন্য আর ঘরের দরজা লাগায়নি ময়না। উত্তুরে হাওয়া উপভোগ করছে। হারিকেনের আলোয় এই অন্ধকারে ময়নাকে স্পষ্ট দেখা না গেলেও মানিকের চেহারাটা একদম পূর্নিমার চাঁদের মতো জ্বলজ্বল করছে। \"কিলো ময়না ঘরে আছস''নি\" বাইরে থেকে কারো কণ্ঠস্বর ভেসে এলো। \"হ''গো আছি! কেডা? ঘরে আহো!!\" কে বা কারা বাইরে দাড়িয়ে আছে না জেনেও ঘরে আসার আহ্বান করলো ময়না। \"আমি লো! আমি! তোর লতার মা ভাবি। তোর পোলাডারে দেখতে আইলাম!\" ময়না ভিতর থেকে একটু হেসে জবাব দিলো \"ওহ্! আকলিমা ভাবি। আহেন! আহেন ভিতরে আহেন!\" আকলিমাও হাসতে হাসতে ভিতরে চলে গেলো। \"কই লো তোর পোলাডারে এট্টু দেহি! আল্লাহ গো কত্ত সুন্দর অইছে তোর পোলাডা। এক্কেরে চান্দের লাহান। কিন্তু তুইও কালা আর আমাগো করিমও কালা তোগো পোলাডা অইছে এক্কেরে ধবধবা বিলাইর লাহান। যাগগে! আল্লাহ বাঁচাইয়া রাখুক।\" ময়না একটু মুচকি হেসে বললো \"হ ভাবি দোয়া কইরেন। আমার মানিকরে নিয়াই তো আমার জীবন। ওয় না থাকলে তো আমিও বাঁচুম না।\" আকলিমা ময়নার কাঁধে হাত রেখে বললো \"বোইন রে! তোর কথা আমরা সবাই কই। কি কপাল লইয়া আইলি এই বাড়ি। হায়রে! করিমরে কত কইরা কই ঠিক মতো কাম কর  কিন্তু হুনে না। যাগগে! হুন! তোগো বাড়ির সামনে আমাগো লাকড়ির মাচা বানাইছি একটু দেইখ্যা রাখিস।\" ময়না এক হাতে চোখ মুছে জবাব দিলো \"আইচ্ছা ভাবি! দেখুম হানে!\"  আকলিমা কিছু বলতে যাবে তখনই বাইরে থেকে লতা ডাকছে, \"মা! ওও মা! মানিকরে দেখা অইছে তোমার! আব্বায় আইছে তাড়াতাড়ি আহো\" আকলিমা শিগগিরই উঠে দাঁড়িয়ে বললো \"আইজ আহি রে বোইন! সাবধানে থাকিস\" ময়না একটু হেসে বললো \"আইচ্ছা ভাবি! আবার আইসেন\" ময়নাকে বিদায় জানিয়ে চলে গেলো আকলিমা। ওদিকে রাত ভারী হয়ে আসছে অথচ করিম মিয়ার আসার কোনো নাম নেই। মাঝে মাঝে এমনই সারারাতও বাড়ি ফিরে না। কোথায় যায়, কি করে কিচ্ছু ময়নাকে জানায় না। এমনকি রাতে যে বাড়ি ফিরবে না এটা পর্যন্ত বলে যায় না। স্বামীর জন্য অপেক্ষা করতে করতে কখন ঘুমিয়ে পড়ে ময়না নিজেও জানে না। ছেলের সুরক্ষার জন্য চারপাশে জাল, কাঠি ম্যাচ, আর লোহার পেরেকটাও রাখতে মনে নেই তার। গভীর রাতে ময়নার ঘুম ভেঙে যায়। প্রকৃতির ডাকে সাড়া দিতে হবে, কিন্তু ঘর থেকে বেশ দূরে টয়লেট। সেই টয়লেটের পাশেই বিশাল এক বটগাছ দাঁড়িয়ে আছে, আর পিছনে মস্ত বড় ময়লার স্তূপ, যেখানে পুরো মহল্লার মানুষ ময়লা ফেলে। এত রাতে জায়গাটা একেবারে নিস্তব্ধ। জায়গাটার পরিবেশে এক অদ্ভুত গা ছমছমে অনুভূতি হয়। তার উপর করিম মিয়াও বাড়িতে নেই, মানিক''কে একা ঘরে রেখে যেতে কিছুতেই মন সায় দেয় না তার। তবুও নিরুপায় হয়ে ময়না ধীরে ধীরে ঘর থেকে বেরিয়ে টয়লেটের দিকে পা বাড়ায়। প্রতিটি পদক্ষেপে তার মনে হতে থাকে, চারপাশের হাওয়া কেমন ভারী হয়ে আসছে। তার ভিতরে একটা অ*স্ব*স্তি*ক*র অনুভূতি জাগতে শুরু করে। মনে হচ্ছে পরিবেশটা ভ*য়া*ন*ক ভু*তু*ড়ে হয়ে উঠেছে। অবশেষে টয়লেটে গিয়ে বসার পর, ময়নার মনে হতে থাকে টয়লেট''টা যেনো নড়ছে। প্রবল বেগে ঝড় বইছে বাইরে। অপবিত্র এই জায়গায় দোয়া কালাম পড়তে গিয়ে তার জিভ আটকে যাচ্ছে। সে শুধুই \"আস্তাগফিরুল্লাহ\" পড়তে থাকে। কিছুক্ষণ পর পরিস্থিতি একটু শান্ত হলে, হালকা একটা স্বস্তি আসে তার মধ্যে। ময়না টয়লেট থেকে বের হয়ে আবার দোয়া কালাম পড়তে পড়তে ঘরের দিকে যেতে থাকে। হঠাৎ ময়নার চোখ পড়ে আকলিমার বলা সেই লাকড়ির মাচার দিকে। স্পষ্ট দেখা যাচ্ছে সায়েরা সেখানে দাঁড়িয়ে লাকড়ি চুরি করছে। ময়না মনে মনে বলে, \"হায় আল্লাহ! সায়েরা ভাবি তাইলে সত্যি সত্যি চুরি করে? আল্লাহ! সবাই কইতো হেয় চুরি করে কিন্তু আমি বিশ্বাস করতাম না। আজ সচক্ষে দেইখ্যা লইলাম। দাঁড়া আজকেই হাতে নাতে ধরুম\" ময়না রাগে ফুঁসে উঠে, সায়েরাকে হাতে নাতে ধরার জন্য সামনে এগোতে থাকে।  \"হ্যাঁ গো সাহানার মা! তোমারে তো আমি ভালো মনে করছিলাম কিন্তু তুমি তো দেখি সত্যি সত্যি চুরি করো। দাঁড়াও আমি অহনই আকলিমা ভাবিরে কইতাছি\" সে জোরে জোরে চিৎকার করে, কিন্তু সায়েরা কোনো প্রতিক্রিয়া দেখায় না। সে নিজের মতো লাকড়ি নামিয়ে যাচ্ছে। \"কিগো! তোমারে কইতাছি, হুনো না?\" ময়না আর এক কদম এগোতেই সায়েরা তার দিকে তাকায়। ময়নার ভেতরটা কেঁপে উঠে। সায়েরার চোখদুটো ধবধবে সাদা, মণিহীন। ভয়ে দোয়া কালামও ভুলে যায় ময়না। সে শক্ত হয়ে দাঁড়িয়ে থাকে, নড়ার সাহসও পাচ্ছে না। ধীরে ধীরে সায়েরা ময়নার সামনে এসে দাঁড়ায়। তার উপস্থিতি ময়নাকে ভেতর থেকে থেঁ*ত*লে দিতে থাকে। বার বার ঢোক গিলতে থাকে সে, চোখ নামাতে পারছে না আবার তাকিয়েও থাকতে পারছে না। এক অদ্ভুত দোটানায় পড়ে গেছে ময়না। ময়না কিছু বুঝার আগেই সায়েরা ময়নার চারপাশে আড়াই পাক দিয়ে সোজা বটগাছের দিকে চলে যায়। ময়না বি*স্ম*য়ে হতবাক হয়ে তাকিয়ে থাকে। বটগাছের সামনে যেতেই সায়েরা গায়েব হয়ে যায়। ময়না এতটাই ভয় পায় যে অন্য কিছুই ভাবতে পারছে না।  দৌড়ে ঘরে ঢুকে দরজা বন্ধ করে দেয়। ঘরে ঢুকতেই মানিক কান্না শুরু করে দেয়। ময়না ছুটে গিয়ে মানিক''কে কোলে তুলে নিয়ে মাতৃদুগ্ধ পান করায়, কিন্তু তারপরও তার কান্না থামে না। এত রাতে একা কী করবে ভেবে পায় না ময়না। ছেলের কান্না থামানোর চেষ্টা করতে করতে কখন সে ঘুমিয়ে পড়ে, তা নিজেও টের পায় না।\n\"এমনে আর কতদিন চলবো? প্রতিদিন এত রাইতে এই শূন্য রাস্তায় আমার ভিতরডা ঠান্ডা হইয়া যায়। আইজ না-হয় ভাগ্য ভালো, কিন্তু যদি কোনোদিন... আল্লাহ! না-না, ভাবতেও ভয় লাগে।\" ফিরোজের গা শিরশির করছে। রাতের নিস্তব্ধতা যেনো প্রতিটি ধাপে তার দিকে গাঢ় অন্ধকারের কালো থাবা বাড়িয়ে দিচ্ছে। হল থেকে বেরিয়ে বাঁশতলা দিয়ে হাঁটতে হাঁটতে সে মনে মনে বলছে। হঠাৎ কিছুদূর সামনে একটা বাঁশ গাছ ঝুঁকে থাকতে দেখে ফিরোজ থমকে দাঁড়ায়। সেই গাছটা! যার কথা শুনে শৈশব থেকেই ভয় ঢুকে আছে তার মনে। লোকের মুখে মুখে শোনা, এই বাঁশতলার নিচে দেহহীন আ*ত্মা*রা ঘুরে বেড়ায়, পথের মধ্যে বাঁশ গাছ ফেলে ফাঁদ তৈরি করে। \"আল্লাহ! যেইডার ডর পাইছিলাম। এদিক দিয়া আমার যাওয়া অইছে। ফিরোজ! জীবনের মায়া থাকলে রাস্তা ঘোরা\" নিজেকেই স্বান্ত্বনা দেয় ফিরোজ, কিন্তু ভেতরে ভেতরে সে জানে, অন্ধকারে এসব কথাই মনে আরও ভয় ঢুকিয়ে দেয়।সিনেমা হলের পাশে থাকা বাঁশতলাটাকে সবাই অশুভ মানে। সবার বিশ্বাস এখানে জ্বিন ভুতের বসবাস। রাত বিরাতে এখানে অনেকে অকালে জীবন দিয়েছে। তাই সবাই সাবধানে চলাফেরা করে। চাকরির সুবাদে ফিরোজকে এখান দিয়েই যাতায়াত করতে হয়। প্রথম দু''দিন সবকিছু ঠিক থাকলেও আজ তার সামনে পড়েছে ঝুঁকে থাকা বাঁশ গাছ। যা সবাই বিশ্বাস করে জ্বি*ন ভু*তের ফাঁদ হিসেবে। \"আইজ তাইলে করিম মিয়ার বাড়ির রাস্তা দিয়াই যাই। কিন্তু ওই রাস্তাটাও তো ভালো না। ইয়া বড় বটগাছ, সবাই কয় বটগাছে নাকী পে*ত্নী আছে\" একা একা বিড়বিড় করে রাস্তা পরিবর্তন করে করিম মিয়ার বাড়ির দিকে হাঁটতে শুরু করে ফিরোজ। তার প্রতিটি পদক্ষেপ যেনো ধীরে ধীরে আরো ভারী হয়ে আসছে। চারপাশের অন্ধকারে তার নিজের শ্বাসও কেমন ভারী হয়ে উঠেছে। কিছুদূর যেতেই চোখ পড়ে করিম মিয়ার বাড়ির দিকে। সে দেখে, দরজার সামনে একটা কালো ছায়া হাত পেতে দাঁড়িয়ে আছে। সেই ছায়াটা নিঃশব্দে দুলছে, যেন বাতাসের সাথে মিশে আছে কিন্তু তার উপস্থিতি ভারি, গা ছমছম করা। “এইডা আবার কি!” আ*ত*ঙ্কি*ত হয়ে ফিরোজ ধীরে ধীরে দরজার দিকে এগোয়। তার মনে হচ্ছে এই কালো ছায়াটা যেনো তাকে ইশারা করছে, কাছে আসার আহ্বান জানাচ্ছে। সে ভয়ে ভয়ে লাইট জ্বালিয়ে ছায়াটার দিকে তাক করে। টর্চের আলো যেই পড়লো, ছায়াটা মুহূর্তেই মিলিয়ে গেলো। ঠিক তখনই, ঘরের ভেতর থেকে একটা শব্দ আসে, যেনো কিছুকে আ*ছা*ড় দিয়ে ফেলা হলো। ফিরোজ দেখলো, দরজার টুই দিয়ে হঠাৎ করে ছোট্ট মানিককে ছুড়ে ফেলে দিলো কেউ। কিন্তু কেউ নেই! ফিরোজ কোনো মতে ছুটে গিয়ে মানিক''কে মাটিতে পড়ার আগেই ধরে ফেলে। তার হাত কাঁপছে, শ্বা*স*রু*দ্ধ*ক*র পরিস্থিতি। \"এসব কি হইতাছে? ক্যান এমন হইতাছে?\" মনে মনে ফিরোজ প্রার্থনা করছে যেনো সবকিছু তার কোনো দুঃস্বপ্ন হয়। \"ভাবি! ভাবি!\" সে দরজায় বারবার ধাক্কাতে লাগলো, কিন্তু কোনো সাড়া নেই। ময়না ঘুমিয়ে আছে, গভীর ঘুমে। ফিরোজের গায়ের রক্ত হিম হয়ে আসছে, মনে হচ্ছে যেনো তার চারপাশে অদৃশ্য কোনো শক্তি আছে, যা তাকে ঘিরে ধরছে। এক মুহূর্তের জন্য মনে হলো সেই কালো ছায়াটা তার পিছনে দাঁড়িয়ে আছে, ঠিক তার গায়ে নিঃশ্বাস ফেলছে। পেছনে তাকানোর সাহসটাও হারিয়ে ফেলেছে ফিরোজ। দরজা খুলতে দেরি হতে দেখে সে মানিককে নিয়ে দ্রুত সেখান থেকে পালায়। তার মনে একটাই চিন্তা, এই জায়গা, এই বাড়ি, সবকিছুই অ*স্বাভাবিক, ভ*য়ংকর, এবং প্রাণঘাতী।\n----------\nভোরের স্নিগ্ধতা ভেদ করে ময়নার বুকফাটা কান্নার শব্দ পুরো মহল্লায় ছড়িয়ে পড়ছে। মাটিতে গড়াগড়ি করতে করতে আ*র্তনাদ করছে ময়না, \"আল্লাহ গো! এ তোমার কেমন বিচার! আমার মানিকরে কই নিয়া গেলা। ফিরাইয়া দাও ওরে!\" তার কান্নায় আকাশ-বাতাস ভারী হয়ে উঠেছে। করিম মিয়ার উঠানে ইতোমধ্যেই পুরো মহল্লার মানুষ ভিড় জমিয়েছে। তাদের মুখে উদ্বেগ আর উৎকণ্ঠা স্পষ্ট। আকলিমা এক কোণায় দাঁড়িয়ে ফিসফিস করে বলছে, \"কাইল রাইতেই তো ময়নার লগে কথা কইলাম। পোলাডা তখনও ওর লগেই আছিল। কেডা নিবো পোলাডারে হঠাৎ কইরা? আল্লাহ মাবুদ ভালো জানে।\"  এমন পরিস্থিতির মধ্যে করিম মিয়া ছুটে আসে উঠানে। তার চোখে কেবল ভয় আর অজানা আশঙ্কা। তিনি চিৎকার করে জিজ্ঞেস করলেন, \"ময়না! ময়য়য়য়নাআআআ! মা-নিক কই? আ-মা-গো মানিক কই?\" ময়নাকে জড়িয়ে ধরে কান্না শুরু করে করিম মিয়া।  ময়নার কান্না যেনো আরও তীব্র হয়ে উঠে। তিনি করিম মিয়ার ফতুয়ার কলার ধরে হাউমাউ করতে করতে বললেন, \"ধরবা না আমারে! তুমি যদি ঠিক মতো বাড়িত সময় দিতা, কাইল যদি বাড়িত থাকতা তাইলে আমার মানিক আমার বুকে থাকতো!\" করিম মিয়ার বুকে মাথা রেখে ময়নার চিৎকার এক মুহূর্তের জন্য চারপাশকে নিস্তব্ধ করে দেয়।  করিম মিয়া নির্বাক হয়ে স্ত্রীর কান্না দেখছে। তার ভেতরটা যেনো ভেঙে চুরমার হয়ে যাচ্ছে, কিন্তু তিনি সেটা প্রকাশ করতে পারছেন না। একদিকে স্ত্রীর বেদনার ভার, অন্যদিকে নিজের অসহায়ত্ব সবকিছু মিলিয়ে তার পৃথিবী অন্ধকার হয়ে যাচ্ছে। এদিকে ঘটনাটা মহল্লার সব মানুষের কানে গিয়ে পৌঁছে যায়। এই ভোরবেলা এমন অদ্ভুত ঘটনা ঘটে গেছে, যা কেউই কল্পনা করতে পারেনি। হঠাৎ করেই ফিরোজ আসে করিম মিয়ার উঠানে, এবং তার কোলে দেখা যায় ছোট্ট মানিককে। মহল্লার সবাই হতবাক হয়ে যায়। ময়না ছুটে এসে ফিরোজের হাত থেকে মানিককে নিজের কোলে তুলে নেয়। তিনি মানিককে জড়িয়ে ধরে চুমু খেতে খেতে বলে, \"আমার মানিক, আমার বাচ্চা!\" কান্নায় ভেঙে পড়েন তিনি, মায়ের এই য*ন্ত্র*ণায় যেনো আকাশও ভারী হয়ে উঠছে। একজন মমতাময়ী মা জানে, সন্তান হারানোর বেদনা কতটা ভয়ংকর। আর একজন দায়িত্বশীল বাবা জানে, বৃদ্ধ বয়সের লাঠির মতো নিজের সন্তানকে হারানোর যন্ত্রণা কেমন হাহাকার নিয়ে আসে। মহল্লার মানুষেরা প্রথমে ভাবছিলো, হয়তো ফিরোজই মানিককে চুরি করেছে। কিন্তু তখনই ফিরোজ গতরাতের সব ঘটনা খুলে বলে, যেভাবে সে মানিককে পেয়েছিল। সবাই একে একে তার কথা বিশ্বাস করতে শুরু করে। এরপর মহল্লার বয়স্ক লোকেরা পরামর্শ দেয় ময়না ও মানিককে হুজুরের কাছে নিয়ে যেতে। ময়না ও করিম মিয়া মানিককে নিয়ে হুজুরের কাছে যান। হুজুর তাদের জন্য পানি পড়া ও কাত্যায়ন পড়ে দেন। তারপর থেকে মানিক আর কোনো সমস্যায় পড়েনি। সবকিছু আবার আগের মতো স্বাভাবিক হয়ে যায়, তবে ময়নার মনে সবসময়ই সেই রাতের ঘটনার স্মৃতি ছায়ার মতো জড়িয়ে থাকে।\n[এটি একটি সত্যি ঘটনা। এটা আমার দাদীর কাছ থেকে শুনেছিলাম। উনারা যখন নেত্রকোনা টাউনে ছিলো তখন উনাদের পাশের বাড়িতেই এই ঘটনা ঘটে। এই ঘটনার প্রত্যক্ষ সাক্ষী আমার দাদী নিজে। জানি না কতটা গুছিয়ে লিখতে পেরেছি, তবে দাদীর মুখে যখন শুনেছিলাম তখন আমার অনেক ভয় করেছিলো। এটা গল্প হলেও সত্যি।  আশা করি সবার ভালো লাগবে।]"}],"comments":0,"is_featured":false,"read_time":null,"season":1,"status":"published","submitted_by":"primary-admin","date":"2026-04-01T20:52:52.350Z","updated_at":"2026-04-01T20:52:52.350Z"}','2026-04-01T20:52:52.331Z','2026-04-01T20:52:52.331Z');
