INSERT INTO "app_table_rows" ("pk","table_name","row_json","created_at","updated_at") VALUES(3488360,'stories','{"id":"1775076898257","title":"নিঃশেষ","excerpt":"__MAHEAN_META__:{\"status\":\"published\",\"submittedBy\":\"primary-admin\",\"author\":\"রিয়াদ ইসলাম আযান\",\"category\":\"অণুগল্প\",\"categories\":[\"অণুগল্প\"],\"coverImage\":\"/uploads/stories/covers/2026/04/69ec4798-d774-4e2a-8ca7-389afb9af80c.png\",\"slug\":\"নিঃশেষ\",\"parts\":[{\"id\":\"1\",\"title\":\"01\",\"slug\":\"part-01\",\"content\":\"\"}],\"comments\":0,\"season\":1}:__MAHEAN_META_END__গরমকাল শেষ হয়ে মাত্র শীতের হালকা ছোঁয়া লেগেছে চারপাশে। প্রকৃতি যেনো ধীরে ধীরে বদলে যাচ্ছে। এই মনোরম আবহাওয়ায় সালাউদ্দিন এসেছে বোন আতিরার শ্বশুরবাড়ি বেড়াতে। ছোটবেলা থেকেই তার একমাত্র আদরের বোন ছিলো আতিরা। সালাউদ্দিনই শখ করে তার নাম রেখেছিলো আতিরা, যার অর্থ বিশুদ্ধতা। আতিরার বিয়ে হয়েছে আট-নয় বছর আগে।","content":"","author_id":"1773089545405","author":"রিয়াদ ইসলাম আযান","category_id":"অণুগল্প","category":"অণুগল্প","views":0,"image":null,"cover_image":"/uploads/stories/covers/2026/04/69ec4798-d774-4e2a-8ca7-389afb9af80c.png","slug":"নিঃশেষ","tags":[],"parts":[{"id":"1","title":"01","slug":"part-01","content":"গরমকাল শেষ হয়ে মাত্র শীতের হালকা ছোঁয়া লেগেছে চারপাশে। প্রকৃতি যেনো ধীরে ধীরে বদলে যাচ্ছে। এই মনোরম আবহাওয়ায় সালাউদ্দিন এসেছে বোন আতিরার শ্বশুরবাড়ি বেড়াতে। ছোটবেলা থেকেই তার একমাত্র আদরের বোন ছিলো আতিরা। সালাউদ্দিনই শখ করে তার নাম রেখেছিলো আতিরা, যার অর্থ বিশুদ্ধতা। আতিরার বিয়ে হয়েছে আট-নয় বছর আগে। সংসারে এখন জমজ দুই ছেলে-মেয়ে মিম, জিম এবং তাদের ছোট্ট ভাই নূর। মিম আর জিমের বয়স সাড়ে সাত বছর এবং নূরের বয়স পাঁচ বছর। কিন্তু বয়সের তুলনায় তার চঞ্চলতা যেনো অন্যরকম। সে সবসময় কিছু না কিছু কাণ্ড করে বেড়ায়, আর তার হাসি মুখ সবসময় সবার মন ভালো করে দেয়। বাড়ির সবার আদরের এই ছোট্ট ছেলেটি জানে কীভাবে নিজের অংশটুকু বুঝে নিতে হয়। তার বোন মিম বা ভাই জিম যখন কোনো খেলনা নিয়ে খেলছে, নূর একরকম নিজের অধিকার নিয়ে সেই খেলনাটি আদায় করে নেয়, যেনো বুঝে গেছে জগতে নিজের চাওয়া পূরণ করতে হয় নিজেই। বাড়িতে সালাউদ্দিনের আগমনে ছোট্ট নূরের উত্তেজনা আরও বেড়ে গেছে। সে মামাকে দেখলেই দৌড়ে এসে গলা জড়িয়ে ধরে, কখনো খেলার কথা বলে, কখনো গল্প শুনতে চায়। নূরকে দেখে সালাউদ্দিনের নিজের ছোটবেলার কথা মনে পড়ে যায়। তারও বোনের সাথে এমন আনন্দময় সময় কাটতো, অথচ এখন সে বড় হয়ে গেছে। আতিরার সংসারে এই শিশুরা যেনো তাদের প্রাণের উৎস। তাদের খুনসুটি, হাসি-আনন্দে বাড়ি ভরে থাকে। নূর একটু দস্যি হলেও তার নিষ্পাপ মুখশ্রী আর মিষ্টি ব্যবহার সবাইকে মুগ্ধ করে রাখে।\nসালাউদ্দিন যখন বিকেলের দিকে উঠানে বসে বই পড়ছিলো, ঠিক তখনই ছোট্ট নূর দৌড়ে এসে সালাউদ্দিনের কোলে চড়ে বসলো। মুখে চিরাচরিত দুষ্টু হাসি, চোখে আকাঙ্ক্ষা।  \"মামা, আমাকে আইসক্রিম খাওয়াবে না?\" নূর মিষ্টি করে বললো। সালাউদ্দিন হেসে নূরকে জিজ্ঞেস করলো, \"তোর মা কি বলেছে? আইসক্রিম খাওয়া যাবে?\" ঠিক তখনই আতিরা রান্নাঘর থেকে কড়া স্বরে বলল, \"নূরকে আইসক্রিম কিনে দিয়ো না। ওর গলা খারাপ হয়ে যাবে।\" সালাউদ্দিন, বোনের কথার অবাধ্য না হয়ে নূরকে বোঝানোর চেষ্টা করল, \"আজ না নূর, অন্যদিন খাবি। তোর মা বলেছে, তাই আইসক্রিম এখন খাওয়া যাবে না।\" কিন্তু নূর কি সহজে মানতে পারে? তার মিষ্টি মুখ গম্ভীর হয়ে গেলো, ঠোঁট ফুলিয়ে রাগ দেখাতে শুরু করলো। সে জানে, আইসক্রিম তার প্রাপ্য, আর কেউ তাকে এভাবে বঞ্চিত করতে পারে না। নূর রাগে ফুঁসছে, তার চোখেমুখে অভিমান স্পষ্ট। সালাউদ্দিন তাকে শান্ত করার জন্য কোলে তুলে নিলো। \"আরে বাবা, রাগ করিস না, আয়! তোকে একটা গল্প শোনাবো।\" কিন্তু নূর চুপ থাকার ছেলে নয়। সে সালাউদ্দিনের মুখের দিকে তাকিয়ে এক মুহূর্তের মধ্যে তার নাক কা/ম/ড়ে ধরলো! সালাউদ্দিন হ/ত/ভ/ম্ব হয়ে গেলো। নূরের শক্ত কা/মড়ে তার নাক ব্য/থায় কুঁ/কড়ে উঠলো।৷ \"আরে নূর! ছাড়! এটা কি করছিস!\" সালাউদ্দিন নূরের মুখ থেকে তার নাক ছাড়ানোর চেষ্টা করলো, কিন্তু ছোট্ট নূর শক্ত দাঁতে কা/মড়ে ধরে রেখেছে। অনেক চেষ্টার পর অবশেষে নূর দাঁত খোললো, সালাউদ্দিন তার নাকের উপর হাত বুলিয়ে হেসে বললো, \"আহারে! তুই তো দেখি আসলেই দুষ্টু। তুই এইরকম করলে তো আর তোর সাথে আইসক্রিম খেতে যাওয়া হবে না!\" নূর রাগ নিয়ে মুখ ফিরিয়ে বসে থাকলেও, তার চোখের কোণায় লুকানো হাসিটা সালাউদ্দিন ঠিকই দেখে ফেললো। সালাউদ্দিন নূরকে শান্ত করার পরপরই বাড়ির উঠানের দরজায় এক অদ্ভুত শব্দ শোনা গেলো। দরজার সামনে দাঁড়িয়ে আছে এক ভিক্ষুক। লোকটির দু''টো পা-ই নেই, ডিগবাজির মতো গড়াতে গড়াতে ভিতরে ঢুকছে। তার শীর্ণ দেহ, মলিন কাপড়, এবং মুখের ক্লান্তি স্পষ্টভাবে ফুটে উঠেছে। এমন দৃশ্য দেখে সালাউদ্দিনের হৃদয়ে এক ধরনের করুণা জাগ্রত হলো।  লোকটি ধীরে ধীরে উঠানের এক কোণায় গিয়ে থেমে সাহায্যের আশায় তাকিয়ে থাকে। সালাউদ্দিন পকেট থেকে মানিব্যাগ বের করে, ভিক্ষুকের হাতে পঞ্চাশ টাকার একটি নোট দেয়। লোকটির মুখে কৃতজ্ঞতার ছাপ ফুটে উঠে। ঠিক তখনই রান্নাঘর থেকে আতিরা বেরিয়ে আসে। নিজের ভাইয়ের মতোই সে''ও লোকটির জন্য কিছু করতে চায়। ছোট্ট নূর এক পাশে দাঁড়িয়ে সব দেখছে, তার ছোট্ট মনের মধ্যে এই পুরো দৃশ্যটি গভীর প্রভাব ফেলছে। আতিরা রান্নাঘর থেকে কিছু খাবার এনে ভিক্ষুকের হাতে তুলে দিলো। লোকটি আতিরা ও সালাউদ্দিনকে অনেক দোয়া করে। নূরের মুগ্ধ দৃষ্টি ভিক্ষুক আর তার মা-মামার দিকে। সে কিছুই বুঝতে পারছে না, কিন্তু এই সাহায্যের মুহূর্তটি তার মনে গভীরভাবে আঁকা হয়ে থাকলো।\nসন্ধ্যা ফুরিয়ে রাত ঘনিয়ে এসেছে। রুম্মান দোকানের কাজ শেষ করে বাসায় ফিরলো। হাতে তিন ভাই-বোনের জন্য চকলেট, বিস্কুট, চিপস। সবকিছু তাদের পছন্দের খাবার। রুম্মানকে দেখেই তিন ভাই-বোনের চোখ উজ্জ্বল হয়ে উঠলো। বাবা তাদের জন্য এত কিছু এনেছে! নূর, মিম, আর জিমের আনন্দে ছোটাছুটি শুরু হয়ে গেলো। কিন্তু দুষ্টু নূর কিছুতেই চুপ থাকে না। খাবারগুলোতে তার ভাগ চাই একটু বেশিই। সে ভাবছে, ছোট বলে সবার থেকে বেশি পাওয়ার অধিকার তারই। কিন্তু মিম আর জিম এমন অসম ভাগ কিছুতেই মেনে নিতে চায় না। তাতেই শুরু হয়ে গেলো তিন ভাইবোনের ঝগড়া। রুম্মান, যদিও স্বভাবে একটু রাগী, কিন্তু তার মনটা খুবই নরম। সে চুপচাপ দাঁড়িয়ে তিন ভাই-বোনের তর্ক-বিতর্ক দেখছে। কিন্তু নূর যখন ঝগড়ায় হেরে গেলো, তখন কান্না শুরু করলো। তার ছোট্ট মুনটা ভেঙে গেলো, চোখ দিয়ে টপটপ করে পানি পড়তে লাগলো। রাগ আর অভিমানে কাঁদতে কাঁদতে নূর উঠানের দিকে চলে গেলো। ওর কান্না শুনে সবার মন কাঁদলো, সবাই নূরের পেছন পেছন বাইরে এলো। সবাইকে আসতে দেখে নূর আরও জোরে কাঁদতে শুরু করলো। চোখের পানি মুছতে মুছতে হঠাৎ বিকেলের সেই খোঁড়া ভিক্ষুকটার মতো নূরও ডিগবাজি দেওয়া শুরু করল! ছোট্ট নূরের ডিগবাজি আর কান্নার মিশ্রণে সে এক মজার দৃশ্য তৈরি করলো।\n সালাউদ্দিন, আতিরা, রুম্মান সবাই উঠানে দাঁড়িয়ে নূরের এমন কাণ্ড দেখে হেসে ফেললো। মিম আর জিমও এবার আর রাগ করতে পারলো না, তারাও হাসিতে যোগ দিলো। নূরের এমন অদ্ভুত কান্নার ধরণে মুহূর্তেই পুরো উঠানজুড়ে হাসির রোল পড়ে গেলো। হাসতে হাসতে হঠাৎ রুম্মানের মুখটা গম্ভীর হয়ে গেলো। তার রাগ চেপে ধরলো নূরের কান্না আর দুষ্টুমিতে। হঠাৎই সে দৌড়ে গিয়ে নূরকে কোলে তুলে নিলো এবং সোজা বাড়ির বাইরে চলে গেলো। সবার মুখ থেকে হাসি মিলিয়ে গেলো, সালাউদ্দিন, আতিরা, মিম, আর জিমও রুম্মানের পেছনে ছুটে এলো। বাড়ির ভেতরে তাদের গরুর গোয়াল ঘর, আর বাইরে গোয়াল ঘরের পাশে ছিলো গোবরের গর্ত। রুম্মান সেই গর্তের দিকে নূরকে নিয়ে এগিয়ে গেলো। \"কান্না বন্ধ করবি নাকী গোবরের গর্তে ফেলে দেবো তোকে!\" রুম্মান একটু রাগী কণ্ঠে বললো। নূর এক মুহূর্তে চুপ হয়ে গেলো। বাবার এমন রাগী স্বর আগে কখনো শোনেনি সে। নূর হঠাৎ ভয়ে কান্না থামিয়ে দিলো। তার ভেজা চোখে একটুকরো বিস্ময়! রুম্মান কি সত্যিই তাকে গোবরের গর্তে ফেলে দেবে? সবাই এই দৃশ্য দেখে আর নিজেকে ধরে রাখতে পারলো না। একসাথে সবাই খক করে হেসে উঠলো। এমনকি নূরও বাবার গম্ভীর মুখ দেখে হেসে ফেললো। বাবা-ছেলের মধ্যকার এই ছোট্ট রাগ-হাসির মুহূর্তটা যেনো সবাইকে আরও কাছে নিয়ে এলো।\nছোট্ট নূরকে এখন স্কুলে ভর্তি করা হয়েছে, কিন্তু সে একদমই স্কুলে যেতে চায় না। স্কুলের নাম শুনলেই যেনো শরীরের সমস্ত শক্তি হারিয়ে ফেলে, একেবারে ম*রা লা*শের মতো টান হয়ে শুয়ে থাকে মেঝেতে। কেউ যতই টেনে তুলতে চেষ্টা করুক, নূর উঠতেই চায় না। একবার স্কুলের সময় হয়ে এলে পুরো এলাকা দৌড়াতে শুরু করতো। এত দ্রুত দৌড়াতো যে কেউ তাকে ধরতেই পারতো না। নূরের জন্য স্কুলে যাওয়া যেনো যু*দ্ধের সমান। স্কুলে যেতে না চাইলে আতিরা তাকে জোর করে, টেনে হিঁ*চড়ে স্কুলের সামনে নিয়ে যেতো। আর এই দৃশ্য দেখে স্কুলের বাকি বাচ্চারা হাসতো। তাদের হাসি শুনে নূরের মেজাজ আরও চড়ে যেতো। রাগে গজগজ করতে করতে আতিরাকে বলতো, \"চলে যাও তুমি, আমি বলেছি আমি স্কুলে আসবো না! দেখছো এখন সবাই আমাকে দেখে হাসছে।\" মাঝে মাঝে নূরের এমন বায়না দেখে আতিরার ধৈর্যের বাঁধ ভেঙে যেতো। বাধ্য হয়ে তাকে শা/সন করতো, কখনও মা*র*তোও। অন্যদিকে, মিম আর জিম পড়াশোনায় খুব মনোযোগী ছিলো। কিন্তু নূরের মন একদমই বসতো না স্কুলের পড়ায়।   তবে আশ্চর্যের বিষয় হলো, যতই পড়াশোনার প্রতি অনীহা থাকুক না কেনো, নূর মুখস্থ বিদ্যায় খুব ভালো ছিলো। যা একবার পড়ে তা সহজেই মনে রাখতে পারতো। পড়াশোনা আর স্কুলকে যতই অপছন্দ করুক, তার মেধা সবার নজর কাড়তো।\nছোট্ট নূর এখন হাই স্কুলে ক্লাস নাইনে পড়ে। একদিন স্কুল থেকে ফেরার সময় সে আর তার বন্ধুরা মিলে পাশের বাগান থেকে আম চু*রি করে। নূর তখন মেহেদীর সাইকেলের পিছনে বসে আম খাচ্ছিলো, আর মেহেদী সাইকেল চালাচ্ছিলো। বাকি বন্ধুরা নিজেদের সাইকেল নিয়ে পিছনে আসছিলো। সবার মধ্যে আনন্দের ঢল বইছে, কিন্তু হঠাৎ মেহেদীর সাইকেলের পাশ দিয়ে একটা চার্জার ভ্যান ওভারটেক করার সময় সাইকেলের সামনের চাকা ভ্যানে লেগে যায়। ধপাস করে নূর রাস্তায় পড়ে গেলো। সবাই চমকে উঠলো, কিন্তু নূর যেনো ব্যস্ত অন্য কিছুতে। সে কোনোভাবে উঠে দাঁড়িয়ে নিজের অর্ধেক খাওয়া আমটা খুঁজছে! তার বাকি বন্ধুরা হতবাক হয়ে বললো, \"বোকা! তোর প্যান্ট ময়লা হয়ে গেছে আর তুই আম খুঁজছিস?\" ওদের কথা শুনে নূর হঠাৎ যেনো হুঁশ ফিরে পেলো। আমের কথা ভুলে গিয়ে নিজের প্যান্টের দিকে তাকালো, যা পুরোপুরি ধুলোয় মাখা। সবাই তার দিকে তাকিয়ে হাসছিলো। সেই মুহূর্তে নূর এতটাই লজ্জা পেলো যে নিজেকে বোকা মনে হলো।\nদিন যাচ্ছে, আর ছোট্ট নূরও বড় হয়ে উঠছে। স্কুল পালানো, দুষ্টুমিগুলো এখন অতীত। এখন সে পড়াশোনায় মন দিয়েছে, আর মাত্র এক বছর পরেই স্কলারশিপ নিয়ে কানাডায় পড়াশোনা করতে যাবে। যেটা ভাবতেই অবাক লাগে, যে নূর স্কুলের নাম শুনলেই অসুস্থ হয়ে যেতো, সেই নূরই এখন বিদেশে পড়তে যাবে। অন্যদিকে, জিম অনেক আগেই পড়াশোনা ছেড়ে দিয়ে বাবার সঙ্গে ব্যবসার হাল ধরেছে। আর মিমের তো বিয়ে হয়েছে কয়েক মাস হলো। একদিন দুই ভাই জিম আর নূর মিলে ঠিক করলো তারা কক্সবাজার ট্রিপে যাবে। যেই ভাবা সেই কাজ। এক মাসের মধ্যেই সবকিছু গুছিয়ে ফেললো। মাস খানেক পরই তারা চলে গেলো কক্সবাজারে। সমুদ্রের ঢেউয়ের শব্দ, মৃদু বাতাসের স্পর্শ আর চারপাশের সবুজে ঘেরা সেই পরিবেশ তাদের মন ভালো করে দিচ্ছিলো। কক্সবাজারের বিস্তীর্ণ সৈকত, যেখানে সমুদ্র আর আকাশ মিলে একাকার হয়ে গেছে। সমুদ্রের নীল জলরাশির মাঝে সূর্যের আলো ঝিকিমিকি করছে, যেনো আলোর খেলা। চারপাশের পর্যটকদের আনাগোনা, নানা ধরনের হোটেল আর রিসোর্ট। সৈকতের আশপাশে ছোট ছোট দোকানে নানা ধরনের সি-ফুড, ঝিনুকের গয়না, আর অন্যান্য সামগ্রী বিক্রি হচ্ছে। এই শহরটা যেনো এক ভিন্ন জগৎ, যেখানে সবাই হাসি-আনন্দে সময় কাটাচ্ছে। দুই ভাই পাশেই একটা হোটেলে উঠেছে। বেশ কিছুদিন কক্সবাজারে থাকার প্ল্যান করেছে তারা। দিনভর ঘুরাঘুরি করে তারা রাতে হোটেলে ফিরে আসে। রাতের খাবার শেষ করে রাত প্রায় বারোটা বাজে, তখনই জিম হঠাৎ নূরকে ডাকলো, \"এই নূর! বি/য়ার খাবি?\" এক গাল হাসি দিয়ে বললো জিম। নূর হকচকিয়ে উঠে বললো, \"কি বলছিস? এখন?\" \"হ্যাঁ! আসার সময় সাথে করে এনেছিলাম,\" বললো জিম। এরপর দুই ভাই মিলে বি/য়ার খেতে বসলো। কিছুক্ষণ পর, মা/তাল অবস্থায় জিম হঠাৎ গম্ভীর হয়ে বললো, \"নূর শোন! তোকে একটা কথা বলি, কাউকে বলবি না।\" নূরও তখন প্রায় মা/তাল। সে মজা করে বললো, \"আচ্ছা বল!\" জিম বললো, \"আমার না একটা মেয়ের সাথে রিলেশন আছে। মেয়েটা খুব সুন্দর। নাম তানিশা। তোদের ভার্সিটিতেই পড়ে।\" জিমের কথা শুনে নূর একদম গম্ভীর হয়ে গেলো, তারপর হঠাৎ করে ঠাস করে জিমকে একটা থা*প্প*ড় দিলো। \"শা*লা! আমি এখনো একটা প্রেম করতে পারলাম না আর তুই আমার ভার্সিটির মেয়েদের পটাচ্ছিস!\" নূর বললো। জিম হাসতে হাসতে বললো, \"আরে শোন না! তানিশাকে আমি বিয়ে করবো কিন্তু বাসায় বলতে পারছি না। তুই হেল্প করবি?\" নূর তখন একটা দুষ্টু হাসি দিয়ে বললো, \"হ্যাঁ, করবো! তবে আমার একটা শর্ত আছে।\" জিম মাথা চুলকাতে চুলকাতে জিজ্ঞাসা করলো, \"শর্ত? কি শর্ত?\" নূর আবারও মজা করে বললো, \"তানিশাকে আমার সাথে রিলেশন করতে হবে। আর তুই আমাদের সেটিং করিয়ে দিবি, তাহলেই তোদের বিয়ের কথা বাসায় জানাবো।\" জিম হাসতে হাসতে বললো, \"ওহ্! এই ব্যাপার! আচ্ছা ঠিক আছে। তুই প্যারা নিস না!\" এরপর দুই ভাই বি/য়ার খেতে খেতে মাতলামি করতে থাকে। হাসি-ঠাট্টা, একে অপরকে ঠেলা-ধা*ক্কা, আর পুরনো দুষ্টুমির গল্প করতে করতে কখন যে ঘুমিয়ে পড়লো, তাদের নিজস্ব কোনো ধারণাই নেই। মাথাগুলো নরম বালিশে হেলে পড়লো, বি/য়ার খেয়ে দুজনেরই চোখ ভারী হয়ে গেলো। হোটেলের ঘরের বাতিটা জ্বলছিলো, কাঁচের জানালার বাইরে থেকে সাগরের মৃদু ঢেউয়ের শব্দ ভেসে আসছিলো। জিম আর নূর, দুই ভাই, একে অপরের পাশেই শুয়ে পড়লো, তাদের হাসি আর মা/ত/লামির গুঞ্জন মিলিয়ে গেলো ঘুমের রাজ্যে। বাইরে রাত গভীর হতে লাগলো, আর ভেতরে দুই ভাইয়ের নিস্তব্ধ ঘুম ভাঙতে চাইলো না।\n----------\nনূর আর মেহেদী বাসে করে তাদের আরেক বন্ধু সাদাফের বাসায় যাওয়ার জন্য রওনা দেয়। বাসের জানালা দিয়ে বাইরে তাকিয়ে থেকে তাদের দুষ্টুমিভরা আলাপ চলতে থাকে। হঠাৎ সামনের রাস্তায় এক নারীর চলাফেরা দেখে মেহেদী নূরকে কনুই দিয়ে খোঁচা মে*রে বলল, \"দেখ, সে*ক্সি আসছে!\" নূর হেসে তার সাথে তাল মিলিয়ে বললো, \"হ্যাঁ, দেখছি দেখছি!\" তাদের আলাপ শুনে পাশে বসে থাকা মধ্যবয়স্ক এক লোক কৌতূহলী হয়ে নূরকে জিজ্ঞাসা করলো, \"এই যে, সে*ক্সি মানে কী?\" নূর কিছুটা বিব্রত হয়ে আমতা আমতা করে বললো, \"সে*ক্সি মানে... মানে... মহিলা।\" লোকটা চুপ করে রইলো, কোনো কথা বললো না। নূর আর মেহেদী পরস্পর একে অপরের দিকে তাকিয়ে চোখের ইশারায় হাসাহাসি করলো। বাস তার নিজস্ব গতিতে চলতে থাকলো। কিছুক্ষণ পর বাসের ভেতরে এক মহিলার শরীর খারাপ হয়ে পড়লো। সেই লোকটি এদিকে-ওদিকে তাকিয়ে বললো, \"এসব সে*ক্সিদের যে কেনো বাসে উঠায়, কে জানে! একা একা এই সে*ক্সিদের বাসে উঠানো ঠিক না!\" বাসের সবাই অবাক হয়ে লোকটার দিকে তাকাতে লাগলো, আর লোকটা নিজের কথার গতি বাড়িয়ে বললো, \"এখন যদি এই সে*ক্সির কিছু হয়ে যায়, তাহলে কে দায়ী নেবে? আজব সে*ক্সি!\" লোকটার এমন অদ্ভুত মন্তব্যে বাসের পরিবেশ থমথমে হয়ে গেলো। নূর আর মেহেদী নিজেদের হাসি লুকানোর জন্য কাঁধ কাঁপাতে লাগলো। দীর্ঘক্ষণ বাসে জার্নি করার পর অবশেষে নূর আর মেহেদী সাদাফের বাসায় এসে পৌঁছায়। ক্লান্ত, কিন্তু উ/ত্তেজিত দুই বন্ধু বাস থেকে নেমে সাদাফের বাড়ির দিকে এগিয়ে যায়। গেটের কাছে পৌঁছাতেই দেখতে পায় সাদাফ আর কাদের দাঁড়িয়ে আছে, দুজনেই হাত গুটিয়ে অপেক্ষা করছে। সাদাফ মুখ কুঁচকে বললো, \"এতক্ষণে তোরা এলি! সেই কখন থেকে দাঁড়িয়ে আছি এখানে, আর তোদের কোনো খবরই নেই!\" মেহেদী হেসে বললো, \"আর বলিস না, বাস লেইট করে ছেড়েছে, পুরাই অসহ্য অবস্থা! তার উপর রাস্তায় জ্যাম\" মেহেদী কথা শেষ করতে করতেই সেখানে তানজিল আর তন্ময় এসে হাজির হয়, তাদের হাতে একটা ব্যাগ। ওদের দেখে কাদের জিজ্ঞেস করলো, \"কিরে, সবকিছু ঠিকঠাক আছে তো?\" তন্ময় মুচকি হেসে বললো, \"হ্যাঁ, হ্যাঁ! সবকিছু ঠিকঠাক আছে, চিন্তা করিস না!\" নূর দাঁত বের করে একটা দুষ্টু হাসি দিয়ে বললো, \"তাহলে চল, একটা জায়গা দেখে গিয়ে বসি। আজকের পরিকল্পনা মিস করা যাবে না!\" এখানে তাদের আসার একটাই কারণ, অনেক দিন পর ছয় বন্ধু একসাথে হয়েছে। তাদের মনের আনন্দে তা/স খেলার জন্য এবং অ্যা/লকো/হল পান করার জন্যই এই আয়োজন। সবাই মিলে চলে গেলো সাদাফদের বাড়ির পিছনের ছোট্ট কাঠের ঘরটায়। ঘরটা বেশ পুরনো, ছোট হলেও ভেতরে একটা কাঠের চৌকিখাট রাখা ছিলো, যেখানে অনায়াসে চার-পাঁচজন বসতে পারে। ঘরের ভিতরে গিয়ে ঘরের দরজাটা বন্ধ করে দিলো, চারদিকে নিরিবিলি পরিবেশ, দূর থেকে হালকা হাওয়ার সুরভি আসছে। সবাই যেনো নিজেদের মাঝে ডুবে গেলো। সবাই ধীরে ধীরে চৌকিখাটে গিয়ে বসলো। তা/সের গুটি বের করে মেহেদী হাসতে হাসতে বললো, \"তা/স, অ্যা/লকো/হল, আর আমাদের বন্ধুত্ব এটাই তো চাই আজ!\" সাদাফ টেবিলে তা/স সাজাতে লাগলো। নূর ব্যাগ থেকে অ্যা/লকো/হলের বোতল বের করে চৌকিতে বসতে গিয়ে দেখে ওরা পাঁচজন আগে থেকে চৌকিতে বসে পরেছে, অবশিষ্ট কোনো জায়গা নেই আরেকজনকে বসানোর মতো। নূর হতাশ হয়ে বললো \"যাহ! তোরাই তো সব জায়গা দখল করে বসে আছিস আমি কোথায় বসবো?\" মেহেদী খিটখিট করে হেসে বললো \"তুই দাঁড়িয়ে থাক!\" মেহেদীর কথার সঙ্গে বাকিরাও তাল মিলিয়ে হেসে উঠলো। নূর দাঁড়িয়ে রইলো, আর ওরা পাঁচজন নিজেদের মতো বসে তা/স খেলতে ব্যস্ত। তা/স খেলতে খেলতে হঠাৎ মেহেদীর প্রচণ্ড হি/সু পেয়ে গেলো, কিন্তু সে নিজের বসার জায়গাটা হারাতে চায় না। তাই সে জায়গা ছেড়ে না গিয়ে, জানালা দিয়ে হি/সু করার চেষ্টা করছিলো। তখনই জানালার ভাঙ্গা কাঠের টুকরোতে মেহেদীর নু/নু কেটে গেলো। চিৎকার দিয়ে মেহেদী বললো, \"ওমা গো! কেটে গেলো!\" সাদাফ অবাক হয়ে জিজ্ঞেস করলো, \"কি কাটলো?\" মেহেদী মুখ ফুপিয়ে বললো, \"আমার নু/নু!\" এই শুনে নূর হাসতে হাসতে বললো, \"জায়গা দখল করতে গিয়ে নু/নু হারালি, বন্ধু!\" নূরের কথা শুনে সবাই অট্টহাসিতে ফেটে পড়লো। মেহেদীর এই কাণ্ড দেখে পুরো ঘরে হাসির রোল পড়ে গেলো। তাদের হাসি মাখা আড্ডার মাঝেই হঠাৎ নূরের ফোনে আতিরার কল আসে। নূর একটু ইতস্তত করে কল রিসিভ করতেই আতিরা বলে, \"তোর নানাকে নিয়ে উইমেন্স হসপিটালে আছি। সকালে বের হওয়ার সময় পরে গিয়ে কোমরে ব্য/থা পেয়েছে। তিনতলায় ভর্তি, তাড়াতাড়ি আয়।\" নানার খবর শুনে নূর তৎক্ষণাৎ আড্ডা থেকে উঠে সবার কাছ থেকে বিদায় নেয়। যদিও নূরের এভাবে চলে যাওয়ায় সবার মন খারাপ হয়, তবুও তারা হাসিমুখে নূরকে বিদায় জানায় এবং জানায় যে কোনো সাহায্যের প্রয়োজন হলে যেন দেরি না করে তাদের জানায়। হাসপাতালে পৌঁছাতে পৌঁছাতে সন্ধ্যা হয়ে যায়। আশেপাশের পরিবেশ বেশ নিরিবিলি। নূর তাড়াহুড়ো করে তিনতলায় যেতে লিফটে উঠে, কিন্তু সে লিফটের সুইচ টিপতে ভুলে যায়। সে ভাবে, লিফট নিজে নিজেই তাকে তিনতলায় নিয়ে যাবে, কারণ সে সবসময় দেখে লিফট একেক তলায় মানুষকে উঠিয়ে দেয়। আবার একেক তলায় নামিয়েও দেয়। তাই সে চুপ করেই দাঁড়িয়ে রইলো লিফটের ভিতরে। কিছুক্ষণ পর নূরের সন্দেহ হয়, কেনো লিফট তাকে উপরে নিয়ে যাচ্ছে না। অবশেষে সে থ্রি নাম্বার বাটনে চাপ দেয়, এবং লিফট তাকে তিনতলায় পৌঁছে দেয়। নূর তখন বুঝতে পারে, কিভাবে লিফট ঠিকভাবে ব্যবহার করতে হয়। নূর তিনতলায় পৌঁছে দেখে আতিরা, সালাউদ্দিন, এবং সালাউদ্দিনের স্ত্রী ফারহানা সবাই হাসপাতালে তার নানার সাথে রয়েছে। লিফটের মজার ঘটনাটি সবাইকে জানালে সবাই হাসতে শুরু করে, এবং নূরও তাদের সাথে হাসে। এরপর নানাকে টানা এক সপ্তাহ ধরে হাসপাতালে চিকিৎসা দেওয়া হলেও অবস্থা ক্রমশ অবনতি হতে থাকে। নূর প্রতিদিন সকাল থেকে গভীর রাত পর্যন্ত নানার পাশে থাকে, তাঁর প্রতি মায়া ও ভালোবাসা আরও গভীর হতে থাকে। আট দিনের দিন ডাক্তাররা জানিয়ে দেয়, নানার সময় ফুরিয়ে এসেছে। সেইদিন বিকেলেই নানার নি/থর দেহটা বাসায় ফিরিয়ে আনা হয়। চারপাশে কেবল শো/কের আবহ, নূর নির্বাক হয়ে বসে থাকে নানার কা/ফ/নে মোড়ানো লা/শের পাশে। চোখের সামনে প্রিয় মানুষটির চলে যাওয়া, হৃদয়ে এক শূন্যতা তৈরি করে দেয়। পরদিনই আরও একটি ম/র্মা/ন্তিক ঘটনা ঘটে। নানার মৃ/ত্যু/তে প্রচণ্ডভাবে ভেঙে পড়া নানিও ধীরে ধীরে নি/স্তেজ হয়ে যান। সকালবেলা সবাই যখন নানার জানাজা নিয়ে ব্যস্ত, তখন খবর আসে নূরের নানিও আর বেঁ/চে নেই। একদিনের ব্যবধানে নূর তার জীবনের দুইজন গুরুত্বপূর্ণ মানুষকে হারিয়ে ফেলে। চারদিকে কেবল কান্নার আওয়াজ, নূরের বুকের ভেতরটা যেনো পাথর হয়ে যায়।  নানির মৃ/ত্যু নূরের জন্য ছিলো আরও বড় ধাক্কা। নানির মৃ/ত্যুতে পুরো পরিবার শো/কে ভেঙে পড়ে। নূর ও আতিরা সেই শো/কের মাঝে একে অপরকে সান্ত্বনা দেওয়ার চেষ্টা করে, কিন্তু প্রিয় মানুষ হারানোর ব্যথা সবার মুখে এক চরম নীরবতা এনে দেয়। নানা এবং নানির বিদায়ের পর নূর নিজেকে একটু স্থির করার চেষ্টা করে। কিছুটা সময় পার হতে থাকে, কিন্তু সেই শো/ক যেনো এখনও বুকের ভেতরে কাঁটা হয়ে বিঁধে থাকে। নূর, আতিরা, এবং পরিবারের অন্য সদস্যরা ধীরে ধীরে পরিস্থিতি মেনে নেওয়ার চেষ্টা করে, যদিও শো/কের ছায়া পুরো পরিবেশেই ঘিরে থাকে। কিন্তু তাদের এই স্বাভাবিকতার দিকে ফিরে আসার প্রচেষ্টা এক মুহূর্তের মধ্যেই চূর্ণ-বিচূর্ণ হয়ে যায়। নানির মৃ/ত্যুর ঠিক দশ দিনের মাথায়, সালাউদ্দিনও হঠাৎ অসুস্থ হয়ে পড়ে এবং মৃ/ত্যু/বরণ করে। একের পর এক প্রিয়জন হারানোর এই দুঃসহ অভিজ্ঞতা আতিরা ও নূরের জন্য ছিলো এক চরম বিপর্যয়। সালাউদ্দিনের মৃ/ত্যুর খবর যেনো তাদের দু’জনের হৃদয়কে আবার ভেঙে ফেলে। নূর কিছুতেই বুঝতে পারে না কেন এতগুলো প্রিয় মানুষকে সে হারিয়ে ফেলছে। আতিরা হতভম্ব হয়ে বসে থাকে, আর নূরের দিকে ফাঁকা দৃষ্টিতে তাকিয়ে থাকে। এই মৃ/ত্যুর ম/র্মা/ন্তিক ধাক্কা তাদের দুজনের মনের ভেতর এক গভীর শূন্যতা সৃষ্টি করে, যা মেনে নেওয়া তাদের জন্য অসম্ভব হয়ে পড়ে। \nপরিশেষে, মানুষ যতই শো/কে ডুবে থাকুক না কেনো বাস্তবতা তাদের সেই শো/কের গভীর অন্ধকারে ঠেলে দেয়, যেখানে দুঃখের সমাপ্তি নেই, শুধু এক অচেনা বিষণ্নতা ছড়িয়ে থাকে চারপাশে।\n"}],"comments":0,"is_featured":false,"read_time":null,"season":1,"status":"published","submitted_by":"primary-admin","date":"2026-04-01T20:54:58.257Z","updated_at":"2026-04-01T20:54:58.257Z"}','2026-04-01T20:54:58.240Z','2026-04-01T20:54:58.240Z');
